      SUBROUTINE GALCDF(X,AK,TAU,IADEDF,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED ASYMMETRIC LAPLACE
!              DISTRIBUTION WITH SHAPE PARAMETERS AK AND LAMBDA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 GALPDF(X,K,TAU) = C1*C2*C3        X <> 0
!              WITH
!                 C1 = SQRT(2/PI)*EXP((SQRT(2)/2)*((1/K)-K)*X)/
!                      GAMMA(TAU)
!                 C2 = ((SQRT(2)*ABS(X)/(K+(1/K))**(TAU-0.5)
!                 C3 = K(TAU-0.5)((SQRT(2)/2)*((1/K)+K)*ABS(X))
!              WHERE K(LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --AK     = THE FIRST SHAPE PARAMETER
!                     --TAU    = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GENERALIZED ASYMMETRIC
!             LAPLACE DISTRIBUTION WITH SHAPE PARAMETERS DAK AND DTAU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSER, 2001,
!                 PP. 189.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
!
      DOUBLE PRECISION AK
      DOUBLE PRECISION TAU
      DOUBLE PRECISION X
      DOUBLE PRECISION CDF
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION GALFUN
      EXTERNAL GALFUN
!
      CHARACTER*4 IADEDF
      CHARACTER*4 IADED2
!
      DOUBLE PRECISION DAK
      DOUBLE PRECISION DTAU
      COMMON/GALCOM/DAK,DTAU
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      CDF=0.0
      IADED2=IADEDF
!
      IF(IADEDF.EQ.'K')THEN
        IF(AK.LE.0.0)THEN
          WRITE(ICOUT,5)
    5     FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (K) ',   &
                 'IN THE GALCDF ROUTINE IS NON-POSITIVE.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,48)AK
   48     FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,',')
          CALL DPWRST('XXX','WRIT')
          GO TO 9000
        ENDIF
      ELSE
        AK=SQRT(2.0)/(AK + SQRT(2.0 + AK*AK))
      ENDIF
!
      IF(TAU.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER (TAU) IN ',   &
               'THE GALCDF ROUTINE IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)TAU
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IADEDF='K'
      INF=-1
      EPSABS=0.0D0
      EPSREL=1.0D-7
      IER=0
      CDF=0.0D0
!
      DX=DBLE(X)
      DTAU=DBLE(TAU)
      DAK=DBLE(AK)
!
      IFLAG=0
      IF(DX.LT.0.0D0)THEN
        IFLAG=1
        INF=1
      ENDIF
!
      CALL DQAGI(GALFUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
!
      IF(IFLAG.EQ.1)THEN
        CDF=1.0D0 - DCDF
      ELSE
        CDF=DCDF
      ENDIF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM GALCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM AKMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM GALCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GALCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM GALCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM GALCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM GALCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      IADEDF=IADED2
      RETURN
      END SUBROUTINE GALCDF
      DOUBLE PRECISION FUNCTION GALFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED ASYMMETRIC LAPLACE
!              DISTRIBUTION WITH SHAPE PARAMETERS AK AND TAU.
!              THIS DISTRIBUTION IS DEFINED
!              FOR ALL X AND HAS THE PROBABILITY DENSITY FUNCTION
!                 GALPDF(X,K,TAU) = C1*C2*C3        X <> 0
!              WITH
!                 C1 = SQRT(2/PI)*EXP((SQRT(2)/2)*((1/K)-K)*X)/
!                      GAMMA(TAU)
!                 C2 = ((SQRT(2)*ABS(X)/(K+(1/K))**(TAU-0.5)
!                 C3 = K(TAU-0.5)((SQRT(2)/2)*((1/K)+K)*ABS(X))
!              WHERE K(LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!              BUT DEFINE AS FUNCTION TO BE USED FOR INTEGRATION
!              CODE CALLED BY GALCDF.  ALSO, THIS ROUTINE USES
!              DOUBLE PRECISION ARITHMETIC.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--GALFUN  = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED ASYMMETRIC
!             LAPLACE DISTRIBUTION WITH SHAPE PARAMETERS AK AND TAU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GALPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSER, 2001,
!                 PP. 189.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.7
!     ORIGINAL VERSION--JULY      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM2
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DAK
      DOUBLE PRECISION DTAU
      COMMON/GALCOM/DAK,DTAU
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL GALPDF(DX,DAK,DTAU,IADEDF,DTERM2)
      GALFUN=DTERM2
!
      RETURN
      END FUNCTION GALFUN
      DOUBLE PRECISION FUNCTION GALFU2(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED ASYMMETRIC LAPLACE
!              DISTRIBUTION WITH SHAPE PARAMETERS K AND TAU.
!              THIS DISTRIBUTION IS DEFINED FOR ALL REAL X.
!     INPUT  ARGUMENTS--DX      = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE CUMULATIVE DISTRIBUTION
!                                 FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--GALFU2  = THE DOUBLE PRECISION CUMULATIVE
!                                 DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE FOR THE GENERALIZED ASYMMETRIC LAPLACE
!             DISTRIBUTION WITH SHAPE PARAMETERS K AND TAU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GALCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSER, 2001,
!                 PP. 189.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DP
      COMMON/GA2COM/DP
!
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTAU
      COMMON/GALCOM/DK,DTAU
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE CDF     FUNCTION  **
!               ************************************
!
      CALL GALCDF(DX,DK,DTAU,IADEDF,DCDF)
      GALFU2=DP - DCDF
!
      RETURN
      END FUNCTION GALFU2
      SUBROUTINE GALPDF(X,AK,TAU,IADEDF,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED ASYMMETRIC LAPLACE
!              DISTRIBUTION.  THIS IS ALSO KNOWN AS THE BESSEL
!              K-FUNCTION DISTRIBUTION.  IT HAS SHAPE PARAMETERS
!              K AND TAU (IF TAU = 1, THIS REDUCES TO THE ASYMMETRIC
!              LAPLACE DISTRIBUTION, IF K = 1, THIS IS A SYMMETRIC
!              DISTRIBUTIONS).  THIS DISTRIBUTION IS DEFINED
!              FOR ALL X AND HAS THE PROBABILITY DENSITY FUNCTION
!                 GALPDF(X,K,TAU) = C1*C2*C3        X <> 0
!              WITH
!                 C1 = SQRT(2/PI)*EXP((SQRT(2)/2)*((1/K)-K)*X)/
!                      GAMMA(TAU)
!                 C2 = ((SQRT(2)*ABS(X)/(K+(1/K))**(TAU-0.5)
!                 C3 = K(TAU-0.5)((SQRT(2)/2)*((1/K)+K)*ABS(X))
!              WHERE K(LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!
!     NOTE--ARGUMENTS TO THIS ROUTINE ARE IN DOUBLE PRECISION.
!     INPUT  ARGUMENTS--X     = THE DOUBLE PRECISION VALUE AT
!                               WHICH THE PROBABILITY DENSITY
!                               FUNCTION IS TO BE EVALUATED.
!                               X SHOULD BE NON-NEGATIVE.
!                     --AK    = THE FIRST SHAPE PARAMETER
!                     --TAU   = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF   = THE DOUBLE PRECISION PROBABILITY
!                               DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE ASYMMETRIC LAPLACE DISTRIBUTION
!             WITH SHAPE PARAMETER = K.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DBESK.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSER, 2001,
!                 PP. 189.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION AK
      DOUBLE PRECISION TAU
      DOUBLE PRECISION DX
      DOUBLE PRECISION DK
      DOUBLE PRECISION DTAU
      DOUBLE PRECISION PDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DC3
      DOUBLE PRECISION DC4
      DOUBLE PRECISION DC5
      DOUBLE PRECISION DC6
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DSAVE
      DOUBLE PRECISION DGAMMA
      EXTERNAL DGAMMA
!
      DOUBLE PRECISION DTEMP1(10)
!
      CHARACTER*4 IADEDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.14159265358979D+00/
      DATA DEPS /0.00000001D0/
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      PDF=0.0
      DSAVE=0.0D0
      IF(IADEDF.EQ.'K')THEN
        IF(AK.LE.0.0)THEN
          WRITE(ICOUT,5)
    5     FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (K) ',   &
                 'IN GALPDF ROUTINE IS NON-POSITIVE.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,48)AK
   48     FORMAT('      VALUE OF ARGUMENT IS: ',G15.7,'.')
          CALL DPWRST('XXX','WRIT')
          GO TO 9000
        ENDIF
      ELSE
        AK=SQRT(2.0)/(AK + SQRT(2.0 + AK*AK))
      ENDIF
!
      IF(TAU.LE.0.0D0)THEN
        WRITE(ICOUT,6)
    6   FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (TAU) IN ',   &
               'GALPDF ROUTINE IS NEGATIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)TAU
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
      ENDIF
!
      DX=X
      DK=AK
      DTAU=TAU
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE DENSITY FUNCTION.  FOR **
!               **  BETTER NUMERICAL STABILITY,        **
!               **  COMPUTE LOGARIGHMS.                **
!               *****************************************
!
!
      IF(X.EQ.0.0D0)THEN
        DX=DEPS
        IPASS=1
      ENDIF
!
 1000 CONTINUE
!
!  COMPUTE BESSEL FUNCTION FIRST.  IF THIS IS 0, SET PDF TO
!  0 AND RETURN.
!
      DC5=(DSQRT(2.0D0)/2.0D0)*(DK + (1.0D0/DK))
      DC6=DTAU - 0.5D0
      IF(DC6.LT.0.0D0)DC6=-DC6
      IARG1=1
      ISCALE=1
      CALL DBESK(DC5*DABS(DX),DC6,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM3=DTEMP1(IARG1)
      IF(DTERM3.LE.0.0D0)THEN
        PDF=0.0D0
        GO TO 9000
      ENDIF
      DTERM3=DLOG(DTEMP1(IARG1))
!
      DC1=DSQRT(2.0D0/DPI)/DGAMMA(DTAU)
      DC2=(DSQRT(2.0D0)/2.0D0)*((1.0D0/DK) - DK)
      DTERM1=DLOG(DC1) + DC2*DX
      DC3=DSQRT(2.0D0)/(DK + (1.0D0/DK))
      DC4=DTAU - 0.5D0
      DTERM2=DC4*DLOG(DC3*DABS(DX))
!
      DTERM4=DTERM1+DTERM2+DTERM3
      PDF=DEXP(DTERM4)
!
      IF(X.EQ.0.0D0)THEN
        IF(IPASS.EQ.1)THEN
          DSAVE=PDF
          IPASS=2
          DX=-DEPS
          GO TO 1000
        ELSEIF(IPASS.EQ.2)THEN
          PDF=(PDF+DSAVE)/2.0D0
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GALPDF
      SUBROUTINE GALPPF(P,AK,TAU,IADEDF,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED ASYMMETRIC LAPLACE
!              DISTRIBUTION.  IT HAS SHAPE PARAMETERS AK AND TAU.
!              THIS DISTRIBUTION IS DEFINED FOR ALL REAL
!              X AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 GALPDF(X,K,TAU) = C1*C2*C3        X <> 0
!              WITH
!                 C1 = SQRT(2/PI)*EXP((SQRT(2)/2)*((1/K)-K)*X)/
!                      GAMMA(TAU)
!                 C2 = ((SQRT(2)*ABS(X)/(K+(1/K))**(TAU-0.5)
!                 C3 = K(TAU-0.5)((SQRT(2)/2)*((1/K)+K)*ABS(X))
!              WHERE K(LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!              THE PERCENT POINT FUNCTION IS COMPUTED BY NUMERICALLY
!              INVERTING THE GENERALIZED ASYMMETRIC LAPLACE CUMULATIVE
!              DISTRIBUTION FUNCTION (WHICH IN TURN IS COMPUTED BY
!              NUMERICAL INTEGRATION OF THE PROBABILITYT DENSITY.
!
!     INPUT  ARGUMENTS--P       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PERCENT POINT
!                                 FUNCTION IS TO BE EVALUATED.
!                                 0 < P < 1
!                     --AK      = THE FIRST SHAPE PARAMETER
!                     --TAU     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF     = THE DOUBLE PRECISION PERCENT POINT
!                                 FUNCTION VALUE.
!     OUTPUT--THE DOUBEL PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE GENERALIZED ASYMMETRIC LAPLACE
!             DISTRIBUTION WITH SHAPE PARAMETERS = AK AND TAU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSER, 2001,
!                 PP. 189.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION AK
      DOUBLE PRECISION TAU
      DOUBLE PRECISION PPF
!
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DU
      DOUBLE PRECISION PTEMPL
      DOUBLE PRECISION PTEMPU
!
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION RE
      DOUBLE PRECISION AE
!
      DOUBLE PRECISION GALFU2
      EXTERNAL GALFU2
!
      DOUBLE PRECISION DP
      COMMON/GA2COM/DP
!
      DOUBLE PRECISION DAK
      DOUBLE PRECISION DTAU
      COMMON/GALCOM/DAK,DTAU
!
      CHARACTER*4 IADEDF
      CHARACTER*4 IADED2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      PPF=0.0D0
      IADED2=IADEDF
!
      IF(IADEDF.EQ.'K')THEN
        IF(AK.LE.0.0)THEN
          WRITE(ICOUT,5)
    5     FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (K) ',   &
                 'IN GALPPF ROUTINE IS NON-POSITIVE.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,48)AK
   48     FORMAT('      VALUE OF ARGUMENT IS: ',G15.7,'.')
          CALL DPWRST('XXX','WRIT')
          GO TO 9000
        ENDIF
      ELSE
        AK=SQRT(2.0)/(AK + SQRT(2.0 + AK*AK))
      ENDIF
!
      IF(P.LE.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR: VALUE OF INPUT ARGUMENT (P) IN ',   &
               'GALPPF ROUTINE')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,14)
   14   FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        WRITE(ICOUT,48)P
        CALL DPWRST('XXX','WRIT')
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ELSEIF(TAU.LE.0.0)THEN
        WRITE(ICOUT,6)
    6   FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (TAU) IN ',   &
               'GALPPF ROUTINE IS NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)TAU
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE PERCENT POINT FUNCTION.**
!               *****************************************
!
!  STEP 1: FIND BRACKETING INTERVAL.  THIS DISTRIBUTION IS UNBOUNDED
!          IN BOTH DIRECTIONS.  BASIC ALGORITHM IS:
!
!          1) MEAN = TAU*(1/SQRT(2))*((1/K) - K)
!             SD   = SQRT(TAU*(U**2 + 1))
!
!             WHERE U = (1/SQRT(2))*((1/K) - K)
!
!          2) START WITH -MEAN AND +MEAN AS THE STARTING LOWER AND
!             UPPER BRACKETS.
!
!          3) INCREMENT IN INTERVALS OF 1 STANDARD DEVIATION.
!
      IADED2=IADEDF
      IADEDF='K'
!
      DAK=AK
      DTAU=TAU
      DU=(1.0D0/SQRT(2.0D0))*((1.0D0/DAK) - DAK)
      DMEAN=DTAU*DU
      DSD=DSQRT(DTAU*(DU**2 + 1.0D0))
!
      XLOW=-REAL(DMEAN)
      XUP2=REAL(DMEAN)
      CALL GALCDF(XLOW,AK,TAU,IADEDF,PTEMPL)
      CALL GALCDF(XUP2,AK,TAU,IADEDF,PTEMPU)
!
      MAXIT=1000
      NIT=0
!
  200 CONTINUE
        IF(NIT.GT.MAXIT)THEN
          PPF=0.0
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,131)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,133)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
        CALL GALCDF(XLOW,AK,TAU,IADEDF,PTEMPL)
        CALL GALCDF(XUP2,AK,TAU,IADEDF,PTEMPU)
        IF(PTEMPL.LE.P .AND. P.LE.PTEMPU)THEN
          XUP=XUP2
          GO TO 300
        ELSEIF(P.GT.PTEMPU)THEN
          XLOW=XUP2
          XUP2=XUP2 + REAL(DSD)
          NIT=NIT+1
          GO TO 200
        ELSEIF(P.LT.PTEMPL)THEN
          XUP2=XLOW
          XLOW=XLOW - REAL(DSD)
          NIT=NIT+1
          GO TO 200
        ENDIF
!
  300 CONTINUE
      AE=1.D-7
      RE=1.D-7
      DP=P
      CALL DFZERO(GALFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM GALPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GALPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GALPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM GALPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      IADEDF=IADED2
      RETURN
      END SUBROUTINE GALPPF
      SUBROUTINE GALRAN(N,AK,TAU,IADEDF,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED ASYMMETRIC DOUBLE EXPONENTIAL
!              (LAPLACE) DISTRIBUTION WITH SHAPE PARAMETERS = AK AND
!              TAU.  THIS DISTRIBUTION IS DEFINED
!              FOR ALL X AND HAS THE PROBABILITY DENSITY FUNCTION
!                 GALPDF(X,K,TAU) = C1*C2*C3        X <> 0
!              WITH
!                 C1 = SQRT(2/PI)*EXP((SQRT(2)/2)*((1/K)-K)*X)/
!                      GAMMA(TAU)
!                 C2 = ((SQRT(2)*ABS(X)/(K+(1/K))**(TAU-0.5)
!                 C3 = K(TAU-0.5)((SQRT(2)/2)*((1/K)+K)*ABS(X))
!              WHERE K(LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --AK     = THE FIRST SHAPE (PARAMETER) FOR THE
!                                GENERALIZED ASYMMETRIC DOUBLE
!                                EXPONENTIAL DISTRIBUTION.
!                     --TAU    = THE SECOND SHAPE (PARAMETER) FOR THE
!                                GENERALIZED ASYMMETRIC DOUBLE
!                                EXPONENTIAL DISTRIBUTION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED ASYMMETRIC DOUBLE EXPONENTIAL
!             DISTRIBUTION WITH SHAPE PARAMETERS = AK AND TAU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --AK AND TAU MUST BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, NORRAN, GAMRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ, KOZUBOWSKI, AND PODGORSKI, "THE LAPLACE
!                 DISTRIBUTION AND GENERALIZATIONS: A REVISIT WITH
!                 APPLICATIONS TO COMMUNICATIONS, ECONOMICS,
!                 ENGINEERING, AND FINANCE", BIRKHAUSR, 2001,
!                 PP. 179-192.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.6
!     ORIGINAL VERSION--JUNE      2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
      CHARACTER*4 IADEDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      IF(IADEDF.EQ.'K')THEN
        IF(AK.LE.0.0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,48)AK
          CALL DPWRST('XXX','WRIT')
          GO TO 9999
        ENDIF
      ELSE
        AK=SQRT(2.0)/(AK + SQRT(2.0 + AK*AK))
      ENDIF
      IF(AK.LE.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)TAU
        CALL DPWRST('XXX','WRIT')
        GO TO 9999
      ENDIF
   15 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (K) IS ',   &
             'NON-POSITIVE.')
   25 FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (TAU) IS ',   &
             'NON-POSITIVE.')
!
    5 FORMAT('***** ERROR--FOR THE GENERALIZED ASYMMETRIC DOUBLE ',   &
             'EXPONENTIAL DISTRIBUTION,')
    6 FORMAT('       THE REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
            'NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!     ALGORITHM FROM PAGE 183 OF KOTZ, ET. AL.:
!
!        Y =  (1/SQRT(2))*((1/K)*G1 - K*G2)
!
!     WHERE G1 AND G2 ARE INDEPENDENT GAMMA RANDOM VARIABLES WITH
!     SHAPE PARAMETER TAU.
!
      NTEMP=2
      C=(1.0/SQRT(2.0))
      DO 100 I=1,N
        CALL GAMRAN(NTEMP,TAU,ISEED,Y)
        G1=Y(1)
        G2=Y(2)
        APPF=C*((1.0/AK)*G1 - AK*G2)
        X(I)=APPF
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GALRAN
      DOUBLE PRECISION FUNCTION gam1(a)
!     ------------------------------------------------------------------
!     COMPUTATION OF 1/GAMMA(A+1) - 1  FOR -0.5 .LE. A .LE. 1.5
!     ------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION bot,d,s1,s2,t,top,w
!     ..
!     .. Local Arrays ..
      DOUBLE PRECISION p(7),q(5),r(9)
!     ..
!     .. Data statements ..
!     -------------------
!     -------------------
!     -------------------
!     -------------------
      DATA p(1)/.577215664901533D+00/,p(2)/-.409078193005776D+00/,   &
           p(3)/-.230975380857675D+00/,p(4)/.597275330452234D-01/,   &
           p(5)/.766968181649490D-02/,p(6)/-.514889771323592D-02/,   &
           p(7)/.589597428611429D-03/
      DATA q(1)/.100000000000000D+01/,q(2)/.427569613095214D+00/,   &
           q(3)/.158451672430138D+00/,q(4)/.261132021441447D-01/,   &
           q(5)/.423244297896961D-02/
      DATA r(1)/-.422784335098468D+00/,r(2)/-.771330383816272D+00/,   &
           r(3)/-.244757765222226D+00/,r(4)/.118378989872749D+00/,   &
           r(5)/.930357293360349D-03/,r(6)/-.118290993445146D-01/,   &
           r(7)/.223047661158249D-02/,r(8)/.266505979058923D-03/,   &
           r(9)/-.132674909766242D-03/
      DATA s1/.273076135303957D+00/,s2/.559398236957378D-01/
!     ..
!     .. Executable Statements ..
!     -------------------
      t = a
      d = a - 0.5D0
      IF (d.GT.0.0D0) t = d - 0.5D0
!CCCC IF (t) 40,10,20
      IF(t.lt.0.0d0)THEN
        top = (((((((r(9)*t+r(8))*t+r(7))*t+r(6))*t+r(5))*t+   &
              r(4))*t+r(3))*t+r(2))*t + r(1)
        bot = (s2*t+s1)*t + 1.0D0
        w = top/bot
        IF (d.GT.0.0D0) THEN
           gam1 = t*w/a
        ELSE
          gam1 = a* ((w+0.5D0)+0.5D0)
        ENDIF
      ELSEIF(t.gt.0.0d0)THEN
        top = (((((p(7)*t+p(6))*t+p(5))*t+p(4))*t+p(3))*t+p(2))*t   &
              + p(1)
        bot = (((q(5)*t+q(4))*t+q(3))*t+q(2))*t + 1.0D0
        w = top/bot
        IF (d.GT.0.0D0) THEN
           gam1 = (t/a)* ((w-0.5D0)-0.5D0)
        ELSE
          gam1 = a*w
        ENDIF
      ELSE
        gam1 = 0.0D0
      ENDIF
!
      RETURN
      END FUNCTION gam1
      SUBROUTINE GAMEST(X,NOBS,SCALE,GAMMA,IERROR)
!
!  COMPUTE MLES FOR SHAPE PARAMETER (GAMMA) AND SCALE
!  PARAMETER (SCALE).
!
      DIMENSION X(*)
!
      DOUBLE PRECISION GAMFUN
      EXTERNAL GAMFUN
!
      DOUBLE PRECISION DLOGGM
      COMMON/GAMCOM/DLOGGM
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION XLOWSV
      DOUBLE PRECISION XUPSV
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IWRITE
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!  FOR STARTING VALUE, USE THE METHOD OF MOMENT ESTIMATORS
!
!    GAMMAHAT = (XBAR/XSD)**2
!    SCALE    = XSD**2/XBAR
!
      IERROR='NO'
      IBUGA3='OFF'
      IWRITE='OFF'
      CALL MEAN(X,NOBS,IWRITE,XMEAN,IBUGA3,IERROR)
      CALL SD(X,NOBS,IWRITE,XSD,IBUGA3,IERROR)
      GAMMMO=(XMEAN/XSD)**2
      SCALMO=XSD**2/XMEAN
      CALL GEOMEA(X,NOBS,IWRITE,XGEOM,IBUGA3,IERROR)
!
      IERROR='NO'
      AN=REAL(NOBS)
!
!  ESTIMATES FOR 2-PARAMETER MODEL.  USE DFZER2 TO FIND ROOT OF
!  THE LIKELIHOOD EQUATION.
!
      DLOGGM=DLOG(DBLE(XMEAN)/DBLE(XGEOM))
      DXSTRT=DBLE(GAMMMO)
      AE=2.0*0.000001D0*DXSTRT
      RE=AE
      IFLAG=0
      DXLOW=DXSTRT/2.0D0
      DXUP=2.0D0*DXSTRT
      ITBRAC=0
 4105 CONTINUE
      XLOWSV=DXLOW
      XUPSV=DXUP
      CALL DFZERO(GAMFUN,DXLOW,DXUP,DXSTRT,RE,AE,IFLAG)
!
      IF(IFLAG.EQ.4 .AND. ITBRAC.LE.100)THEN
        DXLOW=XLOWSV/2.0D0
        DXUP=2.0D0*XUPSV
        ITBRAC=ITBRAC+1
        GO TO 4105
      ENDIF
!
  999 FORMAT(1X)
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM GAMMA MAXIMUM ',
!CCCC1         'LIKELIHOOD--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      ESTIMATE OF GAMMA MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GAMMA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ESTIMATE OF GAMMA MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GAMMA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM GAMMA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GAMMA=REAL(DXLOW)
      SCALE=XMEAN/GAMMA
!
      RETURN
      END SUBROUTINE GAMEST
      DOUBLE PRECISION FUNCTION gamln(a)
!-----------------------------------------------------------------------
!            EVALUATION OF LN(GAMMA(A)) FOR POSITIVE A
!-----------------------------------------------------------------------
!     WRITTEN BY ALFRED H. MORRIS
!          NAVAL SURFACE WARFARE CENTER
!          DAHLGREN, VIRGINIA
!--------------------------
!     D = 0.5*(LN(2*PI) - 1)
!--------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION c0,c1,c2,c3,c4,c5,d,t,w
      INTEGER i,n
!     ..
!     .. External Functions ..
      DOUBLE PRECISION gamln1
      EXTERNAL gamln1
!     ..
!     .. Intrinsic Functions ..
      INTRINSIC dlog
!     ..
!     .. Data statements ..
!--------------------------
      DATA d/.418938533204673D0/
      DATA c0/.833333333333333D-01/,c1/-.277777777760991D-02/,   &
           c2/.793650666825390D-03/,c3/-.595202931351870D-03/,   &
           c4/.837308034031215D-03/,c5/-.165322962780713D-02/
!     ..
!     .. Executable Statements ..
!-----------------------------------------------------------------------
      IF (a.GT.0.8D0) GO TO 10
      gamln = gamln1(a) - dlog(a)
      RETURN
                                                                                                                                  
   10 IF (a.GT.2.25D0) GO TO 20
      t = (a-0.5D0) - 0.5D0
      gamln = gamln1(t)
      RETURN
!
   20 IF (a.GE.10.0D0) GO TO 40
      n = int(a - 1.25D0)
      t = a
      w = 1.0D0
      DO 30 i = 1,n
          t = t - 1.0D0
          w = t*w
   30 CONTINUE
      gamln = gamln1(t-1.0D0) + dlog(w)
      RETURN
!
   40 t = (1.0D0/a)**2
      w = (((((c5*t+c4)*t+c3)*t+c2)*t+c1)*t+c0)/a
      gamln = (d+w) + (a-0.5D0)* (dlog(a)-1.0D0)
      END FUNCTION gamln
      DOUBLE PRECISION FUNCTION gamln1(a)
!-----------------------------------------------------------------------
!     EVALUATION OF LN(GAMMA(1 + A)) FOR -0.2 .LE. A .LE. 1.25
!-----------------------------------------------------------------------
!     .. Scalar Arguments ..
      DOUBLE PRECISION a
!     ..
!     .. Local Scalars ..
      DOUBLE PRECISION p0,p1,p2,p3,p4,p5,p6,q1,q2,q3,q4,q5,q6,r0,r1,r2,   &
                       r3,r4,r5,s1,s2,s3,s4,s5,w,x
!     ..
!     .. Data statements ..
!----------------------
      DATA p0/.577215664901533D+00/,p1/.844203922187225D+00/,   &
           p2/-.168860593646662D+00/,p3/-.780427615533591D+00/,   &
           p4/-.402055799310489D+00/,p5/-.673562214325671D-01/,   &
           p6/-.271935708322958D-02/
      DATA q1/.288743195473681D+01/,q2/.312755088914843D+01/,   &
           q3/.156875193295039D+01/,q4/.361951990101499D+00/,   &
           q5/.325038868253937D-01/,q6/.667465618796164D-03/
      DATA r0/.422784335098467D+00/,r1/.848044614534529D+00/,   &
           r2/.565221050691933D+00/,r3/.156513060486551D+00/,   &
           r4/.170502484022650D-01/,r5/.497958207639485D-03/
      DATA s1/.124313399877507D+01/,s2/.548042109832463D+00/,   &
           s3/.101552187439830D+00/,s4/.713309612391000D-02/,   &
           s5/.116165475989616D-03/
!     ..
!     .. Executable Statements ..
!----------------------
      IF (a.GE.0.6D0) GO TO 10
      w = ((((((p6*a+p5)*a+p4)*a+p3)*a+p2)*a+p1)*a+p0)/   &
          ((((((q6*a+q5)*a+q4)*a+q3)*a+q2)*a+q1)*a+1.0D0)
      gamln1 = -a*w
      RETURN
!
   10 x = (a-0.5D0) - 0.5D0
      w = (((((r5*x+r4)*x+r3)*x+r2)*x+r1)*x+r0)/   &
          (((((s5*x+s4)*x+s3)*x+s2)*x+s1)*x+1.0D0)
      gamln1 = x*w
      RETURN
                                                                                                                                  
      END FUNCTION gamln1
      double precision function gammds (y, p, ifault)
!-----------------------------------------------------------------------
!  Name:       GAMMDS
!
!  Purpose:    Cumulative distribution for the gamma distribution.
!
!  Usage:      PGAMMA (Q, ALPHA,IFAULT)
!
!  Arguments:
!     Q      - Value at which the distribution is desired.  (Input)
!     ALPHA  - Parameter in the gamma distribution.  (Input)
!     IFAULT - Error indicator.  (Output)
!               IFAULT  DEFINITION
!                 0     No error
!                 1     An argument is misspecified.
!                 2     A numerical error has occurred.
!     PGAMMA - The cdf for the gamma distribution with parameter alpha
!              evaluated at Q.  (Output)
!-----------------------------------------------------------------------
!
!       Algorithm AS 147 APPL. Statist. (1980) VOL. 29, P. 113
!
!       Computes the incomplete gamma integral for positive
!       parameters Y, P using and infinite series.
!
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    ifault
      double precision y, p
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    ifail
      double precision a, c, f
!                                  SPECIFICATIONS FOR SAVE VARIABLES
      double precision e, one, zero
      save       e, one, zero
!                                  SPECIFICATIONS FOR INTRINSICS
      intrinsic  dlog, dexp
!cccc double precision dlog, dexp
!                                  SPECIFICATIONS FOR FUNCTIONS
      external   alogam
      double precision alogam
      double precision zexp, zlog
!
      data e, zero, one/1.0d-6, 0.0d0, 1.0d0/
!
      zexp(a) = dexp(a)
      zlog(a) = dlog(a)
!
!       Checks for the admissibility of arguments and value of F
!
      ifault = 1
      gammds = zero
      if (y.le.zero .or. p.le.zero) return
      ifault = 2
!
!       ALOGAM is natural log of gamma function
!       no need to test ifail as an error is impossible
!
      f = zexp(p*zlog(y)-alogam(p+one,ifail)-y)
      if (f .eq. zero) return
      ifault = 0
!
!       Series begins
!
      c      = one
      gammds = one
      a      = p
   10 a = a + one
      c      = c*y/a
      gammds = gammds + c
      if (c/gammds .gt. e) go to 10
      gammds = gammds*f
      return
      end
      SUBROUTINE GAMLIM(XMIN,XMAX)
!***BEGIN PROLOGUE  GAMLIM
!***DATE WRITTEN   770401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C7A,R2
!***KEYWORDS  GAMMA FUNCTION,LIMITS,SPECIAL FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Computes the minimum and maximum bounds for X in GAMMA(X).
!***DESCRIPTION
!
! Calculate the minimum and maximum legal bounds for X in GAMMA(X).
! XMIN and XMAX are not the only bounds, but they are the only non-
! trivial ones to calculate.
!
!             Output Arguments --
! XMIN   minimum legal value of X in GAMMA(X).  Any smaller value of
!        X might result in underflow.
! XMAX   maximum legal value of X in GAMMA(X).  Any larger value will
!        cause overflow.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  R1MACH,XERROR
!***END PROLOGUE  GAMLIM
!***FIRST EXECUTABLE STATEMENT  GAMLIM
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      ALNSML = LOG(R1MACH(1))
      XMIN = -ALNSML
      DO 10 I=1,10
        XOLD = XMIN
        XLN = LOG(XMIN)
        XMIN = XMIN - XMIN*((XMIN+0.5)*XLN - XMIN - 0.2258 + ALNSML)   &
          / (XMIN*XLN + 0.5)
        IF (ABS(XMIN-XOLD).LT.0.005) GO TO 20
 10   CONTINUE
!CCCC CALL XERROR ( 'GAMLIM  UNABLE TO FIND XMIN', 27, 1, 2)
      WRITE(ICOUT,11)
      CALL DPWRST('XXX','BUG ')
   11 FORMAT('***** ERROR FROM GAMLIM: UNABLE TO FIND ',   &
             'XMIN')
!
 20   XMIN = -XMIN + 0.01
!
      ALNBIG = LOG(R1MACH(2))
      XMAX = ALNBIG
      DO 30 I=1,10
        XOLD = XMAX
        XLN = LOG(XMAX)
        XMAX = XMAX - XMAX*((XMAX-0.5)*XLN - XMAX + 0.9189 - ALNBIG)   &
          / (XMAX*XLN - 0.5)
        IF (ABS(XMAX-XOLD).LT.0.005) GO TO 40
 30   CONTINUE
!CCCC CALL XERROR ( 'GAMLIM  UNABLE TO FIND XMAX', 27, 2, 2)
      WRITE(ICOUT,31)
      CALL DPWRST('XXX','BUG ')
   31 FORMAT('***** ERROR FROM GAMLIM: UNABLE TO FIND ',   &
             'XMAX')
!
 40   XMAX = XMAX - 0.01
      XMIN = AMAX1 (XMIN, -XMAX+1.)
!
      RETURN
      END SUBROUTINE GAMLIM
      SUBROUTINE GAMMAF(X,G)
!
!     THIS PROGRAM CALCULATES THE GAMMA FUNCTION
!     THE INPUT IS SINGLE PRECISION X
!     THE OUTPUT IS SINGLE PRECISION G
!     ALL INTERNAL OPERATIONS ARE DONE IN DOUBLE PRECISION
!     THE ALGORITHM IS TO USE THE RECURSION FORMULA G(X)=G(X+1)/X
!     UNTIL X IS LARGE ENOUGH TO USE AN ASYMPTOTIC FORMULA FOR G(X)--THE CUT-OFF
!     POINT USED WAS X = 10
!     THE ASYMPTOTIC FORMULA USED IS IN AMS 55, PAGE 257, 6.1.41 (THE FIRST 9
!     TERMS OF THE SERIES WERE USED--I.E., OUT TO X**-17)
!     ALTHOUGH THE DATA STATEMENT DEFINES 10 COEFFICIENTS, THE PROGRAM MAKES USE
!     OF ONLY 9 COEFFICIENTS (THE ERROR BEING BOUNDED BY THE TENTH COEFFICIENT
!     DIVIDED BY X**19
!     SUBROUTINES NEEDED--NONE
!     PRINTING--NONE UNLESS AN ERROR CONDITION EXISTS
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION Y,Y2,Y3,Y4,Y5,DEN,A,B,C,D
!
      DIMENSION D(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA C/ .918938533204672741D0/
      DATA D(1),D(2),D(3),D(4),D(5)   &
           /+.833333333333333333D-1,-.277777777777777778D-2,   &
            +.793650793650793651D-3,-.595238095238095238D-3,   &
            +.841750841750841751D-3/
      DATA D(6),D(7),D(8),D(9),D(10)   &
           /-.191752691752691753D-2,+.641025641025641025D-2,   &
            -.295506535947712418D-1,+.179644372368830573D0,   &
            -.139243221690590111D1/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GAMMAF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)X
   45   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',D22.15,'.')
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
!
      Y=X
      DEN=1.0D0
  100 CONTINUE
      IF(Y.GE.10.0D0)THEN
        Y2=Y*Y
        Y3=Y*Y2
        Y4=Y2*Y2
        Y5=Y2*Y3
        A=(Y-0.5D0)*DLOG(Y)-Y+C
        B=D(1)/Y+D(2)/Y3+D(3)/Y5+D(4)/(Y2*Y5)+D(5)/(Y4*Y5)+   &
          D(6)/(Y*Y5*Y5)+D(7)/(Y3*Y5*Y5)+D(8)/(Y5*Y5*Y5)+   &
          D(9)/(Y2*Y5*Y5*Y5)
        G=DEXP(A+B)/DEN
      ELSE
        DEN=DEN*Y
        Y=Y+1
        GO TO 100
      ENDIF
!
      RETURN
      END SUBROUTINE GAMMAF
      SUBROUTINE GAMCDF(X,GAMMA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GAMMA
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE GAMMA DISTRIBUTION USED
!              HEREIN HAS MEAN = GAMMA
!              AND STANDARD DEVIATION = SQRT(GAMMA).
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/CONSTANT) * (X**(GAMMA-1)) * EXP(-X)
!              WHERE THE CONSTANT = THE GAMMA FUNCTION EVALUATED
!              AT THE VALUE GAMMA.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GAMMA DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     ACCURACY--(ON THE UNIVAC 1108, EXEC 8 SYSTEM AT NBS)
!               COMPARED TO THE KNOWN GAMMA = 1 (EXPONENTIAL)
!               RESULTS, AGREEMENT WAS HAD OUT TO 7 SIGNIFICANT
!               DIGITS FOR ALL TESTED X.
!               THE TESTED X VALUES COVERED THE ENTIRE
!               RANGE OF THE DISTRIBUTION--FROM THE 0.00001
!               PERCENT POINT UP TO THE 99.99999 PERCENT POINT
!               OF THE DISTRIBUTION.
!     REFERENCES--WILK, GNANADESIKAN, AND HUYETT, 'PROBABILITY
!                 PLOTS FOR THE GAMMA DISTRIBUTION',
!                 TECHNOMETRICS, 1962, PAGES 1-15,
!                 ESPECIALLY PAGES 3-5.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 257, FORMULA 6.1.41.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 166-206.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 68-73.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX,DGAMMA,AI,TERM,SUM,CUT1,CUT2,CUTOFF,T
      DOUBLE PRECISION Z,Z2,Z3,Z4,Z5,DEN,A,B,C,D,G
      DOUBLE PRECISION DEXP,DLOG
      DIMENSION D(10)
      DATA C/ .918938533204672741D0/
      DATA D(1),D(2),D(3),D(4),D(5)   &
           /+.833333333333333333D-1,-.277777777777777778D-2,   &
            +.793650793650793651D-3,-.595238095238095238D-3,   &
            +.841750841750841751D-3/
      DATA D(6),D(7),D(8),D(9),D(10)   &
           /-.191752691752691753D-2,+.641025641025641025D-2,   &
            -.295506535947712418D-1,+.179644372368830573D0,   &
            -.139243221690590111D1/
!
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(X.LE.0.0)THEN
!CCCC   WRITE(ICOUT,4)
!CCC4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO GAMCDF IS ',
!CCCC1         'NON-POSITIVE.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)X
!CCCC   CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GAMCDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DX=X
      DGAMMA=GAMMA
      MAXIT=10000
!
!     COMPUTE THE GAMMA FUNCTION USING THE ALGORITHM IN THE
!     NBS APPLIED MATHEMATICS SERIES REFERENCE.
!
      Z=DGAMMA
      DEN=1.0D0
  300 IF(Z.GE.10.0D0)GO TO 400
      DEN=DEN*Z
      Z=Z+1
      GO TO 300
  400 Z2=Z*Z
      Z3=Z*Z2
      Z4=Z2*Z2
      Z5=Z2*Z3
      A=(Z-0.5D0)*DLOG(Z)-Z+C
      B=D(1)/Z+D(2)/Z3+D(3)/Z5+D(4)/(Z2*Z5)+D(5)/(Z4*Z5)+   &
      D(6)/(Z*Z5*Z5)+D(7)/(Z3*Z5*Z5)+D(8)/(Z5*Z5*Z5)+D(9)/(Z2*Z5*Z5*Z5)
      G=DEXP(A+B)/DEN
!
!     COMPUTE T-SUB-Q AS DEFINED ON PAGE 4 OF THE WILK, GNANADESIKAN,
!     AND HUYETT REFERENCE
!
      SUM=1.0D0/DGAMMA
      TERM=1.0D0/DGAMMA
      CUT1=DX-DGAMMA
      CUT2=DX*10000000000.0D0
      DO 200 I=1,MAXIT
      AI=I
      TERM=DX*TERM/(DGAMMA+AI)
      SUM=SUM+TERM
      CUTOFF=CUT1+(CUT2*TERM/SUM)
      IF(AI.GT.CUTOFF)GO TO 250
  200 CONTINUE
      WRITE(ICOUT,205)MAXIT
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,206)X
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,207)GAMMA
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,208)
      CALL DPWRST('XXX','BUG ')
      CDF=1.0
      GO TO 9000
!
  250 T=SUM
      CDF=(DX**DGAMMA)*(DEXP(-DX))*T/G
!
!C204 FORMAT('*****ERROR IN INTERNAL OPERATIONS IN THE GAMCDF ,')
  205 FORMAT('     SUBROUTINE--THE NUMBER OF ITERATIONS EXCEEDS ',I7)
  206 FORMAT('     THE INPUT VALUE OF X     IS ',G15.7)
  207 FORMAT('     THE INPUT VALUE OF GAMMA IS ',G15.7)
  208 FORMAT('     THE OUTPUT VALUE OF CDF HAS BEEN SET TO 1.0')
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GAMCDF
      DOUBLE PRECISION FUNCTION GAMFUN (GHAT)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF GAMMA FOR THE 2-PARAMETER GAMMA
!              MODEL FOR FULL SAMPLE DATA (NO CENSORING).  THIS
!              FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 LOG(GHAT) - DIGAMMA(GHAT) - LOG(G)
!
!              WITH
!
!                 G        = GEOMETRIC MEAN OF THE DATA
!                 GHAT     = POINT ESTIMATE OF GAMMA (THIS IS THE
!                            PARAMETER WE ARE ITERATING OVER)
!
!              NOTE THAT THE LOG(G) TERM DOES NOT DEPEND ON GHAT,
!              SO THIS IS A CONSTANT.  FOR EFFICIENCY, SAVE THIS AS
!              A CONSTANT IN A COMMON BLOCK.
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--GAMMA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!              --JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                WILEY, 1994, CHAPTER 17.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION GHAT
!
      DOUBLE PRECISION DLOGGM
      COMMON/GAMCOM/DLOGGM
!
      DOUBLE PRECISION DPSI
      EXTERNAL DPSI
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DTERM1=DLOG(GHAT)
      DTERM2=DPSI(GHAT)
!
      GAMFUN=DTERM1 - DTERM2 - DLOGGM
!
      RETURN
      END FUNCTION GAMFUN 
      DOUBLE PRECISION FUNCTION GAMFU2 (DA)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDECE INTERVAL FOR THE 2-PARAMETER GAMMA
!              MODEL (FULL SAMPLE).  THIS FUNCTION FINDS THE ROOT
!              OF THE EQUATION:
!
!                 2*LL(S,G) - 2*LL(xbar/a,a) - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(S,G) = -N*LN(GAMMA(G)) - N*G*LN(S) +
!                          N*(G-1)*LN(G) - N*XBAR/S
!                 S        = POINT ESTIMATE OF SCALE PARAMETER
!                 G        = POINT ESTIMATE OF SHAPE PARAMETER
!                 GAMMA    = GAMMA FUNCTION
!                 A        = PARAMETER WE ARE FINDING ROOT FOR
!
!              NOTE THAT QUANTITIES THAT DO NOT DEPEND ON A ARE
!              COMPUTED ONCE IN DPMLG1 AND PASSED VIA COMMON BLOCK.
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!
!     EXAMPLE--GAMMA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 13 (SEE
!                EXAMPLE 13.3).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DA
!
      DOUBLE PRECISION DK
      DOUBLE PRECISION DXBAR
      DOUBLE PRECISION DGMEAN
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DG
      COMMON/GAMCO2/DK,DXBAR,DGMEAN,DSCALE,DG,N
!
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
!  COMPUTE LL(S,G)
!
      DN=DBLE(N)
      DTERM1=-DN*DLNGAM(DG) - DN*DG*DLOG(DSCALE) +   &
             DN*(DG-1.0D0)*DLOG(DGMEAN) - DN*DXBAR/DSCALE
!
!  COMPUTE LL(XBAR/A,A)
!
      DTERM2=-DN*DLNGAM(DA) - DN*DA*DLOG(DXBAR/DA) +   &
             DN*(DA-1.0D0)*DLOG(DGMEAN) - DN*DXBAR/(DXBAR/DA)
!
      GAMFU2=2.0*DTERM1 - 2.0D0*DTERM2 - DK
!
      RETURN
      END FUNCTION GAMFU2 
      DOUBLE PRECISION FUNCTION GAMFU3 (DB,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE SCALE PARAMETER OF A
!              2-PARAMETER GAMMA MODEL (FULL SAMPLE).  THIS FUNCTION
!              FINDS THE ROOT OF THE EQUATION:
!
!                 2*LL(S,G) - 2*LL(b,G(b)) - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(S,G) = -N*LN(GAMMA(G)) - N*G*LN(S) +
!                          N*(G-1)*LN(G) - N*XBAR/S
!                 S        = POINT ESTIMATE OF SCALE PARAMETER
!                 G        = POINT ESTIMATE OF SHAPE PARAMETER
!                 B        = CURRENT GUESS FOR SCALE PARAMETER
!                 G(B)     = ML ESTIMATE OF GAMMA GIVEN VALUE OF
!                            SCALE
!
!              NOTE THAT QUANTITIES THAT DO NOT DEPEND ON B ARE
!              COMPUTED ONCE IN DPMLG1 AND PASSED VIA COMMON BLOCK.
!
!              GIVEN A VALUE FOR THE SCALE PARAMETER (DB), WE NEED
!              TO CALL A ROOT FINDING ROUTINE TO DETERMINE THE VALUE
!              OF THE SHAPE PARAMETER (A).  THIS IS THE ROOT OF THE
!              EQUATION:
!
!                 LN(SCALEHAT) + DIGAMMA(GHAT) - LN(GEOMETRIC MEAN)
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.  DFZER2 IS MODIFIED VERSION OF DFZERO THAT
!              PASSES ALONG THE DATA ARRAY.
!
!     EXAMPLE--GAMMA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 13 (SEE
!                EXAMPLE 13.3).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DB
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      DOUBLE PRECISION DK
      DOUBLE PRECISION DXBAR
      DOUBLE PRECISION DGMEAN
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DG
      COMMON/GAMCO2/DK,DXBAR,DGMEAN,DSCALE,DG,N
!
      DOUBLE PRECISION DBTEMP
      DOUBLE PRECISION DGMEA2
      COMMON/GAMCO4/DBTEMP,DGMEA2,N2
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
      DOUBLE PRECISION DA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
      DOUBLE PRECISION GAMFU4
      EXTERNAL GAMFU4
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: GIVEN VALUE OF SCALE PARAMETER (DB), NEED TO COMPUTE
!          THE SHAPE PARAMETER (WHICH IN TURN INVOLVES FINDING A
!          ROOT).
                                                                                                                                  
      N2=N
      DBTEMP=DB
      DGMEA2=DGMEAN
      AE=1.D-7
      RE=1.D-7
      XSTRT=DG
      XLOW=XSTRT/5.0D0
      XUP=XSTRT*5.0D0
      CALL DFZER3(GAMFU4,XLOW,XUP,XSTRT,RE,AE,IFLAG,DX)
      DA=XLOW
!
!  COMPUTE LL(S,G)
!
      DN=DBLE(N)
      DTERM1=-DN*DLNGAM(DG) - DN*DG*DLOG(DSCALE) +   &
             DN*(DG-1.0D0)*DLOG(DGMEAN) - DN*DXBAR/DSCALE
!
!  COMPUTE LL(B,A)
!
      DTERM2=-DN*DLNGAM(DA) - DN*DA*DLOG(DB) +   &
             DN*(DA-1.0D0)*DLOG(DGMEAN) - DN*DXBAR/DB
!
      GAMFU3=2.0*DTERM1 - 2.0D0*DTERM2 - DK
!
      RETURN
      END FUNCTION GAMFU3 
      DOUBLE PRECISION FUNCTION GAMFU4 (DA,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE SCALE PARAMETER OF
!              THE 2-PARAMETER GAMMA MODEL (FULL SAMPLE).
!              SPECIFICALLY, IT IS USED TO DETERMINE AN ESTIMATE
!              OF THE SHAPE PARAMETER GIVEN A VALUE OF THE SCALE
!              PARAMETER.  IT FINDS THE ROOT OF THE FOLLOWING
!              EQUATION:
!
!                 LN(BHAT) + DIGAMMA(AHAT) - LN(GEOMETRIC MEAN)
!
!              WITH A DENOTING THE SHAPE PARAMETER, B THE SCALE
!              PARAMETER, AND THE ROOT IS WITH RESPECT TO A.
!
!              CALLED BY DFZER3 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.  DFZER3 IS MODIFIED VERSION OF DFZERO THAT
!              PASSES ALONG THE DATA ARRAY.
!
!     EXAMPLE--GAMMA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 13 (SEE
!                EXAMPLE 13.3).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DA
      DOUBLE PRECISION DX(*)
!
      DOUBLE PRECISION DGMEAN
      DOUBLE PRECISION DB
      COMMON/GAMCO4/DB,DGMEAN,N
!
      DOUBLE PRECISION DPSI
      EXTERNAL DPSI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBG4.EQ.'MFU4')THEN
        WRITE(ICOUT,52)DA,DX(1)
   52   FORMAT('DA,DX(1) = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GAMFU4=DLOG(DB) + DPSI(DA) - DLOG(DGMEAN)
!
      RETURN
      END FUNCTION GAMFU4 
      DOUBLE PRECISION FUNCTION GAMFU5(UHAT,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE FOR THE LOCATION PARAMETER FOR THE
!              3-PARAMETER GAMMA MODEL (FULL SAMPLE).  IT FINDS THE
!              ROOT OF THE FOLLOWING EQUATION:
!
!                 DIGAMMA({1 - 1/((XBAR - UHAT)*S1(UHAT))}**(-1)) +
!                 LOG(XBAR - UHAT - 1/S1(UHAT)) - S2(UAT) = 0
!
!              WHERE
!
!                 UHAT     = ESTIMATE OF LOCATION PARAMETER
!                 S1(UHAT) = SUM[i=1 to N][1/(X(i) - UHAT)]/N
!                 S2(UHAT) = SUM[i=1 to N][LOG(X(i) - UHAT)]/N
!                 XBAR     = MEAN OF X
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!
!     EXAMPLE--GAMMA MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 13.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/04
!     ORIGINAL VERSION--APRIL      2014.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION UHAT
      DOUBLE PRECISION DX(*)
!
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSUM1
      COMMON/GAMCO3/DMEAN,DSUM1,N
!
      DOUBLE PRECISION DPSI
      EXTERNAL DPSI
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DN=DBLE(N)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 100 I=1,N
        DTERM1=DX(I) - UHAT
        DSUM1=DSUM1 + (1.0D0/DTERM1)
        DSUM2=DSUM2 + DLOG(DTERM1)
  100 CONTINUE
      DSUM1=DSUM1/DN
      DSUM2=DSUM2/DN
      DTERM1=1.0D0 - 1.0D0/((DMEAN - UHAT)*DSUM1)
      DTERM2=DPSI(1.0D0/DTERM1)
      DTERM3=DLOG(DMEAN - UHAT - (1.0D0/DSUM1))
!
      GAMFU5=DTERM2 + DTERM3 - DSUM2
!
      RETURN
      END FUNCTION GAMFU5
      SUBROUTINE GAMFU7(X,DLOC,DMEAN,N,   &
                        RHO,DB,FOUT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF THE LOCATION PARAMETER FOR THE 3-PARAMETER
!              GAMMA MODEL FOR FULL SAMPLE DATA (NO CENSORING).
!     REFERENCE-COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!               RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!               PP. 365-367.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/04
!     ORIGINAL VERSION--APRIL      2014.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION RHO
      DOUBLE PRECISION DB
      DOUBLE PRECISION FOUT
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DX
      DOUBLE PRECISION DA
      DOUBLE PRECISION DN
!
      DOUBLE PRECISION DPSI
      EXTERNAL DPSI
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      IERROR='NO'
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DN=DBLE(N)
!
      DO 100 I=1,N
        DX=X(I) - DLOC
        DSUM1=DSUM1 + 1.0D0/DX
        DSUM2=DLOG(DX) + DSUM2
  100 CONTINUE
!
      DA=(DMEAN-DLOC)*DSUM1
      RHO=-DA/(DN-DA)
      DB=(DMEAN-DLOC)/RHO
      FOUT=DPSI(RHO) + DLOG(DB) - (DSUM2/DN)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MFU7')THEN
        WRITE(ICOUT,115)DN,DSUM1,DSUM2,DA,RHO,DB,FOUT
  115   FORMAT('DN,DSUM1,DSUM2,DA,RHO,DB,FOUT = ',7G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE GAMFU7
      REAL FUNCTION GAMFU8(GHAT)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING CONFIDENCE LIMITS
