!===================================================== GAMIND.FOR
      DOUBLE PRECISION FUNCTION GAMIND(X,ALPHA,G)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  THE INCOMPLETE GAMMA INTEGRAL
!
!  BASED ON ALGORITHM AS239, APPL. STATIST. (1988) VOL.37 NO.3
!
!  PARAMETERS OF ROUTINE:
!  X      * INPUT* ARGUMENT OF FUNCTION (UPPER LIMIT OF INTEGRATION)
!  ALPHA  * INPUT* SHAPE PARAMETER
!  G      * INPUT* LOG(GAMMA(ALPHA)). MUST BE SUPPLIED BY THE PROGRAM,
!                  E.G. AS DLGAMA(ALPHA).
!
!  OTHER ROUTINES USED: DERF
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,HALF/0.5D0/,ONE/1D0/,TWO/2D0/,THREE/3D0/,X13/13D0/,   &
        X36/36D0/,X42/42D0/,X119/119D0/,X1620/1620D0/,X38880/38880D0/,   &
        RTHALF/0.707106781186547524D0/
!
!         EPS,MAXIT CONTROL THE TEST FOR CONVERGENCE OF THE SERIES AND
!           CONTINUED-FRACTION EXPANSIONS.
!         OFL IS A LARGE NUMBER, USED TO RESCALE THE CONTINUED FRACTION.
!         UFL IS SUCH THAT EXP(UFL) IS JUST .GT. ZERO.
!         AHILL CONTROLS THE SWITCH TO HILL'S APPROXIMATION.
!
      DATA EPS/1D-12/,MAXIT/100000/,OFL/1D30/,UFL/-180D0/,AHILL/1D4/
!
      GAMIND=ZERO
      IF(ALPHA.LE.ZERO)THEN
        WRITE(ICOUT,7000)
 7000   FORMAT('***** ERROR FROM ROUTINE GAMIND:',   &
               ' SHAPE PARAMETER IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)ALPHA
 7002   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO  9000
      ENDIF
!
      IF(X.LT.ZERO)THEN
        WRITE(ICOUT,7010)
 7010   FORMAT('***** ERROR FROM ROUTINE GAMIND:',   &
               ' ARGUMENT OF FUNCTION IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7002)X
        CALL DPWRST('XXX','BUG ')
        GO TO  9000
      ENDIF
!
      IF(X.EQ.ZERO)GO TO 9000
!
      IF(ALPHA.GT.AHILL)GO TO  100
      IF(X.GT.ONE.AND.X.GE.ALPHA)GO TO  50
!
!         SERIES EXPANSION
!
      SUM=ONE
      TERM=ONE
      A=ALPHA
      DO 10 IT=1,MAXIT
      A=A+ONE
      TERM=TERM*X/A
      SUM=SUM+TERM
      IF(TERM.LE.EPS)GO TO  20
   10 CONTINUE
!
      WRITE(ICOUT,7020)
 7020 FORMAT('**** WARNING FROM ROUTINE GAMIND:',   &
             ' ITERATION HAS NOT CONVERGED. RESULT MAY BE UNRELIABLE.')
      CALL DPWRST('XXX','BUG ')
!
   20 ARG=ALPHA*DLOG(X)-X-G+DLOG(SUM/ALPHA)
      GAMIND=ZERO
      IF(ARG.GE.UFL)GAMIND=DEXP(ARG)
      GO TO 9000
!
!         CONTINUED-FRACTION EXPANSION
!
   50 CONTINUE
      A=ONE-ALPHA
      B=A+X+ONE
      TERM=ZERO
      PN1=ONE
      PN2=X
      PN3=X+ONE
      PN4=X*B
      RATIO=PN3/PN4
      DO 70 IT=1,MAXIT
      A=A+ONE
      B=B+TWO
      TERM=TERM+ONE
      AN=A*TERM
      PN5=B*PN3-AN*PN1
      PN6=B*PN4-AN*PN2
      IF(PN6.EQ.ZERO)GO TO  60
      RN=PN5/PN6
      DIFF=DABS(RATIO-RN)
      IF(DIFF.LE.EPS.AND.DIFF.LE.EPS*RN)GO TO  80
      RATIO=RN
   60 PN1=PN3
      PN2=PN4
      PN3=PN5
      PN4=PN6
      IF(DABS(PN5).LT.OFL)GO TO  70
      PN1=PN1/OFL
      PN2=PN2/OFL
      PN3=PN3/OFL
      PN4=PN4/OFL
   70 CONTINUE
!
      WRITE(ICOUT,7020)
      CALL DPWRST('XXX','BUG ')
!
   80 ARG=ALPHA*DLOG(X)-X-G+DLOG(RATIO)
      GAMIND=ONE
      IF(ARG.GE.UFL)GAMIND=ONE-DEXP(ARG)
      GO TO 9000
!
!         ALPHA IS LARGE: USE HILL'S APPROXIMATION (N.L. JOHNSON AND
!         S. KOTZ, 1970, 'CONTINUOUS UNIVARIATE DISTRIBUTIONS 1', P.180)
!
!         THE 'DO 110' LOOP CALCULATES 2*(X-ALPHA-ALPHA*DLOG(X/ALPHA)),
!         USING POWER-SERIES EXPANSION TO AVOID ROUNDING ERROR
!
  100 CONTINUE
      R=ONE/DSQRT(ALPHA)
      Z=(X-ALPHA)*R
      TERM=Z*Z
      SUM=HALF*TERM
      DO 110 I=1,12
      TERM=-TERM*Z*R
      SUM=SUM+TERM/(I+TWO)
      IF(DABS(TERM).LT.EPS)GO TO  120
  110 CONTINUE
  120 WW=TWO*SUM
      W=DSQRT(WW)
      IF(X.LT.ALPHA)W=-W
      H1=ONE/THREE
      H2=-W/X36
      H3=(-WW+X13)/X1620
      H4=(X42*WW+X119)*W/X38880
      Z=(((H4*R+H3)*R+H2)*R+H1)*R+W
      GAMIND=HALF+HALF*DERFDP(Z*RTHALF)
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION GAMIND
      SUBROUTINE GAMLI1(Y,N,ICASPL,IGAMFL,ALOC,SCALE,SHAPE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE GAMMA (OR INVERTED GAMMA) DISTRIBUTION.  THIS IS
!              FOR THE RAW DATA CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 13.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IGAMFL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DG
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DLGADP
!
      EXTERNAL DLGADP
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GAML'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GAMLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IGAMFL
   52   FORMAT('IBUGA3,ISUBRO,IGAMFL = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE,SHAPE
   55   FORMAT('N,ALOC,SCALE,SHAPE = ',I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.NE.'3GAM')ALOC=0.0
!
!     LOG-LIKELIHOOD FUNCTION IS:
!
!     -N*(LOGGAMMA(SHAPE) - N*SHAPE*LOG(SCALE)) +
!     (SHAPE-1)*SUM[i=1 to n][LOG(X(i) - LOC] -
!     SUM[i=1 to n][X(i) - LOC]/SCALE
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DG=DBLE(SHAPE)
!
      DTERM1=-DN*DLGADP(DG) - DN*DG*DLOG(DS)
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 1010 I=1,N
        DX=DBLE(Y(I)) - DU
        DSUM1=DSUM1 + DLOG(DX)
        DSUM2=DSUM2 + DX
 1010 CONTINUE
!
      DLIK=DTERM1 + (DG-1.0D0)*DSUM1 - DSUM2/DS
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'3GAM')DNP=3.0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GAMLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1
 9013   FORMAT('DSUM1,DSUM2,DTERM1 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GAMLI1
      SUBROUTINE GAMML1(Y,N,IGAMFL,   &
                        TEMP1,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XGEOM,   &
                        ZMEAN,ZSD,ZGEOM,   &
                        SCALML,SCALSE,SHAPML,SHAPSE,COVSE,   &
                        SCALMO,SHAPMO,   &
                        SCALYE,SHAPYE,SCYEBC,SHYEBC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER GAMMA DISTRIBUTION FOR THE RAW DATA
!              CASE (I.E., NO CENSORING AND NO GROUPING).  THIS ROUTINE
!              RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE INTERVALS
!              WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLG1 WILL GENERATE THE OUTPUT
!              FOR THE GAMMA MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!              --JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                WILEY, 1994, CHAPTER xx.
!              --YE AND CHEN (2017), "CLOSED-FORM ESTIMATORS FOR THE
!                GAMMA DISTRIBUTION DERIVED FROM LIKELIHOOD
!                EQUATIONS", THE AMERICAN STATISTICIAN, VOL. 71,
!                NO. 2, PP. 177-181.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/2
!     ORIGINAL VERSION--FEBRUARY  2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLE1)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DOUBLE PRECISION DTEMP1(*)
!
      CHARACTER*4 ICASE
      CHARACTER*4 IGAMFL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DG
      DOUBLE PRECISION DS
      DOUBLE PRECISION DX
      DOUBLE PRECISION DXLOG
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION XLOWSV
      DOUBLE PRECISION XUPSV
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION DANS(10)
      DOUBLE PRECISION TRIGAM
      DOUBLE PRECISION DTRM11
      DOUBLE PRECISION DTRM12
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DENOM
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DSHAPE
!
      DOUBLE PRECISION GAMFUN
      EXTERNAL GAMFUN
      DOUBLE PRECISION DLOGGM
      COMMON/GAMCOM/DLOGGM
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GAMM'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GAMML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE,IGAMFL
   52   FORMAT('IBUGA3,ISUBRO,ICASE,IGAMFL = ',3(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),TEMP1(I),DTEMP1(I)
   57     FORMAT('I,Y(I),TEMP1(I),DTEMP1(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR GAMMA MLE ESTIMATE              **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GAMMA'
      IF(IGAMFL.EQ.'IGAM')IDIST='INVERTED GAMMA'
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  ZMEAN,ZVAR,ZSD,ZMIN,ZMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      CALL GEOMEA(Y,N,IWRITE,ZGEOM,IBUGA3,IERROR)
!
      IF(IGAMFL.EQ.'IGAM')THEN
        DO 1118 I=1,N
          Y(I)=1.0/Y(I)
 1118   CONTINUE
        CALL MEAN(Y,N,IWRITE,ZMEAN,IBUGA3,IERROR)
        CALL SD(Y,N,IWRITE,ZSD,IBUGA3,IERROR)
        CALL GEOMEA(Y,N,IWRITE,ZGEOM,IBUGA3,IERROR)
      ENDIF
      XMEAN=ZMEAN
      XSD=ZSD
      XGEOM=ZGEOM
!
      SHAPML=CPUMIN
      SHAPMO=CPUMIN
      SHAPSE=CPUMIN
      SHAMSE=CPUMIN
      SCALML=CPUMIN
      SCALSE=CPUMIN
      COVSE=CPUMIN
!
!     FOR THE SHAPE PARAMETER, SOLVE THE EQUATION:
!
!         LOG(GAMMAHAT) - PHI(GAMMAHAT) - LOG(XBAR/G) = 0
!
!     WITH G DENOTING THE GEOMETRIC MEAN (PRODUCT[i=1 to n][X(i)**(1/N)]
!
!     THEN
!
!        SCALE = XBAR/GAMMAHAT
!
!     FOR STARTING VALUE, USE THE METHOD OF MOMENT ESTIMATORS
!
!        GAMMAHAT = (XBAR/XSD)**2
!        SCALE    = XSD**2/XBAR
!
!     THE YE AND CHEN ESTIMATES ARE:
!
!        SHAPE = N*SUM[X(i)]/
!                N*SUM[X(i)*LOG(X(i)) - SUM[LOG(X(i)*SUM[X(i)]
!        SCALE = (1/N**2)*(N*SUM[X(i)*LOG(X(i)) -
!                SUM[LOG(X(i))*SUM[X(i)])
!
!     THE BIAS CORRECTION TERMS ARE
!
!         SHAPE' = ((N-1)/(N+2))*SHAPE
!         SCALE' = ((N-1)/(N+2))*SHAPE
!
      AN=REAL(N)
      SHAPMO=(XMEAN/XSD)**2
      SCALMO=XSD**2/XMEAN
!
!     YE AND CHEN METHOD
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DN=DBLE(N)
      DO 100 I=1,N
        DX=DBLE(Y(I))
        DXLOG=DBLE(DLOG(DX))
        DSUM1=DSUM1 + DX
        DSUM2=DSUM2 + DXLOG
        DSUM3=DSUM3 + DX*DXLOG
  100 CONTINUE
      DNUM=DN*DSUM1
      DENOM=DN*DSUM3 - DSUM2*DSUM1
      DSHAPE=DNUM/DENOM
      DSCALE=(1.0D0/DN**2)*(DN*DSUM3 - DSUM2*DSUM1)
      SCALYE=REAL(DSCALE)
      SCYEBC=REAL((DN-1.0D0)*DSCALE/(DN+2.0D0))
      SHAPYE=REAL(DSHAPE)
      SHYEBC=REAL((DN/(DN-1.0D0))*DSHAPE)
!
!     ESTIMATES FOR 2-PARAMETER MODEL.  USE DFZER2 TO FIND ROOT OF
!     THE LIKELIHOOD EQUATION.
!
      DLOGGM=DLOG(DBLE(XMEAN)/DBLE(XGEOM))
      DXSTRT=DBLE(SHAPMO)
      AE=2.0*0.000001D0*DXSTRT
      RE=AE
      IFLAG=0
      DXLOW=DXSTRT/2.0D0
      DXUP=2.0D0*DXSTRT
      ITBRAC=0
 2205 CONTINUE
      XLOWSV=DXLOW
      XUPSV=DXUP
      CALL DFZERO(GAMFUN,DXLOW,DXUP,DXSTRT,RE,AE,IFLAG)
!
      IF(IFLAG.EQ.4 .AND. ITBRAC.LE.100)THEN
        DXLOW=XLOWSV/2.0D0
        DXUP=2.0D0*XUPSV
        ITBRAC=ITBRAC+1
        GO TO 2205
      ENDIF
!
!
      IF(IFLAG.EQ.2)THEN
!
!       NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2111)
!2111   FORMAT('***** WARNING FROM GAMMA MAXIMUM LIKELIHOOD--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,2113)
!2113   FORMAT('      ESTIMATE OF SIGMA MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2121)
 2121   FORMAT('***** WARNING FROM GAMMA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2123)
 2123   FORMAT('      ESTIMATE OF SHAPE PARAMETER MAY BE NEAR ',   &
               'A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2131)
 2131   FORMAT('***** ERROR FROM GAMMA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2133)
 2133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2141)
 2141   FORMAT('***** WARNING FROM GAMMA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2143)
 2143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      SHAPML=REAL(DXLOW)
      SCALML=XMEAN/SHAPML
      IF(IGAMFL.EQ.'IGAM')SCALML=1.0/SCALML
!
!     COMPUTE STANDARD ERRORS (CAN BASE ON EITHER THE NORMAL BIASED
!     ESTIMATORS OR THE BIAS CORRECTED ESTIMATORS)
!
!     NOTE THAT DPSIFN COMPUTES THE SCALED PSI DERIVATIVE FUNCTION:
!
!        (-1)**(K+1)/GAMMA(K+1)
!
!     FOR TRIGAMMA, K=1 AND THE SCALING FACTOR REDUCES TO 1.
!
      SHAPML=REAL(DXLOW)
      SCALML=XMEAN/SHAPML
      IF(IGAMFL.EQ.'IGAM')THEN
        SCALML=1.0/SCALML
      ENDIF
!
      DN=DBLE(N)
      DG=DBLE(SHAPML)
      DS=DBLE(SCALML)
      KODE=1
      NTEMP=1
      M=1
      NZ=0
      CALL DPSIFN(DG,NTEMP,KODE,M,DANS,NZ,IERR)
      TRIGAM=DANS(1)
      IF(IERR.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3101)IDIST
 3101   FORMAT('***** ERROR FROM ',A14,' MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3103)
 3103   FORMAT('      UNABLE TO COMPUTE TRIGAMMA FUNCTION.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(IERR.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3101)IDIST
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3105)
 3105   FORMAT('      OVERFLOW IN COMPUTING THE TRIGAMMA FUNCTION.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(IERR.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3101)IDIST
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,3107)
 3107   FORMAT('      OVERFLOW IN COMPUTING THE TRIGAMMA FUNCTION.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DTRM11=DN*(DG*TRIGAM-1.0D0)
      DTRM12=DS**2*TRIGAM
      SCALSE=REAL(DSQRT(DTRM12/DTRM11))
      SHAPSE=REAL(DSQRT(DG/DTRM11))
      COVSE=REAL(-DS/DTRM11)
!
 9000 CONTINUE
!
      XMEAN=ZMEAN
      XSD=ZSD
      XVAR=ZVAR
      XMIN=ZMIN
      XMAX=ZMAX
      XGEOM=ZGEOM
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GAMML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)N,XMEAN,XSD,XMIN,XMAX
 9015   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPML,SCALML,SHAPSE,SCALSE
 9017   FORMAT('SHAPML,SCALML,SHAPSE,SCALSE =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9018)SHAPMO,SCALMO,SHAPYE,SCALYE
 9018   FORMAT('SHAPMO,SCALMO,SHAPYE,SCALYE =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)SHAPBC,SHABSE,COVSE,COVBSE
 9019   FORMAT('SHAPBC,SHABSE,COVSE,COVBSE =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GAMML1
      SUBROUTINE GAMML2(Y,TAG,N,IGAMFL,MAXNXT,   &
                        ICASE,IDIST,   &
                        TEMP1,XTEMP,YSAVE,DTEMP1,ITEMP,   &
                        XMEANF,XSDF,XVARF,XMINF,XMAXF,XGEOMF,   &
                        XMEANC,XSDC,XVARC,XMINC,XMAXC,XGEOMC,   &
                        SCALMO,SHAPMO,   &
                        SCALML,SCALSE,SHAPML,SHAPSE,COVSE,   &
                        IRSAV,ISE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER GAMMA DISTRIBUTION FOR THE RAW DATA
!              CASE WITH CENSORING (BUT NO GROUPING).  THIS ROUTINE
!              RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE INTERVALS
!              WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLG2 WILL GENERATE THE OUTPUT
!              FOR THE GAMMA MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!              --JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                WILEY, 1994, CHAPTER xx.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLG2)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION TEMP1(*)
      DIMENSION XTEMP(*)
      DIMENSION YSAVE(*)
      DOUBLE PRECISION DTEMP1(*)
      INTEGER ITEMP(*)
!
      CHARACTER*4 ICASE
      CHARACTER*40 IDIST
      CHARACTER*4 IGAMFL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
      CHARACTER*4 IWRITE
!
      EXTERNAL GC1FUN
      DOUBLE PRECISION J1FUN
      DOUBLE PRECISION J2FUN
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DGAMI
      DOUBLE PRECISION DPSI
      EXTERNAL J1FUN
      EXTERNAL J2FUN
      EXTERNAL DGAMMA
      EXTERNAL DGAMI
      EXTERNAL DPSI
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION DGEOME
      INTEGER IN
      INTEGER IR
      COMMON/GC1COM/XBAR,DGEOME,IN,IR
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=200)
      PARAMETER(LENW=4*LIMIT)
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DLOW
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION DA
      COMMON/J1COM/DA
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      DIMENSION FISH(2,2)
      DIMENSION COV(2,2)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DGAM
      DOUBLE PRECISION DS
      DOUBLE PRECISION DP
      DOUBLE PRECISION DTJ
      DOUBLE PRECISION DJ1
      DOUBLE PRECISION DJ2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
      DOUBLE PRECISION DANS(10)
      DOUBLE PRECISION TRIGAM
      DOUBLE PRECISION DTERM1
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GAMM'
      ISUBN2='L2  '
      IERROR='NO'
!
      TRIGAM=0.0D0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GAMML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR GAMMA MLE ESTIMATE              **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GAMMA'
      IF(IGAMFL.EQ.'ON')IDIST='INVERTED GAMMA'
!
      CALL CKCENS(TAG,TEMP1,N,IDIST,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEANF,XVARF,XSDF,XMINF,XMAXF,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      CALL GEOMEA(Y,IR,IWRITE,XGEOMF,IBUGA3,IERROR)
!
      IF(IGAMFL.EQ.'IGAM')THEN
        DO 1118 I=1,N
          Y(I)=1.0/Y(I)
 1118   CONTINUE
        CALL MEAN(Y,N,IWRITE,ZMEANF,IBUGA3,IERROR)
        CALL SD(Y,N,IWRITE,ZSDF,IBUGA3,IERROR)
      ENDIF
!
      CALL SORTC(Y,TAG,N,Y,TAG)
      IR=0
      DO 2120 I=1,N
        IF(TAG(I).EQ.1.0)IR=IR+1
 2120 CONTINUE
      IRSAV=IR
!
      ICNT=0
      DO 2122 I=1,N
        IF(TAG(I).EQ.1.0)THEN
          ICNT=ICNT+1
          XTEMP(ICNT)=Y(I)
        ENDIF
 2122 CONTINUE
      DO 2124 I=1,N
        IF(TAG(I).EQ.0.0)THEN
          ICNT=ICNT+1
          XTEMP(ICNT)=Y(I)
        ENDIF
 2124 CONTINUE
      DO 2126 I=1,N
        Y(I)=XTEMP(I)
        IF(I.LE.IR)THEN
          TAG(I)=1.0
        ELSE
          TAG(I)=0.0
        ENDIF
        IF(IGAMFL.EQ.'IGAM')THEN
          YSAVE(I)=1.0/Y(I)
        ELSE
          YSAVE(I)=Y(I)
        ENDIF
 2126 CONTINUE
      IM=N-IR
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MML2')THEN
        WRITE(ICOUT,2127)N,IR,IM
 2127   FORMAT(1X,'N,IR,IM = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 2128 I=1,MIN(100,N)
          WRITE(ICOUT,2129)I,Y(I),TAG(I)
 2129     FORMAT(1X,'I,Y(I),TAG(I)=',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 2128   CONTINUE
      ENDIF
!
      IR1=IR
      IR2=IR
      IR3=IR
!
      AR=REAL(IR)
      DR=DBLE(IR)
      AN=REAL(N)
      AM=REAL(IM)
!
      IF(IM.EQ.0)THEN
        ICASE='NONE'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)IDIST(1:14)
 2131   FORMAT('***** WARNING FROM ',A14,' MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2133)
 2133   FORMAT('      NO CENSORING TIMES DETECTED.  IT IS RECOMMENDED')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2135)
 2135   FORMAT('      THAT THE FULL SAMPLE SYNTAX BE USED:')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2137)IDIST(1:14)
 2137   FORMAT('      ',A14,' MAXIMUM LIKELIHOOD  Y')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSE
        ICASE='SING'
        AHOLD=Y(IR+1)
        DO 2140 I=IR+1,N
          IF(Y(I).NE.AHOLD)THEN
            ICASE='MULT'
            GO TO 2149
          ENDIF
 2140   CONTINUE
 2149   CONTINUE
      ENDIF
!
!               ************************************
!               **  STEP 41--                     **
!               **  CARRY OUT CALCULATIONS        **
!               **  FOR GAMMA MLE                 **
!               **  ESTIMATE (TIME CENSORED CASE) **
!               ************************************
!
!  THE MAXIMUM LIKELIHOOD EQUATIONS FOR THE CENSORED CASE ARE:
!
!      R*XBAR/SHAT - R*GHAT + SUM[i=1 to M]
!        [Z(j)**GHAT*EXP(Z(j)/(GAMMA(GHAT) - G(Z(j),GHAT))] = 0
!
!      R*LOG(GEOMEAN/SHAT)  - N*DIGAMMA(GHAT) + SUM[i=1 to M]
!        [(GAMMA(GHAT)*DIGAMMA(GHAT) J(Z(j),GHAT))/
!        (GAMMA(GHAT) - G(Z(j),GHAT))] = 0
!
!      WHERE
!
!
!         XBAR = MEAN OF FAILURE DATA
!         GEOMEAN  = GEOMETRIC MEAN OF FAILURE DATA
!         R        = NUMBER OF FAILURES
!         M        = NUMBER OF CENSORING TIMES
!         SHAT     = FVEC(1) = CURRENT ESTIMATE OF SCALE PARAMETER
!         GHAT     = FVEC(2) = CURRENT ESTIMATE OF SHAPE PARAMETER
!         Z(j)     = jth CENSORING TIME
!         GAMMA    = GAMMA FUNCTION
!         DIGAMMA  = DIGAMMA FUNCTION
!         G(x,a)   = INCOMPLETE GAMMA FUNCTION
!         J(X,a)   = INTEGRAL[0 to x][t**(A-1)*LOG(t)*EXP(-t)]dt
!
!  THESE ARE SOLVED USING THE DNSQE ROUTINE.
!
!
      ISTEPN='41'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
      IWRITE='OFF'
      AN=REAL(N)
!
!  COMPUTE STATISTICS FOR FAILURE ONLY DATA
!
      IF(IGAMFL.EQ.'IGAM')THEN
        CALL MEAN(Y,IR,IWRITE,ZMEAN,IBUGA3,IERROR)
        CALL SD(Y,IR,IWRITE,ZSD,IBUGA3,IERROR)
        CALL MINIM(Y,IR,IWRITE,ZMIN,IBUGA3,IERROR)
        CALL MAXIM(Y,IR,IWRITE,ZMAX,IBUGA3,IERROR)
        CALL GEOMEA(Y,IR,IWRITE,ZGEOM,IBUGA3,IERROR)
        XMEANC=ZMEAN
        XSDC=ZSD
        XVARC=SQRT(XSDC)
        XMINC=ZMIN
        XMAXC=ZMAX
        XGEOMC=ZGEOM
        ZCOEFV=ZSD/ZMEAN
        CALL MEAN(YSAVE,IR,IWRITE,XMEAN,IBUGA3,IERROR)
        CALL SD(YSAVE,IR,IWRITE,XSD,IBUGA3,IERROR)
        CALL MINIM(YSAVE,IR,IWRITE,XMIN,IBUGA3,IERROR)
        CALL GEOMEA(YSAVE,IR,IWRITE,XGEOM,IBUGA3,IERROR)
        XCOEFV=XSD/XMEAN
      ELSE
        CALL MEAN(Y,IR,IWRITE,XMEAN,IBUGA3,IERROR)
        CALL SD(Y,IR,IWRITE,XSD,IBUGA3,IERROR)
        CALL MINIM(Y,IR,IWRITE,XMIN,IBUGA3,IERROR)
        CALL MAXIM(Y,IR,IWRITE,XMAX,IBUGA3,IERROR)
        CALL GEOMEA(Y,IR,IWRITE,XGEOM,IBUGA3,IERROR)
        XCOEFV=XSD/XMEAN
        XMEANC=XMEAN
        XSDC=XSD
        XVARC=SQRT(XSDC)
        XMINC=XMIN
        XMAXC=XMAX
        XGEOMC=XGEOM
      ENDIF
!
!  USE MOMENT ESTIMATES OF FAILURE DATA AS STARTING VALUES FOR
!  EQUATION SOLVER.
!
      IF(IGAMFL.EQ.'IGAM')THEN
        SHAPMO=(ZMEAN/ZSD)**2
        SCALMO=ZSD**2/ZMEAN
        XPAR(2)=DBLE(SCALMO)
        SCALMO=1.0/SCALMO
        XBAR=DBLE(ZMEAN)
        DGEOME=DBLE(ZGEOM)
      ELSE
        SHAPMO=(XMEAN/XSD)**2
        SCALMO=XSD**2/XMEAN
        XBAR=DBLE(XMEAN)
        DGEOME=DBLE(XGEOM)
        XPAR(2)=DBLE(SCALMO)
      ENDIF
!
      XPAR(1)=DBLE(SHAPMO)
!
      IN=N
      JAC=0
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      FVEC(1)=0.0D0
      FVEC(2)=0.0D0
      CALL DNSQE(GC1FUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y(IR+1),IM)
!
      SHAPML=REAL(XPAR(1))
      SCALML=REAL(XPAR(2))
      IF(IGAMFL.EQ.'IGAM')THEN
        SCALML=1.0/SCALML
      ENDIF
!
!  COMPUTE STANDARD ERRORS.
!
!  NOTE THAT DPSIFN COMPUTES THE SCALED PSI DERIVATIVE FUNCTION:
!
!     (-1)**(K+1)/GAMMA(K+1)
!
!  FOR TRIGAMMA, K=1 AND THE SCALING FACTOR REDUCES TO 1.
!
      ISE=1
      DN=DBLE(N)
      DG=DBLE(SHAPML)
      DS=DBLE(SCALML)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DSUM5=0.0D0
      IF(IM.GT.0)THEN
        KODE=1
        NTEMP=1
        MTEMP=1
        NZ=0
!
        EPSABS=1.0D-7
        EPSREL=1.0D-7
        IER=0
        IKEY=3
        DLOW=0.0D0
        DA=DBLE(SHAPML)
        DGAM=DGAMMA(DG)
        DP=DPSI(DG)
        CALL DPSIFN(DG,NTEMP,KODE,MTEMP,DANS,NZ,IERR)
        TRIGAM=DANS(1)
        IF(IERR.EQ.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4201)IDIST(1:14)
 4201     FORMAT('***** ERROR FROM ',A14,' (CENSORED CASE) MAXIMUM ',   &
                 'LIKELIHOOD--')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4203)
 4203     FORMAT('      UNABLE TO COMPUTE TRIGAMMA FUNCTION.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4209)
 4209     FORMAT('      PARAMETER STANDARD ERRORS AND CONFIDENCE ',   &
                 'WILL NOT BE COMPUTED.')
          CALL DPWRST('XXX','WRIT')
          ISE=0
          GO TO 4999
        ELSEIF(IERR.EQ.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4201)IDIST
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4205)
 4205     FORMAT('      OVERFLOW IN COMPUTING THE TRIGAMMA ',   &
                 'FUNCTION.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4209)
          CALL DPWRST('XXX','WRIT')
          ISE=0
          GO TO 4999
        ELSEIF(IERR.EQ.3)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4201)IDIST
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4207)
 4207     FORMAT('      OVERFLOW IN COMPUTING THE TRIGAMMA ',   &
                 'FUNCTION.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,4209)
          CALL DPWRST('XXX','WRIT')
          ISE=0
          GO TO 4999
        ENDIF
!
        DO 4310 I=IR+1,N
!
          DX=DBLE(Y(I)/SCALML)
          DTERM1=DGAM - DGAMI(DG,DX)
          DTJ=DX**DG*DEXP(-DX)/DTERM1
!
          DJ1=0.0D0
          CALL DQAG(J1FUN,DLOW,DX,EPSABS,EPSREL,IKEY,DJ1,   &
                    ABSERR,NEVAL,   &
                    IER,LIMIT,LENW,LAST,IWORK,WORK)
          DJ2=0.0D0
          CALL DQAG(J2FUN,DLOW,DX,EPSABS,EPSREL,IKEY,DJ2,   &
                    ABSERR,NEVAL,   &
                    IER,LIMIT,LENW,LAST,IWORK,WORK)
!
          DSUM1=DSUM1 + DTJ*(DX-DTJ)
          DSUM2=DSUM2 + DTJ*DLOG(DX)
          DSUM3=DSUM3 + DTJ*(DGAM*DP - DJ1)/DTERM1
          DSUM4=DSUM4 + (DGAM*(DP**2 + TRIGAM) - DJ2)/DTERM1
          DSUM5=DSUM5 + ((DGAM*DP - DJ1)/DTERM1)**2
!
 4310   CONTINUE
      ENDIF
      IF(ISE.EQ.0)GO TO 4999
!
      DTERM1=(-DR/DS**2)*((XBAR/DS)*(DG-1.0D0) - DG**2) - DSUM1/(DS**2)
      FISH(1,1)=REAL(DTERM1)
      DTERM1=DN*TRIGAM - DSUM4 + DSUM5
      FISH(2,2)=REAL(DTERM1)
      DTERM1=(1.0D0/DS)*(DR - DSUM2 + DSUM3)
      FISH(2,1)=REAL(DTERM1)
      FISH(1,2)=FISH(2,1)
!
      NDIM=2
      CALL SGECO(FISH,NDIM,NDIM,ITEMP,RCOND,XTEMP)
      IJOB=1
      CALL SGEDI(FISH,NDIM,NDIM,ITEMP,XTEMP,XTEMP(MAXNXT/2),IJOB)
      DO 4410 J=1,NDIM
        DO 4415 I=1,NDIM
          COV(I,J)=FISH(I,J)
 4415   CONTINUE
 4410 CONTINUE
!
      SCALSE=0.0
      SHAPSE=0.0
      IF(COV(1,1).GE.0.0)SCALSE=SQRT(COV(1,1))
      IF(COV(2,2).GE.0.0)SHAPSE=SQRT(COV(2,2))
      COVSE=COV(2,1)
!
 4999 CONTINUE
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GAMML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPML,SCALML,SHAPSE,SCALSE
 9017   FORMAT('SHAPML,SCALML,SHAPSE,SCALSE =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GAMML2
      SUBROUTINE GAMML3(Y,N,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XSKEW,   &
                        ALOCML,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 3-PARAMETER GAMMA DISTRIBUTION FOR THE RAW DATA
!              CASE (I.E., NO CENSORING AND NO GROUPING).
!
!              THIS METHOD IS BASED ON THE CODE GIVEN ON PP. 365-367 OF
!              COHEN AND WHITTEN.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLL3 WILL GENERATE THE OUTPUT
!              FOR THE 3-PARAMATER GAMMA MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!              --COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 6, APPENDIX.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/04
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION TL
      DOUBLE PRECISION TU
      DOUBLE PRECISION T
      DOUBLE PRECISION FL
      DOUBLE PRECISION FU
      DOUBLE PRECISION F
      DOUBLE PRECISION BOUND
      DOUBLE PRECISION STEP
      DOUBLE PRECISION EPS
      DOUBLE PRECISION DB
      DOUBLE PRECISION RHO
!
      DOUBLE PRECISION V(6)
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IMETH
!
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSUM1
      COMMON/GAMCO3/DMEAN,DSUM1,IN
      DOUBLE PRECISION GAMFU5
      EXTERNAL GAMFU5
!
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION DTERM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     TWO METHODS CODED:
!
!         1. METHOD GIVEN BY COHEN AND WHITTEN
!
!         2. METHOD GIVEN BY BURY
!
      ISUBN1='GAMM'
      ISUBN2='L3  '
      IDIST='GAMMA'
      IWRITE='OFF'
      IERROR='NO'
      IMETH='BURY'
!
      ALOCML=CPUMIN
      SCALML=CPUMIN
      SHAPML=CPUMIN
      V(1)=CPUMIN
      V(2)=CPUMIN
      V(3)=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GAMML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR GAMMA MLE ESTIMATE              **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN 3-PARAMETER GAMMA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 5.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)N
  113   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      CALL STMOM3(Y,N,IWRITE,XSKEW,IBUGA3,IERROR)
!
      DO 210 I=1,N
        DTEMP1(I)=DBLE(Y(I))
  210 CONTINUE
!
      IN=N
      DMEAN=DBLE(XMEAN)
!
!     STEP 1: SOLVE EQUATION IN GAMFU7 TO ESTIMATE THE LOCATION
!             PARAMETER.
!
!             FIRST NEED TO FIND A BRACKETING INTERVAL.  USE
!             MINIMUM VALUE AS UPPER LIMIT.  DESCEND IN SMALL
!             INCREMENTS UNTIL "MEAN - 60*SD".  IF NO BRACKETING
!             INTERVAL FOUND AT THAT POINT, THEN NO ML SOLUTION.
!
      IF(IMETH.EQ.'COHE')THEN
        EPS=0.1D-08
        BOUND=DBLE(XMEAN) - 25.0D0*DBLE(XSD)
        STEP=DBLE(XSD)/100.0D0
        TU=DBLE(XMIN) - EPS
        CALL GAMFU7(DTEMP1,TU,DBLE(XMEAN),N,   &
                    RHO,DB,FU,   &
                    ISUBRO,IBUGA3,IERROR)
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML3')THEN
          WRITE(ICOUT,211)TU,RHO,DB,FU
  211     FORMAT('INITIAL GAMFU7: TU,RHO,DB,FU = ',4G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
!     LOCATE A LOWER BOUND FOR THE LOCATION
!
        TL=TU
        FL=FU
!
 300    CONTINUE
        IF(FL/FU.GT.0.0D0)THEN
          TL=TL-STEP
          IF(TL.GT.BOUND)THEN
            CALL GAMFU7(DTEMP1,TL,DBLE(XMEAN),N,   &
                        RHO,DB,FL,   &
                        ISUBRO,IBUGA3,IERROR)
!
            IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML3')THEN
              WRITE(ICOUT,301)TL,RHO,DB,FL
  301         FORMAT('BRACKETING GAMFU7: TL,RHO,DB,FL = ',4G15.7)
              CALL DPWRST('XXX','WRIT')
           ENDIF
!
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,292)
  292       FORMAT('      UNABLE TO FIND A BRACKETING INTERVAL FOR ',   &
                   'THE LOCATION PARAMETER.')
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
!
          GO TO 300
        ELSE
          IF(TL.LT.BOUND)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,292)
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
          ELSE
!
!         USE BINARY SEARCH TO FIND ESTIMATE OF LOCATION PARAMETER
!
            T=(TL+TU)/2.0D0
  400       CONTINUE
            CALL GAMFU7(DTEMP1,T,DBLE(XMEAN),N,   &
                        RHO,DB,F,   &
                        ISUBRO,IBUGA3,IERROR)
!
            IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML3')THEN
              WRITE(ICOUT,401)T,RHO,DB,F
  401         FORMAT('BINARY SEARCH GAMFU7: T,RHO,DB,F = ',4G15.7)
              CALL DPWRST('XXX','WRIT')
            ENDIF
!
            V(1)=T
            V(2)=DB
            V(3)=RHO
            V(4)=V(3)*V(2) + T
            V(5)=V(2)*DSQRT(V(3))
            V(6)=2.0D0/DSQRT(RHO)
            IF(DABS(TL-T).GT.EPS)THEN
              IF(F*FL.LT.0.0D0)THEN
                TU=T
              ELSE
                TL=T
                FL=F
              ENDIF
              T=(TL+TU)/2.0D0
              GO TO 400
            ENDIF
          ENDIF
        ENDIF
!
        ALOCML=REAL(V(1))
        SCALML=REAL(V(2))
        SHAPML=REAL(V(3))
!
      ELSEIF(IMETH.EQ.'BURY')THEN
!
!       METHOD GIVEN ON PAGES 220-221 OF BURY.
!
!       STEP 1: USE DFZER2 TO SOLVE FOR LOCATION PARAMETER.
!               STARTING VALUE PASSED IN (DPMLG3 WILL USE THE
!               MODIFIED MOMENTS ESTIMATOR AS THE STARTING
!               VALUE).
!
!CCCC   DXSTRT=DBLE(ALOCSV)
        STEP=DBLE(XSD)/100.0D0
        BOUND=DBLE(XMEAN) - 25.0D0*DBLE(XSD)
!
!       FIND BRACKETING INTERVAL FIRST
!
        DXUP=DBLE(XMIN) - STEP
        FU=GAMFU5(DXUP,DTEMP1)
        DXLOW=DXUP - STEP
        FL=GAMFU5(DXLOW,DTEMP1)
2105    CONTINUE
        IF(FU*FL.GT.0.0D0)THEN
          DXLOW=DXLOW - STEP
          IF(DXLOW.LT.BOUND)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2131)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2133)
            CALL DPWRST('XXX','BUG ')
            GO TO 9000
          ENDIF
          FL=GAMFU5(DXLOW,DTEMP1)
          GO TO 2105
        ENDIF
!
        IFLAG=0
        DXSTRT=(DXLOW + DXUP)/2.0D0
        DAE=2.0*0.000001D0*DXSTRT
        DRE=DAE
!
        CALL DFZER2(GAMFU5,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP1)
!
        IF(IFLAG.EQ.2)THEN
!
!         NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC     WRITE(ICOUT,999)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     WRITE(ICOUT,2111)
!2111     FORMAT('***** WARNING FROM GAMMA MAXIMUM LIKELIHOOD--')
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC     WRITE(ICOUT,2113)
!2113     FORMAT('      ESTIMATE OF LOCATION MAY NOT BE COMPUTED TO ',
!CCCC1           'DESIRED TOLERANCE.')
!CCCC     CALL DPWRST('XXX','BUG ')
        ELSEIF(IFLAG.EQ.3)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2121)
 2121     FORMAT('***** WARNING FROM GAMMA MAXIMUM LIKELIHOOD--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2123)
 2123     FORMAT('      ESTIMATE OF SHAPE PARAMETER MAY BE NEAR ',   &
                 'A SINGULAR POINT.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IFLAG.EQ.4)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2131)
 2131     FORMAT('***** ERROR FROM GAMMA MAXIMUM LIKELIHOOD--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2133)
 2133     FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IFLAG.EQ.5)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2121)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2143)
 2143     FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ALOCML=REAL(DXLOW)
!
!       STEP 2: COMPUTE ESTIMATES FOR SHAPE AND SCALE
!
        DTERM1=1.0D0 - (1.0D0/((DMEAN - DXLOW)*DSUM1))
        SHAPML=REAL(1.0D0/DTERM1)
        SCALML=(XMEAN-ALOCML)/SHAPML
!
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GAMML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)ALOCML,SCALML,SHAPML
 9013   FORMAT('ALOCML,SCALML,SHAPML = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GAMML3
      SUBROUTINE GAMML5(ALOC,SCALE,SHAPE,X,N,COV,   &
                        XTEMP,ITEMP,MAXNXT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE PARAMETER VARIANCE-COVARIANCE
!              MATRIX FOR THE 3-PARAMETER GAMMA DISTRIBUTION.
!
!              IF SHAPE > 2, THE EXPECTED INFORMATION MATRIX IS
!              OBTAINED FROM THE FOLLOWING QUANTITIES:
!
!                 I(1,1) = N/(SCALE**2*(SHAPE-2)
!                 I(1,2) = n/SCALE**2
!                 I(1,3) = n/(SCALE*(SHAPE-1))
!                 I(2,2) = N*SHAPE/SCALE**2
!                 I(2,3) = N/SCALE
!                 I(3,3) = N*TRIGAMMA(SHAPE)
!
!              IF 1 < SHAPE <= 2, THEN THE LOCAL INFORMATION MATRIX
!              CAN BE USED.  FOR THIS CASE, USE
!
!                 I(1,1) = (SHAPE-1)*SUM[i=1 to N][1/(X(i) - LOC)**2]
!
!              THE PARAMETER VARIANCE-COVARIANCE MATRIX IS THE
!              INVERSE OF THE INFORMATION MATRIX.
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13, P. 212.
!              --COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 4.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
      REAL X(*)
      REAL XTEMP(*)
      REAL FISH(3,3)
      REAL COV(3,3)
!
      INTEGER ITEMP(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DSHAPE
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DX
!
      DOUBLE PRECISION TRIGAM
      EXTERNAL TRIGAM
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GAMM'
      ISUBN2='L5  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GAMML5--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)ALOC,SCALE,SHAPE
   54   FORMAT('ALOC,SCALE,SHAPE = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR VARIANCE-COVARIANCE MATRIX      **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 101 J=1,3
        DO 103 I=1,3
          FISH(I,J)=CPUMIN
          COV(I,J)=CPUMIN
  103   CONTINUE
  101 CONTINUE
!
      DN=REAL(N)
      DLOC=DBLE(ALOC)
      DSCALE=DBLE(SCALE)
      DSHAPE=DBLE(SHAPE)
!
      IF(SHAPE.GT.2.0)THEN
        FISH(1,1)=DN/(DSCALE**2*(DSHAPE-2.0D0))
      ELSEIF(SHAPE.GT.1.0)THEN
        DSUM1=0.0D0
        DO 110 I=1,N
          DX=(DBLE(X(I)) - DLOC)**2
          DSUM1=DSUM1 + 1.0D0/DX
  110   CONTINUE
        FISH(1,1)=(DSHAPE - 1.0D0)*DSUM1
      ELSE
        GO TO 9000
      ENDIF
      FISH(1,2)=REAL(DN/DSCALE**2)
      FISH(1,3)=REAL(DN/(DSCALE*(DSHAPE - 1.0D0)))
      FISH(2,2)=REAL(DN*DSHAPE/DSCALE**2)
      FISH(2,3)=REAL(DN/DSCALE)
      FISH(2,3)=REAL(DN/DSCALE)
      FISH(3,3)=REAL(DN*TRIGAM(DSHAPE,IFAULT))
      FISH(2,1)=FISH(1,2)
      FISH(3,1)=FISH(1,3)
      FISH(3,2)=FISH(2,3)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')THEN
        DO 120 I=1,3
          WRITE(ICOUT,121)FISH(I,1),FISH(I,2),FISH(I,3)
  121     FORMAT('FISH(I,1),FISH(I,2),FISH(I,3) = ',3G15.7)
          CALL DPWRST('XXX','WRIT')
  120   CONTINUE
      ENDIF
!
      CALL SGECO(FISH,3,3,ITEMP,RCOND,XTEMP)
      IJOB=1
      CALL SGEDI(FISH,3,3,ITEMP,XTEMP,XTEMP(MAXNXT/2),IJOB)
      DO 130 J=1,3
        DO 135 I=1,3
          COV(I,J)=FISH(I,J)
  135   CONTINUE
  130 CONTINUE
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'AML5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GAMML5--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)RCOND
 9012   FORMAT('RCOND = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 9020 I=1,3
          WRITE(ICOUT,9021)COV(I,1),COV(I,2),COV(I,3)
 9021     FORMAT('COV(I,1),COV(I,2),COV(I,3) = ',3G15.7)
          CALL DPWRST('XXX','WRIT')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE GAMML5
      SUBROUTINE GAMML8(Y,N,IGAMFL,P3GAMI,IOPFLG,   &
                        TEMP1,DTEMP1,Y2,   &
                        ALOCML,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--USE THE LAWLESS "PROFILE LIKELIHOOD" METHOD (THIS WAS
!              DEVELOPED FOR THE 3-PARAMETER WEIBULL DISTRIBUTION, BUT
!              THE SAME IDEA CAN BE APPLIED TO THE 3-PARAMETER GAMMA
!              DISTRIBUTION.  THIS CAN BE USEFUL AS THE STANDARD
!              MAXIMUM LIKELIHOOD ALGORITHM CAN SOMETIMES FAIL.
!
!     PURPOSE--THIS SUBROUTINE IMPLEMENTS THE PROFILE LOG-LIKELIHOOD
!              METHOD ORIGINALLY PROPOSED BY LAWLESS FOR THE 3-PARAMETER
!              WEIBULL.  THIS METHOD DOES THE FOLLOWING:
!
!                1. CREATE A GRID FOR THE LOCATION PARAMETER FROM 0 TO
!                   THE DATA MINIMUM (MINUS AN EPSILON) VALUE.
!
!                2. ITERATE THROUGH THE GRID AND DO THE FOLLOWING:
!
!                    A. SET THE LOCATION PARAMETER TO THE GRID VALUE.
!                       CALL THIS VALUE A0.
!
!                    B. LET Y2 = Y - A0.
!
!                    C. ESTIMATE THE SCALE AND SHAPE PARAMETER USING
!                       STANDARD 2-PARAMETER GAMMA ML METHODS.
!
!                    D. COMPUTE THE LOG-LIKELIHOOD OF THE 3-PARAMETER
!                       GAMMA BASED ON THESE PARAMETER ESTIMATES.
!
!              THE PARAMETER ESTIMATES THAT GENERATE THE MAXIMUM
!              LIKELIHOOD VALUE ARE THE ESTIMATES USED.
!
!     REFERENCES--LAWLESS (2003), "STATISTICAL MODELS AND METHODS FOR
!                 LIFETIME DATA", SECOND EDITION, WILEY, PP. 187-190.
!              --COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION Y2(*)
      DIMENSION TEMP1(*)
      DOUBLE PRECISION DTEMP1(*)
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IGAMFL
      CHARACTER*4 IOPFLG
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IOP
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GAMM'
      ISUBN2='L8  '
      IWRITE='OFF'
      IERROR='NO'
!
      EPS=0.1E-5
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML8')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GAMML8--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IGAMFL,N
   52   FORMAT('IBUGA3,ISUBRO,IGAMFL,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!
!               **************************************************
!               **  STEP 0--OPEN THE STORAGE FILES              **
!               **************************************************
!
      ISTEPN='1.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML8')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IOPFLG.EQ.'ON' .OR. IOPFLG.EQ.'YES')THEN
        IOP='OPEN'
        IFLAG1=0
        IFLAG2=1
        IFLAG3=0
        IFLAG4=0
        IFLAG5=0
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR LOGNORMAL MLE ESTIMATE          **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML8')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GAMMA'
      ICASAN='GAMM'
      IGAMFL='GAMM'
!
      IF(N.LE.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN GAMMA MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 5.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)N
  113   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     THIS METHOD ASSUMES LOCATION IS NON-NEGATIVE (IT CAN BE EXTENDED
!     TO A NEGATIVE LOWER LIMITS, BUT DEFER ON IMPLEMENTING THAT FOR
!     NOW).
!
      DO 120 I=1,N
        IF(Y(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,127)I,Y(I)
  127     FORMAT('      ROW ',I8,' IS NON-POSITIVE (',G15.7,')')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
  120 CONTINUE
!
!     STEP 1: COMPUTE 2-PARAMETER ML ESTIMATES FOR ORIGINAL DATA SET
!
      CALL GAMML1(Y,N,IGAMFL,   &
                  TEMP1,DTEMP1,   &
                  XMEAN,XSD,XVAR,XMIN,XMAX,XGEOM,   &
                  ZMEAN,ZSD,ZGEOM,   &
                  SCALML,SCALSE,SHAPML,SHAPSE,COVSE,   &
                  SCALMO,SHAPMO,   &
                  SCALYE,SHAPYE,SCYEBC,SHYEBC,   &
                  ISUBRO,IBUGA3,IERROR)
      YMIN=P3GAMI
      IF(YMIN.GE.XMIN)YMIN=0.0
      ALOCML=YMIN
      CALL GAMLI1(Y,N,ICASAN,IGAMFL,ALOCML,SCALML,SHAPML,   &
                  ALIK,AIC,AICC,BIC,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IOPFLG.EQ.'ON' .OR. IOPFLG.EQ.'YES')THEN
        WRITE(IOUNI2,151)ALOCML,ALIK,SCALML,SHAPML
  151   FORMAT(4E15.7)
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML8')THEN
        WRITE(ICOUT,131)SCALML,SHAPML,ALIK
  131   FORMAT('ZERO CASE: SCALML,SHAPML,ALIK = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!     STEP 2: NOW ITERATE THROUGH VALUES OF THE LOCATION PARAMETER
!
!             IF MINIMUM VALUE IS SUFFICIENTLY SMALL, JUST DEFINE A
!             SINGLE GRID.  IF IT IS LARGE, THEN DO 2 PASSES.  ONCE
!             WITH A BROAD GRID AND THEN WITH A FINER GRID.
!
      XMINT=XMIN - EPS
      IF(XMIN.LE.100.0)THEN
        NITER=1
        IPASS=1
        IF(XMIN.LE.10)THEN
          AINC=0.001
        ELSE
          AINC=0.01
        ENDIF
        NLOOP=INT(((XMINT-YMIN)/AINC)+0.1)
      ELSE
        NITER=2
        IPASS=1
        NLOOP=100
        AINC=(XMIN-YMIN)/REAL(NLOOP)
      ENDIF
!
 1000 CONTINUE
!
      IF(IPASS.EQ.2)THEN
        XSTRT=ALOCML - AINC
        IF(XSTRT.LE.0.0)XSTRT=0.0
        XSTOP=ALOCML + AINC
        NLOOP=100
        AINC=XMIN/REAL(NLOOP)
      ELSE
        XSTRT=YMIN
      ENDIF
!
      DO 1100 ILOOP=1,NLOOP
!
!       STEP 2A: SUBTRACT OFF CONDITIONAL VALUE OF LOCATION
!
        ALOC=XSTRT + REAL(ILOOP)*AINC
        IF(ALOC.GE.XMIN)GO TO 1100
        DO 1110 I=1,N
          Y2(I)=Y(I) - ALOC
 1110   CONTINUE
!
!       STEP 2B: COMPUTE 2-PARAMETER ML ESTIMATES FOR MODIFIED DATA SET
!                (BUT NOT THAT LIKELIHOOD IS COMPUTED FOR ORIGINAL DATA)
!
        CALL GAMML1(Y2,N,IGAMFL,   &
                    TEMP1,DTEMP1,   &
                    XMEANT,XSDT,XVART,XMINT,XMAXT,XGEOMT,   &
                    ZMEANT,ZSDT,ZGEOMT,   &
                    SCALMT,SCALSE,SHAPMT,SHAPSE,COVSE,   &
                    SCALMO,SHAPMO,   &
                    SCALYE,SHAPYE,SCYEBC,SHYEBC,   &
                    ISUBRO,IBUGA3,IERROR)
        CALL GAMLI1(Y,N,ICASAN,IGAMFL,ALOCMT,SCALMT,SHAPMT,   &
                    ALIKT,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
!
        IF(IOPFLG.EQ.'ON' .OR. IOPFLG.EQ.'YES')THEN
          WRITE(IOUNI2,151)ALOC,ALIKT,SCALMT,SHAPMT
        ENDIF
!
!       STEP 2C: COMPARE LIKELIHOOD TO CURRENT MAXIMUM
!
        IF(ALIKT.GT.ALIK)THEN
          ALIK=ALIKT
          ALOCML=ALOC
          SCALML=SCALMT
          SHAPML=SHAPMT
          ITEMP=ILOOP
        ENDIF
!
 1100 CONTINUE
!
      IF(NITER.EQ.2 .AND. IPASS.EQ.1)THEN
        IPASS=2
        GO TO 1000
      ENDIF
!
 9000 CONTINUE
!
      IF(IOPFLG.EQ.'ON' .OR. IOPFLG.EQ.'YES')THEN
        IOP='CLOS'
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MML8')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GAMML8--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)NITER,NLOOP,IPASS,IERROR
 9013   FORMAT('NITER,NLOOP,IPASS,IERROR = ',3I8,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9021)ALOCML,SCALML,SHAPML,ALIK
 9021   FORMAT('MLE: ALOCML,SCALML,SHAPML,ALIK = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GAMML8
      SUBROUTINE GAMMO1(XMEAN,XSD,XMIN,XSKEW,N,PSTAMV,   &
                        ALOCMO,SCALMO,SHAPMO,   &
                        ALOCMM,SCALMM,SHAPMM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES MOMENT ESTIMATES FOR THE 3-PARAMETER
!              GAMMA DISTRIBUTION.  THE INPUT VALUES ARE:
!
!                 XMEAN   - THE SAMPLE MEAN
!                 XSD     - THE SAMPLE STANDARD DEVIATION
!                 XSKEW   - THE SAMPLE SKEWNESS
!                 XMIN    - THE SAMPLE MINIMUM
!
!              THIS IS FOR THE UNCENSORED CASE.
!
!     REFERENCE--COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., P. 61 AND
!                PP. 363-364.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION AMOM(3)
      DOUBLE PRECISION VMOM(6)
      DOUBLE PRECISION VMMOM(6)
      DOUBLE PRECISION RHO
      DOUBLE PRECISION RHOL
      DOUBLE PRECISION RHOU
      DOUBLE PRECISION FL
      DOUBLE PRECISION FU
      DOUBLE PRECISION F
      DOUBLE PRECISION EPS
      DOUBLE PRECISION DN
      DOUBLE PRECISION Z
      DOUBLE PRECISION Z1
      DOUBLE PRECISION DCDF
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GAMM'
      ISUBN2='O1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MMO1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GAMMO1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)XMEAN,XSD,XMIN,XSKEW
   54   FORMAT('XMEAN,XSD,XMIN,XSKEW = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR GAMMA MOMENT ESTIMATE       **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MMO1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(XMEAN.EQ.CPUMIN .OR. XMEAN.EQ.PSTAMV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN GAMMA MOMENT ESTIMATION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE SAMPLE MEAN IS UNDEFINED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(XSD.EQ.CPUMIN .OR. XSD.EQ.PSTAMV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,107)
  107   FORMAT('      THE SAMPLE STANDARD DEVIATION IS UNDEFINED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(XSD.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE SAMPLE STANDARD DEVIATION IS NON-POSTIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)XSD
  113   FORMAT('      STANDARD DEVIATION = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N.LT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,122)
  122   FORMAT('      THE SAMPLE SIZE IS LESS THAN FIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,123)N
  123   FORMAT('      SAMPLE SIZE  = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      EPS=0.1D-7
!
      ALOCMO=CPUMIN
      SCALMO=CPUMIN
      SHAPMO=CPUMIN
!
      ALOCMM=CPUMIN
      SCALMM=CPUMIN
      UHATMM=CPUMIN
!
      VMMOM(1)=CPUMIN
      VMMOM(2)=CPUMIN
      VMMOM(3)=CPUMIN
      VMMOM(4)=CPUMIN
      VMMOM(5)=CPUMIN
      VMMOM(6)=CPUMIN
      VMOM(1)=CPUMIN
      VMOM(2)=CPUMIN
      VMOM(3)=CPUMIN
      VMOM(4)=CPUMIN
      VMOM(5)=CPUMIN
      VMOM(6)=CPUMIN
      AMOM(1)=CPUMIN
      AMOM(2)=CPUMIN
      AMOM(3)=CPUMIN
!
!               ******************************************
!               **  STEP 2--                            **
!               **  MOMENT ESTIMATES                    **
!               ******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MMO1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     IN CODE BELOW:
!
!        VMOM(1) = ESTIMATE OF LOCATION
!        VMOM(2) = ESTIMATE OF SCALE
!        VMOM(3) = ESTIMATE OF SHAPE (SIGMA)
!        VMOM(4) = ESTIMATE OF MEAN
!                = LOC + SHAPE*SCALE
!        VMOM(5) = ESTIMATE OF STANDARD DEVIATION
!                = SHAPE*SCALE**2
!        VMOM(6) = THIRD STANDARD MOMENT, A3
!
!     FOR OUR PURPOSES, WE ARE PRIMARILY INTERESTED IN THE PARAMETER
!     ESTIMATES.
!
      AMOM(1)=DBLE(XMEAN)
      AMOM(2)=DBLE(XSD)
      AMOM(3)=DBLE(XSKEW)
!
      VMOM(1)=AMOM(1) - (2.0D0*AMOM(2)/AMOM(3))
      VMOM(2)=AMOM(2)*AMOM(3)/2.0D0
      VMOM(3)=4.0D0/AMOM(3)**2
      VMOM(4)=VMOM(2)*VMOM(3) + VMOM(1)
      VMOM(5)=VMOM(2)*DSQRT(VMOM(3))
      VMOM(6)=AMOM(3)
!
      ALOCMO=REAL(VMOM(1))
      SCALMO=REAL(VMOM(2))
      SHAPMO=REAL(VMOM(3))
!
!     IN CODE BELOW:
!
!        VMMOM(1) = ESTIMATE OF LOCATION
!        VMMOM(2) = ESTIMATE OF SCALE
!        VMMOM(3) = ESTIMATE OF SHAPE (SIGMA)
!        VMMOM(4) = ESTIMATE OF MEAN
!                 = LOC + SHAPE*SCALE
!        VMMOM(5) = ESTIMATE OF STANDARD DEVIATION
!                 = SHAPE*SCALE**2
!        VMMOM(6) = THIRD STANDARD MOMENT, A3
!
!     COMPUTE MODIFIED MOMENT ESTIMATORS USING CODE FOUND ON
!     PP. 363-364 OF COHEN/WHITTEN BOOK.
!
!     IF XMIN PARAMETER NOT GIVEN, THEN SKIP THIS CASE.
!
      IF(XMIN.EQ.CPUMIN)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,212)
  212   FORMAT('      MINIMUM VALUE NOT SPECIFIED.  MODIFIED ',   &
               'MOMENTS WILL NOT BE COMPUTED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IERR=0
      EPS=0.1D-08
      DN=DBLE(N)
!
!     FIND THE STANDARDIZED FIRST ORDER STATISTIC
!
      Z=(DBLE(XMIN) - AMOM(1))/AMOM(2)
!
!     SET UPPER BOUND ON SHAPE TO 1600 (LOWER BOUND ON SKEWNESS IS 0.05)
!
!CCCC RHOU=1600.D0
      RHOU=200.D0
      RHOL=((AMOM(1) - DBLE(XMIN))/AMOM(2))**2
!
!     CALCULATE FUNCTION AT UPPER BOUND, A3U, AND SCALE Z1 SO THAT Z1 > 0
!
      Z1=(Z + DSQRT(RHOU))*DSQRT(RHOU)
      CALL GAMCDF(REAL(Z1),REAL(RHOU),CDF)
      DCDF=DBLE(CDF)
      FU=DCDF - (1.0D0/(DN+1.0D0))
      Z1=(Z + DSQRT(RHOL))*DSQRT(RHOL)
      CALL GAMCDF(REAL(Z1),REAL(RHOL),CDF)
      DCDF=DBLE(CDF)
      FL=DCDF - (1.0D0/(DN+1.0D0))
!
      IF(FL*FU.GT.0.0)THEN
        IERR=1
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,222)
  222   FORMAT('      NO MODIFIED MOMENT ESTIMATOR FOUND.')
        CALL DPWRST('XXX','WRIT')
      ELSE
        RHO=(RHOL+RHOU)/2.0D0
        F=FL
300     CONTINUE
        IF(DABS(RHO-RHOL).GT.EPS)THEN
          Z1=(Z + DSQRT(RHO))*DSQRT(RHO)
          CALL GAMCDF(REAL(Z1),REAL(RHO),CDF)
          DCDF=DBLE(CDF)
          F=DCDF - (1.0D0/(DN+1.0D0))
          IF(F*FL.LT.0.0D0)THEN
            RHOU=RHO
          ELSE
            RHOL=RHO
            FL=F
          ENDIF
          RHO=(RHOL+RHOU)/2.0D0
          GO TO 300
        ELSE
          VMMOM(1)=AMOM(1) - AMOM(2)*DSQRT(RHO)
          VMMOM(2)=AMOM(2)/DSQRT(RHO)
          VMMOM(3)=RHO
          VMMOM(4)=VMMOM(3)*VMMOM(2) + VMMOM(1)
          VMMOM(5)=VMMOM(2)*DSQRT(VMMOM(3))
          VMMOM(6)=2.0D0/DSQRT(VMMOM(3))
        ENDIF
      ENDIF
!
      ALOCMM=VMMOM(1)
      SCALMM=VMMOM(2)
      SHAPMM=VMMOM(3)
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MMO1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GAMMO1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)ALOCMO,SCALMO,SHAPMO
 9012   FORMAT('ALOCMO,SCALMO,SHAPMO = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)ALOCMM,SCALMM,SHAPMM
 9013   FORMAT('ALOCMM,SCALMM,SHAPMM = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GAMMO1
      SUBROUTINE GAMPDF(X,GAMMA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GAMMA
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE GAMMA DISTRIBUTION USED
!              HEREIN HAS MEAN = GAMMA
!              AND STANDARD DEVIATION = SQRT(GAMMA).
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/CONSTANT) * (X**(GAMMA-1)) * EXP(-X)
!              WHERE THE CONSTANT = THE GAMMA FUNCTION EVALUATED
!              AT THE VALUE GAMMA.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--WILK, GNANADESIKAN, AND HUYETT, 'PROBABILITY
!                 PLOTS FOR THE GAMMA DISTRIBUTION',
!                 TECHNOMETRICS, 1962, PAGES 1-15,
!                 ESPECIALLY PAGES 3-5.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 257, FORMULA 6.1.41.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 166-206.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 68-73.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--SEPTEMBER 1994.
!     UPDATED         --JANUARY   1996.  HANDLE X=0 AS SPECIAL CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
!CCCC JANUARY 1996.  ADD FOLLOWING LINE.
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX,DGAMMA,DLNGAM,DPDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO GAMPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GAMPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DGAMMA=DBLE(GAMMA)
!
!CCCC JANUARY 1996.  TRREAT X = 0 AS SPECIAL CASE.
      IF(ABS(DX).LE.D1MACH(1))THEN
        IF(DGAMMA.EQ.1.0D0)THEN
          PDF=1.0
          GO TO 9999
        ELSEIF(DGAMMA.LT.1.0D0)THEN
          DX=1.0D-10
        ELSE
          DX=D1MACH(1)
        ENDIF
      ENDIF
!
!     COMPUTE THE GAMMA FUNCTION USING THE ALGORITHM IN THE
!     NBS APPLIED MATHEMATICS SERIES REFERENCE.
!
      DTERM1=(DGAMMA-1.0D0)*DLOG(DX)
      DTERM2=-DX
      DTERM3=DLOG(1.0D0)
      DTERM4=DLNGAM(DGAMMA)
      DTERM5=DTERM1+DTERM2-DTERM3-DTERM4
      IF(DTERM5.LT.-80.D0)THEN
        PDF=0.0
      ELSEIF(DTERM5.GT.65.D0)THEN
        WRITE(ICOUT,105)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PDF=EXP(65.0)
      ELSE
        DPDF=DEXP(DTERM5)
        PDF=REAL(DPDF)
      ENDIF
  105 FORMAT('****** WARNING--OVERFLOW IN GAMPDF ROUTINE.  PDF VALUE ',   &
      'SET TO EXP(65)')
!CCCC   WRITE(ICOUT,25)
!CCCC   CALL DPWRST('XXX','BUG ')
!
!CC25 FORMAT('***** WARNING--UNDERFLOW IN CALCULATION OF GAMMA PDF.',
!CCCC1       '  PDF SET TO ZERO. *****')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GAMPDF
      SUBROUTINE GAMPPF(P,GAMMA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GAMMA DISTRIBUTION
!              WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE GAMMA DISTRIBUTION USED
!              HEREIN HAS MEAN = GAMMA
!              AND STANDARD DEVIATION = SQRT(GAMMA).
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/CONSTANT) * (X**(GAMMA-1)) * EXP(-X)
!              WHERE THE CONSTANT = THE GAMMA FUNCTION EVALUATED
!              AT THE VALUE GAMMA.
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE GAMMA DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ACCURACY--(ON THE UNIVAC 1108, EXEC 8 SYSTEM AT NBS)
!               COMPARED TO THE KNOWN GAMMA = 1 (EXPONENTIAL)
!               RESULTS, AGREEMENT WAS HAD OUT TO 6 SIGNIFICANT
!               DIGITS FOR ALL TESTED P IN THE RANGE P = .001 TO
!               P = .999.  FOR P = .95 AND SMALLER, THE AGREEMENT
!               WAS EVEN BETTER--7 SIGNIFICANT DIGITS.
!               (NOTE THAT THE TABULATED VALUES GIVEN IN THE WILK,
!               GNANADESIKAN, AND HUYETT REFERENCE BELOW, PAGE 20,
!               ARE IN ERROR FOR AT LEAST THE GAMMA = 1 CASE--
!               THE WORST DETECTED ERROR WAS AGREEMENT TO ONLY 3
!               SIGNIFICANT DIGITS (IN THEIR 8 SIGNIFICANT DIGIT TABLE)
!               FOR P = .999.)
!     REFERENCES--WILK, GNANADESIKAN, AND HUYETT, 'PROBABILITY
!                 PLOTS FOR THE GAMMA DISTRIBUTION',
!                 TECHNOMETRICS, 1962, PAGES 1-15,
!                 ESPECIALLY PAGES 3-5.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 257, FORMULA 6.1.41.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 166-206.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 68-73.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1974.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JUNE      1987.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP,DGAMMA
!CCCC DOUBLE PRECISION Z,Z2,Z3,Z4,Z5,DEN,A,B,C,D,G
      DOUBLE PRECISION Z,Z2,DEN,A,B,C,D
      DOUBLE PRECISION XMIN0,XMIN,AI,XMAX,DX,PCALC,XMID
      DOUBLE PRECISION XLOWER,XUPPER,XDEL
      DOUBLE PRECISION SUM,TERM,CUT1,CUT2,AJ,CUTOFF,T
      DOUBLE PRECISION DLG,DLT,DLX,DLPCAL
      DOUBLE PRECISION DLP,DLGAMM,DLXMI0
      DOUBLE PRECISION Z2INV
      DOUBLE PRECISION DEXP,DLOG
!
      DIMENSION D(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA C/ .918938533204672741D0/
      DATA D(1),D(2),D(3),D(4),D(5)   &
           /+.833333333333333333D-1,-.277777777777777778D-2,   &
            +.793650793650793651D-3,-.595238095238095238D-3,   &
            +.841750841750841751D-3/
      DATA D(6),D(7),D(8),D(9),D(10)   &
           /-.191752691752691753D-2,+.641025641025641025D-2,   &
            -.295506535947712418D-1,+.179644372368830573D0,   &
            -.139243221690590111D1/
!
!-----START POINT-----------------------------------------------------
!
      XMID=0.0
      XLOWER=0.0
      XUPPER=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GAMPPF IS OUTSIDE ',   &
               'THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GAMMPPF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DP=P
      DGAMMA=GAMMA
      MAXIT=10000
!
!     COMPUTE THE GAMMA FUNCTION USING THE ALGORITHM IN THE
!     NBS APPLIED MATHEMATICS SERIES REFERENCE.
!     THIS GAMMA FUNCTION NEED BE CALCULATED ONLY ONCE.
!     IT IS USED IN THE CALCULATION OF THE CDF BASED ON
!     THE TENTATIVE VALUE OF THE PPF IN THE ITERATION.
!
      Z=DGAMMA
      DEN=1.0D0
  150 IF(Z.GE.10.0D0)GO TO 160
      DEN=DEN*Z
      Z=Z+1.0D0
      GO TO 150
  160 Z2=Z*Z
!CCCC Z3=Z*Z2
!CCCC Z4=Z2*Z2
!CCCC Z5=Z2*Z3
      A=(Z-0.5D0)*DLOG(Z)-Z+C
!CCCC B=D(1)/Z+D(2)/Z3+D(3)/Z5+D(4)/(Z2*Z5)+D(5)/(Z4*Z5)+
!CCCC1D(6)/(Z*Z5*Z5)+D(7)/(Z3*Z5*Z5)+D(8)/(Z5*Z5*Z5)+D(9)/(Z2*Z5*Z5*Z5)
      Z2INV=1.0D0/Z2
      B=D(9)
      B=Z2INV*B+D(8)
      B=Z2INV*B+D(7)
      B=Z2INV*B+D(6)
      B=Z2INV*B+D(5)
      B=Z2INV*B+D(4)
      B=Z2INV*B+D(3)
      B=Z2INV*B+D(2)
      B=Z2INV*B+D(1)
      B=(1.0D0/Z)*B
!CCCC G=DEXP(A+B)/DEN
      DLG=(A+B)-DLOG(DEN)
!CCCC WRITE(ICOUT,277)Z,B,DEN,DLG
!C277 FORMAT('Z,B,DEN,DLG = ',4E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
!
!     DETERMINE LOWER AND UPPER LIMITS ON THE DESIRED 100P
!     PERCENT POINT.
!
      ILOOP=1
!CCCC WRITE(ICOUT,377)DP,DGAMMA
!C377 FORMAT('DP,DGAMMA = ',2D15.7)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC XMIN0=(DP*DGAMMA*G)**(1.0D0/DGAMMA)
      DLP=DLOG(DP)
      DLGAMM=DLOG(DGAMMA)
      DLXMI0=(1.0D0/DGAMMA)*(DLP+DLGAMM+DLG)
      XMIN0=DEXP(DLXMI0)
!CCCC WRITE(ICOUT,378)XMIN0
!C378 FORMAT('XMIN0 = ',E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      XMIN=XMIN0
      ICOUNT=1
  350 AI=ICOUNT
      XMAX=AI*XMIN0
      DX=XMAX
      GO TO 1000
  360 IF(PCALC.GE.DP)GO TO 370
      XMIN=XMAX
      ICOUNT=ICOUNT+1
      IF(ICOUNT.LE.30000)GO TO 350
  370 XMID=(XMIN+XMAX)/2.0D0
!
!     NOW ITERATE BY BISECTION UNTIL THE DESIRED ACCURACY IS ACHIEVED.
!
      ILOOP=2
      XLOWER=XMIN
      XUPPER=XMAX
      ICOUNT=0
  550 DX=XMID
      GO TO 1000
  560 IF(PCALC.EQ.DP)GO TO 570
      IF(PCALC.GT.DP)GO TO 580
      XLOWER=XMID
      XMID=(XMID+XUPPER)/2.0D0
      GO TO 590
  580 XUPPER=XMID
      XMID=(XMID+XLOWER)/2.0D0
  590 XDEL=XMID-XLOWER
      IF(XDEL.LT.0.0D0)XDEL=-XDEL
      ICOUNT=ICOUNT+1
      IF(XDEL.LT.0.0000000001D0.OR.ICOUNT.GT.100)GO TO 570
      GO TO 550
  570 PPF=XMID
      GO TO 9000
!
!********************************************************************
!     THIS SECTION BELOW IS LOGICALLY SEPARATE FROM THE ABOVE.
!     THIS SECTION COMPUTES A CDF VALUE FOR ANY GIVEN TENTATIVE
!     PERCENT POINT X VALUE AS DEFINED IN EITHER OF THE 2
!     ITERATION LOOPS IN THE ABOVE CODE.
!
!     COMPUTE T-SUB-Q AS DEFINED ON PAGE 4 OF THE WILK, GNANADESIKAN,
!     AND HUYETT REFERENCE
!
 1000 SUM=1.0D0/DGAMMA
      TERM=1.0D0/DGAMMA
      CUT1=DX-DGAMMA
      CUT2=DX*10000000000.0D0
      DO 700 J=1,MAXIT
      AJ=J
      TERM=DX*TERM/(DGAMMA+AJ)
      SUM=SUM+TERM
      CUTOFF=CUT1+(CUT2*TERM/SUM)
      IF(AJ.GT.CUTOFF)GO TO 750
  700 CONTINUE
      WRITE(ICOUT,705)MAXIT
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,706)P
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,707)GAMMA
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,708)
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      GO TO 9000
!
  750 T=SUM
!CCCC WRITE(ICOUT,777)T,DX
!C777 FORMAT('T,DX = ',2E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      DLT=DLOG(T)
      DLX=DLOG(DX)
!CCCC WRITE(ICOUT,778)DX,DGAMMA,T,DLT,G,DLG
!C778 FORMAT('DX,DGAMMA,T,DLT,G,DLG = ',6D15.7)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC PCALC=(DX**DGAMMA)*(DEXP(-DX))*T/G
      DLPCAL=DGAMMA*DLX-DX+DLT-DLG
      PCALC=DEXP(DLPCAL)
      IF(ILOOP.EQ.1)GO TO 360
      GO TO 560
!
  705 FORMAT('*****ERROR IN INTERNAL OPERATIONS IN THE GAMPPF ',   &
      'SUBROUTINE--THE NUMBER OF ITERATIONS EXCEEDS ',I7)
  706 FORMAT(33H     THE INPUT VALUE OF P     IS ,E15.8)
  707 FORMAT(33H     THE INPUT VALUE OF GAMMA IS ,E15.8)
  708 FORMAT(48H     THE OUTPUT VALUE OF PPF HAS BEEN SET TO 0.0)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GAMPPF
      SUBROUTINE GAMRAN(N,GAMMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GAMMA DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!              THE PROTOTYPE GAMMA DISTRIBUTION USED
!              HEREIN HAS MEAN = GAMMA
!              AND STANDARD DEVIATION = SQRT(GAMMA).
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/CONSTANT) * (X**(GAMMA-1)) * EXP(-X)
!              WHERE THE CONSTANT = THE GAMMA FUNCTION EVALUATED
!              AT THE VALUE GAMMA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                                GAMMA SHOULD BE LARGER
!                                THAN 1/3 (ALGORITHMIC RESTRICTION).
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GAMMA DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!                 --GAMMA SHOULD BE LARGER
!                   THAN 1/3 (ALGORITHMIC RESTRICTION).
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, NORRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT, EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--GREENWOOD, 'A FAST GENERATOR FOR
!                 GAMMA-DISTRIBUTED RANDOM VARIABLES',
!                 COMPSTAT 1974, PROCEEDINGS IN
!                 COMPUTATIONAL STATISTICS, VIENNA,
!                 SEPTEMBER, 1974, PAGES 19-27.
!               --TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 24-27.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGES 36-37.
!               --WILK, GNANADESIKAN, AND HUYETT, 'PROBABILITY
!                 PLOTS FOR THE GAMMA DISTRIBUTION',
!                 TECHNOMETRICS, 1962, PAGES 1-15.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 166-206.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 68-73.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 952.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --FEBRUARY  1976.
!     UPDATED         --JUNE      1978.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       2003. REPLACE WITH CALL TO
!                                       AHRENS-DIETER CODE
!     UPDATED  VERSION--JANUARY   2005. BUG IF ROUTINE CALLED MORE
!                                       THAN ONCE, RESET AA AND AAA
!                                       AND STORE IN COMMON
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!CCCC DIMENSION XN(2)
!CCCC DIMENSION U(2)
!
      COMMON/SGAMM/AA,AAA,S2,S,D,Q0,B,SI,C
      REAL SGAMMA
      EXTERNAL SGAMMA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!CCCC DATA ATHIRD/0.3333333/
!CCCC DATA SQRT3 /1.73205081/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GAMRAN IS ',   &
               'NON-POSITIVE *****')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GAMRAN IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
!CCCC ELSEIF(GAMMA.LE.0.33333333)THEN
!CCCC   WRITE(ICOUT,16)
!CC16   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GAMRAN ',
!CCCC1         'IS SMALLER THAN OR EQUAL TO 0.3333333')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,17)
!CC17   FORMAT('      (ALGORITHMIC RESTIRCTION)')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)GAMMA
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9000
      ENDIF
!
!     GENERATE N GAMMA DISTRIBUTION RANDOM NUMBERS
!     USING GREENWOOD'S REJECTION ALGORITHM--
!     1) GENERATE A NORMAL RANDOM NUMBER;
!     2) TRANSFORM THE NORMAL VARIATE TO AN APPROXIMATE
!        GAMMA VARIATE USING THE WILSON-HILFERTY
!        APPROXIMATION (SEE THE JOHNSON AND KOTZ
!        REFERENCE, PAGE 176);
!     3) FORM THE REJECTION FUNCTION VALUE, BASED
!        ON THE PROBABILITY DENSITY FUNCTION VALUE
!        OF THE ACTUAL DISTRIBUTION OF THE PSEUDO-GAMMA
!        VARIATE, AND THE PROBABILITY DENSITY FUNCTION VALUE
!        OF A TRUE GAMMA VARIATE.
!     4) GENERATE A UNIFORM RANDOM NUMBER;
!     5) IF THE UNIFORM RANDOM NUMBER IS LESS THAN
!        THE REJECTION FUNCTION VALUE, THEN ACCEPT
!        THE PSEUDO-RANDOM NUMBER AS A GAMMA VARIATE;
!        IF THE UNIFORM RANDOM NUMBER IS LARGER THAN
!        THE REJECTION FUNCTION VALUE, THEN REJECT
!        THE PSEUDO-RANDOM NUMBER AS A GAMMA VARIATE.
!
!  MAY 2003: THIS ALGORITHM DOESN'T WORK FOR GAMMA < 1/3.
!            REPLACE WITH THE POPULAR AHRENS-DIETER CODE FOR
!            GAMMA RANDOM NUMBERS.
!
!CCCC A1=1.0/(9.0*GAMMA)
!CCCC B1=SQRT(A1)
!CCCC XN0=-SQRT3+B1
!CCCC XG0=GAMMA*(1.0-A1+B1*XN0)**3
!CCCC DO100I=1,N
!C150 CALL NORRAN(1,ISEED,XN)
!CCCC XG=GAMMA*(1.0-A1+B1*XN(1))**3
!CCCC IF(XG.LT.0.0)GO TO 150
!CCCC TERM=(XG/XG0)**(GAMMA-ATHIRD)
!CCCC ARG=0.5*XN(1)*XN(1)-XG-0.5*XN0*XN0+XG0
!CCCC FUNCT=TERM*EXP(ARG)
!CCCC CALL UNIRAN(1,ISEED,U)
!CCCC IF(U(1).LE.FUNCT)GO TO 170
!CCCC GO TO 150
!C170 X(I)=XG
!C100 CONTINUE
!
      AA=0.0
      AAA=0.0
      DO 100 I=1,N
        ATEMP=SGAMMA(ISEED,GAMMA)
        X(I)=ATEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GAMRAN
      SUBROUTINE GATHER(N,A,B,IINDEX,MAXOBV,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COLLECTS ELEMENTS FROM ARRAY B
!              BASED ON THE INDEX ELEMENTS IN ARRAY INDEX AND
!              STORES THEM CONTIGUOUSLY IN ARRAY A.
!     INPUT  ARGUMENTS--IINDEX = THE INTEGER VECTOR THAT SPECIFIES
!                                THE ELEMENTS OF B THAT WILL BE
!                                EXTRACTED.
!                       B      = A SINGLE PRECISION VECTOR FROM WHIC
!                                DATA VALUES WILL BE EXTRACTED.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                TO BE EXTRACTED.
!     OUTPUT ARGUMENTS--A      = THE OUTPUT ARRAY THAT WILL CONTAIN
!                                N ELEMENTS.
!     OUTPUT--THE COMPUTED SINGLE PRECISION ARRAY A.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.11
!     ORIGINAL VERSION--NOVEMBER  2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      INTEGER N
      INTEGER IINDEX(*)
      REAL A(*)
      REAL B(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'THER')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF GATHER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GT.0)THEN
          DO 55 I=1,N
            WRITE(ICOUT,56)I,IINDEX(I),B(I)
   56       FORMAT('I,IINDX(I),B(I) = ',I8,2X,I8,G15.7)
            CALL DPWRST('XXX','BUG ')
   55     CONTINUE
        ENDIF
      ENDIF
!
      DO 1010 I = 1,N
         ITEMP=IINDEX(I)
         IF(ITEMP.GE.1 .AND. ITEMP.LE.MAXOBV)THEN
           A(I) = B(ITEMP)
         ELSE
           WRITE(ICOUT,1011)
 1011      FORMAT('***** ERROR IN GATHER OPERATION--')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1013)I
 1013      FORMAT('      FOR ROW ',I8,' THE INDEX VALUE IS OUTSIDE THE')
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,1015)MAXOBV
 1015      FORMAT('      THE INTERVAL (1,',I10,').')
           CALL DPWRST('XXX','BUG ')
           IERROR='YES'
           GO TO 9000
         ENDIF
 1010 CONTINUE
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'THER')THEN
        WRITE(ICOUT,9051)
 9051   FORMAT('***** AT THE BEGINNING OF GATHER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9053)N
 9053   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GT.0)THEN
          DO 9055 I=1,N
            WRITE(ICOUT,9056)I,A(I)
 9056       FORMAT('I,A(I) = ',I8,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
 9055     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE GATHER
      SUBROUTINE GC1FUN (NPAR, XPAR, FVEC, IFLAG, ZDATA, M)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GAMMA MAXIMUM LIKELIHOOD EQUATIONS FOR THE CENSORING
!              CASE (FROM PP. 217-218 OF BURY).
!
!      R*XBAR/SHAT - R*GHAT + SUM[i=1 to M]
!        [Z(j)**GHAT*EXP(Z(j)/(GAMMA(GHAT) - G(Z(j),GHAT))] = 0
!
!      R*LOG(GEOMEAN/SHAT)  - N*DIGAMMA(GHAT) + SUM[i=1 to M]
!        [(GAMMA(GHAT)*DIGAMMA(GHAT) J(Z(j),GHAT))/
!        (GAMMA(GHAT) - G(Z(j),GHAT))] = 0
!
!      WHERE
!
!
!         XBAR = MEAN OF FAILURE DATA
!         GEOMEAN  = GEOMETRIC MEAN OF FAILURE DATA
!         R        = NUMBER OF FAILURES
!         M        = NUMBER OF CENSORING TIMES
!         SHAT     = FVEC(1) = CURRENT ESTIMATE OF SCALE PARAMETER
!         GHAT     = FVEC(2) = CURRENT ESTIMATE OF SHAPE PARAMETER
!         Z(j)     = jth CENSORING TIME
!         GAMMA    = GAMMA FUNCTION
!         DIGAMMA  = DIGAMMA FUNCTION
!         G(x,a)   = INCOMPLETE GAMMA FUNCTION
!         J(X,a)   = INTEGRAL[0 to x][t**(A-1)*LOG(t)*EXP(-t)]dt
!
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--GAMMA MAXIMUM LIKELIHOOD Y X
!     REFERENCE--KARL BURY, (1999). "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                PP. 217-218.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 CENTER FOR APPLIED MATHEMATICS
!                 NATIONAL BUREAU OF STANDARDS
!                 WASHINGTON, D. C. 20234
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER  2004.
!
!---------------------------------------------------------------------
!
      INTEGER M
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL ZDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DX
      DOUBLE PRECISION GHAT
      DOUBLE PRECISION SHAT
      DOUBLE PRECISION DGI
      DOUBLE PRECISION DP
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTERM6
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=200)
      PARAMETER(LENW=4*LIMIT)
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DLOW
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION GEOMEA
      INTEGER N
      INTEGER R
      COMMON/GC1COM/XBAR,GEOMEA,N,R
!
      DOUBLE PRECISION DA
      COMMON/J1COM/DA
!
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DGAMI
      DOUBLE PRECISION DPSI
      DOUBLE PRECISION J1FUN
      EXTERNAL DGAMMA
      EXTERNAL DGAMI
      EXTERNAL DPSI
      EXTERNAL J1FUN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      NPAR=2
      IFLAG=0
!
      DN=DBLE(N)
      DR=DBLE(R)
      GHAT=XPAR(1)
      SHAT=XPAR(2)
      DG=DGAMMA(GHAT)
      DP=DPSI(GHAT)
      DA=GHAT
!
      DTERM1=DR*XBAR/SHAT - DR*GHAT
      DTERM2=DR*DLOG(GEOMEA/SHAT) - DN*DP
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      EPSABS=1.0D-7
      EPSREL=1.0D-7
      IER=0
      IKEY=3
      DLOW=0.0D0
!
      IF(M.GT.0)THEN
        DO 100 I=1,M
          DX=DBLE(ZDATA(I))/SHAT
          DGI=DGAMI(GHAT,DX)
          DTERM3=DX**GHAT*DEXP(-DX)
          DTERM6=0.0D0
          CALL DQAG(J1FUN,DLOW,DX,EPSABS,EPSREL,IKEY,DTERM6,   &
                    ABSERR,NEVAL,   &
                    IER,LIMIT,LENW,LAST,IWORK,WORK)
          DTERM4=DG*DP - DTERM6
          DTERM5=DG - DGI
          DSUM1=DSUM1 + DTERM3/DTERM5
          DSUM2=DSUM2 + DTERM4/DTERM5
  100   CONTINUE
      ENDIF
!
      FVEC(1) = DTERM1 + DSUM1
      FVEC(2) = DTERM2 + DSUM2
!
      RETURN
      END SUBROUTINE GC1FUN 
      subroutine gci1(ngrp, ni, xi, obsi, conf, nrun, mean,   &
                      llmt, ulmt,segci,   &
                      esi, thold, emu,   &
                      ierror)
!
!     Note: This routine performs a consensus means analysis
!           based on generalized confidence interval approach.
!           This is documented in:
!
!           Hari K. Iyer, C. M. Wang, and Thomas Matthew,
!           "Models and Confidence Intervals for True Values
!           in Interlaboratory Trials", Journal of the
!           American Statistical Association, Volume 99,
!           No. 468, pp. 1060-1071.
!
!           Modified for Dataplot 3/2006.
!
!           1) I/O modified to use DPWRST
!           2) Compute standard deviation of EMU as estimate of
!              standard error
!           3) Pass THOLD, EMU, ESI as arguments
!
!           Modified for Dataplot 4/2021.
!
!           1) Allow maximum of 1,000 labs
!
      implicit none
!
!  parameters:
!
!    input:
!     ngrp - number of groups (labs)
!     ni   - vector of size ngrp containing the sample size of each lab
!     xi   - vector of size ngrp containing the mean of each lab
!     obsi - vector of size ngrp containing the variance of each lab
!     conf - nominal confidence coefficient, e.g., 0.95
!     nrun - number of Monte Carlo samples to be used, e.g., 10000
!
!    output:
!     mean - mean of the simulated distribution of the GPQ
!     llmt - lower confidence limit
!     ulmt - upper confidence limit
!
      integer ngrp, nrun, ni(ngrp)
      integer njunk
      double precision  obsi(ngrp), xi(ngrp)
      double precision conf, mean, llmt, ulmt
!
      integer iseed
      double precision thold(ngrp)
      real    atemp
      real    atemp2(1)
      double precision esi(ngrp)
      double precision xbar, esa, emu(nrun), sesi, zval
      double precision lbd, ubd, errabs, tmp, segci
!
      double precision zeroin
!
      integer kk
!cccc double precision aa, ybar, cc, bb(100), yy(100)
      double precision aa, ybar, cc, bb(1000), yy(1000)
      common /cmn1/ kk
      common /cmn2/ aa, ybar, cc, bb, yy
!
      integer j, m, ilb, iub
!
      external ff
      double precision  ff
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
      iseed = 1234579
      esa=0.0d0
!
      ilb = int(real(nrun) * ((1.0d0 - conf)/2.0)) + 1
      iub = int(real(nrun) * ((1.0d0 + conf)/2.0))
!
      kk = ngrp
      errabs = 0.001d0
!
      ybar = 0.0
      do 10 m = 1, ngrp
         yy(m) = xi(m)
         ybar = ybar + xi(m)
   10 continue
      ybar = ybar/real(ngrp)
!
!  for each set of observed \bar{x}_i and S_i^2
!
      mean = 0.0d0
!
      do 20 j = 1, nrun
!
!  generate chi-square deviates to calculate
!  esi(*) = \hat{\sigma}_i^2 = (n_i - 1)*S_i^2/\chi^2
!
         njunk=1
         do 30 m = 1, ngrp
            atemp = real(abs(ni(m)) - 1)
            call chsran(njunk, atemp, iseed, atemp2)
            thold(m)=atemp2(1)
            esi(m) = (abs(ni(m)) - 1) * obsi(m)/thold(m)
            bb(m) = esi(m)/abs(ni(m))
   30    continue
         atemp = real(ngrp - 1)
         call chsran(njunk, atemp, iseed, atemp2)
         thold(1)=atemp2(1)
         cc = thold(1)
!
!  calculate the max of quadratic form, if it is less than cc
!  set esa to zero, else call zeroin (bi-section method) to
!  find the solution of esa = \sigma_a^2
!
         call maxofq
!
         ubd = 99999.9d0
         if (cc .ge. aa) then
            esa = 0.0d0
         else
            if (ff(ubd) .lt. 0.0d0) then
               lbd = 0.0d0
               ierror='NO'
               esa = zeroin(lbd, ubd, ff, errabs,ierror)
               if(ierror.eq.'YES')GO TO 9000
            end if
         end if
!
!  form emu(*) = \hat{\mu}
!
         call norran(1, iseed, atemp2)
         thold(1)=atemp2(1)
         zval = thold(1)
         xbar = 0.0d0
         sesi = 0.0d0
         do 40 m = 1, ngrp
            tmp = esa + bb(m)
            sesi = sesi + 1.0d0/tmp
            xbar = xbar + xi(m)/tmp
   40    continue
         xbar = xbar/sesi
         emu(j) = xbar - zval/sqrt(sesi)
!
         mean = mean + emu(j)
!
   20 continue
!
      mean = mean/real(nrun)
!
!  sort emu(*) to find appropriate percentiles as
!  the confidence limits
!
      call ssort(emu, emu, nrun, 1)
      llmt = emu(ilb)
      ulmt = emu(iub)
      iwrite='OFF'
      ibuga3='OFF'
      call sddp(emu,nrun,iwrite,segci,ibuga3,ierror)
!
 9000 continue
      return
      end
      SUBROUTINE GCHAR(CHR,X,Y,SZ,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--XX
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!
!---------------------------------------------------------------------
!
      CHARACTER CHR(15)*1
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'CHAR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1011)CHR,X,Y,SZ
 1011   FORMAT('FROM GCHAR--CHR,X,Y,SZ = ',4F10.5)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IERROR='NO'
!
      RETURN
      END SUBROUTINE GCHAR
      SUBROUTINE GDER(MEW, THETA, RL, MRL, LM, IDER, RD, PD)
!
!        ALGORITHM AS 189.4 APPL. STATIST. (1983) VOL.32, NO.2
!
!        GENERAL DERIVATIVE SUBROUTINE
!
      DOUBLE PRECISION MEW, THETA, PD(IDER), A, B, C, D
      INTEGER RL(MRL,3), LM(3), RD(2,IDER)
!
      MLM = LM(3)
      KK = IDER-1
      DO 5 I = 1,IDER
        PD(I) = 0.0D0
    5 CONTINUE
      DO 45 I = 1,MLM
        C = DBLE(I-1)
        A = C*THETA
        DO 40 J = 1,3
          IF(I.GT.LM(J)) GO TO  40
          GO TO  (10,15,20) J
   10     D = MEW+A
          GO TO  25
   15     D = 1.0D0-MEW+A
          GO TO  25
   20     D = 1.0D0+A
   25     B = DBLE(RL(I,J))/D**KK
          IF(J.EQ.3) GO TO  35
          DO 30 K = 1,IDER
            PD(K) = PD(K)+DBLE(RD(J,K))*B
            B = B*C
   30     CONTINUE
          GO TO  40
   35     D = -DBLE(RD(1,1))*B*C**KK
          PD(IDER) = PD(IDER)+D
   40   CONTINUE
   45 CONTINUE
      RETURN
      END SUBROUTINE GDER
      SUBROUTINE GEECDF(X,GAMMA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GEOMETRIC EXTREME EXPONENTIAL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE GEOMETRIC EXTREME EXPONENTIAL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X >= 0
!              AND HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!              F(X) = 1 - GAMMA/[EXP(X) + GAMMA - 1]      GAMMA > 0
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GEOMETRIC EXTREME
!             EXPONENTIAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"CAN DATA RECOGNOZE ITS PARENT DISTRIBUTION?",
!                 MARSHALL, MEZA, OLKIN, JOURNAL OF COMPUTATIONAL
!                 AND GRAPHICAL STATISTICS, SEPTEMBER, 2001,
!                 PP. 555-580.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.11
!     ORIGINAL VERSION--NOVEMBER  2001.
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(X.LT.0.0)THEN
!CCCC   WRITE(ICOUT,5)
!CCC5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEECDF IS NEGATIVE.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)X
!CCCC   CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEECDF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DGAMMA=DBLE(GAMMA)
      DX=DBLE(X)
      DCDF=1.0D0 - DGAMMA/(EXP(DX) + DGAMMA - 1.0D0)
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEECDF
      SUBROUTINE GEECHA(X,GAMMA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE GEOMETRIC EXTREME EXPONENTIAL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE GEOMETRIC EXTREME EXPONENTIAL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X >= 0
!              AND HAS THE CUMULATIVE HAZARD FUNCTION
!              H(X) = -LOG(1-GEECDF(X)),    GAMMA > 0
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE PDF FOR THE GEOMETRIC EXTREME
!             EXPONENTIAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"CAN DATA RECOGNOZE ITS PARENT DISTRIBUTION?",
!                 MARSHALL, MEZA, OLKIN, JOURNAL OF COMPUTATIONAL
!                 AND GRAPHICAL STATISTICS, SEPTEMBER, 2001,
!                 PP. 555-580.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.11
!     ORIGINAL VERSION--NOVEMBER  2001.
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DHAZ
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEECHA IS NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEECHA IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9000
      ENDIF
!
      DGAMMA=DBLE(GAMMA)
      DX=DBLE(X)
      DCDF=DGAMMA/(EXP(DX) + DGAMMA - 1.0D0)
      DHAZ=-LOG(DCDF)
      HAZ=REAL(DHAZ)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEECHA
      SUBROUTINE GEEFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GENERALIZED EXTREME EXPONENTIAL MAXIMUM LIKELIHOOD
!              EQUATIONS.
!
!              N/G - 2*SUM[i=1 to N][EXP(-L*X(i)/(1-(1-G)*EXP(-L*X(i)))]
!
!              N/L - SUM[i=1 to n][X(i)] -
!                    2*SUM[i=1 to N][(1-G)*X(i)*EXP(-L*X(i))/
!                    (1 - (1-G)*EXP(-L*X(i)))]
!
!              WITH G AND L DENOTING THE SHAPE PARAMETER GAMMA AND
!              SCALE PARAMETER LAMBDA RESPECTIVELY.  NOTE THAT L
!              IS ACTUALLY (1/SCALE).
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--GENERALIZED EXTREME EXPONENTIAL MAXIMUM LIKELIHOOD Y
!     REFERENCE--"CAN DATA RECOGNIZE ITS PARENT DISTRIBUTION?",
!                MARSHALL, MEZA, AND OLKIN, JOURNAL OF COMPUTATIONAL
!                AND GRAPHICAL STATISTICS, SEPTEMBER, 2001,
!                PP. 555-580.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/3
!     ORIGINAL VERSION--MARCH     2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DGC
      DOUBLE PRECISION DL
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DG=X(1)
      DGC=1.0D0-DG
      DL=X(2)
      DN=DBLE(NOBS)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
!
      DO 200 I=1,NOBS
        DX=DBLE(XDATA(I))
        DTERM1=DEXP(-DL*DX)
        DTERM2=1.0D0 - DGC*DEXP(-DL*DX)
        DSUM1=DSUM1 + DTERM1/DTERM2
        DTERM1=DGC*DX*DEXP(-DL*DX)
        DTERM2=1.0D0 - DGC*DEXP(-DL*DX)
        DSUM2=DSUM2 + DTERM1/DTERM2
        DSUM3=DSUM3 + DX
  200 CONTINUE
!
      FVEC(1)=(DN/DG) - 2.0D0*DSUM1
      FVEC(2)=(DN/DL) - DSUM3 - 2.0D0*DSUM2
!
      RETURN
      END SUBROUTINE GEEFUN 
      SUBROUTINE GEEML1(Y,N,MAXNXT,   &
                        TEMP1,TEMP2,DISPAR,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        SCALSV,SHAPSV,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER GEOMETRIC EXTREME EXPONENTIAL
!              DISTRIBUTION FOR THE RAW DATA CASE (I.E., NO CENSORING
!              AND NO GROUPING).  THIS ROUTINE RETURNS ONLY THE POINT
!              ESTIMATES (CONFIDENCE INTERVALS WILL BE COMPUTED IN A
!              SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLGX WILL GENERATE THE OUTPUT
!              FOR THE GEOMETRIC EXTREME EXPONENTIAL MLE COMMAND).
!
!              THE MLE ESTIMATES ARE THE SOLUTION TO THE FOLLOWING
!              TWO SIMULTANEOUS NON-LINEAR EQUATIONS:
!
!              N/G - 2*SUM[i=1 to N][EXP(-L*X(i)/(1-(1-G)*EXP(-L*X(i)))]
!
!              N/L - SUM[i=1 to n][X(i)] -
!                    2*SUM[i=1 to N][(1-G)*X(i)*EXP(-L*X(i))/
!                    (1 - (1-G)*EXP(-L*X(i)))]
!
!              WITH G AND L DENOTING THE SHAPE PARAMETER GAMMA AND
!              SCALE PARAMETER LAMBDA RESPECTIVELY.  NOTE THAT L
!              IS ACTUALLY (1/SCALE).
!
!     REFERENCE--"CAN DATA RECOGNIZE ITS PARENT DISTRIBUTION?",
!                MARSHALL, MEZA, AND OLKIN, JOURNAL OF COMPUTATIONAL
!                AND GRAPHICAL STATISTICS, SEPTEMBER, 2001,
!                PP. 555-580.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/2
!     ORIGINAL VERSION--FEBRUARY  2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLE1)
!     UPDATED         --FEBRUARY  2010. LAMBDA IS ACTUALLY (1/SCALE)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION DISPAR(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
      DIMENSION DISPA2(1)
!
      INTEGER IPPCAP(2)
!
      EXTERNAL GEEFUN
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GEEM'
      ISUBN2='L1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'EML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GEEML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'EML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************************
!               **  STEP 2--                                       **
!               **  CARRY OUT CALCULATIONS                         **
!               **  FOR GEOMETRIC EXTREME EXPONENTIAL MLE ESTIMATE **
!               *****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'EML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GEOMETRIC EXTREME EXPONENTIAL'
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      SHAPML=CPUMIN
      SCALML=CPUMIN
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(SHAPSV.GT.0.0 .AND. SCALSV.GT.0.0)THEN
        XPAR(1)=DBLE(SHAPSV)
        XPAR(2)=DBLE(1.0/SCALSV)
      ELSE
!
!       IF NO STARTING VALUES SPECIFIED, COMPUTE STARTING
!       VALUES BASED ON PPCC METHOD.
!
        CALL UNIMED(N,TEMP1)
        CALL SORT(Y,N,Y)
        ICASP2='GEEX'
        ICASPL='PPCC'
        IPPCAP(1)=100
        IPPCAP(2)=1
!
!       OBTAIN LOWER/UPPER LIMITS FOR SHAPE PARAMETER
!
        CALL EXTPA2(ICASP2,IDIST,A,B,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    ISUBRO,IBUGA3,IERROR)
!
!       CREATE ARRAY FOR THE CANDIDATE VALUES OF SHAPE PARAMETER
!
        NUMSHA=1
        CALL DPPPC7(ICASPL,ICASP2,IPPCAP,   &
                    SHAP11,SHAP12,SHAP21,SHAP22,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                    XMIN,XMAX,A,B,   &
                    DISPAR,DISPA2,NUMDIS,NUMSHA,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,   &
                    ICONDF,IGOMDF,IKATDF,IGIGDF,IGEODF,   &
                    IBUGA3,ISUBRO,IERROR)
!
        CORRMX=-1.0
        IWRITE='OFF'
        DO 1010 IDIS=1,NUMDIS
          SHAPE=DISPAR(IDIS)
          DO 1020 I=1,N
            CALL GEEPPF(TEMP1(I),SHAPE,TEMP2(I))
 1020     CONTINUE
          CALL CORR(Y,TEMP2,N,IWRITE,CC,IBUGA3,IERROR)
          IF(CC.GT.CORRMX)THEN
            SHAPE1=SHAPE
            CALL LINFI2(Y,TEMP2,N,PPA0,PPA1,ISUBRO,IBUGA3,IERROR)
            CORRMX=CC
          ENDIF
 1010   CONTINUE
        XPAR(1)=DBLE(SHAPE1)
        XPAR(2)=DBLE(1.0/PPA1)
      ENDIF
!
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(GEEFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      SHAPML=REAL(XPAR(1))
      SCALML=1.0/REAL(XPAR(2))
      IF(SHAPML.LE.0.0)IERROR='YES'
      IF(SCALML.LE.0.0)IERROR='YES'
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'EML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GEEML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPSV,SCALSV,SHAPML,SCALML
 9017   FORMAT('SHAPSV,SCALSV,SHAPML,SCALML =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)XPAR(1),XPAR(2)
 9019   FORMAT('XPAR(1),XPAR(2) =  ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GEEML1
      SUBROUTINE GEEPDF(X,GAMMA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GEOMETRIC EXTREME EXPONENTIAL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE GEOMETRIC EXTREME EXPONENTIAL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X >= 0
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA*EXP(X)/[(EXP(X)+GAMMA-1)**2]  GAMMA > 0
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GEOMETRIC EXTREME
!             EXPONENTIAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"CAN DATA RECOGNOZE ITS PARENT DISTRIBUTION?",
!                 MARSHALL, MEZA, OLKIN, JOURNAL OF COMPUTATIONAL
!                 AND GRAPHICAL STATISTICS, SEPTEMBER, 2001,
!                 PP. 555-580.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.11
!     ORIGINAL VERSION--NOVEMBER  2001.
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** FATAL ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
               'GEEPDF SUBROUTINE IS NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
      IF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
               'GEEPDF SUBROUTINE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8)
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
      DGAMMA=DBLE(GAMMA)
      DX=DBLE(X)
      DPDF=LOG(DGAMMA) + DX - 2.0D0*LOG(EXP(DX)+DGAMMA-1.0D0)
      IF(DPDF.LT.-36.0D0)THEN
        PDF=0.0
      ELSEIF(DPDF.GT.36.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** FATAL ERROR--GEEPDF ROUTINE OVERFLOWS FOR')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,26)X,GAMMA
   26   FORMAT('      X = ',E15.7,'  GAMMA = ',E15.7)
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
      ELSE
        DPDF=EXP(DPDF)
        PDF=REAL(DPDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEEPDF
      SUBROUTINE GEEHAZ(X,GAMMA,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE GEOMETRIC EXTREME EXPONENTIAL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE GEOMETRIC EXTREME EXPONENTIAL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL X >= 0
!              AND HAS THE HAZARD FUNCTION
!              H(X) = GEEPDF(X)/(1-GEECDF(X)),    GAMMA > 0
!                   = EXP(X)/[EXP(X)+GAMMA-1)]    GAMMA > 0
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE PDF FOR THE GEOMETRIC EXTREME
!             EXPONENTIAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"CAN DATA RECOGNOZE ITS PARENT DISTRIBUTION?",
!                 MARSHALL, MEZA, OLKIN, JOURNAL OF COMPUTATIONAL
!                 AND GRAPHICAL STATISTICS, SEPTEMBER, 2001,
!                 PP. 555-580.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.11
!     ORIGINAL VERSION--NOVEMBER  2001.
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DHAZ
!
!-----COMMON---------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEEHAZ IS NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEEHAZ IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DGAMMA=DBLE(GAMMA)
      DX=DBLE(X)
      DTERM1=EXP(DX)
      DTERM2=DTERM1+DGAMMA-1.0D0
      IF(DTERM2.NE.0.0D0)THEN
        DHAZ=DTERM1/DTERM2
        HAZ=REAL(DHAZ)
      ELSE
        HAZ=0.0
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEEHAZ
      SUBROUTINE GEEPPF(P,GAMMA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GEOMETRIC EXTREME EXPONENTIAL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE GEOMETRIC EXTREME EXPONENTIAL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL 0 <= P < 1.
!              AND HAS THE PERCENT POINT FUNCTION
!              G(P) = LOG[GAMMA/(1-P) + 1 - GAMMA],    GAMMA > 0
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE GEOMETRIC EXTREME
!             EXPONENTIAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"CAN DATA RECOGNOZE ITS PARENT DISTRIBUTION?",
!                 MARSHALL, MEZA, OLKIN, JOURNAL OF COMPUTATIONAL
!                 AND GRAPHICAL STATISTICS, SEPTEMBER, 2001,
!                 PP. 555-580.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.11
!     ORIGINAL VERSION--NOVEMBER  2001.
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEEPPF IS OUTSIDE ',   &
               'THE ALLOWABLE (0,1] INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEEPPF IS ',   &
               'NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DGAMMA=DBLE(GAMMA)
      DP=DBLE(P)
      DPPF=LOG(DGAMMA/(1.0D0-DP) + 1.0D0 - DGAMMA)
      PPF=REAL(DPPF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEEPPF
      SUBROUTINE GEERAN(N,GAMMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GEOMETRIC EXTREME EXPONENTIAL DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GEOMETRIC EXTREME EXPONENTIAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"CAN DATA RECOGNOZE ITS PARENT DISTRIBUTION?",
!                 MARSHALL, MEZA, OLKIN, JOURNAL OF COMPUTATIONAL
!                 AND GRAPHICAL STATISTICS, SEPTEMBER, 2001,
!                 PP. 555-580.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.11
!     ORIGINAL VERSION--NOVEMBER  2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEERAN IS ',   &
             'NON-POSITIVE')
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEERAN IS ',   &
             'NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GEOMETRIC EXTREME EXPONENTIAL DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL GEEPPF(X(I),GAMMA,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEERAN
      SUBROUTINE GENARI(Y1,Y2,Y3,Y4,N1,N3,IACASE,IWRITE,   &
                        Y5,Y6,N5,N6,SCAL3,ITYP3,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CARRY OUT (DEX) GENERATOR ARITHMETIC OPERATIONS
!              OF THE REAL DATA IN Y1 AND Y3.
!
!     OPERATIONS--ADDITION
!                 SUBTRACTION
!                 MULTIPLICATION
!
!     INPUT  ARGUMENTS--Y1 (REAL PART)       Y2 (IMAGINARY PART)
!                     --Y3 (REAL PART)       Y4 (IMAGINARY PART)
!     OUTPUT ARGUMENTS--Y5 (REAL PART)       Y6 (IMAGINARY PART)
!
!     NOTE--IT IS NOT PERMISSIBLE TO HAVE THE OUTPUT VECTORS Y5(.) AND Y6(.)
!           BEING IDENTICAL TO THE INPUT VECTORS Y1(.) AND Y2(.), OR
!           Y3(.) AND Y4(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/12
!     ORIGINAL VERSION--DECEMBER  1989.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE
!                                       COMMON
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IACASE
      CHARACTER*4 IWRITE
      CHARACTER*4 ITYP3
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION Y4(*)
      DIMENSION Y5(*)
      DIMENSION Y6(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GENA'
      ISUBN2='RI  '
      IERROR='NO'
!
      SCAL3=(-999.0)
      ITYP3='VECT'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NARI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF GENARI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IACASE,IWRITE
   52   FORMAT('IBUGA3,ISUBRO,IACASE,IWRITE = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N1,N3
   53   FORMAT('N1,N3 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N3
          WRITE(ICOUT,66)I,Y3(I),Y4(I)
   66     FORMAT('I,Y3(I),Y4(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               **************************************************
!               **  CARRY OUT (DEX) GENERATOR ARITHMETIC OPERATIONS  **
!               **************************************************
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N1.LT.1)GO TO 1100
      IF(N3.LT.1)GO TO 1100
      GO TO 1190
!
 1100 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN GENERATOR ARITHMETIC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE VARIABLE ',   &
             'FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'GEAD')THEN
        WRITE(ICOUT,1161)
 1161   FORMAT('      THE (DEX) GENERATOR ADDITION IS TO BE COMPTED')
      ELSEIF(IACASE.EQ.'GESU')THEN
        WRITE(ICOUT,1162)
 1162   FORMAT('      THE (DEX) GENERATOR SUBTRACTION IS TO BE ',   &
               'COMPUTED')
      ELSEIF(IACASE.EQ.'GEMU')THEN
        WRITE(ICOUT,1163)
 1163   FORMAT('      THE (DEX) GENERATOR MULTIPLICATION IS TO BE ',   &
               'COMPUTED')
      ENDIF
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('      MUST BE 1 OR LARGER.  SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1183)N1,N3
 1183 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',2I8,'.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1190 CONTINUE
!
!               *********************************
!               **  STEP 12--                  **
!               **  BRANCH TO THE PROPER CASE  **
!               *********************************
!
      IF(IACASE.EQ.'GEAD')THEN
        GO TO 2300
      ELSEIF(IACASE.EQ.'GESU')THEN
        GO TO 2300
      ELSEIF(IACASE.EQ.'GEMU')THEN
        GO TO 2300
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1211)
 1211   FORMAT('***** INTERNAL ERROR IN GENARI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1212)
 1212   FORMAT('      IACASE NOT EQUAL TO GEAD, GESU, OR GEMU')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1215)
 1215   FORMAT('      IACASE = ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
 2300 CONTINUE
      N5TEMP=0
      L=0
!
      DO 2310 J=1,N1
        Y1J=Y1(J)
        DO 2320 K=1,N3
          IF(Y3(K).EQ.Y1J)GO TO 2310
 2320   CONTINUE
        L=L+1
        Y5(L)=Y1J
 2310 CONTINUE
!
      DO 2330 J=1,N3
        Y3J=Y3(J)
        DO 2340 K=1,N1
          IF(Y1(K).EQ.Y3J)GO TO 2330
 2340   CONTINUE
        L=L+1
        Y5(L)=Y3J
 2330 CONTINUE
!
      N5TEMP=L
!
      IF(N5TEMP.LE.0)GO TO 2359
      DO 2350 J=1,N5TEMP
        JP1=J+1
        IF(JP1.GT.N5TEMP)GO TO 2359
        DO 2360 K=JP1,N5TEMP
          IF(Y5(K).GT.Y5(J))GO TO 2360
          HOLD=Y5(J)
          Y5(J)=Y5(K)
          Y5(K)=HOLD
 2360   CONTINUE
 2350 CONTINUE
 2359 CONTINUE
!
      ITYP3='VECT'
      N5=N5TEMP
      N6=N5
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NARI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF GENARI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)IERROR,N1,N3,N5,N6
 9017   FORMAT('IERROR,N1,N3,N5,N6 = ',A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)SCAL3,ITYP3
 9018   FORMAT('SCAL3,ITYP3 = ',G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        IF(ITYP3.NE.'SCAL')THEN
          DO 9021 I=1,N1
            WRITE(ICOUT,9022)I,Y1(I),Y2(I)
 9022       FORMAT('I,Y1(I),Y2(I) = ',I8,2E13.5)
            CALL DPWRST('XXX','BUG ')
 9021     CONTINUE
          DO 9031 I=1,N3
            WRITE(ICOUT,9032)I,Y3(I),Y4(I)
 9032       FORMAT('I,Y3(I),Y4(I) = ',I8,2E13.5)
            CALL DPWRST('XXX','BUG ')
 9031     CONTINUE
          DO 9041 I=1,N5
            WRITE(ICOUT,9042)I,Y5(I),Y6(I)
 9042       FORMAT('I,Y5(I),Y6(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
 9041     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE GENARI
      SUBROUTINE GEOCDF(X,P,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X FOR THE
!              GEOMETRIC DISTRIBUTION WITH DOUBLE PRECISION 'BERNOULLI
!              PROBABILITY' PARAMETER = P.  THE GEOMETRIC DISTRIBUTION
!              USED HEREIN HAS MEAN = (1-P)/P AND STANDARD DEVIATION
!              = SQRT((1-P)/(P*P))).  THIS DISTRIBUTION IS DEFINED FOR
!              ALL NON-NEGATIVE INTEGER X--X = 0, 1, 2, ... .  THIS
!              DISTRIBUTION HAS THE PROBABILITY MASS FUNCTION
!
!                 p(X;P) = P * (1-P)**X.
!
!              THE GEOMETRIC DISTRIBUTION IS THE DISTRIBUTION OF THE
!              NUMBER OF FAILURES BEFORE OBTAINING 1 SUCCESS IN AN
!              INDEFINITE SEQUENCE OF BERNOULLI (0,1) TRIALS WHERE THE
!              PROBABILITY OF SUCCESS IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT WHICH
!                                THE CUMULATIVE DISTRIBUTION FUNCTION
!                                IS TO BE EVALUATED.  X SHOULD BE
!                                NON-NEGATIVE AND INTEGRAL-VALUED.
!                     --P      = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE GEOMETRIC DISTRIBUTION.  P SHOULD
!                                BE BETWEEN 0.0 (EXCLUSIVELY) AND
!                                1.0 (INCLUSIVELY).
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE GEOMETRIC DISTRIBUTION WITH
!             'BERNOULLI PROBABILITY' PARAMETER = P.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE AND INTEGRAL-VALUED.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!               --CATHERINE LOADER (2000), "FAST AND ACCURATE COMPUTATION
!                 OF BINOMIAL PROBABILITIES", BELL LABS?
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --MARCH     2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      EXTERNAL DLNREL
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
      IF(P.LE.0.0D0 .OR. P.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0D0)THEN
        WRITE(ICOUT,3)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    3 FORMAT('***** WARNING--THE FIRST ARGUMENT TO GEOPDF IS NEGATIVE')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEOPDF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      INTX=INT(X+0.00001D0)
      DX=DBLE(INTX)
      IF(P.EQ.1.0D0)THEN
        CDF=1.0D0
      ELSE
        DTERM1=DLNREL(-P)*(DX+1.0D0)
        CDF=-EXPM1(DTERM1)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEOCDF
      SUBROUTINE GE2CDF(X,P,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE GEOMETRIC DISTRIBUTION
!              WITH SINGLE PRECISION
!              'BERNOULLI PROBABILITY' PARAMETER = P.
!              THIS USES AN ALTERNATE DEFINITION THAN GEOPDF
!              (THE VERSION HERE IS USED IN THE DIGITAL LIBRARY OF
!              MATHEMATICAL FUNCTIONS).
!              THE GEOMETRIC DISTRIBUTION USED HEREIN
!              HEREIN HAS MEAN = 1/P
!              AND STANDARD DEVIATION = SQRT((1-P)/(P*P))).
!              THIS DISTRIBUTION IS DEFINED FOR
!              ALL POSITIVE INTEGER X--X = 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = P * (1-P)**X.
!              THE GEOMETRIC DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF TRIALS UP TO AND
!              INCLUDING THE FIRST SUCCESS IN AN
!              INDEFINITE SEQUENCE OF BERNOULLI (0,1)
!              TRIALS WHERE THE PROBABILITY OF SUCCESS
!              IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE AND
!                                INTEGRAL-VALUED.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE 'BERNOULLI PROBABILITY'
!                                PARAMETER FOR THE GEOMETRIC
!                                DISTRIBUTION.
!                                P SHOULD BE BETWEEN
!                                0.0 (EXCLUSIVELY) AND
!                                1.0 (EXCLUSIVELY).
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF
!             FOR THE GEOMETRIC DISTRIBUTION
!             WITH 'BERNOULLI PROBABILITY' PARAMETER = P.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE AND INTEGRAL-VALUED.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     COMMENT--NOTE THAT EVEN THOUGH THE INPUT
!              TO THIS CUMULATIVE
!              DISTRIBUTION FUNCTION SUBROUTINE
!              FOR THIS DISCRETE DISTRIBUTION
!              SHOULD (UNDER NORMAL CIRCUMSTANCES) BE A
!              DISCRETE INTEGER VALUE,
!              THE INPUT VARIABLE X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL INPUT ****DATA****
!              (AS OPPOSED TO SAMPLE SIZE, FOR EXAMPLE)
!              VARIABLES TO ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0D0
!
!-----START POINT-----------------------------------------------------
!
      X2=X-1.0D0
      CALL GEOCDF(X2,P,CDF)
!
      RETURN
      END SUBROUTINE GE2CDF
      SUBROUTINE GEOMEA(X,N,IWRITE,XGEOM,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE GEOMETRIC MEAN, XGEOM,
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE XGEOM = (PRODUCT OF THE OBSERVATIONS)**(1/N)
!                               = EXP((SUM OF LOG OF OBSERVATIONS)/N)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XGEOM  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE GEOMETRIC MEAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE GEOMETRIC MEAN
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--99.3
!     ORIGINAL VERSION--MARCH     1999.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GEOM'
      ISUBN2='EA  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF GEOMEA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ******************************
!               **  COMPUTE GEOMETRIC MEAN  **
!               ******************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN GEOMEA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE GEOMEA IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
      XGEOM=X(1)
      GO TO 9000
  129 CONTINUE
!
!               ***********************************
!               **  STEP 2--                     **
!               **  COMPUTE THE GEOMETRIC MEAN.  **
!               ***********************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
      IF(X(I).LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,211)
  211   FORMAT('***** ERROR FROM GEOMEA')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,213)
  213   FORMAT('      NON-POSITIVE NUMBER ENCOUNTERED.  MEAN SET ',   &
               'TO ZERO.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        XGEOM=0.0
        GO TO 9000
      ENDIF
      DX=DBLE(X(I))
      DSUM=DSUM+DLOG(DX)
  200 CONTINUE
      DSUM=DSUM/DN
      DSUM=DEXP(DSUM)
      XGEOM=REAL(DSUM)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XGEOM
  811 FORMAT('THE GEOMETRIC MEAN OF THE ',I8,' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF GEOMEA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XGEOM
 9015 FORMAT('XGEOM = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE GEOMEA
      SUBROUTINE GEOSD(X,N,IWRITE,XGEOSD,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE GEOMETRIC STANDARD DEVIATION, XGEOSD,
!              OF THE DATA IN THE INPUT VECTOR X.
!                XGSD = EXP(SD(LOG(Y)))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XGEOSD  = THE SINGLE PRECISION VALUE OF THE
!                                 COMPUTED SAMPLE GEOMETRIC STANDARD
!                                 DEVIATION.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE GEOMETRIC STANDARD DEVIATION
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--99.3
!     ORIGINAL VERSION--MARCH     1999.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GEOS'
      ISUBN2='D   '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF GEOSD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  COMPUTE GEOMETRIC STANDARD DEVIATION  **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN GEOSD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE GEOSD IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE GEOMETRIC STANDARD DEVIATION.  **
!               *************************************************
!
      DN=DBLE(N)
      DSUM1=0.0D0
!
      DO 200 I=1,N
        IF(X(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,211)
  211     FORMAT('***** ERROR FROM GEOSD')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,213)
  213     FORMAT('      NON-POSITIVE NUMBER ENCOUNTERED.  SD SET ',   &
                 'TO ZERO.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          XGEOSD=0.0
          GO TO 9000
        ENDIF
        DX=DBLE(X(I))
        DSUM1=DSUM1+DLOG(DX)
  200 CONTINUE
      DMEAN=DSUM1/DN
      DSUM1=0.0D0
      DO 300 I=1,N
        DX=DLOG(DBLE(X(I)))
        DSUM1=DSUM1 + (DX-DMEAN)**2
  300 CONTINUE
      DSD=DSQRT(DSUM1/(DN-1.0D0))
      XGEOSD=   &
        REAL(DEXP(DSD))
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XGEOSD
  811 FORMAT('THE GEOMETRIC STANDARD DEVIATION OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF GEOSD--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XGEOSD
 9015 FORMAT('XGEOSD = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE GEOSD
      SUBROUTINE GEOPDF(X,P,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X
!              FOR THE GEOMETRIC DISTRIBUTION WITH DOUBLE PRECISION
!              'BERNOULLI PROBABILITY' PARAMETER = P.  THE GEOMETRIC
!              DISTRIBUTION USED HEREIN HAS MEAN = (1-P)/P AND
!              STANDARD DEVIATION = SQRT((1-P)/(P*P))).  THIS
!              DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE INTEGER
!              X--X = 0, 1, 2, ... .  THIS DISTRIBUTION HAS THE
!              PROBABILITY MASS FUNCTION
!
!                 p(X;P) = P * (1-P)**X.
!
!              THE GEOMETRIC DISTRIBUTION IS THE DISTRIBUTION OF THE
!              NUMBER OF FAILURES BEFORE OBTAINING 1 SUCCESS IN AN
!              INDEFINITE SEQUENCE OF BERNOULLI (0,1) TRIALS WHERE THE
!              PROBABILITY OF SUCCESS IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT WHICH
!                                THE PROBABILITY MASS FUNCTION IS TO
!                                BE EVALUATED.  X SHOULD BE NON-NEGATIVE
!                                AND INTEGRAL-VALUED.
!                     --P      = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE GEOMETRIC DISTRIBUTION.  P SHOULD
!                                BE BETWEEN 0.0 (EXCLUSIVELY) AND
!                                1.0 (INCLUSIVELY).
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS FUNCTION VALUE PDF
!             FOR THE GEOMETRIC DISTRIBUTION WITH 'BERNOULLI
!             PROBABILITY' PARAMETER = P.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE AND INTEGRAL-VALUED.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (INCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!               --CATHERINE LOADER (2000), "FAST AND ACCURATE COMPUTATION
!                 OF BINOMIAL PROBABILITIES", BELL LABS?
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --MARCH     2009. USE CATHERINE LOADER BINOMIAL
!                                       PDF ALGORITHM
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0D0
      IF(P.LE.0.0D0 .OR. P.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.0.0D0)THEN
        WRITE(ICOUT,3)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    3 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEOPDF IS NEGATIVE')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEOPDF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(P.EQ.0.0D0)THEN
        PDF=0.0D0
      ELSE
        INTX=INT(X+0.00001D0)
        DX=DBLE(INTX) + 1.0D0
        DQ=1.0D0 - P
        DN=0.0D00
        ILOG=0
        CALL BINRAW(DN,P,DQ,DX,DTERM1,ILOG)
        PDF=P*DTERM1
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEOPDF
      SUBROUTINE GE2PDF(X,P,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE AT THE DOUBLE PRECISION VALUE X
!              FOR THE GEOMETRIC DISTRIBUTION WITH DOUBLE PRECISION
!              'BERNOULLI PROBABILITY' PARAMETER = P.  THE GEOMETRIC
!              DISTRIBUTION USED HEREIN HAS MEAN = 1/P AND
!              STANDARD DEVIATION = SQRT((1-P)/(P*P))).  THIS
!              DISTRIBUTION IS DEFINED FOR ALL POSITIVE INTEGER
!              X--X = 1, 2, ... .  THIS DISTRIBUTION HAS THE
!              PROBABILITY MASS FUNCTION
!
!                 p(X;P) = P * (1-P)**(X-1).
!
!              THE GEOMETRIC DISTRIBUTION IS THE DISTRIBUTION OF THE
!              NUMBER OF FAILURES UP TO AND INCLUDING THE FIRST SUCCESS
!              IN AN INDEFINITE SEQUENCE OF BERNOULLI (0,1) TRIALS WHERE
!              THE PROBABILITY OF SUCCESS IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT WHICH
!                                THE PROBABILITY MASS FUNCTION IS TO
!                                BE EVALUATED.  X SHOULD BE POSITIVE
!                                AND INTEGRAL-VALUED.
!                     --P      = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE GEOMETRIC DISTRIBUTION.  P SHOULD
!                                BE BETWEEN 0.0 (EXCLUSIVELY) AND
!                                1.0 (INCLUSIVELY).
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS FUNCTION VALUE PDF
!             FOR THE GEOMETRIC DISTRIBUTION WITH 'BERNOULLI
!             PROBABILITY' PARAMETER = P.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE AND INTEGRAL-VALUED.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (INCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!               --CATHERINE LOADER (2000), "FAST AND ACCURATE COMPUTATION
!                 OF BINOMIAL PROBABILITIES", BELL LABS?
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --MARCH     2009. USE CATHERINE LOADER BINOMIAL
!                                       PDF ALGORITHM
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0D0
      IF(P.LE.0.0D0 .OR. P.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(X.LT.1.0D0)THEN
        WRITE(ICOUT,3)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    3 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GE2PDF IS ',   &
             'NON-POSITIVE')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GE2PDF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(P.EQ.0.0D0)THEN
        PDF=0.0D0
      ELSE
        INTX=INT(X+0.00001D0)
!CCCC   DX=DBLE(INTX) - 1.0D0
        DX=DBLE(INTX)
        DQ=1.0D0 - P
        DN=0.0D00
        ILOG=0
        CALL BINRAW(DN,P,DQ,DX,DTERM1,ILOG)
        PDF=P*DTERM1
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GE2PDF
      SUBROUTINE GEOPPF(P,PPAR,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION
!              VALUE FOR THE GEOMETRIC DISTRIBUTION WITH DOUBLE
!              PRECISION 'BERNOULLI PROBABILITY' PARAMETER = PPAR.
!              THE GEOMETRIC DISTRIBUTION USED HEREIN HAS MEAN =
!              (1-PPAR)/PPAR AND STANDARD DEVIATION =
!              SQRT((1-PPAR)/(PPAR*PPAR))).  THIS DISTRIBUTION IS
!              DEFINED FOR ALL NON-NEGATIVE INTEGER X--X = 0, 1, 2, ...
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!
!                 p(X;PPAR) = PPAR * (1-PPAR)**X
!
!              THE GEOMETRIC DISTRIBUTION IS THE DISTRIBUTION OF THE
!              NUMBER OF FAILURES BEFORE OBTAINING 1 SUCCESS IN AN
!              INDEFINITE SEQUENCE OF BERNOULLI (0,1) TRIALS WHERE THE
!              PROBABILITY OF SUCCESS IN A SINGLE TRIAL = PPAR.
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE (BETWEEN
!                                0.0 (INCLUSIVELY) AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT FUNCTION IS
!                                TO BE EVALUATED.
!                     --PPAR   = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE GEOMETRIC DISTRIBUTION.  PPAR
!                                SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (INCLUSIVELY).
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE PPF
!             FOR THE GEOMETRIC DISTRIBUTION WITH 'BERNOULLI
!             PROBABILITY' PARAMETER VALUE = PPAR.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--PPAR SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (INCLUSIVELY).
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     2009. USE DOUBLE PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
      IF(P.LT.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(PPAR.LE.0.0D0 .OR. PPAR.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PPAR
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEOPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEOPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(P.EQ.0.0D0)THEN
        PPF=0.0D0
      ELSEIF(PPAR.EQ.1.0D0)THEN
        PPF=0.0D0
      ELSE
!
        ARG1=1.0D0-P
        ARG2=1.0D0-PPAR
        ANUM=LOG(ARG1)
        ADEN=LOG(ARG2)
        RATIO=ANUM/ADEN
        IRATIO=INT(RATIO)
        PPF=REAL(IRATIO)
        ARATIO=REAL(IRATIO)
        IF(ARATIO.EQ.RATIO)PPF=REAL(IRATIO-1)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEOPPF
      SUBROUTINE GEORAN(N,P,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GEOMETRIC DISTRIBUTION
!              WITH SINGLE PRECISION 'BERNOULLI PROBABILITY'
!              PARAMETER = P.
!              THE GEOMETRIC DISTRIBUTION USED
!              HEREIN HAS MEAN = (1-P)/P
!              AND STANDARD DEVIATION = SQRT((1-P)/(P*P))).
!              THIS DISTRIBUTION IS DEFINED FOR
!              ALL NON-NEGATIVE INTEGER X--X = 0, 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = P * (1-P)**X.
!              THE GEOMETRIC DISTRIBUTION IS THE
!              DISTRIBUTION OF THE NUMBER OF FAILURES
!              BEFORE OBTAINING 1 SUCCESS IN AN
!              INDEFINITE SEQUENCE OF BERNOULLI (0,1)
!              TRIALS WHERE THE PROBABILITY OF SUCCESS
!              IN A SINGLE TRIAL = P.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE 'BERNOULLI PROBABILITY'
!                                PARAMETER FOR THE GEOMETRIC
!                                DISTRIBUTION.
!                                P SHOULD BE BETWEEN
!                                0.0 (EXCLUSIVELY) AND
!                                1.0 (EXCLUSIVELY).
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GEOMETRIC DISTRIBUTION
!             WITH 'BERNOULLI PROBABILITY' PARAMETER = P.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE RANDOM NUMBER
!              GENERATOR MUST NECESSARILY BE A
!              SEQUENCE OF ***INTEGER*** VALUES,
!              THE OUTPUT VECTOR X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VECTORS FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF GEOMETRIC ',   &
               'RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE PROBABILITY OF SUCCESS PARAMETER ',   &
               'FOR THE GEOMETRIC DISTRIBUTION')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
   12   FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',F10.5)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GEOMETRIC RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        IF(X(I).EQ.0.0)GO TO 100
        ARG1=1.0-X(I)
        ARG2=1.0-P
        ANUM=LOG(ARG1)
        ADEN=LOG(ARG2)
        RATIO=ANUM/ADEN
        IRATIO=INT(RATIO)
        X(I)=REAL(IRATIO)
        ARATIO=REAL(IRATIO)
        IF(ARATIO.EQ.RATIO)X(I)=REAL(IRATIO-1)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEORAN
      SUBROUTINE GE2RAN(N,P,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GEOMETRIC DISTRIBUTION
!              WITH SINGLE PRECISION 'BERNOULLI PROBABILITY'
!              PARAMETER = P.
!              THIS USES AN ALTERNATE DEFINITION THAN GEOPDF
!              (THE VERSION HERE IS USED IN THE DIGITAL LIBRARY OF
!              MATHEMATICAL FUNCTIONS).
!              THE GEOMETRIC DISTRIBUTION USED HEREIN
!              HEREIN HAS MEAN = 1/P
!              AND STANDARD DEVIATION = SQRT((1-P)/(P*P))).
!              THIS DISTRIBUTION IS DEFINED FOR
!              ALL POSITIVE INTEGER X--X = 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              F(X) = P * (1-P)**(X-1).
!              NOTE THAT THIS ALTERNATE DEFINITION IS ESENTIALLY
!              THE DEFAULT DEFINITION SHIFTED 1 TO THE RIGHT.
!              SO FOR RANDOM NUMBERS, JUST USE THE ALGORITHM FOR
!              THE DEFAULT DEFINITION AND ADD 1.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE 'BERNOULLI PROBABILITY'
!                                PARAMETER FOR THE GEOMETRIC
!                                DISTRIBUTION.
!                                P SHOULD BE BETWEEN
!                                0.0 (EXCLUSIVELY) AND
!                                1.0 (EXCLUSIVELY).
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GEOMETRIC DISTRIBUTION
!             WITH 'BERNOULLI PROBABILITY' PARAMETER = P.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE RANDOM NUMBER
!              GENERATOR MUST NECESSARILY BE A
!              SEQUENCE OF ***INTEGER*** VALUES,
!              THE OUTPUT VECTOR X IS SINGLE
!              PRECISION IN MODE.
!              X HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VECTORS FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF GEOMETRIC ',   &
              'RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE PROBABILITY OF SUCCESS PARAMETER ',   &
               'FOR THE GEOMETRIC DISTRIBUTION')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
   12   FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GEOMETRIC RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        IF(X(I).EQ.0.0)GO TO 100
        ARG1=1.0-X(I)
        ARG2=1.0-P
        ANUM=LOG(ARG1)
        ADEN=LOG(ARG2)
        RATIO=ANUM/ADEN
        IRATIO=INT(RATIO)
        X(I)=REAL(IRATIO)
        ARATIO=REAL(IRATIO)
        IF(ARATIO.EQ.RATIO)X(I)=REAL(IRATIO-1)
        X(I)=X(I)+1.0
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GE2RAN
      SUBROUTINE GENER (W, N, WPRIME, NPRIME, INDEX, R)
!
!        ALGORITHM AS 304.6 APPL.STATIST. (1996), VOL.45, NO.3
!
!        Computes an array of sums of the various R-combinations of
!        the elements of W
!
!        DATAPLOT NOTE: UTILITY ROUTINE USED BY FISHER TWO SAMPLE
!                       RANDOMIZATION TEST
!
      INTEGER N, NPRIME, R, INDEX(R)
      REAL W(N), WPRIME(NPRIME)
!
      INTEGER I, J
      DOUBLE PRECISION SUM
      LOGICAL INIT
!
      EXTERNAL NEXT
!
      INIT = .TRUE.
!
      DO 20 I = 1, NPRIME
         CALL NEXT(INDEX, R, N, INIT)
         SUM = 0.0D0
         DO 10 J = 1, R
            SUM = SUM + DBLE(W(INDEX(J)))
   10    CONTINUE
         WPRIME(I) = REAL(SUM)
   20 CONTINUE
!
      RETURN
      END SUBROUTINE GENER 
      SUBROUTINE GEPCDF(X,GAMMA,MINMAX,IGEPDF,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED PARETO
!              DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE LENGTH PARAMETER = GAMMA.
!
!              THE GENERALIZED PARETO DENSITY FOR THE MAXIMUM
!              CASE HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!
!              F(X;GAMMA) = 1 - [1+GAMMA*X]**(-1/GAMMA)
!                           IF GAMMA < 0: X >= 0
!                           IF GAMMA > 0: 0 <= X < 1/GAMMA
!
!                         = 1 - EXP(-X)
!                           X >= 0, GAMMA = 0
!
!              SOME SOURCES (E.G., JOHNSON, KOTZ, AND BALAKRISHNAN
!              AND CASTILLO, HADI, BALAKRISHNAN, AND SARABIA)
!              USE THE PARAMETERIZATION GAMMA=-GAMMA:
!
!              F(X;GAMMA) = 1 - [1-GAMMA*X]**(1/GAMMA)
!                           IF GAMMA < 0: 0 <= X < -1/GAMMA
!                           IF GAMMA > 0: X >= 0
!
!                         = 1 - EXP(-X)
!                           X >= 0, GAMMA = 0
!
!              THE GENERALIZED PARETO DENSITY FOR THE MINIMUM
!              CASE HAS THE PROBABILITY DENSITY FUNCTION
!
!              F(X;GAMMA) = [1-GAMMA*X]**(-(1/GAMMA))
!                           IF GAMMA < 0: 0 <= X < 1/GAMMA
!                           IF GAMMA > 0: X >= 0
!
!                         = EXP(X)
!                           X <= 0, GAMMA = 0
!
!              IN THE ALTERNATE PARAMETERIZATION
!
!              F(X;GAMMA) = [1+GAMMA*X]**(1/GAMMA)
!                           IF GAMMA < 0: X >= 0
!                           IF GAMMA > 0: 0 <= X < 1/GAMMA
!
!                         = EXP(X)
!                           X <= 0, GAMMA = 0
!
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA CAN BE NEATIVE, 0, OR POSITIVE.
!                     --MINMAX = INTEGER VALUE, CURRENTLY NOT USED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION .
!             VALUE CDF FOR THE GENERALIZED PARETO DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --X SHOULD BE POSITIVE
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTIUOUS UNIVARIATE
!                 DISTRIBUTIONS--VOLUME 1", SECOND EDITION, PP. 614-620.
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA (2005),
!                 "EXTREME VALUES AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, PP. 65-66.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--93/12
!     ORIGINAL VERSION--DECEMBER  1993.
!     UPDATED         --DECEMBER  1994  CHECK FOR NEGATIVE X
!     UPDATED         --JANUARY   1995  CHECK FOR OUT OF RANGE X
!     UPDATED         --JUNE      2004  ALTERNATE DEFINITION FOR
!                                       GENERAPLIZED PARETO (USES
!                                       DIFFERENT SIGN)
!     UPDATED         --JANUARY   2008  SUPPORT MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IGEPDF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
!
!     COMPUTE THE CDF VALUE
!
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!       2) X >= 0                 FOR BOTH PARAMETERIZATIONS
!
        IF(X.LT.0.0)THEN
          CDF=0.0
          GO TO 9000
        ENDIF
!
        IF(GAMMA.EQ.0.0)THEN
          CDF=1.0 - EXP(-X)
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(X.GE.1.0/GAMMA .AND. GAMMA.GT.0.0)THEN
            CDF=1.0
            GO TO 9000
          ENDIF
        ELSE
          IF(X.GE.-1.0/GAMMA .AND. GAMMA.LT.0.0)THEN
            CDF=1.0
            GO TO 9000
          ENDIF
        ENDIF
!
!       COMPUTE THE CDF VALUE
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
!
        IF(IGEPDF.EQ.'JOHN')THEN
          DCDF=1.0D0-((1.0D0-DG*DX)**(1.0D0/DG))
        ELSE
          DCDF=1.0D0-((1.0D0+DG*DX)**(-1.0D0/DG))
        ENDIF
        CDF=REAL(DCDF)
!
!     NOW DO THE MINIMUM CASE
!
      ELSE
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!       2) X <= 0                 FOR BOTH PARAMETERIZATIONS
!
        IF(X.GE.0.0)THEN
          CDF=1.0
          GO TO 9000
        ENDIF
!
        IF(GAMMA.EQ.0.0)THEN
          CDF=EXP(X)
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(X.LE.-1.0/GAMMA .AND. GAMMA.GT.0.0)THEN
            CDF=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(X.LE.1.0/GAMMA .AND. GAMMA.LT.0.0)THEN
            CDF=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
!       COMPUTE THE CDF VALUE
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
!
        IF(IGEPDF.EQ.'JOHN')THEN
          DCDF=(1.0D0+DG*DX)**(1.0D0/DG)
        ELSE
          DCDF=(1.0D0-DG*DX)**(-(1.0D0/DG))
        ENDIF
        CDF=REAL(DCDF)
!
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEPCDF
      SUBROUTINE GEPCHA(X,GAMMA,MINMAX,IGEPDF,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE GENERALIZED PARETO
!              DENSITY WITH SINGLE PRECISION
!              SHAPE LENGTH PARAMETER = GAMMA.
!              THE GENERALIZED PARETO DENSITY USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE CUMULATIVE HAZARD FUNCTION
!                H(X) = -LOG[(1-GAMMA*X)**(1/GAMMA)]
!              JOHNSON, KOTZ, AND BALAKRISHNANA REVERSE THE SIGN OF THE
!              SHAPE PARAMETER:
!                H(X) = -LOG[(1+GAMMA*X)**(-1/GAMMA)]
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION POSITIVE VALUE AT
!                                WHICH THE HAZARD FUNCTION IS TO BE
!                                EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA CAN BE NEG., 0, OR POS.
!                     --MINMAX = THE INTEGER VALUE, NOT CURRENTLY USED
!                     --IGEPDF = CHARACTER VALUE SPECIFYING WHETHER
!                                EMIL SIMIU OR JOHNSON AND KOTZ DEFINITION
!                                SHOULD BE USED.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION
!                                CUMULATIVE HAZARD FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD FUNCTION .
!             VALUE HAZ FOR THE GENERALIZED PARETO DENSITY
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA MAY BE NEGATIVE, 0, OR POSITIVE
!                 --X SHOULD BE POSITIVE
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTIUOUS UNIVARIATE
!                 DISTRIBUTIONS--VOLUME 1", SECOND EDITION, PP. 614-620.
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA (2005),
!                 "EXTREME VALUES AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, PP. 65-66.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --JUNE      2004  ALTERNATE DEFINITION FOR
!                                       GENERAPLIZED PARETO (USES
!                                       DIFFERENT SIGN)
!     UPDATED         --JANUARY   2008  SUPPORT MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOMC.INC'
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IGEPDF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DHAZ
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!       2) X >= 0                 FOR BOTH PARAMETERIZATIONS
!
        IF(X.LT.0.0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          HAZ=0.0
          GO TO 9000
        ENDIF
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEPCHAZ IS ',   &
               'NEGATIVE.')
!
        IF(GAMMA.EQ.0.0)THEN
          HAZ=X
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(X.GT.1.0/GAMMA .AND. GAMMA.GT.0.0)THEN
            WRITE(ICOUT,3)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(X.GT.-1.0/GAMMA .AND. GAMMA.LT.0.0)THEN
            WRITE(ICOUT,2)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
    2   FORMAT('***** ERROR--FROM GEPCHAZ: X >= -1/GAMMA.')
    3   FORMAT('***** ERROR--FROM GEPCHAZ: X >= 1/GAMMA.')
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47   FORMAT('***** THE VALUE OF X IS     ',G15.7)
   48   FORMAT('***** THE VALUE OF GAMMA IS ',G15.7)
!
!       COMPUTE THE HAZ VALUE
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
!
        IF(IGEPDF.EQ.'JOHN')THEN
          DHAZ=-DLOG((1.0D0-DG*DX)**(1.0D0/DG))
        ELSE
          DHAZ=-DLOG((1.0D0+DG*DX)**(-1.0D0/DG))
        ENDIF
        HAZ=REAL(DHAZ)
!
!     NOW DO THE MINIMUM CASE
!
      ELSE
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!       2) X <= 0                 FOR BOTH PARAMETERIZATIONS
!
        IF(X.GT.0.0)THEN
          WRITE(ICOUT,11)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          HAZ=0.0
          GO TO 9000
        ENDIF
   11   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEPHAZ IS ',   &
               'POSITIVE.')
!
        IF(GAMMA.EQ.0.0)THEN
          HAZ=1.0
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(X.LE.-1.0/GAMMA .AND. GAMMA.GT.0.0)THEN
            WRITE(ICOUT,13)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(X.LE.1.0/GAMMA .AND. GAMMA.LT.0.0)THEN
            WRITE(ICOUT,12)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
   12   FORMAT('***** ERROR--FROM GEPHAZ: X <= 1/GAMMA.')
   13   FORMAT('***** ERROR--FROM GEPHAZ: X <= -1/GAMMA.')
!
!       COMPUTE THE HAZ VALUE
!
        CALL GEPCDF(X,GAMMA,MINMAX,IGEPDF,CDF)
        XTEMP1=1.0 - CDF
        IF(XTEMP1.NE.0.0)THEN
          HAZ=-LOG(XTEMP1)
        ELSE
          HAZ=0.0
          WRITE(ICOUT,22)
          CALL DPWRST('XXX','BUG ')
        ENDIF
   22   FORMAT('***** ERROR FROM GEPCHAZ: HAZARD VALUE OVERFLOWS.')
!
      ENDIF
!
                                                                                                                                  
                                                                                                                                  
                                                                                                                                  
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEPCHA
      SUBROUTINE GEPHAZ(X,GAMMA,MINMAX,IGEPDF,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE GENERALIZED PARETO
!              DENSITY WITH SINGLE PRECISION
!              SHAPE LENGTH PARAMETER = GAMMA.
!              THE GENERALIZED PARETO DENSITY USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE HAZARD FUNCTION
!                 H(X) = 1/(1+GAMMA*X)
!              JOHNSON, KOTZ, AND BALARKRISHNAN REVERSE THE SIGN:
!                 H(X) = 1/(1-GAMMA*X)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION POSITIVE VALUE
!                                AT WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA CAN BE NEG., 0, OR POS.
!                     --MINMAX = THE INTEGER VALUE, NOT CURRENTLY USED
!                     --IGEPDF = CHARACTER VALUE SPECIFYING WHETHER
!                                EMIL SIMIU OR JOHNSON AND KOTZ DEFINITION
!                                SHOULD BE USED.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION
!                                HAZARD FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD FUNCTION .
!             VALUE HAZ FOR THE GENERALIZED PARETO DENSITY
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA MAY BE NEGATIVE, 0, OR POSITIVE
!                 --X SHOULD BE POSITIVE
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTIUOUS UNIVARIATE
!                 DISTRIBUTIONS--VOLUME 1", SECOND EDITION, PP. 614-620.
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA (2005),
!                 "EXTREME VALUES AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, PP. 65-66.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --JUNE      2004  ALTERNATE DEFINITION FOR
!                                       GENERAPLIZED PARETO (USES
!                                       DIFFERENT SIGN)
!     UPDATED         --JANUARY   2008  SUPPORT MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IGEPDF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DHAZ
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
!     COMPUTE THE HAZ VALUE
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!       2) X >= 0                 FOR BOTH PARAMETERIZATIONS
!
        IF(X.LT.0.0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          HAZ=0.0
          GO TO 9000
        ENDIF
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEPHAZ IS ',   &
               'NEGATIVE.')
!
        IF(GAMMA.EQ.0.0)THEN
          HAZ=1.0
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(X.GT.1.0/GAMMA .AND. GAMMA.GT.0.0)THEN
            WRITE(ICOUT,3)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(X.GT.-1.0/GAMMA .AND. GAMMA.LT.0.0)THEN
            WRITE(ICOUT,2)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
    2   FORMAT('***** ERROR--FROM GEPHAZ: X >= -1/GAMMA.')
    3   FORMAT('***** ERROR--FROM GEPHAZ: X >= 1/GAMMA.')
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47   FORMAT('***** THE VALUE OF X IS     ',G15.7)
   48   FORMAT('***** THE VALUE OF GAMMA IS ',G15.7)
!
!       COMPUTE THE HAZ VALUE
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
!
        IF(IGEPDF.EQ.'JOHN')THEN
          DHAZ=1.0D0/(1.0D0 - DG*DX)
        ELSE
          DHAZ=1.0D0/(1.0D0 + DG*DX)
        ENDIF
        HAZ=REAL(DHAZ)
!
!     NOW DO THE MINIMUM CASE
!
      ELSE
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!       2) X <= 0                 FOR BOTH PARAMETERIZATIONS
!
        IF(X.GT.0.0)THEN
          WRITE(ICOUT,11)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          HAZ=0.0
          GO TO 9000
        ENDIF
   11   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEPHAZ IS ',   &
               'POSITIVE.')
!
        IF(GAMMA.EQ.0.0)THEN
          HAZ=1.0
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(X.LE.-1.0/GAMMA .AND. GAMMA.GT.0.0)THEN
            WRITE(ICOUT,13)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(X.LE.1.0/GAMMA .AND. GAMMA.LT.0.0)THEN
            WRITE(ICOUT,12)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
   12   FORMAT('***** ERROR--FROM GEPHAZ: X <= 1/GAMMA.')
   13   FORMAT('***** ERROR--FROM GEPHAZ: X <= -1/GAMMA.')
!
!       COMPUTE THE HAZ VALUE
!
        CALL GEPPDF(X,GAMMA,MINMAX,IGEPDF,PDF)
        CALL GEPCDF(X,GAMMA,MINMAX,IGEPDF,CDF)
        XTEMP1=1.0 - CDF
        IF(XTEMP1.NE.0.0)THEN
          HAZ=PDF/XTEMP1
        ELSE
          HAZ=0.0
          WRITE(ICOUT,22)
          CALL DPWRST('XXX','BUG ')
        ENDIF
   22   FORMAT('***** ERROR FROM GEPHAZ: HAZARD VALUE OVERFLOWS.')
!
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEPHAZ
      SUBROUTINE GEPLI1(Y,N,MINMAX,IGEPDF,ALOC,SCALE,SHAPE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR THE
!              GENERALIZED PARETO DISTRIBUTION.  THIS IS FOR THE
!              RAW DATA CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--CASTILLO, HADI, BALAKRISHNAN, SARABIA, "EXTREME
!                VALUE AND RELATED MODELS WITH APPLICATIONS IN
!                ENGINEERING AND SCIENCE", WILEY, 2005.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IGEPDF
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DG
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GEPL'
      ISUBN2='I1  '
      IERROR='NO'
!
      SHAPSV=CPUMIN
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IGEPDF.EQ.'SIMI')THEN
        SHAPSV=SHAPE
        SHAPE=-SHAPE
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GEPLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,ALOC,SCALE,SHAPE
   52   FORMAT('IBUGA3,ISUBRO,N,ALOC,SCALE,SHAPE = ',2(A4,2X),I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     FOR THE MAXIMUM CASE, THE LOG-LIKELIHOOD FUNCTION IS
!     (U = LOCATION, S = SCALE, G = SHAPE):
!
!        -N*LOG(S) + ((1/G - 1)*SUM[i=1 to N][LOG(1 - G*(X(i)-U)/S)]
!
!     WHEN G = 0, THIS SIMPLIFIES TO
!
!        -N*LOG(S) + (1/G)*SUM[i=1 to N][X(i) - U]
!
!     FOR THE MINIMUM CASE, JUST TAKE X(I) = -X(I) AND USE ABOVE FORMULA.
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DG=DBLE(SHAPE)
      IF(MINMAX.EQ.1)THEN
        DO 100 I=1,N
          Y(I)=-Y(I)
  100   CONTINUE
      ENDIF
!
      DTERM1=-DN*DLOG(DS)
      DSUM1=0.0D0
      IF(SHAPE.NE.0.0)THEN
        DTERM2=(1.0D0/DG) - 1.0D0
        DO 1010 I=1,N
          DX=(DBLE(Y(I)) - DU)/DS
          IF(1.0D0 - DG*DX.LE.0.0D0)THEN
            IERROR='YES'
            GO TO 9000
          ENDIF
          DSUM1=DSUM1 + DLOG(1.0D0 - DG*DX)
 1010   CONTINUE
        DLIK=DTERM1 + DTERM2*DSUM1
      ELSE
        DO 1020 I=1,N
          DX=(DBLE(Y(I)) - DU)/DS
          DSUM1=DSUM1 + DX
 1020   CONTINUE
        DLIK=DTERM1 - DSUM1
      ENDIF
!
      ALIK=REAL(DLIK)
      DNP=3.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
!     FOR MINIMUM CASE, CONVERT Y BACK TO ORIGINAL VALUES
!
      IF(MINMAX.EQ.1)THEN
        DO 8010 I=1,N
          Y(I)=-Y(I)
 8010   CONTINUE
      ENDIF
!
 9000 CONTINUE
!
      IF(IGEPDF.EQ.'SIMI')THEN
        SHAPE=SHAPSV
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GEPLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM2,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM2,DTERM3 = ',5G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GEPLI1
      SUBROUTINE GEPML1(Y,N,MAXNXT,MINMAX,ICASPL,IGEPDF,IGEPSV,IDFTTY,   &
                        GAMMSV,SCALSV,ISEED,THRESH,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,YTEMP,   &
                        DTEMP1,XMOM,NMOM,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALOCMO,SCALMO,SHAPMO,   &
                        ALOCLM,SCALLM,SHAPLM,   &
                        ALOCEP,SCALEP,SHAPEP,   &
                        ALOCML,SCALML,SHAPML,MLFLAG,   &
                        NUSE,ZMEAN,ZVAR,ZSD,ALOC,   &
                        VARMM1,VARMM2,COVMOM,   &
                        VARML1,VARML2,COVML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 3-PARAMETER GENERALIZED PARETO DISTRIBUTION FOR
!              THE RAW DATA CASE (I.E., NO CENSORING AND NO GROUPING).
!              THIS ROUTINE RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE
!              INTERVALS WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLGP WILL GENERATE THE OUTPUT
!              FOR THE GENERALIZED PARETO MLE COMMAND).
!
!              THE FOLLOWING METHODS ARE SUPPORTED:
!
!                  1) MOMENTS
!                  2) L-MOMENTS
!                  3) ELEMENTAL PERCENTILES
!                  4) MAXIMUM LIKELIHOOD
!
!               NOTE THAT MOMENT, L-MOMENT AND MAXIMUM LIKELIHOOD ARE
!               ONLY SUPOORTED FOR CERTAIN RANGES OF THE SHAPE PARAMETER.
!               ELEMENTAL PERCENTILES DOES NOT HAVE THIS RESTRICTION.
!
!               FOR CERTAIN PROCEDURES (E.G., BOOTSTRAP OR
!               BEST DISTRIBUTIONAL FIT) WE MAY WANT TO RESTRICT
!               FITTING TO THE ELEMENTAL PERCENTILES METHOD SINCE
!               THIS SHOULD RETURN A VALID VALUE REGARDLESS OF THE
!               VALUE OF THE SHAPE PARAMETER.
!
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN.  "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS, VOLUME I", SECOND
!                EDITION, WILEY, 1994, PP. 614-619.
!              --CASTILLO, HADI, BALAKRISHNAN, SARABIA, "EXTREME
!                VALUE AND RELATED MODELS WITH APPLICATIONS IN
!                ENGINEERING AND SCIENCE", WILEY, 2005.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLGP)
!     UPDATED         --APRIL     2011. IDFTTY TO SUPPRESS MOMENT
!                                       OR ML METHODS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION YTEMP(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION XMOM(*)
      DOUBLE PRECISION XPAR(3)
      DOUBLE PRECISION FVEC(2)
      DOUBLE PRECISION TOL
      DOUBLE PRECISION G
      DOUBLE PRECISION T3
!
      CHARACTER*4 IGEPDF
      CHARACTER*4 IGEPSV
      CHARACTER*4 IDFTTY
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      EXTERNAL GPAFUN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GEPM'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      AN=REAL(N)
      ALOCMO=CPUMIN
      SCALMO=CPUMIN
      SHAPMO=CPUMIN
      ALOCLM=CPUMIN
      SCALLM=CPUMIN
      SHAPLM=CPUMIN
      ALOCEP=CPUMIN
      SCALEP=CPUMIN
      SHAPEP=CPUMIN
      ALOCML=CPUMIN
      SCALMO=CPUMIN
      SHAPML=CPUMIN
      VARML1=CPUMIN
      VARML2=CPUMIN
      COVML=CPUMIN
      VARMM1=CPUMIN
      VARMM2=CPUMIN
      COVMOM=CPUMIN
      IFRST=0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GEPML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASPL,IGEPDF,IDFTTY,MINMAX
   52   FORMAT('IBUGA3,ISUBRO,ICASPL,IGEPDF,IDFTTY,MINMAX = ',   &
               5(A4,2X),I5)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(MINMAX.NE.1)THEN
        DO 1145 I=1,N
          IF(Y(I).LE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1148)I,Y(I)
 1148       FORMAT('      ROW ',I8,' IS NON-POSITIVE (VALUE = ',   &
                   G15.7,')')
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
 1145   CONTINUE
      ELSE
        DO 1155 I=1,N
          IF(Y(I).GE.0.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1111)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1158)I,Y(I)
 1158       FORMAT('      ROW ',I8,' IS NON-NEGATIVE (VALUE = ',   &
                   G15.7,')')
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
 1155   CONTINUE
      ENDIF
!
!               **************************************************
!               **  STEP 2--                                   **
!               **  CARRY OUT CALCULATIONS                     **
!               **  FOR GENERALIZED PARETO MLE ESTIMATE        **
!               *************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GENERALIZED PARETO'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(MINMAX.EQ.1)THEN
        DO 2002 I=1,N
          Y(I)=-Y(I)
 2002   CONTINUE
      ENDIF
      CALL SORT(Y,N,Y)
      XMIN2=Y(1)
!
!     NOTE: L-MOMENTS WILL ESTIMATE THE THRESHOLD PARAMETER, SO
!           GENERATE THIS FIRST.  THE OTHER ESTIMATES ESTIMATE
!           ONLY SHAPE/SCALE PARAMETER, SO SUBTRACT OFF THE
!           L-MOMENT LOCATION ESTIMATE.
!
!           ALTERNATIVELY, THE USER CAN SPECIFY A THRESHOLD.
!           IF THE L-MOMENT ESTIMATE APPEARS TO BE INVALID
!           AND NO USER SPECIFIED THRESHOLD IS GIVEN, THEN
!           SUBTRACT THE DATA MINIMUM (PLUS AN EPSILON) FROM
!           THE DATA.
!
      NMOM=3
      DO 2110 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 2110 CONTINUE
      CALL SAMLMU(DTEMP1,N,XMOM,NMOM)
      T3=XMOM(3)
      IF(XMOM(2).LE.0.0D0 .OR. DABS(T3).GE.1.0D0)THEN
        CONTINUE
      ELSE
        G=(1.0D0-3.0D0*T3)/(1.0D0+T3)
        SHAPLM=REAL(G)
        SCALLM=REAL((1.0D0+G)*(2.0D0+G)*XMOM(2))
        ALOCLM=REAL(XMOM(1)-DBLE(SCALLM)/(1.0D0+G))
        IF(IGEPDF.EQ.'SIMI')SHAPLM=-SHAPLM
      ENDIF
!
!     EXTRACT POINTS ABOVE THE THRESHOLD.  MOMENT AND ML ESTIMATORS
!     ARE CURRENTLY BASED ON 2-PARAMETER CASE, SO USE THIS
!     THRESHOLD AS LOCATION ESTIMATE IN THESE CASES.
!
!        1) IF USER-SPECIFIED VALUE GIVEN, USE THAT
!        2) IF NO THRESHOLD SPECIFIED, THEN
!           A) IF L-MOMENTS ESTIMATES ARE VALID, USE THE L-MOMENT
!              ESTIMATE OF LOCATION.  IF THIS IS >= DATA MINIMUM,
!              THEN USE OPTION B.
!           B) IF L-MOMENTS ESTIMATES ARE NOT VALID, USE THE
!              DATA MINIMUM (MINUS AN EPSILON)
!
      IF(THRESH.EQ.CPUMIN)THEN
        IF(ALOCLM.NE.CPUMIN .AND. ABS(SHAPLM).LE.0.6 .AND.   &
           ALOCLM.LT.XMIN2) THEN
          ALOC=ALOCLM
        ELSE
          EPS=XMIN2*0.0001
          ALOC=XMIN2 - EPS
        ENDIF
        NUSE=N
        DO 2005 I=1,N
          YTEMP(I)=Y(I) - ALOC
 2005   CONTINUE
      ELSE
        ALOC=THRESH
        IFIRST=N+1
        DO 2010 I=1,N
          IF(Y(I).GT.THRESH)THEN
            IFRST=I
            GO TO 2019
          ENDIF
 2010   CONTINUE
 2019   CONTINUE
!
        NUSE=N-IFRST+1
        IF(NUSE.LT.3)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1111)
 1111     FORMAT('****** ERROR IN GENERALIZED PARETO ',   &
                 'MAXIMUM LIKELIHOOD--')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,2021)
 2021     FORMAT('      LESS THAN 3 POINTS ARE ABOVE THE THRESHOLD.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,2023)THRESH
 2023     FORMAT('      THRESHOLD          = ',G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,2024)Y(1)
 2024     FORMAT('      MINIMUM DATA POINT = ',G15.7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,2025)Y(N)
 2025     FORMAT('      MAXIMUM DATA POINT = ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSE
          ICNT=0
          DO 2030 I=IFRST,N
            ICNT=ICNT+1
            YTEMP(ICNT)=Y(I)
 2030     CONTINUE
        ENDIF
      ENDIF
!
      ITEMP=2
      NSAMP=20*NUSE
      IF(NSAMP.GT.5000)NSAMP=5000
      CALL DPEPM2(YTEMP,NUSE,ICASPL,MAXNXT,MINMAX,IGEPDF,   &
                  ISEED,NSAMP,   &
                  TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                  ALOCDM,SCALEP,SHAPEP,   &
                  IBUGA3,ISUBRO,IERROR)
      ALOCEP=ALOC
!
      IF(IDFTTY.EQ.'EPER')GO TO 9000
!
!     MOMENT ESTIMATES (BASED ON POINTS ABOVE THRESHOLD)
!
      CALL MEAN(YTEMP,NUSE,IWRITE,ZMEAN,IBUGA3,IERROR)
      CALL VAR(YTEMP,NUSE,IWRITE,ZVAR,IBUGA3,IERROR)
      ZSD=SQRT(ZVAR)
!
      SHAPMO=0.5*(ZMEAN*ZMEAN/ZVAR - 1.0)
      SCALMO=0.5*ZMEAN*(ZMEAN*ZMEAN/ZVAR + 1.0)
      ALOCMO=ALOC
      IF(IGEPDF.EQ.'SIMI')SHAPMO=-SHAPMO
!
!     MAXIMUM LIKELIHOOD ESTIMATES (BASED ON POINTS ABOVE THRESHOLD)
!
      IF(IGEPSV.EQ.'EPER')THEN
        XPAR(1)=DBLE(SHAPEP)
        XPAR(2)=DBLE(SCALEP)
      ELSEIF(IGEPSV.EQ.'LMOM')THEN
        XPAR(1)=DBLE(SHAPLM)
        XPAR(2)=DBLE(SCALLM)
      ELSEIF(IGEPSV.EQ.'MOME')THEN
        XPAR(1)=DBLE(SHAPMO)
        XPAR(2)=DBLE(SCALMO)
      ELSEIF(IGEPSV.EQ.'USER')THEN
        XPAR(1)=DBLE(GAMMSV)
        XPAR(2)=DBLE(SCALSV)
      ELSE
        XPAR(1)=DBLE(SHAPEP)
        XPAR(2)=DBLE(SCALEP)
      ENDIF
      DO 2111 I=1,MAXNXT
        DTEMP1(I)=0.0D0
 2111 CONTINUE
!
      IOPT=2
      TOL=1.0D-5
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(GPAFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,YTEMP,NUSE)
!
      ALOCML=ALOC
      SHAPML=REAL(XPAR(1))
      SCALML=REAL(XPAR(2))
      MLFLAG=0
      IF(INFO.EQ.0)MLFLAG=1
      IF(INFO.EQ.2)MLFLAG=1
      IF(INFO.EQ.4)MLFLAG=1
!
      IF(SHAPMO.GT.-0.25)THEN
        AC1=(1.0+SHAPMO)**2/   &
            ((1.0+2.0*SHAPMO)*(1.0+3.0*SHAPMO)*(1.0+4.0*SHAPMO))
        AC1=AC1/REAL(N)
        VARMM2=2.0*SCALMO**2*(1.0+6.0*SHAPMO+12.0*SHAPMO**2)
        VARMM2=AC1*VARMM2
        VARMM1=(1.0+2.0*SHAPMO)**2*(1.0+SHAPMO+6.0*SHAPMO**2)
        VARMM1=AC1*VARMM1
        COVMOM=AC1*SCALMO*   &
               (1.0+2.0*SHAPMO)*(1.0+4.0*SHAPMO+12.0*SHAPMO**2)
      ELSE
        VARMM1=CPUMIN
        VARMM2=CPUMIN
        COVMOM=CPUMIN
      ENDIF
!
      IF(MLFLAG.EQ.0)THEN
        AN=REAL(N)
        VARML1=(1.0-SHAPML)**2/AN
        VARML2=2.0*SCALML**2*(1.0-SHAPML)/AN
        COVML=SCALML*(1.0-SHAPML)/AN
        IF(IGEPDF.NE.'SIMI')SHAPML=-SHAPML
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GEPML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9016)ALOCMO,SCALMO,SHAPMO
 9016   FORMAT('ALOCMO,SCALMO,SHAPMO =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)ALOCLM,SCALLM,SHAPLM
 9017   FORMAT('ALOCLM,SCALLM,SHAPLM =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9018)ALOCEP,SCALEP,SHAPEP
 9018   FORMAT('ALOCLM,SCALLM,SHAPLM =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)ALOCML,SCALML,SHAPML
 9019   FORMAT('ALOCML,SCALML,SHAPML =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GEPML1
      SUBROUTINE GEPPDF(X,GAMMA,MINMAX,IGEPDF,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED PARETO
!              DENSITY WITH SINGLE PRECISION
!              SHAPE LENGTH PARAMETER = GAMMA.
!
!              THE GENERALIZED PARETO DENSITY FOR THE MAXIMUM
!              CASE HAS THE PROBABILITY DENSITY FUNCTION
!
!              f(X;GAMMA) = (1+GAMMA*X)**(-(1/GAMMA)-1)
!                           IF GAMMA < 0: X >= 0
!                           IF GAMMA > 0: 0 <= X < 1/GAMMA
!
!                         = EXP(-X)
!                           X >= 0, GAMMA = 0
!
!              SOME SOURCES (E.G., JOHNSON, KOTZ, AND BALAKRISHNAN
!              AND CASTILLO, HADI, BALAKRISHNAN, AND SARABIA)
!              USE THE PARAMETERIZATION GAMMA=-GAMMA:
!
!              f(X;GAMMA) = (1-GAMMA*X)**((1/GAMMA)-1)
!                           IF GAMMA < 0: 0 <= X < -1/GAMMA
!                           IF GAMMA > 0: X >= 0
!
!                         = EXP(-X)
!                           X >= 0, GAMMA = 0
!
!              THE GENERALIZED PARETO DENSITY FOR THE MINIMUM
!              CASE HAS THE PROBABILITY DENSITY FUNCTION
!
!              f(X;GAMMA) = (1-GAMMA*X)**(-(1/GAMMA)-1)
!                           IF GAMMA < 0: 1/GAMMA < X <= 0
!                           IF GAMMA > 0: X <= 0
!
!                         = EXP(X)
!                           X <= 0, GAMMA = 0
!
!              IN THE ALTERNATE PARAMETERIZATION
!
!              f(X;GAMMA) = (1+GAMMA*X)**((1/GAMMA)-1)
!                           IF GAMMA < 0: X <= 0
!                           IF GAMMA > 0: -1/GAMMA < X <= 0
!
!                         = EXP(X)
!                           X <= 0, GAMMA = 0
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                (BETWEEN ...
!                                AND ... (EXCLUSIVELY))
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA CAN BE NEGATIVE 0, OR POSITIVE.
!                     --MINMAX = SPECIFY WHETHER THE MINIMUM OR
!                                MAXIMUM CASE IS USED
!                     --IGEPDF = CHARACTER VALUE SPECIFYING WHETHER
!                                EMIL SIMIU OR JOHNSON AND KOTZ DEFINITION
!                                SHOULD BE USED.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY FUNCTION .
!             VALUE PDF FOR THE GENERALIZED PARETO DENSITY
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA MAY BE NEGATIVE, 0, OR POSITIVE
!                 --X SHOULD BE BETWEEN 0 (EXCLUSIVELY)
!                   AND INFINITY OR (1/-GAMMA) (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTIUOUS UNIVARIATE
!                 DISTRIBUTIONS--VOLUME 1", SECOND EDITION, PP. 614-620.
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA (2005),
!                 "EXTREME VALUES AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, PP. 65-66.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--93/12
!     ORIGINAL VERSION--DECEMBER  1993.
!     UPDATED         --DECEMBER  1994  CHECK FOR NEGATIVE X
!     UPDATED         --JANUARY   1995  CHECK FOR OUT OF RANGE X
!     UPDATED         --JUNE      2004  ALTERNATE DEFINITION FOR
!                                       GENERAPLIZED PARETO (USES
!                                       DIFFERENT SIGN)
!     UPDATED         --JANUARY   2008  SUPPORT MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IGEPDF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!       2) X >= 0                 FOR BOTH PARAMETERIZATIONS
!
        IF(X.LT.0.0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9000
        ENDIF
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEPPDF IS ',   &
               'NEGATIVE.')
!
        IF(GAMMA.EQ.0.0)THEN
          PDF=EXP(-X)
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(X.GT.1.0/GAMMA .AND. GAMMA.GT.0.0)THEN
            WRITE(ICOUT,3)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            PDF=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(X.GT.-1.0/GAMMA .AND. GAMMA.LT.0.0)THEN
            WRITE(ICOUT,2)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            PDF=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
    2   FORMAT('***** ERROR--FROM GEPPDF: X >= -1/GAMMA.')
    3   FORMAT('***** ERROR--FROM GEPPDF: X >= 1/GAMMA.')
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47   FORMAT('***** THE VALUE OF X IS     ',G15.7)
   48   FORMAT('***** THE VALUE OF GAMMA IS ',G15.7)
!
!       COMPUTE THE PDF VALUE
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
!
        IF(IGEPDF.EQ.'JOHN')THEN
          DPDF=(1.0D0-DG*DX)**((1.0D0/DG)-1.0D0)
        ELSE
          DPDF=(1.0D0+DG*DX)**(-(1.0D0/DG)-1.0D0)
        ENDIF
        PDF=REAL(DPDF)
!
!     NOW DO THE MINIMUM CASE
!
      ELSE
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!       2) X <= 0                 FOR BOTH PARAMETERIZATIONS
!
        IF(X.GT.0.0)THEN
          WRITE(ICOUT,11)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9000
        ENDIF
   11   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEPPDF IS ',   &
               'POSITIVE.')
!
        IF(GAMMA.EQ.0.0)THEN
          PDF=EXP(X)
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(X.LE.-1.0/GAMMA .AND. GAMMA.GT.0.0)THEN
            WRITE(ICOUT,13)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            PDF=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(X.LE.1.0/GAMMA .AND. GAMMA.LT.0.0)THEN
            WRITE(ICOUT,12)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,48)GAMMA
            CALL DPWRST('XXX','BUG ')
            PDF=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
   12   FORMAT('***** ERROR--FROM GEPPDF: X <= 1/GAMMA.')
   13   FORMAT('***** ERROR--FROM GEPPDF: X <= -1/GAMMA.')
!
!       COMPUTE THE PDF VALUE
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
!
        IF(IGEPDF.EQ.'JOHN')THEN
          DPDF=(1.0D0+DG*DX)**((1.0D0/DG)-1.0D0)
        ELSE
          DPDF=(1.0D0-DG*DX)**(-(1.0D0/DG)-1.0D0)
        ENDIF
        PDF=REAL(DPDF)
!
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEPPDF
      SUBROUTINE GEPPPF(P,GAMMA,MINMAX,IGEPDF,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED PARETO
!              DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE LENGTH PARAMETER = GAMMA.
!              THE GENERALIZED PARETO DENSITY FOR THE MAXIMUM
!              CASE HAS THE PERCENT POINT FUNCTION
!
!              G(P;GAMMA) = (-1/GAMMA)*(1.0 - (1-P)**(-GAMMA)))
!                           IF GAMMA < 0: 0 <= P < 1
!                           IF GAMMA > 0: 0 <= P <= 1
!
!                         = -LOG(1-P)
!                           0 < P <= 1, GAMMA = 0
!
!              SOME SOURCES (E.G., JOHNSON, KOTZ, AND BALAKRISHNAN
!              AND CASTILLO, HADI, BALAKRISHNAN, AND SARABIA)
!              USE THE PARAMETERIZATION GAMMA=-GAMMA:
!
!              G(P;GAMMA) = (1/GAMMA)*(1.0 - (1-P)**GAMMA))
!                           IF GAMMA < 0: 0 <= P <= 1
!                           IF GAMMA > 0: 0 <= P < 1
!
!                         = -LOG(1-P)
!                           0 < P <= 1, GAMMA = 0
!
!              THE GENERALIZED PARETO DENSITY FOR THE MINIMUM
!              CASE HAS THE PROBABILITY DENSITY FUNCTION
!
!              G(P;GAMMA) = (-1/GAMMA)*(P**(-GAMMA) - 1)
!                           IF GAMMA < 0: 0 <= P <= 1
!                           IF GAMMA > 0: 0 <  P <= 1
!
!                         = LOG(P)
!                           0 < P <= 1, GAMMA = 0
!
!              IN THE ALTERNATE PARAMETERIZATION
!
!              G(P;GAMMA) = (1/GAMMA)*(P**GAMMA - 1)
!                           IF GAMMA < 0: 0 <  P <= 1
!                           IF GAMMA > 0: 0 <= P <= 1
!
!                         = LOG(P)
!                           0 < P <= 1, GAMMA = 0
!
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA CAN BE NEGATIVE, 0, OR POSITIVE.
!                     --MINMAX = THE INTEGER VALUE, NOT CURRENTLY USED
!                     --IGEPDF = CHARACTER VALUE SPECIFYING WHETHER
!                                EMIL SIMIU OR JOHNSON AND KOTZ DEFINITION
!                                SHOULD BE USED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE GENERALIZED PARETO DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTIUOUS UNIVARIATE
!                 DISTRIBUTIONS--VOLUME 1", SECOND EDITION, PP. 614-620.
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA (2005),
!                 "EXTREME VALUES AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, PP. 65-66.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--93/12
!     ORIGINAL VERSION--DECEMBER  1993.
!     UPDATED         --JUNE      2004  ALTERNATE DEFINITION FOR
!                                       GENERAPLIZED PARETO (USES
!                                       DIFFERENT SIGN)
!     UPDATED         --JANUARY   2008  SUPPORT MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IGEPDF
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DG
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DP=DBLE(P)
      DG=DBLE(GAMMA)
      IF(GAMMA.EQ.0.0)THEN
        DPPF=(-DLOG(1.0D0-DP))
      ELSE
         IF(IGEPDF.EQ.'JOHN')THEN
            DPPF=(-1.0D0/DG)*(((1.0D0-DP)**DG)-1.0D0)
         ELSE
            DPPF=(1.0D0/DG)*(((1.0D0-DP)**(-DG))-1.0D0)
         ENDIF
      ENDIF
      PPF=REAL(DPPF)
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!
        IF(P.LT.0.0 .OR. P.GT.1.0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)P
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9000
        ENDIF
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEPPPF IS ',   &
               'OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
!
        IF(GAMMA.EQ.0.0)THEN
          IF(P.GE.1.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9000
          ENDIF
          DPPF=-DLOG(1.0D0 - DBLE(P))
          PPF=REAL(DPPF)
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(P.GE.1.0 .AND. GAMMA.LT.0.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(P.GE.1.0 .AND. GAMMA.GT.0.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!       COMPUTE THE PPF VALUE
!
        DP=DBLE(P)
        DG=DBLE(GAMMA)
!
        IF(IGEPDF.EQ.'JOHN')THEN
          DPPF=(1.0D0/DG)*(1.0D0 - (1.0D0 - DP)**DG)
        ELSE
          DPPF=(-1.0D0/DG)*(1.0D0 - (1.0D0 - DP)**(-DG))
        ENDIF
        PPF=REAL(DPPF)
!
!     NOW DO THE MINIMUM CASE
!
      ELSE
!
!       1) GAMMA = 0 CASE IS SAME FOR BOTH PARAMETERIZATIONS
!
        IF(P.LT.0.0 .OR. P.GT.1.0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)P
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9000
        ENDIF
!
        IF(GAMMA.EQ.0.0)THEN
          IF(P.LE.0.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9000
          ENDIF
          DPPF=DLOG(DBLE(P))
          PPF=REAL(DPPF)
          GO TO 9000
        ENDIF
!
        IF(IGEPDF.EQ.'JOHN')THEN
          IF(P.LE.0.0 .AND. GAMMA.LT.0.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9000
          ENDIF
        ELSE
          IF(P.LE.0.0 .AND. GAMMA.GT.0.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9000
          ENDIF
        ENDIF
!
!       COMPUTE THE PPF VALUE
!
        DP=DBLE(P)
        DG=DBLE(GAMMA)
!
        IF(IGEPDF.EQ.'JOHN')THEN
          DPPF=(1.0D0/DG)*(DP**DG - 1.0D0)
        ELSE
          DPPF=(-1.0D0/DG)*(DP**(-DG) - 1.0D0)
        ENDIF
        PPF=REAL(DPPF)
!
      ENDIF
!
                                                                                                                                  
                                                                                                                                  
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEPPPF
      SUBROUTINE GEDPPF(DP,DG,MINMAX,IGEPDF,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED PARETO
!              DISTRIBUTION WITH DOUBLE PRECISION
!              SHAPE LENGTH PARAMETER = GAMMA.
!              THE GENERALIZED PARETO DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PERCENT POINT FUNCTION
!                 G(P) = (1/GAMMA)*(((1-P)**(-GAMMA))-1.0)
!              JOHNSON, KOTZ, AND BALAKRISHNAN REVERSE THE SIGN:
!                 G(P) = (-1/GAMMA)*(((1-P)**GAMMA)-1.0)
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!
!              THIS VERSION IS A DOUBLE PRECISION VERSION.
!
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE
!                                (BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE DOUBLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA CAN BE NEGATIVE, 0, OR POSITIVE.
!                     --MINMAX = THE INTEGER VALUE, NOT CURRENTLY USED
!                     --IGEPDF = CHARACTER VALUE SPECIFYING WHETHER
!                                EMIL SIMIU OR JOHNSON AND KOTZ DEFINITION
!                                SHOULD BE USED.
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE GENERALIZED PARETO DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTIUOUS UNIVARIATE
!                 DISTRIBUTIONS--VOLUME 1", SECOND EDITION, PP. 614-620.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--2005/5
!     ORIGINAL VERSION--MAY       2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IGEPDF
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DG
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ISUBG4.EQ.'DPPF')THEN
        WRITE(ICOUT,52)IGEPDF,MINMAX,DP,DG
   52   FORMAT('IGEPDF,MINMAX,DP,DG = ',A4,2X,I5,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(DP.LE.0.0D0.OR.DP.GE.1.0D0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
               'GEDPPF IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        DPPF=0.0D0
        GO TO 9000
      ENDIF
!
      IF(DG.EQ.0.0D0)THEN
        DPPF=(-DLOG(1.0D0-DP))
      ELSE
         IF(IGEPDF.EQ.'JOHN')THEN
            DPPF=(-1.0D0/DG)*(((1.0D0-DP)**DG)-1.0D0)
         ELSE
            DPPF=(1.0D0/DG)*(((1.0D0-DP)**(-DG))-1.0D0)
         ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEDPPF
      SUBROUTINE GE2PPF(P,PPAR,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION
!              VALUE FOR THE GEOMETRIC DISTRIBUTION WITH DOUBLE
!              PRECISION 'BERNOULLI PROBABILITY' PARAMETER = PPAR.
!              THIS VERSION USES AN ALTERNATIVE DEFINITION
!              USED IN THE DIGITAL LIBRARY OF MATHEMATICAL FUNCTIONS.
!              THE GEOMETRIC DISTRIBUTION USED HEREIN HAS MEAN = 1/PPAR
!              AND STANDARD DEVIATION = SQRT((1-PPAR)/(PPAR*PPAR))).
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE INTEGER
!              X--X = 1, 2, ... .
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!
!                 p(X;PPAR) = PPAR * (1-PPAR)**(X-1).
!
!              THE GEOMETRIC DISTRIBUTION IS THE DISTRIBUTION OF THE
!              NUMBER OF FAILURES BEFORE OBTAINING 1 SUCCESS IN AN
!              INDEFINITE SEQUENCE OF BERNOULLI (0,1) TRIALS WHERE THE
!              PROBABILITY OF SUCCESS IN A SINGLE TRIAL = PPAR.
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE (BETWEEN
!                                0.0 (INCLUSIVELY) AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT FUNCTION IS
!                                TO BE EVALUATED.
!                     --PPAR   = THE DOUBLE PRECISION VALUE OF THE
!                                'BERNOULLI PROBABILITY' PARAMETER FOR
!                                THE GEOMETRIC DISTRIBUTION.  PPAR
!                                SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (INCLUSIVELY).
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE PPF
!             FOR THE GEOMETRIC DISTRIBUTION WITH 'BERNOULLI
!             PROBABILITY' PARAMETER VALUE = PPAR.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--PPAR SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (INCLUSIVELY).
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FELLER, AN INTRODUCTION TO PROBABILITY
!                 THEORY AND ITS APPLICATIONS, VOLUME 1,
!                 EDITION 2, 1957, PAGES 155-157, 210.
!               --NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 929.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-921-3651
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     2009. USE DOUBLE PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
      IF(P.LT.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(PPAR.LE.0.0D0 .OR. PPAR.GT.1.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PPAR
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GEOPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GEOPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(P.EQ.0.0D0)THEN
        PPF=1.0D0
      ELSEIF(PPAR.EQ.1.0D0)THEN
        PPF=1.0D0
      ELSE
!
        ARG1=1.0D0-P
        ARG2=1.0D0-PPAR
        ANUM=LOG(ARG1)
        ADEN=LOG(ARG2)
        RATIO=ANUM/ADEN
        IRATIO=INT(RATIO+0.99999D0)
        PPF=REAL(IRATIO)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GE2PPF
      SUBROUTINE GEPRAN(N,GAMMA,MINMAX,IGEPDF,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED PARETO DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE
!                                IDENTIFYING THE
!                                CHOSEN GEN. PARETO DISTRIBUTION.
!                                1 = MIN, 2 = MAX.
!                     --IGEPDF = CHARACTER VALUE SPECIFYING WHETHER
!                                EMIL SIMIU OR JOHNSON AND KOTZ DEFINITION
!                                SHOULD BE USED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED PARETO DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTIUOUS UNIVARIATE
!                 DISTRIBUTIONS--VOLUME 1", SECOND EDITION, PP. 614-620.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     VERSION NUMBER--93/12
!     ORIGINAL VERSION--DECEMBER  1993.
!     UPDATED         --JUNE      2004  ALTERNATE DEFINITION FOR
!                                       GENERAPLIZED PARETO (USES
!                                       DIFFERENT SIGN)
!     UPDATED         --JANUARY   2008  TO SUPPORT MINIMUM CASE, JUST
!                                       CALL GEPPPF INSTEAD OF
!                                       COMPUTING PPF INLINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!CCCC DOUBLE PRECISION DP
!CCCC DOUBLE PRECISION DG
!CCCC DOUBLE PRECISION DPPF
!
      CHARACTER*4 IGEPDF
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
!
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--FOR THE GENERALIZED PARETO DISTRIBUTION, ',   &
               'THE REQUESTED NUMBER OF RANDOM NUMBERS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
    6   FORMAT('      IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE REQUESTED NUMBER OF RANDOM NUMBERS IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
!     NOTE THAT GAMMA = 0 REDUCES TO AN EXPONENTIAL, SO HANDLE THAT CASE
!     SEPARATELY.  ALSO, JOHNSON, KOTZ, AND BALAKRISHNAN PARAMETERIZE
!     WITH THE SIGN OF THE SHAPE PARAMETER REVERSED.  HANDLE THAT CASE
!     SEPARATELY.
!
!CCCC IF(GAMMA.EQ.0.0)THEN
!CCCC   CALL EXPRAN(N,ISEED,X)
!CCCC ELSE
!CCCC   CALL UNIRAN(N,ISEED,X)
!
!       GENERATE N GENERALIZED PARETO DISTRIBUTION RANDOM NUMBERS
!       USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
!CCCC   DG=DBLE(GAMMA)
!
!CCCC   IF(IGEPDF.EQ.'JOHN')THEN
!CCCC     DO100I=1,N
!CCCC       DP=DBLE(X(I))
!CCCC       DPPF=(-1.0D0/DG)*(((1.0D0-DP)**DG)-1.0D0)
!CCCC       X(I)=REAL(DPPF)
!C100     CONTINUE
!CCCC   ELSE
!CCCC     DO200I=1,N
!CCCC       DP=DBLE(X(I))
!CCCC       DPPF=(1.0D0/DG)*(((1.0D0-DP)**(-DG))-1.0D0)
!CCCC       X(I)=REAL(DPPF)
!C200     CONTINUE
!CCCC   ENDIF
!CCCC ENDIF
!
      CALL UNIRAN(N,ISEED,X)
!
      DO 100 I=1,N
        PTEMP=X(I)
        CALL GEPPPF(PTEMP,GAMMA,MINMAX,IGEPDF,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEPRAN
      SUBROUTINE GETCDF(DX,DSHAPE,DBETA,IGETDF,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GEETA DISTRIBUTION WITH SHAPE
!              PARAMETERS THETA AND BETA.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL INTEGER X >= 1.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA)=
!                  (BETA*X-1  X)*THETA**(X-1)*(1-THETA)**(BETA*X-X)/
!                  (BETA*X-1)
!                  X = 1, 2, 3, ,...
!                  0 < THETA < 1; 1 <= BETA < 1/THETA
!
!              THE MEAN AND VARIANCE ARE:
!
!                  MU = (1-THETA)/(1-THETA*BETA)
!                  SIGMA**2 = (BETA-1)*THETA*(1-THETA)/
!                             (1-THETA*BETA)**3
!
!              THIS DISTRIBUTION IS SOMETIMES PARAMETERIZED USING
!              THE MEAN (MU) INSTEAD OF THETA.  THIS RESULTS IN
!              THE PROBABILITY MASS FUNCTION:
!              p(X;MU,BETA)=
!                  (BETA*X-1  X)*((MU-1)/(BETA*MU-1))**(X-1)*
!                  (MU*(BETA-1)/(BETA*MU-1))**(BETA*X-X)/(BETA*X-1)
!                  X = 1, 2, 3, ,...
!                  MU >= 1; BETA > 1
!              THE PROBABILITY MASS FUNCTION IS ALSO GIVEN AS
!              p(X;MU,BETA)=
!                  (BETA*X-1  X)*((MU-1)/(BETA*MU-MU))**(X-1)*
!                  (MU*(BETA-1)/(BETA*MU-1))**(BETA*X-1)/(BETA*X-1)
!
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED USING THE
!              FOLLOWING RECURRENCE RELATION:
!
!              F(1;MU,BETA) = ((BETA-1)*MU/(BETA*MU-1))**(BETA-1)
!              F(2;MU,BETA) = ((MU-1)/MU)*
!                             ((BETA-1)*MU/(BETA*MU-1))**(2*BETA-1)
!              F(X=k+1;MU,BETA) = PROD[i=1 to k][1 + BETA/(BETA*k-1)]*
!                                 ((MU-1)/MU)*
!                                 ((BETA-1)*MU/(BETA*MU-1))**BETA*
!                                 P(X=k;MU,BETA)
!
!              NOTE: THIS RECCURENCE RELATION DOES NOT SEEM TO
!                    RETURN ACCURATE RESULTS.  SO UNTIL THIS IS
!                    RESOLVED, JUST USE BRUTE FORCE AND CALL THE
!                    PDF FUNCTION.
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                DX SHOULD BE A NON-NEGATIVE INTEGER.
!                     --DSHAPE = THE FIRST SHAPE PARAMETER
!                                (EITHER THETA OR MU)
!                     --DBETA  = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE DCDF FOR THE GEETA DISTRIBUTION WITH SHAPE
!             PARAMETERS THETA (OR MU) AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--DX SHOULD BE A POSITIVE INTEGER
!                 --0 < THETA < 1; 1 < BETA < 1/THETA
!                 --MU >= 1; BETA > 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL (1990), "GEETA DISTRIBUTION AND ITS
!                 PROPERTIES", COMMUNICATIONS IN STATISTICS--
!                 THEORY AND METHODS, 19, PP. 3051-3068.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSHAPE
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DPDF
!
      CHARACTER*4 IGETDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IGETDF.EQ.'THET')THEN
        DTHETA=DSHAPE
      ELSE
        DMU=DSHAPE
      ENDIF
!
      IX=INT(DX+0.5D0)
      IF(IX.LT.1)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GETCDF IS LESS ',   &
      'THAN 1')
!
      IF(IGETDF.EQ.'THET')THEN
        IF(DTHETA.LE.0.0D0 .OR. DTHETA.GE.1.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DTHETA
          CALL DPWRST('XXX','BUG ')
          DCDF=0.0
          GO TO 9000
        ENDIF
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GETCDF IS NOT ',   &
               'IN THE INTERVAL (0,1)')
!
        IF(DBETA.LT.1.0D0 .OR. DBETA.GE.1.0D0/DTHETA)THEN
          WRITE(ICOUT,25)1.0D0/DTHETA
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DBETA
          CALL DPWRST('XXX','BUG ')
          DCDF=0.0
          GO TO 9000
        ENDIF
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GETCDF IS NOT ',   &
               'IN THE INTERVAL (1,',G15.7,')')
      ELSE
        IF(DMU.LT.1.0D0)THEN
          WRITE(ICOUT,35)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DMU
          CALL DPWRST('XXX','BUG ')
          DCDF=0.0
          GO TO 9000
        ENDIF
   35   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GETCDF IS ',   &
               'LESS THAN 1')
!
        IF(DBETA.LE.1.0D0)THEN
          WRITE(ICOUT,38)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DBETA
          CALL DPWRST('XXX','BUG ')
          DCDF=0.0
          GO TO 9000
        ENDIF
   38   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GETCDF IS ',   &
               'LESS THAN OR EQUAL TO 1')
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!CCCC USE PDF FUNCTION UNTIL WE GET RECURRENCE RELATION RESOLVED.
!
      IF(IGETDF.EQ.'THET')THEN
        IF(DBETA.LE.1.0D0)THEN
          DCDF=1.0D0
        ELSE
          DCDF=0.0D0
          DO 100 I=IX,1,-1
            CALL GETPDF(DBLE(I),DTHETA,DBETA,IGETDF,DPDF)
            DCDF=DCDF + DPDF
  100     CONTINUE
        ENDIF
      ELSE
        IF(DMU.LE.1.0D0)THEN
          DCDF=1.0D0
        ELSE
          DCDF=0.0D0
          DO 200 I=IX,1,-1
            CALL GETPDF(DBLE(I),DMU,DBETA,IGETDF,DPDF)
            DCDF=DCDF + DPDF
  200     CONTINUE
        ENDIF
      ENDIF
!
!CCCC IF(IGETDF.EQ.'THET')THEN
!CCCC   DTHETA=DBLE(THETA)
!CCCC   DMU=(1.0D0 - DTHETA)/(1.0D0 - DTHETA*DBETA)
!CCCC ELSE
!CCCC   DMU=DBLE(MU)
!CCCC ENDIF
!
!CCCC DCDF=((DBETA-1.0D0)*DMU/(DBETA*DMU-1.0D0))**(DBETA-1.0D0)
!CCCC IF(IX.LE.1)THEN
!CCCC   CDF=REAL(DCDF)
!CCCC   GO TO 9000
!CCCC ENDIF
!CCCC DPDF=((DMU-1.0D0)/DMU)*
!CCCC1     ((DBETA-1.0D0)*DMU/(DBETA*DMU-1.0D0))**(2.0D0*DBETA-1.0D0)
!CCCC DCDF=DCDF+DPDF
!CCCC IF(IX.LE.2)THEN
!CCCC   CDF=REAL(DCDF)
!CCCC   GO TO 9000
!CCCC ENDIF
!CCCC DPDFSV=DPDF
!
!CCCC DTERM1=DLOG(DMU-1.0D0) - DLOG(DMU)
!CCCC DTERM2=DBETA*(DLOG(DBETA-1.0D0)+DLOG(DMU)-DLOG(DBETA*DMU-1.0D0))
!CCCC DO100I=3,IX
!CCCC   K=I-1
!CCCC   DX=DBLE(I)
!CCCC   DSUM=0.0D0
!CCCC   DO200J=1,K
!CCCC     DSUM=DSUM+DLOG(1.0D0+DBETA/(DBETA*DBLE(K)-DBLE(J)))
!C200   CONTINUE
!CCCC   IF(DPDFSV.GT.0.0D0)THEN
!CCCC     DTERM3=DLOG(DPDFSV)
!CCCC     DPDF=DEXP(DTERM3 + DSUM + DTERM1 + DTERM2)
!CCCC   ELSE
!CCCC     CDF=REAL(DCDF)
!CCCC     GO TO 9000
!CCCC   ENDIF
!CCCC   DCDF=DCDF + DPDF
!CCCC   DPDFSV=DPDF
!C100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GETCDF
      DOUBLE PRECISION FUNCTION GETFUN(DBETA)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GEETA MEAN AND ONES FREQUENCY EQUATION.
!
!              THE MEAN AND ONES FREQUENCY ESTIMATE OF MU IS:
!
!                  MUHAT = XBAR
!
!              THE ESTIMATE OF BETA IS THEN THE SOLUTION OF THE
!              EQUATION
!
!                 ((BETA-1)*XBAR/(BETA*XBAR-1))**(BETA-1) - (N1/N) = 0
!
!              CALLED BY DFZERO ROUTINE FOR SOLVING A NONLINEAR
!              UNIVARIATE EQUATION.
!     EXAMPLE--GEETA MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DBETA
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION F1FREQ
      COMMON/GETCOM/XBAR,S2,F1FREQ,MAXROW,N
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      GETFUN=((DBETA-1.0D0)*XBAR/(DBETA*XBAR-1.0D0))**(DBETA-1.0D0) -   &
             F1FREQ
!
      RETURN
      END FUNCTION GETFUN
      SUBROUTINE GETFU2(N,XPAR,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GEETA MAXIMUM LIKELIHOOD EQUATION.
!
!              THE MAXIMUM LIKELIHOOD FREQUENCY ESTIMATE OF MU IS:
!
!                  MUHAT = XBAR
!
!              THE ESTIMATE OF BETA IS THEN THE SOLUTION OF THE
!              EQUATION
!
!                 ((BETA-1)*XBAR/(BETA*XBAR-1))**(BETA-1) -
!                 (1/(N*XBAR))*
!                 SUM[X=2 to k][SUM[i=2 to k][X*N(x)/(BETA*X-1)]] = 0
!
!              THIS ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--GEETA MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DFREQ
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION F1FREQ
      COMMON/GETCOM/XBAR,S2,F1FREQ,MAXROW,NTOT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      N=2
      IFLAG=0
!
      DBETA=XPAR(1)
      DN=DBLE(NTOT)
      IINDX=MAXROW/2
!
      DTERM1=(DBETA - 1.0D0)*XBAR/(DBETA*XBAR - 1.0D0)
      DTERM2=1.0D0/(DN*XBAR)
!
      DSUM1=0.0D0
      DO 100 I=2,K
        DX=DBLE(Y(IINDX+I))
        DFREQ=Y(I)
        DO 200 J=2,I
          DX2=DBLE(Y(IINDX+J))
          DSUM1=DSUM1 + DX*DFREQ/(DBETA*DX - DX2)
  200   CONTINUE
  100 CONTINUE
!
      DTERM3=DTERM2*DSUM1
      FVEC(1)=DEXP(-DTERM3) - DTERM1
!
      RETURN
      END SUBROUTINE GETFU2
      SUBROUTINE GETPDF(DX,DSHAPE,DBETA,IGETDF,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE FOR THE GEETA DISTRIBUTION WITH SHAPE
!              PARAMETERS THETA AND BETA.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL INTEGER X >= 1.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA)=
!                  (BETA*X-1  X)*THETA**(X-1)*(1-THETA)**(BETA*X-X)/
!                  (BETA*X-1)
!                  X = 1, 2, 3, ,...
!                  0 < THETA < 1; 1 <= BETA < 1/THETA
!
!              THE MEAN AND VARIANCE ARE:
!
!                  MU = (1-THETA)/(1-THETA*BETA)
!                  SIGMA**2 = (BETA-1)*THETA*(1-THETA)/
!                             (1-THETA*BETA)**3
!
!              THIS DISTRIBUTION IS SOMETIMES PARAMETERIZED USING
!              THE MEAN (MU) INSTEAD OF THETA.  THIS RESULTS IN
!              THE PROBABILITY MASS FUNCTION:
!              p(X;MU,BETA)=
!                  (BETA*X-1  X)*((MU-1)/(BETA*MU-1))**(X-1)*
!                  (MU*(BETA-1)/(BETA*MU-1))**(BETA*X-X)/(BETA*X-1)
!                  X = 1, 2, 3, ,...
!                  MU >= 1; BETA > 1
!              THE PROBABILITY MASS FUNCTION IS ALSO GIVEN AS
!              p(X;MU,BETA)=
!                  (BETA*X-1  X)*((MU-1)/(BETA*MU-MU))**(X-1)*
!                  (MU*(BETA-1)/(BETA*MU-1))**(BETA*X-1)/(BETA*X-1)
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --DSHAPE = THE FIRST SHAPE PARAMETER
!                                (EITHER THETA OR MU)
!                     --DBETA  = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY MASS
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS FUNCTION VALUE
!             PDF FOR THE GEETA
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A POSITIVE INTEGER
!                 --0 < THETA < 1; 1 < BETA < 1/THETA
!                 --MU >= 1; BETA > 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL (1990), "GEETA DISTRIBUTION AND ITS
!                 PROPERTIES", COMMUNICATIONS IN STATISTICS--
!                 THEORY AND METHODS, 19, PP. 3051-3068.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSHAPE
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DPDF
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DLNGAM
!
      CHARACTER*4 IGETDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IGETDF.EQ.'THET')THEN
        DTHETA=DSHAPE
      ELSE
        DMU=DSHAPE
      ENDIF
!
      IX=INT(DX+0.5D0)
      IF(IX.LT.1)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GETPDF IS LESS ',   &
      'THAN 1')
!
      IF(IGETDF.EQ.'THET')THEN
        IF(DTHETA.LE.0.0D0 .OR. DTHETA.GE.1.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DTHETA
          CALL DPWRST('XXX','BUG ')
          DPDF=0.0
          GO TO 9000
        ENDIF
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GETPDF IS NOT ',   &
               'IN THE INTERVAL (0,1)')
!
        IF(DBETA.LT.1.0D0 .OR. DBETA.GE.1.0D0/DTHETA)THEN
          WRITE(ICOUT,25)1.0D0/DTHETA
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DBETA
          CALL DPWRST('XXX','BUG ')
          DPDF=0.0
          GO TO 9000
        ENDIF
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GETPDF IS NOT ',   &
               'IN THE INTERVAL (1,',G15.7,')')
      ELSE
        IF(DMU.LT.1.0D0)THEN
          WRITE(ICOUT,35)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DMU
          CALL DPWRST('XXX','BUG ')
          DPDF=0.0
          GO TO 9000
        ENDIF
   35   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GETPDF IS ',   &
               'LESS THAN 1')
!
        IF(DBETA.LE.1.0D0)THEN
          WRITE(ICOUT,38)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DBETA
          CALL DPWRST('XXX','BUG ')
          DPDF=0.0
          GO TO 9000
        ENDIF
   38   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GETPDF IS ',   &
               'LESS THAN OR EQUAL TO 1')
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(IX)
!
      IF(IGETDF.EQ.'THET')THEN
        IF(DBETA.LE.1.0D0)THEN
          IF(IX.EQ.1)THEN
            DPDF=1.0D0
          ELSE
            DPDF=0.0D0
          ENDIF
        ELSE
          DTERM1=DLNGAM(DBETA*DX) + (DX-1.0D0)*DLOG(DTHETA) +   &
                 (DBETA*DX-DX)*DLOG(1.0D0 - DTHETA)
          DTERM2=DLNGAM(DX+1.0D0) + DLOG(DBETA*DX-1.0D0)
          DTERM3=DLNGAM(DBETA*DX-DX)
          DTERM4=DTERM1 - DTERM2 - DTERM3
          DPDF=DEXP(DTERM4)
        ENDIF
      ELSE
        IF(DMU.LE.1.0D0)THEN
          IF(IX.EQ.1)THEN
            DPDF=1.0D0
          ELSE
            DPDF=0.0D0
          ENDIF
        ELSE
          DTERM1=-DLOG(DBETA*DX - 1.0D0)
          DTERM2=DLNGAM(DBETA*DX) - DLNGAM(DX+1.0D0) -   &
                 DLNGAM(DBETA*DX-DX)
          DTERM3=(DX-1.0D0)*(DLOG(DMU-1.0D0) - DLOG(DMU) -   &
                 DLOG(DBETA-1.0D0))
          DTERM4=(DBETA*DX-1.0D0)*(DLOG(DBETA*DMU - DMU) -   &
                 DLOG(DBETA*DMU - 1.0D0))
          DTERM5=DTERM1 + DTERM2 + DTERM3+ DTERM4
          DPDF=DEXP(DTERM5)
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GETPDF
      SUBROUTINE GETPPF(DP,DSHAPE,DBETA,IGETDF,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GEETA DISTRIBUTION WITH SHAPE
!              PARAMETERS THETA AND BETA.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL INTEGER X >= 1.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA)=
!                  (BETA*X-1  X)*THETA**(X-1)*(1-THETA)**(BETA*X-X)/
!                  (BETA*X-1)
!                  X = 1, 2, 3, ,...
!                  0 < THETA < 1; 1 <= BETA < 1/THETA
!
!              THE MEAN AND VARIANCE ARE:
!
!                  MU = (1-THETA)/(1-THETA*BETA)
!                  SIGMA**2 = (BETA-1)*THETA*(1-THETA)/
!                             (1-THETA*BETA)**3
!
!              THIS DISTRIBUTION IS SOMETIMES PARAMETERIZED USING
!              THE MEAN (MU) INSTEAD OF THETA.  THIS RESULTS IN
!              THE PROBABILITY MASS FUNCTION:
!              p(X;MU,BETA)=
!                  (BETA*X-1  X)*((MU-1)/(BETA*MU-1))**(X-1)*
!                  (MU*(BETA-1)/(BETA*MU-1))**(BETA*X-X)/(BETA*X-1)
!                  X = 1, 2, 3, ,...
!                  MU >= 1; BETA > 1
!              THE PROBABILITY MASS FUNCTION IS ALSO GIVEN AS
!              p(X;MU,BETA)=
!                  (BETA*X-1  X)*((MU-1)/(BETA*MU-MU))**(X-1)*
!                  (MU*(BETA-1)/(BETA*MU-1))**(BETA*X-1)/(BETA*X-1)
!
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              BY SUMMING THE PROBABILITY MASS FUNCTION.  THE
!              PERCENT POINT FUNCTION IS COMPUTED BY COMPUTING THE
!              CUMULATIVE DISTRIBUTION UNTIL THE APPROPRIATE
!              PROBABILITY IS REACHED.
!
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DSHAPE = THE FIRST SHAPE PARAMETER
!                                (EITHER THETA OR MU)
!                     --DBETA  = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE DCDF FOR THE GEETA DISTRIBUTION WITH SHAPE
!             PARAMETERS THETA (OR MU) AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= DP < 1
!                 --0 < THETA < 1; 1 < BETA < 1/THETA
!                 --MU >= 1; BETA > 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL (1990), "GEETA DISTRIBUTION AND ITS
!                 PROPERTIES", COMMUNICATIONS IN STATISTICS--
!                 THEORY AND METHODS, 19, PP. 3051-3068.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DSHAPE
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DPPF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DEPS
!
      CHARACTER*4 IGETDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IGETDF.EQ.'THET')THEN
        DTHETA=DSHAPE
      ELSE
        DMU=DSHAPE
      ENDIF
!
      IF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        DPPF=0.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GETPPF IS OUTSIDE ',   &
      'THE (0,1] INTERVAL')
!
      IF(IGETDF.EQ.'THET')THEN
        IF(DTHETA.LE.0.0D0 .OR. DTHETA.GE.1.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DTHETA
          CALL DPWRST('XXX','BUG ')
          DPPF=0.0
          GO TO 9000
        ENDIF
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GETPPF IS NOT ',   &
               'IN THE INTERVAL (0,1)')
!
        IF(DBETA.LT.1.0D0 .OR. DBETA.GE.1.0D0/DTHETA)THEN
          WRITE(ICOUT,25)1.0D0/DTHETA
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DBETA
          CALL DPWRST('XXX','BUG ')
          DPPF=0.0
          GO TO 9000
        ENDIF
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GETPPF IS NOT ',   &
               'IN THE INTERVAL (1,',G15.7,')')
      ELSE
        IF(DMU.LT.1.0D0)THEN
          WRITE(ICOUT,35)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DMU
          CALL DPWRST('XXX','BUG ')
          DPPF=0.0
          GO TO 9000
        ENDIF
   35   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GETPPF IS ',   &
               'LESS THAN 1')
!
        IF(DBETA.LE.1.0D0)THEN
          WRITE(ICOUT,38)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DBETA
          CALL DPWRST('XXX','BUG ')
          DPPF=0.0
          GO TO 9000
        ENDIF
   38   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GETPPF IS ',   &
               'LESS THAN OR EQUAL TO 1')
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!CCCC USE PDF FUNCTION UNTIL WE GET RECURRENCE RELATION RESOLVED.
!
      IF(IGETDF.EQ.'THET')THEN
        IF(DBETA.LE.1.0D0)THEN
          DPPF=1.0D0
        ELSE
          I=0
          DCDF=0.0D0
          DEPS=1.0D-7
  100     CONTINUE
          I=I+1
          IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
            WRITE(ICOUT,55)
   55       FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                   'EXCEEDS THE LARGEST MACHINE INTEGER.')
            CALL DPWRST('XXX','BUG ')
            DPPF=0.0D0
            GO TO 9000
          ENDIF
          DX=DBLE(I)
          CALL GETPDF(DX,DTHETA,DBETA,IGETDF,DPDF)
          DCDF=DCDF + DPDF
          IF(DCDF.GE.DP-DEPS)THEN
            DPPF=DX
            GO TO 9000
          ENDIF
          GO TO 100
        ENDIF
      ELSE
        IF(DMU.LE.1.0D0)THEN
          DPPF=1.0D0
        ELSE
          I=0
          DCDF=0.0D0
          DEPS=1.0D-7
  200     CONTINUE
          I=I+1
          IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
            WRITE(ICOUT,55)
            CALL DPWRST('XXX','BUG ')
            DPPF=0.0D0
            GO TO 9000
          ENDIF
          DX=DBLE(I)
          CALL GETPDF(DX,DMU,DBETA,IGETDF,DPDF)
          DCDF=DCDF + DPDF
          IF(DCDF.GE.DP-DEPS)THEN
            DPPF=DX
            GO TO 9000
          ENDIF
          GO TO 200
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GETPPF
      SUBROUTINE GETRAN(N,SHAPE,BETA,IGETDF,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GEETA DISTRIBUTION WITH SHAPE PARAMETERS
!              THETA OR MU AND BETA.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA)=
!                  (BETA*X-1  X)*THETA**(X-1)*(1-THETA)**(BETA*X-X)/
!                  (BETA*X-1)
!                  X = 1, 2, 3, ,...
!                  0 < THETA < 1; 1 <= BETA < 1/THETA
!
!              THE MEAN AND VARIANCE ARE:
!
!                  MU = (1-THETA)/(1-THETA*BETA)
!                  SIGMA**2 = (BETA-1)*THETA*(1-THETA)/
!                             (1-THETA*BETA)**3
!
!              THIS DISTRIBUTION IS SOMETIMES PARAMETERIZED USING
!              THE MEAN (MU) INSTEAD OF THETA.  THIS RESULTS IN
!              THE PROBABILITY MASS FUNCTION:
!              p(X;MU,BETA)=
!                  (BETA*X-1  X)*((MU-1)/(BETA*MU-1))**(X-1)*
!                  (MU*(BETA-1)/(BETA*MU-1))**(BETA*X-X)/(BETA*X-1)
!                  X = 1, 2, 3, ,...
!                  MU >= 1; BETA > 1
!              THE PROBABILITY MASS FUNCTION IS ALSO GIVEN AS
!              p(X;MU,BETA)=
!                  (BETA*X-1  X)*((MU-1)/(BETA*MU-MU))**(X-1)*
!                  (MU*(BETA-1)/(BETA*MU-1))**(BETA*X-1)/(BETA*X-1)
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --SHAPE  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GEETA DISTRIBUTION
!             WITH SHAPE PARAMETERS THETA (OR MU) AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 < THETA < 1, 1 < BETA < 1/THETA
!                   MU >= 1; BETA > 1
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GETPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL (1990), "GEETA DISTRIBUTION AND ITS
!                 PROPERTIES", COMMUNICATIONS IN STATISTICS--
!                 THEORY AND METHODS, 19, PP. 3051-3068.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 8.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      CHARACTER*4 IGETDF
!
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF GEETA RANDOM ',   &
             'NUMBERS IS NON-POSITIVE')
!
      IF(IGETDF.EQ.'THET')THEN
        THETA=SHAPE
        IF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,16)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)THETA
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
   15   FORMAT('***** ERROR--THE THETA PARAMETER FOR THE GEETA')
   16   FORMAT('      RANDOM NUMBERS IS OUTSIDE THE (0,1) INTERVAL')
!
        IF(BETA.LE.1.0 .OR. BETA.GE.1.0/THETA)THEN
          WRITE(ICOUT,25)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,26)1.0/THETA
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)BETA
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
   25   FORMAT('***** ERROR--THE BETA PARAMETER FOR THE GEETA')
   26   FORMAT('      RANDOM NUMBERS IS OUTSIDE THE (1,',G15.7,') ',   &
               'INTERVAL')
      ELSE
        AMU=SHAPE
        IF(AMU.LT.1.0)THEN
          WRITE(ICOUT,35)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,36)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)AMU
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
   35   FORMAT('***** ERROR--THE MU PARAMETER FOR THE GEETA')
   36   FORMAT('      RANDOM NUMBERS IS LESS THAN 1')
!
        IF(BETA.LE.1.0)THEN
          WRITE(ICOUT,38)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,39)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)BETA
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
   38   FORMAT('***** ERROR--THE BETA PARAMETER FOR THE GEETA')
   39   FORMAT('      RANDOM NUMBERS IS LESS THAN OR EQUAL TO 1')
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N GEETA DISTRIBUTION RANDOM NUMBERS USING THE
!     INVERSION METHOD.
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        XTEMP=X(I)
        CALL GETPPF(DBLE(XTEMP),DBLE(SHAPE),DBLE(BETA),IGETDF,DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9000 CONTINUE
!
      RETURN
      END SUBROUTINE GETRAN
      SUBROUTINE GEVCDF(X,GAMMA,MINMAX,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED EXTREME VALUE
!              DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE PARAMETER = GAMMA.
!              THERE ARE TWO GENERALIZED EXTREME VALUE FAMALIES:
!              ONE BASED ON THE MAXIMUM ORDER STATISTIC (THE MOST
!              COMMONLY USED, SPECIFIED BY MINMAX=2) AND THE OTHER
!              BASED ON THE MINIMUM ORDER STATISTIC (SPECIFIED BY
!              SET MINMAX = 1).
!
!              THE CUMUALTIVE DISTRIBUTION FUNCTION FOR THE MAXIMUM
!              CASE OF THE GENERALIZED EXTREME VALUE DISTRIBUTION IS:
!              F(X,G) = EXP(-EXP(-X))                          G = 0
!                     = EXP(-(1 - GAMMA*X)**(1/GAMMA)]         G <> 0
!                                     1 - GAMMA*X >= 0
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION FOR THE MINIMUM CASE
!              OF THE GENERALIZED EXTREME VALUE DISTRIBUTION IS:
!              F(X,G) = 1 - EXP(-EXP(X))                       G = 0
!                     = 1 - EXP(-(1 + GAMMA*X)**(1/GAMMA)]     G <> 0
!                                     1 + GAMMA*X >= 0
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GENERALIZED EXTREME VALUE
!             DISTRIBUTION WITH SHAPE PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--RANGE OF X DEPENDS ON SIGN OF GAMMA
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 75-76
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA,
!                 "EXTREME VALUE AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, 2005, PP. 64-65.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--OCTOBER   1995.
!     UPDATED         --MAY       2005. SUPPORT FOR MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DG
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     MAY 2005.  HANDLE MIN AND MAX CASES SEPARATELY.
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
        IF(GAMMA.GT.0.0)THEN
          IF(X.GE.(1.0/GAMMA))THEN
            CDF=1.0
            GO TO 9999
          ENDIF
        ELSEIF(GAMMA.LT.0.0)THEN
          IF(X.LE.(1.0/GAMMA))THEN
            CDF=0.0
            GO TO 9999
          ENDIF
        ENDIF
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
        DCDF=0.0D0
!
        IF(GAMMA.EQ.0.0)THEN
          IF(DX.GE.40.D0)THEN
            DCDF=1.0D0
          ELSEIF(DX.LE.-40.D0)THEN
            DCDF=0.0D0
          ELSE
            DTERM1=-DEXP(-DX)
            IF(DTERM1.GE.0.0D0)THEN
              DCDF=1.0D0
            ELSE
              DCDF=DEXP(DTERM1)
            ENDIF
          ENDIF
        ELSE
          IF(GAMMA.GT.0.0.AND.X.EQ.1.0/GAMMA)THEN
            DCDF=1.0D0
          ELSEIF(GAMMA.LT.0.0.AND.X.EQ.1.0/GAMMA)THEN
            DCDF=0.0D0
          ELSE
            DTERM1=-(1.D0-DX*DG)**(1.D0/DG)
            IF(DTERM1.LT.-40.0D0)THEN
              DCDF=0.0D0
            ELSEIF(DTERM1.GE.0.0D0)THEN
              DCDF=1.0D0
            ELSE
              DCDF=DEXP(DTERM1)
            ENDIF
          END IF
        END IF
        CDF=REAL(DCDF)
      ELSE
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
        IF(GAMMA.GT.0.0)THEN
          IF(X.LE.(-1.0/GAMMA))THEN
            CDF=0.0
            GO TO 9999
          ENDIF
        ELSEIF(GAMMA.LT.0.0)THEN
          IF(X.GE.(-1.0/GAMMA))THEN
            CDF=1.0
            GO TO 9999
          ENDIF
        ENDIF
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
        DCDF=0.D0
!
        IF(GAMMA.EQ.0.0)THEN
          DTERM1=DEXP(DX)
          DCDF=1.0D0 - DEXP(-DTERM1)
        ELSE
          IF(GAMMA.GT.0.0.AND.X.EQ.-1.0/GAMMA)THEN
            DCDF=0.0D0
          ELSEIF(GAMMA.LT.0.0.AND.X.EQ.-1.0/GAMMA)THEN
            DCDF=1.0D0
          ELSE
            DTERM1=-(1.D0+DX*DG)**(1.D0/DG)
            DCDF=1.0D0 - DEXP(DTERM1)
          END IF
        END IF
        CDF=REAL(DCDF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEVCDF
      SUBROUTINE GEVCHA(X,GAMMA,MINMAX,CHAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE GENERALIZED EXTREME VALUE
!              DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE PARAMETER = GAMMA.
!              THERE ARE TWO GENERALIZED EXTREME VALUE FAMALIES:
!              ONE BASED ON THE MAXIMUM ORDER STATISTIC (THE MOST
!              COMMONLY USED, SPECIFIED BY MINMAX=2) AND THE OTHER
!              BASED ON THE MINIMUM ORDER STATISTIC (SPECIFIED BY
!              SET MINMAX = 1).
!
!              THE CUMUALTIVE DISTRIBUTION FUNCTION FOR THE MAXIMUM
!              CASE OF THE GENERALIZED EXTREME VALUE DISTRIBUTION IS:
!              F(X,G) = EXP(-EXP(-X))                          G = 0
!                     = EXP(-(1 - GAMMA*X)**(1/GAMMA)]         G <> 0
!                                     1 - GAMMA*X >= 0
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION FOR THE MINIMUM CASE
!              OF THE GENERALIZED EXTREME VALUE DISTRIBUTION IS:
!              F(X,G) = 1 - EXP(-EXP(X))                       G = 0
!                     = 1 - EXP(-(1 + GAMMA*X)**(1/GAMMA)]     G <> 0
!                                     1 + GAMMA*X >= 0
!
!              THE CUMULATIVE HAZARD IS THEN
!
!              H(X,G) = -LOG(1 - F(X,G))
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE SHAPE PARAMETER.
!                     --MINMAX = THE INTEGER VALUE THAT SPECIES
!                                THE MINIMUM/MAXIMUM CASE.
!     OUTPUT ARGUMENTS--CHAZ   = THE SINGLE PRECISION CUMULATIVE
!                                HAZARD FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE CDF FOR THE GENERALIZED EXTREME VALUE
!             DISTRIBUTION WITH SHAPE PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--RANGE OF X DEPENDS ON SIGN OF GAMMA
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 75-76
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA,
!                 "EXTREME VALUE AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, 2005, PP. 64-65.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MAY       2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DCHAZ
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     MAY 2005.  HANDLE MIN AND MAX CASES SEPARATELY.
!
    4 FORMAT('****** ERROR FROM GEVCHAZ--THE CDF VALUE IS 1 WHICH ',   &
             'RESULTS IN AN UNDEFINED CUMULATIVE HAZARD.')
   46 FORMAT('****** THE VALUE OF THE INPUT ARGUMENT IS  ',G15.7)
   47 FORMAT('****** THE VALUE OF THE SHAPE PARAMETER IS ',G15.7)
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
        IF(GAMMA.GT.0.0)THEN
          IF(X.GE.(1.0/GAMMA))THEN
            CHAZ=0.0
            WRITE(ICOUT,4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            GO TO 9999
          ENDIF
        ELSEIF(GAMMA.LT.0.0)THEN
          IF(X.LE.(1.0/GAMMA))THEN
            CHAZ=0.0
            GO TO 9999
          ENDIF
        ENDIF
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
        DCDF=0.0D0
        DCHAZ=0.0D0
!
        IF(GAMMA.EQ.0.0)THEN
          DTERM1=-DEXP(-DX)
          DCDF=DEXP(DTERM1)
          IF(DCDF.GE.1.0D0)THEN
            CHAZ=0.0
            WRITE(ICOUT,4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            GO TO 9999
          ELSE
            DCHAZ=-DLOG(1.0D0 - DCDF)
          ENDIF
        ELSE
          DTERM1=-(1.D0-DX*DG)**(1.D0/DG)
          DCDF=DEXP(DTERM1)
          IF(DCDF.GE.1.0D0)THEN
            CHAZ=0.0
            WRITE(ICOUT,4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            GO TO 9999
          ELSE
            DCHAZ=-DLOG(1.0D0 - DCDF)
          ENDIF
        ENDIF
      ELSE
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
        IF(GAMMA.GT.0.0)THEN
          IF(X.LE.(-1.0/GAMMA))THEN
            CHAZ=0.0
            GO TO 9999
          ENDIF
        ELSEIF(GAMMA.LT.0.0)THEN
          IF(X.GE.(-1.0/GAMMA))THEN
            CHAZ=0.0
            WRITE(ICOUT,4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            GO TO 9999
          ENDIF
        ENDIF
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
        DCHAZ=0.D0
!
        IF(GAMMA.EQ.0.0)THEN
          DCHAZ=DEXP(DX)
        ELSE
          DCHAZ=(1.D0+DX*DG)**(1.D0/DG)
        END IF
      ENDIF
      CHAZ=REAL(DCHAZ)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEVCHA
      SUBROUTINE GEVHAZ(X,GAMMA,MINMAX,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE GENERALIZED EXTREME VALUE
!              DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE PARAMETER = GAMMA.
!              THERE ARE TWO GENERALIZED EXTREME VALUE FAMALIES:
!              ONE BASED ON THE MAXIMUM ORDER STATISTIC (THE MOST
!              COMMONLY USED, SPECIFIED BY MINMAX=2) AND THE OTHER
!              BASED ON THE MINIMUM ORDER STATISTIC (SPECIFIED BY
!              SET MINMAX = 1).
!
!              THE HAZARD IS DEFINED AS
!
!              H(X,G) = f(X,G)/(1 - F(X,G))
!
!              WHERE f AND F ARE THE PROBABILITY DENSITY AND
!              CUMULATIVE DISTRIBUTION FUNCTIONS, RESPECTIVELY.
!
!              FOR THE MAXIMUM CASE, THIS ROUTINE CALLS GEVPDF AND
!              GEVCDF AND THEN USES THE ABOVE FORMULA.  FOR THE
!              MINIMUM CASE, THE HAZARD FUNCTION REDUCES TO:
!
!              H(X,G) = (1 + G*X)**((1/G)-1)              G <> 0
!              H(X,G) = EXP(X)                            G = 0
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE HAZARD FUNCTION IS TO
!                                BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE SHAPE PARAMETER.
!                     --MINMAX = THE INTEGER VALUE THAT SPECIFIES
!                                THE MINIMUM/MAXIMUM CASE
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD FUNCTION VALUE HAZ FOR THE
!             GENERALIZED EXTREME VALUE DISTRIBUTION WITH
!             SHAPE PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--RANGE OF X DEPENDS ON SIGN OF GAMMA
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 75-76
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA,
!                 "EXTREME VALUE AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, 2005, PP. 64-65.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MAY       2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DG
      DOUBLE PRECISION DHAZ
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     MAY 2005.  HANDLE MIN AND MAX CASES SEPARATELY.
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
        IF(GAMMA.GT.0.0)THEN
          IF(X.GT.(1.0/GAMMA))THEN
            WRITE(ICOUT,4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9999
          ENDIF
        ELSEIF(GAMMA.LT.0.0)THEN
          IF(X.LT.(1.0/GAMMA))THEN
            WRITE(ICOUT,14)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9999
          ENDIF
        ENDIF
    4   FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO GEVHAZ ',   &
               'IS GREATER THAN 1/GAMMA.')
   14   FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO GEVHAZ ',   &
               'IS LESS THAN 1/GAMMA.')
   16   FORMAT('***** ERROR--FOR THE GEVHAZ FUNCTION, THE ',   &
               'CDF IS EQUAL TO 1.')
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47   FORMAT('***** THE VALUE OF GAMMA IS ',G15.7)
!
        CALL GEVCDF(X,GAMMA,MINMAX,CDF)
        IF(CDF.GE.1.0)THEN
          WRITE(ICOUT,16)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,47)GAMMA
          CALL DPWRST('XXX','BUG ')
          HAZ=0.0
          GO TO 9999
        ENDIF
        CALL GEVPDF(X,GAMMA,MINMAX,PDF)
        HAZ=PDF/(1.0 - CDF)
      ELSE
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
        IF(GAMMA.GT.0.0)THEN
          IF(X.LE.(-1.0/GAMMA))THEN
            WRITE(ICOUT,24)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9999
          ENDIF
        ELSEIF(GAMMA.LT.0.0)THEN
          IF(X.GE.(-1.0/GAMMA))THEN
            WRITE(ICOUT,34)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            HAZ=0.0
            GO TO 9999
          ENDIF
        ENDIF
   24   FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO GEVHAZ ',   &
               'IS LESS THAN -1/GAMMA.')
   34   FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO GEVHAZ ',   &
               'IS GREATER THAN -1/GAMMA.')
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
        DHAZ=0.D0
!
        IF(GAMMA.EQ.0.0)THEN
          DHAZ=DEXP(DX)
        ELSE
          DHAZ=(1.0D0+DX*DG)**((1.D0/DG)-1.0)
        END IF
        HAZ=REAL(DHAZ)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEVHAZ
      SUBROUTINE GEVLI1(Y,N,MINMAX,ALOC,SCALE,SHAPE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR THE
!              GENERALIZED EXTREME VALUE DISTRIBUTION.  THIS IS FOR THE
!              RAW DATA CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--CASTILLO, HADI, BALAKRISHNAN, SARABIA, "EXTREME
!                VALUE AND RELATED MODELS WITH APPLICATIONS IN
!                ENGINEERING AND SCIENCE", WILEY, 2005.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DG
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='WEIL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'VLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GEVLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,ALOC,SCALE,SHAPE
   52   FORMAT('IBUGA3,ISUBRO,N,ALOC,SCALE,SHAPE = ',2(A4,2X),I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'VLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     FOR THE MAXIMUM CASE, THE LOG-LIKELIHOOD FUNCTION IS
!     (U = LOCATION, S = SCALE, G = SHAPE):
!
!        -N*LOG(S) - (1- G)*SUM[i=1 to N][Z(i)] - SUM[i=1 to N][EXP(-Z(i))]
!
!     WHERE
!
!        Z(i) = (1/G)*LOG(1 - G*(X(i) - U)/S)
!
!     FOR THE MINIMUM CASE, JUST TAKE X(I) = -X(I) AND USE ABOVE FORMULA.
!
!     IF SHAPE = 0, THEN LOG-LIKELIHOOD REDUCES TO
!
!        -N*LOG(S) - SUM[i=1 to N][(X(i)-U)/S] - SUM[i=1 to N][EXP(-(X(i)-U)/S)]
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DG=DBLE(SHAPE)
      IF(MINMAX.EQ.1)THEN
        DO 100 I=1,N
          Y(I)=-Y(I)
  100   CONTINUE
      ENDIF
!
      DTERM1=-DN*DLOG(DS)
      DTERM2=1.0D0 - DG
      DSUM1=0.0D0
      DSUM2=0.0D0
      IF(SHAPE.EQ.0.0)THEN
        DO 1010 I=1,N
          DX=DBLE((Y(I) - DU)/DS)
          DSUM1=DSUM1 + DX
          DSUM2=DSUM2 + DEXP(-DX)
 1010   CONTINUE
        DLIK=DTERM1 - DSUM1 - DSUM2
      ELSE
        DO 1020 I=1,N
          DX=DBLE(Y(I))
          DTERM3=1.0D0 - DG*(DX - DU)/DS
          IF(DTERM3.LE.0.0D0)THEN
            IERROR='YES'
            GO TO 9000
          ENDIF
          DZ=-(1.0D0/DG)*DLOG(1.0D0 - DG*(DX - DU)/DS)
          DSUM1=DSUM1 + DZ
          DSUM2=DSUM2 + DEXP(-DZ)
 1020   CONTINUE
        DLIK=DTERM1 - DTERM2*DSUM1 - DSUM2
      ENDIF
!
      ALIK=REAL(DLIK)
      DNP=3.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
!     FOR MINIMUM CASE, CONVERT Y BACK TO ORIGINAL VALUES
!
      IF(MINMAX.EQ.1)THEN
        DO 8010 I=1,N
          Y(I)=-Y(I)
 8010   CONTINUE
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'VLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GEVLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM2,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM2,DTERM3 = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GEVLI1
      SUBROUTINE GEVML1(Y,N,MAXNXT,MINMAX,ICASPL,MLFLAG,IGEPDF,   &
                        ISEED,IDFTTY,IGEVML,   &
                        TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                        DTEMP1,XMOM,NMOM,VARCOV,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALOCLM,SCALLM,SHAPLM,   &
                        ALOCEP,SCALEP,SHAPEP,   &
                        ALOCML,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 3-PARAMETER GENERALIZED EXTREME VALUE
!              DISTRIBUTION FOR THE RAW DATA CASE (I.E., NO CENSORING
!              AND NO GROUPING).  THIS ROUTINE RETURNS ONLY THE POINT
!              ESTIMATES (CONFIDENCE INTERVALS WILL BE COMPUTED IN A
!              SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLW1 WILL GENERATE THE OUTPUT
!              FOR THE GENERALIZED EXTREME VALUE MLE COMMAND).
!
!              THE FOLLOWING METHODS ARE SUPPORTED:
!
!                  1) L-MOMENTS
!                  2) ELEMENTAL PERCENTILES
!                  3) MAXIMUM LIKELIHOOD
!
!               NOTE THAT L-MOMENT AND MAXIMUM LIKELIHOOD ARE ONLY
!               SUPOORTED FOR CERTAIN RANGES OF THE SHAPE PARAMETER.
!               ELEMENTAL PERCENTILES DOES NOT HAVE THIS RESTRICTION.
!
!               CURRENTLY HAVING SOME ISSUES GETTING THE ML CODE
!               TO WORK.
!
!     REFERENCE--JOHNSON, KOTZ, AND BALAKRISHNAN.  "CONTINUOUS
!                UNIVARIATE DISTRIBUTIONS, VOLUME I", SECOND
!                EDITION, WILEY, 1994, PP. 614-619.
!              --HOSKING, ALGORITHM AS215   APPL. STATIST. (1985)
!                VOL. 34, NO. 3, Modifications in AS R76 (1989)
!                have been incorporated.
!              --CASTILLO, HADI, BALAKRISHNAN, SARABIA, "EXTREME
!                VALUE AND RELATED MODELS WITH APPLICATIONS IN
!                ENGINEERING AND SCIENCE", WILEY, 2005.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/07
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLGV)
!     UPDATED         --APRIL     2011. IDFTTY TO SUPPRESS MOMENT
!                                       OR ML METHODS
!     UPDATED         --OCTOBER   2014. IGEVML SWITCH
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION XMOM(*)
      DOUBLE PRECISION XPAR(3)
      DOUBLE PRECISION VARCOV(*)
!
      CHARACTER*4 IGEPDF
      CHARACTER*4 IDFTTY
      CHARACTER*4 IGEVML
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      LOGICAL MLFLAG
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GEVM'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      AN=REAL(N)
      ALOCLM=CPUMIN
      SCALLM=CPUMIN
      SHAPLM=CPUMIN
      ALOCEP=CPUMIN
      SCALEP=CPUMIN
      SHAPEP=CPUMIN
      ALOCML=CPUMIN
      SCALMO=CPUMIN
      SHAPML=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'VML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GEVML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASPL,MINMAX
   52   FORMAT('IBUGA3,ISUBRO,ICASPL,MINMAX = ',3(A4,2X),I5)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               **************************************************
!               **  STEP 2--                                   **
!               **  CARRY OUT CALCULATIONS                     **
!               **  FOR GENERALIZED EXTREME VALUE MLE ESTIMATE **
!               *************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'VML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GENERALIZED EXTREME VALUE'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(MINMAX.EQ.1)THEN
        DO 2002 I=1,N
          Y(I)=-Y(I)
 2002   CONTINUE
      ENDIF
      CALL SORT(Y,N,Y)
!
!     COMPUTE L-MOMENT ESTIMATORS
!
      NMOM=3
      DO 2110 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 2110 CONTINUE
      CALL SAMLMU(DTEMP1,N,XMOM,NMOM)
      CALL GEVPEL(XMOM,XPAR)
      ALOCLM=REAL(XPAR(1))
      SCALLM=REAL(XPAR(2))
      SHAPLM=REAL(XPAR(3))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'VML1')THEN
        WRITE(ICOUT,2012)ALOCLM,SCALLM,SHAPLM
 2012   FORMAT('ALOCLM,SCALLM,SHAPLM = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,MINMAX
      ENDIF
!
      ITEMP=2
      NSAMP=20*N
      IF(NSAMP.GT.5000)NSAMP=5000
      CALL DPEPM2(Y,N,ICASPL,MAXNXT,MINMAX,IGEPDF,   &
                  ISEED,NSAMP,   &
                  TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                  ALOCEP,SCALEP,SHAPEP,   &
                  IBUGA3,ISUBRO,IERROR)
!
      IF(IDFTTY.EQ.'EPER')GO TO 9000
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'VML1')THEN
        WRITE(ICOUT,2022)ALOCEP,SCALEP,SHAPEP
 2022   FORMAT('ALOCEP,SCALEP,SHAPEP = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,MINMAX
      ENDIF
!
      IF(SHAPLM.NE.CPUMIN)THEN
        XPAR(1)=DBLE(ALOCLM)
        XPAR(2)=DBLE(SCALLM)
        XPAR(3)=DBLE(SHAPLM)
      ELSE
        XPAR(1)=DBLE(ALOCEP)
        XPAR(2)=DBLE(SCALEP)
        XPAR(3)=DBLE(SHAPEP)
      ENDIF
!
!     NOTE: ONLY ATTEMP MLE IF L-MOMENT ESTIMATES IN THE
!           RANGE -0.5 TO 0.5.
!
!     NOTE: OUR EXPERIENCE WITH THE HOSKING ROUTINE IS THAT THE
!           ML ESTIMATES ARE NOT VERY STABLE.  SO SUPPRESS
!           UNLESS THE IGEVML SWITCH IS EXPLICITLY TURNED ON.
!
      IF(IGEVML.EQ.'OFF')GO TO 9000
!
      IF(MLFLAG .AND. SHAPLM.GE.-0.5 .AND. SHAPLM.LE.0.5)THEN
        MONIT=0
!CCCC   MONIT=1
        IFAULT=0
        DO 2130 I=1,N
          DTEMP1(I)=DBLE(Y(I))
 2130   CONTINUE
!
        CALL MLEGEV(DTEMP1,N,XPAR,VARCOV,MONIT,IFAULT)
!
!       RETURN ML VALUES EVEN IF ERROR RETURNED FROM FIT
!       PROCEDURE
!
!CCCC   IF(IFAULT.EQ.0)THEN
          SHAPML=REAL(XPAR(3))
          SCALML=REAL(XPAR(2))
          ALOCML=REAL(XPAR(1))
!CCCC   ENDIF
!
        IF(IFAULT.EQ.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1111)
 1111     FORMAT('****** ERROR IN GENERALIZED EXTREME VALUE ',   &
                 'MAXIMUM LIKELIHOOD--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1013)N
 1013     FORMAT('      EXTREME VALUE REQUIRES N > 2.  N = ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
        ELSEIF(IFAULT.EQ.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1023)
 1023     FORMAT('      MAXIMUM NUMBER OF ITERATIONS EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
!CCCC     IERROR='YES'
        ELSEIF(IFAULT.EQ.3)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1033)
 1033     FORMAT('      MAXIMUM NUMBER OF EVALUATIONS FOR LOG ',   &
                 'LIKELIHOOD EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
        ELSEIF(IFAULT.EQ.4)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1043)
 1043     FORMAT('      MAXIMUM NUMBER OF STEP LENGTH REDUCTIONS ',   &
                 'EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
        ENDIF
      ENDIF
!
!     FOR MINIMUM CASE, NEED TO REVERSE SIGN OF LOCATION
!     ESTIMATE.  ALSO, CONVERT Y BACK TO ORIGINAL DATA.
!
      IF(MINMAX.EQ.1)THEN
        IF(ALOCLM.NE.CPUMIN)ALOCLM=-ALOCLM
        IF(ALOCEP.NE.CPUMIN)ALOCEP=-ALOCEP
        IF(ALOCML.NE.CPUMIN)ALOCML=-ALOCML
        DO 8010 I=1,N
          Y(I)=-Y(I)
 8010   CONTINUE
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'VML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GEVML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)ALOCLM,SCALLM,SHAPLM
 9017   FORMAT('ALOCLM,SCALLM,SHAPLM =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9018)ALOCEP,SCALEP,SHAPEP
 9018   FORMAT('ALOCEP,SCALEP,SHAPEP =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)ALOCML,SCALML,SHAPML
 9019   FORMAT('ALOCML,SCALML,SHAPML =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GEVML1
      SUBROUTINE GEVPDF(X,GAMMA,MINMAX,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED EXTREME VALUE
!              DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE PARAMETER = GAMMA.
!              THERE ARE TWO GENERALIZED EXTREME VALUE FAMALIES:
!              ONE BASED ON THE MAXIMUM ORDER STATISTIC (THE MOST
!              COMMONLY USED, SPECIFIED BY MINMAX=2) AND THE OTHER
!              BASED ON THE MINIMUM ORDER STATISTIC (SPECIFIED BY
!              SET MINMAX = 1).
!
!              THE PROBABILITY DENSITY FUNCTION FOR THE MAXIMUM CASE
!              OF THE GENERALIZED EXTREME VALUE DISTRIBUTION IS:
!              F(X,G) = EXP(-EXP(-X))*EXP(-X)        G = 0
!                     = EXP(-(1-G*X)**(1/G))*(1-G*X)**((1/G)-1) G<>0
!                                     X<=1/G   FOR G > 0
!                                     X>=1/G   FOR G < 0
!
!              THE PROBABILITY DENSITY FUNCTION FOR THE MINIMUM CASE
!              OF THE GENERALIZED EXTREME VALUE DISTRIBUTION IS:
!              F(X,G) = EXP(-EXP(X))*EXP(X)        G = 0
!                     = EXP(-(1+G*X)**(1/G))*(1+G*X)**((1/G)-1) G<>0
!                                     X>=1/G   FOR G > 0
!                                     X<=1/G   FOR G < 0
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED EXTREME VALUE
!             DISTRIBUTION WITH SHAPE PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--RANGE OF X DEPENDS ON SIGN OF GAMMA
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 75-76
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA,
!                 "EXTREME VALUE AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, 2005, PP. 64-65.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --MAY       2005. SUPPORT FOR MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DG
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!
!     MAY 2005.  HANDLE MIN AND MAX CASES SEPARATELY.
!
!     MAXIMUM CASE
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
!
!       CHECK THE INPUT ARGUMENTS FOR ERRORS
!
        IF(GAMMA.GT.0.0)THEN
          IF(X.GT.(1.0/GAMMA))THEN
            WRITE(ICOUT,4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            PDF=0.0
            GO TO 9999
          ENDIF
        ELSEIF(GAMMA.LT.0.0)THEN
          IF(X.LT.(1.0/GAMMA))THEN
            WRITE(ICOUT,14)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            PDF=0.0
            GO TO 9999
          ENDIF
        ENDIF
    4   FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO GEVPDF ',   &
               'IS GREATER THAN 1/GAMMA.')
   14   FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO GEVPDF ',   &
               'IS LESS THAN 1/GAMMA.')
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47   FORMAT('***** THE VALUE OF GAMMA IS ',G15.7)
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
!
        IF(GAMMA.EQ.0.0)THEN
          DTERM1=-DX
          IF(ABS(DTERM1).GE.500.D0)THEN
            PDF=0.0
          ELSE
            DTERM2=-DEXP(-DX) - DX
            DPDF=0.D0
            IF(DABS(DTERM2).LE.500.D0)DPDF=DEXP(DTERM2)
            PDF=REAL(DPDF)
          ENDIF
        ELSE
          DTERM1=-(1.D0-DX*DG)**(1.D0/DG)
          DTERM2=((1.D0/DG)-1.D0)*DLOG(1.D0-DX*DG)
          DTERM3=DTERM1+DTERM2
          DPDF=0.D0
          IF(DABS(DTERM3).LE.500.D0)DPDF=DEXP(DTERM3)
          PDF=REAL(DPDF)
        END IF
!
!  MINIMUM CASE
!
      ELSE
!
!       CHECK THE INPUT ARGUMENTS FOR ERRORS
!
        IF(GAMMA.GT.0.0)THEN
          IF(X.LT.(-1.0/GAMMA))THEN
            WRITE(ICOUT,24)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            PDF=0.0
            GO TO 9999
          ENDIF
        ELSEIF(GAMMA.LT.0.0)THEN
          IF(X.GT.(-1.0/GAMMA))THEN
            WRITE(ICOUT,34)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)X
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,47)GAMMA
            CALL DPWRST('XXX','BUG ')
            PDF=0.0
            GO TO 9999
          ENDIF
        ENDIF
   24   FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO GEVPDF ',   &
               'IS LESS THAN -1/GAMMA.')
   34   FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT TO GEVPDF ',   &
               'IS GREATER THAN -1/GAMMA.')
!
        DX=DBLE(X)
        DG=DBLE(GAMMA)
!
        IF(GAMMA.EQ.0.0)THEN
          DTERM1=-DX
          IF(ABS(DTERM1).GE.500.D0)THEN
            PDF=0.0
          ELSE
            DTERM2=-DEXP(DX) + DX
            DPDF=0.D0
            IF(DABS(DTERM2).LE.500.D0)DPDF=DEXP(DTERM2)
            PDF=REAL(DPDF)
          ENDIF
        ELSE
          DTERM1=-(1.D0+DX*DG)**(1.D0/DG)
          DTERM2=((1.D0/DG)-1.D0)*DLOG(1.D0+DX*DG)
          DTERM3=DTERM1+DTERM2
          DPDF=0.D0
          IF(DABS(DTERM3).LE.500.D0)DPDF=DEXP(DTERM3)
          PDF=REAL(DPDF)
        END IF
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEVPDF
!===================================================== PELGEV.FOR
      SUBROUTINE GEVPEL(XMOM,PARA)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  PARAMETER ESTIMATION VIA L-MOMENTS FOR THE GENERALIZED EXTREME-VALUE
!  DISTRIBUTION
!
!  PARAMETERS OF ROUTINE:
!  XMOM   * INPUT* ARRAY OF LENGTH 3. CONTAINS THE L-MOMENTS LAMBDA-1,
!                  LAMBDA-2, TAU-3.
!  PARA   *OUTPUT* ARRAY OF LENGTH 3. ON EXIT, CONTAINS THE PARAMETERS
!                  IN THE ORDER XI, ALPHA, K (LOCATION, SCALE, SHAPE).
!
!  OTHER ROUTINES USED: DLGAMA (RENAMED TO: DLGADP)
!
!  METHOD: FOR  -0.8 LE TAU3 LT 1,  K IS APPROXIMATED BY RATIONAL
!  FUNCTIONS AS IN DONALDSON (1996, COMMUN. STATIST. SIMUL. COMPUT.).
!  IF TAU3 IS OUTSIDE THIS RANGE, NEWTON-RAPHSON ITERATION IS USED.
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION XMOM(3),PARA(3)
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,HALF/0.5D0/,ONE/1D0/,TWO/2D0/,THREE/3D0/
      DATA P8/0.8D0/,P97/0.97D0/
!
!         SMALL IS USED TO TEST WHETHER K IS EFFECTIVELY ZERO
!         EPS,MAXIT CONTROL THE TEST FOR CONVERGENCE OF N-R ITERATION
!
      DATA SMALL/1D-5/,EPS/1D-6/,MAXIT/20/
!
!         EU IS EULER'S CONSTANT
!         DL2 IS LOG(2), DL3 IS LOG(3)
!
      DATA EU/0.57721566D0/,DL2/0.69314718D0/,DL3/1.0986123D0/
!
!         COEFFICIENTS OF RATIONAL-FUNCTION APPROXIMATIONS FOR K
!
      DATA A0,A1,A2/ 0.28377530D0,-1.21096399D0,-2.50728214D0/
      DATA A3,A4   /-1.13455566D0,-0.07138022D0/
      DATA B1,B2,B3/ 2.06189696D0, 1.31912239D0, 0.25077104D0/
      DATA C1,C2,C3/ 1.59921491D0,-0.48832213D0, 0.01573152D0/
      DATA D1,D2   /-0.64363929D0, 0.08985247D0/
!
      T3=XMOM(3)
      IF(XMOM(2).LE.ZERO)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7000)
 7000   FORMAT('****** ERROR IN GENERALIZED EXTREME VALUE L-MOMENTS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7003)
 7003   FORMAT('       L-MOMENTS INVALID.')
        CALL DPWRST('XXX','BUG ')
        PARA(1)=CPUMIN
        PARA(2)=CPUMIN
        PARA(3)=CPUMIN
        GO TO 9000
      ELSEIF(DABS(T3).GE.ONE)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7000)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7003)
        CALL DPWRST('XXX','BUG ')
        PARA(1)=CPUMIN
        PARA(2)=CPUMIN
        PARA(3)=CPUMIN
        GO TO 9000
      ENDIF
!
!
      PARA(1)=0.0D0
      PARA(2)=1.0D0
      PARA(3)=0.0D0
      IF(T3.LE.ZERO)GO TO  10
!
!         RATIONAL-FUNCTION APPROXIMATION FOR TAU3 BETWEEN 0 AND 1
!
      Z=ONE-T3
      G=(-ONE+Z*(C1+Z*(C2+Z*C3)))/(ONE+Z*(D1+Z*D2))
      IF(DABS(G).LT.SMALL)GO TO  50
      GO TO  40
!
!         RATIONAL-FUNCTION APPROXIMATION FOR TAU3 BETWEEN -0.8 AND 0
!
   10 CONTINUE
      G=(A0+T3*(A1+T3*(A2+T3*(A3+T3*A4))))/(ONE+T3*(B1+T3*(B2+T3*B3)))
      IF(T3.GE.-P8)GO TO  40
!
!         NEWTON-RAPHSON ITERATION FOR TAU3 LESS THAN -0.8
!
      IF(T3.LE.-P97)G=ONE-DLOG(ONE+T3)/DL2
      T0=(T3+THREE)*HALF
      DO 20 IT=1,MAXIT
        X2=TWO**(-G)
        X3=THREE**(-G)
        XX2=ONE-X2
        XX3=ONE-X3
        T=XX3/XX2
        DERIV=(XX2*X3*DL3-XX3*X2*DL2)/(XX2*XX2)
        GOLD=G
        G=G-(T-T0)/DERIV
        IF(DABS(G-GOLD).LE.EPS*G)GO TO  30
   20 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7000)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7010)
 7010 FORMAT('****** WARNING FROM GENERALIZED EXTREME VALUE ',   &
            'L-MOMENTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,7013)
 7013 FORMAT('       ITERATION HAS NOT CONVERGED.  RESULTS MAY ',   &
             'BE UNRELIABLE.')
      CALL DPWRST('XXX','BUG ')
   30 CONTINUE
!
!         ESTIMATE ALPHA,XI
!
   40 CONTINUE
      PARA(3)=G
!CCCC GAM=DEXP(DLGAMA(ONE+G))
      GAM=DEXP(DLNGAM(ONE+G))
      PARA(2)=XMOM(2)*G/(GAM*(ONE-TWO**(-G)))
      PARA(1)=XMOM(1)-PARA(2)*(ONE-GAM)/G
      GO TO 9000
!
!         ESTIMATED K EFFECTIVELY ZERO
!
   50 CONTINUE
      PARA(3)=ZERO
      PARA(2)=XMOM(2)/DL2
      PARA(1)=XMOM(1)-EU*PARA(2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEVPEL
      SUBROUTINE GEVPPF(P,GAMMA,MINMAX,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED EXTREME VALUE
!              DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE PARAMETER = GAMMA.
!              THERE ARE TWO GENERALIZED EXTREME VALUE FAMALIES:
!              ONE BASED ON THE MAXIMUM ORDER STATISTIC (THE MOST
!              COMMONLY USED, SPECIFIED BY MINMAX=2) AND THE OTHER
!              BASED ON THE MINIMUM ORDER STATISTIC (SPECIFIED BY
!              SET MINMAX = 1).
!
!              THE PERCENT POINT FUNCTION FOR THE MAXIMUM CASE
!              OF THE GENERALIZED EXTREME VALUE DISTRIBUTION IS:
!              G(P,G) = -LOG(-(LOG(P)))               G = 0
!                     = (1 - (-LOG(P)**G)/G           G <> 0
!
!              THE PERCENT POINT FUNCTION FOR THE MINIMUM CASE
!              OF THE GENERALIZED EXTREME VALUE DISTRIBUTION IS:
!              G(P,G) = LOG(-(LOG(1-P)))              G = 0
!                     = -(1 - (-LOG(1-P)**G)/G        G <> 0
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE GENERALIZED EXTREME VALUE DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA CAN HAVE ANY VALUE
!                 --P SHOULD BE BETWEEN 0.0 AND 1.0.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 75-76
!               --CASTILLO, HADI, BALAKRISHNAN, AND SARABIA,
!                 "EXTREME VALUE AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, 2005, PP. 64-65.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!     UPDATED         --MAY       2005. SUPPORT FOR MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DG
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.EQ.0.0)THEN
        IF(P.LE.0.0.OR.P.GE.1.0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)P
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9999
        ENDIF
      ENDIF
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        IF(GAMMA.GT.0.0)THEN
          IF(P.LE.0.0.OR.P.GT.1.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9999
          ENDIF
        ELSE
          IF(P.LT.0.0.OR.P.GE.1.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9999
          ENDIF
        ENDIF
      ELSE
        IF(GAMMA.GT.0.0)THEN
          IF(P.LT.0.0.OR.P.GE.1.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9999
          ENDIF
        ELSE
          IF(P.LE.0.0.OR.P.GT.1.0)THEN
            WRITE(ICOUT,1)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0
            GO TO 9999
          ENDIF
        ENDIF
      ENDIF
!
    1 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO GEVPPF ',   &
      'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DP=DBLE(P)
      DG=DBLE(GAMMA)
      DPPF=0.0D0
!
      IF(MINMAX.EQ.2 .OR. MINMAX.EQ.0)THEN
        IF(GAMMA.EQ.0.0)THEN
           DPPF=-DLOG(-DLOG(DP))
        ELSE IF(GAMMA.GT.0.0.AND.P.EQ.1.0)THEN
           DPPF=1.0D0/DG
        ELSE IF(GAMMA.LT.0.0.AND.P.EQ.0.0)THEN
           DPPF=1.0D0/DG
        ELSE
           DPPF=(1.0D0 - (-DLOG(DP))**DG)/DG
        ENDIF
      ELSE
        IF(GAMMA.EQ.0.0)THEN
           DPPF=DLOG(-DLOG(1.0D0 - DP))
        ELSE IF(GAMMA.GT.0.0.AND.P.EQ.0.0)THEN
           DPPF=-1.0D0/DG
        ELSE IF(GAMMA.LT.0.0.AND.P.EQ.1.0)THEN
           DPPF=-1.0D0/DG
        ELSE
           DPPF=-(1.0D0 - (-DLOG(1.0D0 - DP))**DG)/DG
        ENDIF
      ENDIF
!
      PPF=REAL(DPPF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEVPPF
      SUBROUTINE GEVRAN(N,GAMMA,MINMAX,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED EXTREME VALUE DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!              THERE ARE TWO GENERALIZED EXTREME VALUE FAMALIES:
!              ONE BASED ON THE MAXIMUM ORDER STATISTIC (THE MOST
!              COMMONLY USED, SPECIFIED BY MINMAX=2) AND THE OTHER
!              BASED ON THE MINIMUM ORDER STATISTIC (SPECIFIED BY
!              SET MINMAX = 1).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!                     --MINMAX = THE INTEGER VALUE WHICH SPECIFIES
!                                WHETHER THE MAXIMUM OR THE MINIMUM
!                                FAMILY IS BEING GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED EXTREME VALUE DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CASTILLO, HADI, BALAKRISHNAN, AND SARABIA,
!                 "EXTREME VALUE AND RELATED MODELS WITH APPLICATIONS
!                 IN ENGINEERING AND SCIENCE", WILEY, 2005, PP. 64-65.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 2ND. ED., 1994.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!     UPDATED         --MAY       2005. SUPPORT FOR MINIMUM CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE NUMBER OF REQUESTED GENERALIZED ',   &
             'EXTREME VALUE')
    6 FORMAT('      RANDOM NUMBERS WAS NOT POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED EXTREME VALUE DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL GEVPPF(X(I),GAMMA,MINMAX,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GEVRAN
      SUBROUTINE GEXCDF(X,ALAM1,ALAM12,S,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED EXPONENTIAL
!              DISTRIBUTION
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (L1+L12*(1-EXP(-S*X)))*
!                     EXP[-L1*X-L12*X+(L12/S)*(1-EXP(-S*X))]
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALAM1  = POSITIVE SHAPE PARAMETER
!                     --ALAM12 = POSITIVE SHAPE PARAMETER
!                     --S      = POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND. ED., 1994, PAGES 555.
!               --RYU, "AN EXTENSION OF MARSHALL AND OLKIN'S BIVARIATE
!                 EXPONENTIAL DISTRIBUTION", JOURNAL OF THE AMERICAN
!                 STATISTICAL ASSOCIATION, 1993, PP. 1458-1465.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--FEBRUARY  1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DLAM1, DLAM12, DS, DCDF
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(ALAM1.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(ALAM12.LE.0.0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(S.LE.0.0)THEN
        WRITE(ICOUT,34)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GEXCDF SUBROUTINE IS NEGATIVE')
   14 FORMAT('***** FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
      'TO THE GEXCDF SUBROUTINE IS NON-POSITIVE')
   24 FORMAT('***** FATAL DIAGNOSTIC--THE THIRD INPUT ARGUMENT ',   &
      'TO THE GEXCDF SUBROUTINE IS NON-POSITIVE')
   34 FORMAT('***** FATAL DIAGNOSTIC--THE FOURTH INPUT ARGUMENT ',   &
      'TO THE GEXCDF SUBROUTINE IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DLAM1=DBLE(ALAM1)
      DLAM12=DBLE(ALAM12)
      DS=DBLE(S)
!
      IF(X.LE.0.0)THEN
        CDF=0.0
        GO TO 9999
      ENDIF
!
      DTERM1=-DLAM1*X - DLAM12*DX + (DLAM12/DS)*(1.0D0-DEXP(-DS*DX))
      IF(DTERM1.LE.-65.0D0)THEN
        CDF=1.0
      ELSEIF(DTERM1.GE.65.D0)THEN
        CDF=1.0
        WRITE(ICOUT,101)X
        CALL DPWRST('XXX','BUG ')
      ELSE
        DCDF=1.0D0-DEXP(DTERM1)
        CDF=SNGL(DCDF)
      ENDIF
  101 FORMAT('***** FATAL DIAGNOSTIC--OVERFLOW IN GEXCDF ROUTINE ',   &
      'FOR X = ',E15.7)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEXCDF
      SUBROUTINE GEXPDF(X,ALAM1,ALAM12,S,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED EXPONENTIAL
!              DISTRIBUTION
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (L1+L12*(1-EXP(-S*X)))*
!                     EXP[-L1*X-L12*X+(L12/S)*(1-EXP(-S*X))]
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALAM1  = POSITIVE SHAPE PARAMETER
!                     --ALAM12 = POSITIVE SHAPE PARAMETER
!                     --S      = POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND. ED., 1994, PAGES 555.
!               --RYU, "AN EXTENSION OF MARSHALL AND OLKIN'S BIVARIATE
!                 EXPONENTIAL DISTRIBUTION", JOURNAL OF THE AMERICAN
!                 STATISTICAL ASSOCIATION, 1993, PP. 1458-1465.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--FEBRUARY  1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DLAM1, DLAM12, DS, DPDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(ALAM1.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(ALAM12.LE.0.0)THEN
        WRITE(ICOUT,24)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(S.LE.0.0)THEN
        WRITE(ICOUT,34)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GEXPDF SUBROUTINE IS NEGATIVE')
   14 FORMAT('***** FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
      'TO THE GEXPDF SUBROUTINE IS NON-POSITIVE')
   24 FORMAT('***** FATAL DIAGNOSTIC--THE THIRD INPUT ARGUMENT ',   &
      'TO THE GEXPDF SUBROUTINE IS NON-POSITIVE')
   34 FORMAT('***** FATAL DIAGNOSTIC--THE FOURTH INPUT ARGUMENT ',   &
      'TO THE GEXPDF SUBROUTINE IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DLAM1=DBLE(ALAM1)
      DLAM12=DBLE(ALAM12)
      DS=DBLE(S)
!
      DTERM1=DLOG(DLAM1 + DLAM12*(1.0D0-DEXP(-DS*DX)))
      DTERM2=-DLAM1*X - DLAM12*DX + (DLAM12/DS)*(1.0D0-DEXP(-DS*DX))
      DTERM3=DTERM1+DTERM2
      IF(DTERM3.LE.-80.0D0)THEN
        PDF=0.0
        GO TO 9999
      ELSEIF(DTERM3.GE.80.D0)THEN
        PDF=0.0
        WRITE(ICOUT,101)X
        CALL DPWRST('XXX','BUG ')
      ELSE
        DPDF=DEXP(DTERM3)
        PDF=SNGL(DPDF)
      ENDIF
  101 FORMAT('***** FATAL DIAGNOSTIC--OVERFLOW IN GEXPDF ROUTINE ',   &
      'FOR X = ',E15.7)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEXPDF
      SUBROUTINE GEXPPF(P,ALAM1,ALAM2,S,PPF)
!
!     PURPOSE         --PERCENT POINT FUNCTION FOR THE GENERALIZED
!                       EXPONENTIAL DISTRIBUTION.  USES A BISECTION
!                       METHOD.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALAM1  = POSITIVE SHAPE PARAMETER
!                     --ALAM12 = POSITIVE SHAPE PARAMETER
!                     --S      = POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION VALUE PPF
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GEXCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND. ED., 1994, PAGES 555.
!               --RYU, "AN EXTENSION OF MARSHALL AND OLKIN'S BIVARIATE
!                 EXPONENTIAL DISTRIBUTION", JOURNAL OF THE AMERICAN
!                 STATISTICAL ASSOCIATION, 1993, PP. 1458-1465.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--96/2
!     ORIGINAL VERSION--FEBRUARY  1996.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.0001/
      DATA SIG /1.0E-5/
      DATA ZERO /0./
      DATA MAXIT /50000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
      IF(ALAM1.LE.0.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAM1
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
      IF(ALAM2.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAM2
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
      IF(S.LE.0.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)S
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
!
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      ' GEXPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   11 FORMAT('***** FATAL ERROR--THE 2ND INPUT ARGUMENT TO THE ',   &
      ' GEXPPF SUBROUTINE IS NON-POSITIVE.')
   12 FORMAT('***** FATAL ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      ' GEXPPF SUBROUTINE IS NON-POSITIVE.')
   35 FORMAT('***** FATAL ERROR--THE FOURTH INPUT ARGUMENT TO THE ',   &
      ' GEXPPF SUBROUTINE IS NEGATIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!  FIND BRACKETING INTERVAL.  USE 0.
!  AS INITIAL GUESS, INCREMENTS OF 10 AROUND IT.
!  AFTER SUCCESSFULLY FIND BRACKETING INTERVAL, THEN SWITCH TO
!  MORE EFFICIENT BISECTION METHOD.
!
      XINC=10.0
      XL=0.0
      ICOUNT=0
      MAXCNT=100000
!
   91 CONTINUE
      XR=XL+XINC
      IF(XL.LE.0.0)XL=0.0
      IF(XR.LE.0.0)XR=XL+1.0
      CALL GEXCDF(XL,ALAM1,ALAM2,S,CDFL)
      CALL GEXCDF(XR,ALAM1,ALAM2,S,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** FATAL ERROR--GEXPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL. *****')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -P
      FXR = 1.0 - P
  105 CONTINUE
      X = (XL+XR)*0.5
      CALL GEXCDF(X,ALAM1,ALAM2,S,CDF)
      P1=CDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      IF(ABS(FCS).GT.EPS)THEN
        WRITE(ICOUT,130)
        CALL DPWRST('XXX','BUG ')
      ENDIF
  130 FORMAT('***** FATAL ERROR--GEXPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEXPPF
      SUBROUTINE GEXRAN(N,ALAM1,ALAM12,S,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED EXPONENTIAL DISTRIBUTION
!              WITH SHAPE PARAMETERS = LAMBDA1, LAMBDA12, S.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (L1+L12*(1-EXP(-S*X)))*
!                     EXP[-L1*X-L12*X+(L12/S)*(1-EXP(-S*X))]
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALAM1  = THE SINGLE PRECISION VALUE OF THE
!                                LAMBDA1 SHAPE PARAMETER.
!                                ANU SHOULD BE A POSITIVE INTEGER.
!                     --ALAM12 = THE SINGLE PRECISION VALUE OF THE
!                                LAMBDA12 SHAPE PARAMETER.
!                     --S      = THE SINGLE PRECISION VALUE OF THE
!                                S SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED EXPONENTIAL DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ALAM1, ALAM12, AND S.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ANU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2003.7
!     ORIGINAL VERSION--JULY      2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
             'EXPONENTIAL RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      IF(ALAM1.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAM1
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** FATAL ERROR--THE FIRST SHAPE PARAMETER (LAMBDA1)')
   16 FORMAT('      FOR THE  GENERALIZED EXPONENTIAL RANDOM NUMBERS ',   &
             'IS NON-POSITIVE')
      IF(ALAM12.LE.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,26)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALAM12
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   25 FORMAT('***** FATAL ERROR--THE SECOND SHAPE PARAMETER ',   &
            '(LAMBDA12) ')
   26 FORMAT('      FOR THE  GENERALIZED EXPONENTIAL RANDOM NUMBERS ',   &
             'IS NON-POSITIVE')
      IF(S.LE.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,36)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)S
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   35 FORMAT('***** FATAL ERROR--THE THIRD SHAPE PARAMETER (S) ')
   36 FORMAT('      FOR THE  GENERALIZED EXPONENTIAL RANDOM NUMBERS ',   &
             'IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED EXPONENTIAL DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL GEXPPF(X(I),ALAM1,ALAM12,S,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GEXRAN
      SUBROUTINE GGDCDF(X,ALPHA,C,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETERS ALPHA AND C.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!              THE CDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,ALPAH,C) = GAMMAIP(X**C,ALPHA)
!              WHERE GAMMAIP = GAMMAI(ALPHA,X)/GAMMA(ALPHA).
!              THE CDF IS CAN BE COMPUTED WITH THE SLATEC ROUTINE
!              DGAMIC.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALPHA  = A POSITIVE SHAPE PARAMETER
!                     --C      = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GENERALIZED GAMMA DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = ANU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 417.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DALPHA, DC
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DGAMIP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(ALPHA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(C.EQ.0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GGDCDF SUBROUTINE IS NEGATIVE *****')
   15 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'GGDCDF SUBROUTINE IS NON-POSITIVE *****')
   16 FORMAT('***** FATAL ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      'GGDCDF SUBROUTINE IS ZERO *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      IF(X.LE.R1MACH(1))THEN
        CDF=0.0
        RETURN
      ENDIF
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
      DC=DBLE(C)
!
      DTERM1=DX**DC
      DCDF=DGAMIP(DALPHA,DTERM1)
      IF(C.LT.0)DCDF=1.0D0-DCDF
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GGDCDF
      SUBROUTINE GG2CDF(DX,DALPHA,DC,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETERS ALPHA AND C.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!              THE CDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,ALPAH,C) = GAMMAIP(X**C,ALPHA)
!              WHERE GAMMAIP = GAMMAI(ALPHA,X)/GAMMA(ALPHA).
!              THE CDF IS CAN BE COMPUTED WITH THE SLATEC ROUTINE
!              DGAMIC.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALPHA  = A POSITIVE SHAPE PARAMETER
!                     --C      = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GENERALIZED GAMMA DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = ANU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 417.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DALPHA, DC
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DGAMIP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DX.LT.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        DCDF=0.0
        GO TO 9999
      ENDIF
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DALPHA
        CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9999
      ENDIF
      IF(DC.EQ.0.0D0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GGDCDF SUBROUTINE IS NEGATIVE *****')
   15 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'GGDCDF SUBROUTINE IS NON-POSITIVE *****')
   16 FORMAT('***** FATAL ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      'GGDCDF SUBROUTINE IS ZERO *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',D15.8,' *****')
!
      IF(DX.LE.D1MACH(1))THEN
        DCDF=0.0D0
        RETURN
      ENDIF
!
      DTERM1=DX**DC
      DCDF=DGAMIP(DALPHA,DTERM1)
      IF(DC.LT.0.0D0)DCDF=1.0D0-DCDF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GG2CDF
      SUBROUTINE GGDCHA(X,ALPHA,C,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE GENERALIZED GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETERS ALPHA AND C.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,ALPAH,C) = C*X**(C*ALPHA-1)*EXP(-(X**C))/
!                                   GAMMA(ALPHA)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALPHA  = A POSITIVE SHAPE PARAMETER
!                     --C      = A SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE PDF FOR THE GENERALIZED GAMMA DISTRIBUTION
!             WITH SHAPE PARAMETERS C AND ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --ALPHA AND C SHOULD BE POSITIVE NUMBERS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 388.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DALPHA, DC
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DGAMIP
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9999
      ENDIF
      IF(ALPHA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9999
      ENDIF
      IF(C.EQ.0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GGDHAZ SUBROUTINE IS NEGATIVE *****')
   15 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'GGDHAZ SUBROUTINE IS NON-POSITIVE *****')
   16 FORMAT('***** FATAL ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      'GGDHAZ SUBROUTINE IS ZERO *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      IF(X.LE.R1MACH(1))THEN
        DCDF=0.0D0
      ELSE
!
        DX=DBLE(X)
        DALPHA=DBLE(ALPHA)
        DC=DBLE(C)
        DTERM1=DX**DC
        DCDF=DGAMIP(DALPHA,DTERM1)
        IF(C.LT.0)DCDF=1.0D0-DCDF
      ENDIF
      DCDF=1.0D0-DCDF
      IF(DCDF.NE.0.0D0)THEN
        HAZ=REAL(-DLOG(DCDF))
      ELSE
        WRITE(ICOUT,9969)X
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
      ENDIF
 9969 FORMAT('*****WARNING: FOR ARGUMENT = ',F15.7,' CDF TERM ',   &
      'ESSENTIALLY 1, VALUE SET TO 0')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GGDCHA
      SUBROUTINE GGDHAZ(X,ALPHA,C,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE GENERALIZED GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETERS ALPHA AND C.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,ALPAH,C) = C*X**(C*ALPHA-1)*EXP(-(X**C))/
!                                   GAMMA(ALPHA)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALPHA  = A POSITIVE SHAPE PARAMETER
!                     --C      = A SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE PDF FOR THE GENERALIZED GAMMA DISTRIBUTION
!             WITH SHAPE PARAMETERS C AND ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --ALPHA AND C SHOULD BE POSITIVE NUMBERS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 388.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--98/4
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DALPHA, DC
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DGAMIP
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLNGAM
      DOUBLE PRECISION DUL
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9999
      ENDIF
      IF(ALPHA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9999
      ENDIF
      IF(C.EQ.0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GGDHAZ SUBROUTINE IS NEGATIVE *****')
   15 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'GGDHAZ SUBROUTINE IS NON-POSITIVE *****')
   16 FORMAT('***** FATAL ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      'GGDHAZ SUBROUTINE IS ZERO *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      IF(X.LE.R1MACH(1))THEN
        DCDF=0.0D0
      ELSE
!
        DX=DBLE(X)
        DALPHA=DBLE(ALPHA)
        DC=DBLE(C)
        DTERM1=DX**DC
        DCDF=DGAMIP(DALPHA,DTERM1)
        IF(C.LT.0)DCDF=1.0D0-DCDF
      ENDIF
      DCDF=1.0D0-DCDF
      IF(DCDF.NE.0.0D0)THEN
        IF(X.LE.R1MACH(1))THEN
          DPDF=0.0D0
        ELSE
!
          DX=DBLE(X)
          DALPHA=DBLE(ALPHA)
          DC=DBLE(C)
!
          DUL=D1MACH(2)
          IF(C.GE.1.0)THEN
            IF(DX.GT.DUL**(1.0D0/DC))THEN
              WRITE(ICOUT,106)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,46)X
              CALL DPWRST('XXX','BUG ')
              DPDF=0.0
            ENDIF
          ELSEIF(C.GT.0.0.AND.C.LT.1.0)THEN
            IF(DX.GT.DUL**DC)THEN
              WRITE(ICOUT,106)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,46)X
              CALL DPWRST('XXX','BUG ')
              DPDF=0.0
            ENDIF
          ELSE
            CONTINUE
          ENDIF
  106 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GGDPDF SUBROUTINE GENERATES AN INVALID VALUE *****')
!
          DTERM1=DLOG(DABS(DC))
          DTERM2=(DC*DALPHA-1.0D0)*DLOG(DX)
          DTERM3=-(DX**DC)
          DTERM4=DLNGAM(DALPHA)
          DTERM5=DTERM1+DTERM2+DTERM3-DTERM4
          DPDF=0.0D0
          IF(DTERM5.GE.-80.0D0)DPDF=DEXP(DTERM5)
        ENDIF
        HAZ=REAL(DPDF/DCDF)
      ELSE
        WRITE(ICOUT,9969)X
        CALL DPWRST('XXX','BUG ')
        HAZ=0.0
      ENDIF
 9969 FORMAT('*****WARNING: FOR ARGUMENT = ',F15.7,' CDF TERM ',   &
      'ESSENTIALLY 1, VALUE SET TO 0')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GGDHAZ
      SUBROUTINE GGDFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GENERALIZED GAMMA MOMENT EQUATIONS.
!
!              A*(GAMMA(K+1/C))**2 - GAMMA(K+2/C)*GAMMA(K) = 0
!
!              XBAR - GAMMA(K+1/C)/(ALPHA*GAMMA(K)) = 0
!
!              SUM[i=1 to n][X(i)**C] - N*K/(ALPHA**C)
!
!              WHERE
!
!
!              ALPHA = 1/SCALE
!              C, K  = SHAPE PARAMETERS
!              A = {N*XBAR**2 + (N-1)*S**2}/{N*XBAR**2 - S**2)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--GENERALIZED GAMMA MAXIMUM LIKELIHOOD Y
!     REFERENCE--HWANG AND HUANG (2006), "ON NEW MOMENT ESTIMATION
!                OF PARAMETERS OF THE GENERALIZED GAMMA DISTRIBUTION
!                USING IT'S CHARACTERIZATION", TAIWANESE JOURNAL OF
!                MATHEMATICS, VOL.10, NO. 4, PP. 1083-1093.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/1
!     ORIGINAL VERSION--JANUARY   2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DC
      DOUBLE PRECISION DK
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
!
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
      DOUBLE PRECISION DGAMMA
      EXTERNAL DGAMMA
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION DA
      COMMON/GGDCOM/XBAR,S2,DA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DC=X(1)
      DK=X(2)
      DALPHA=X(3)
      DN=DBLE(NOBS)
!
      DSUM1=0.0D0
!
      DO 200 I=1,NOBS
        DX=DBLE(XDATA(I))
        DSUM1=DSUM1 + DX**DC
  200 CONTINUE
!
      DTERM1=DLNGAM(DK)
      DTERM2=DLNGAM(DK + 1.0D0/DC)
      DTERM3=DLNGAM(DK + 2.0D0/DC)
!
      DTERM4=DLOG(DA) + 2.0D0*DTERM2
      DTERM5=DTERM3 + DTERM1
      FVEC(1)=DEXP(DTERM4) - DEXP(DTERM5)
      FVEC(2)=XBAR - DEXP(DTERM2 - DLOG(DALPHA) - DTERM1)
      FVEC(3)=DSUM1 - (DN*DK)/(DALPHA**DC)
!
!CCCC FVEC(1)=DA*DGAMMA(DK+1.0D0/DC)**2 -
!CCCC1        DGAMMA(DK+2.0D0/DC)*DGAMMA(DK)
!CCCC FVEC(2)=XBAR - DGAMMA(DK+1.0D0/DC)/(DALPHA*DGAMMA(DK))
!CCCC FVEC(3)=DSUM1 - (DN*DK)/(DALPHA**DC)
!CCCC print *,'fvec(1)=',fvec(1)
!CCCC print *,'fvec(2)=',fvec(2)
!CCCC print *,'fvec(3)=',fvec(3)
!
      RETURN
      END SUBROUTINE GGDFUN 
      SUBROUTINE GGDPDF(X,ALPHA,C,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETERS ALPHA AND C.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,ALPAH,C) = C*X**(C*ALPHA-1)*EXP(-(X**C))/
!                                   GAMMA(ALPHA)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALPHA  = A POSITIVE SHAPE PARAMETER
!                     --C      = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED GAMMA DISTRIBUTION
!             WITH SHAPE PARAMETERS C AND ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --ALPHA AND C SHOULD BE POSITIVE NUMBERS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 388.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DALPHA, DC
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLNGAM
      DOUBLE PRECISION DUL
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(ALPHA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(C.EQ.0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GGDPDF SUBROUTINE IS NEGATIVE *****')
   15 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'GGDPDF SUBROUTINE IS NON-POSITIVE *****')
   16 FORMAT('***** FATAL ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      'GGDPDF SUBROUTINE IS ZERO *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      IF(X.LE.R1MACH(1))THEN
        PDF=0.0
        RETURN
      ENDIF
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
      DC=DBLE(C)
!
      DUL=D1MACH(2)
      IF(C.GE.1.0)THEN
        IF(DX.GT.DUL**(1.0D0/DC))THEN
          WRITE(ICOUT,106)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ENDIF
      ELSEIF(C.GT.0.0.AND.C.LT.1.0)THEN
        IF(DX.GT.DUL**DC)THEN
          WRITE(ICOUT,106)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ENDIF
      ELSE
        CONTINUE
      ENDIF
  106 FORMAT('***** FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT ',   &
      'TO THE GGDPDF SUBROUTINE GENERATES AN INVALID VALUE *****')
!
      DTERM1=DLOG(DABS(DC))
      DTERM2=(DC*DALPHA-1.0D0)*DLOG(DX)
      DTERM3=-(DX**DC)
      DTERM4=DLNGAM(DALPHA)
      DTERM5=DTERM1+DTERM2+DTERM3-DTERM4
      DPDF=0.0D0
      IF(DTERM5.GE.-80.0D0)DPDF=DEXP(DTERM5)
      PDF=REAL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GGDPDF
