      DATA SIG /1.0D-5/
      DATA ZERO /0.0D0/
      DATA MAXIT /3000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      DMEAN=0.0D0
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GGDPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ALPHA.LE.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GGDPPF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.EQ.0)THEN
        WRITE(ICOUT,16)
   16   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GGDPPF ',   &
               'IS ZERO.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      IF(P.EQ.0.)THEN
        PPF=0.
        GO TO 9999
      ENDIF
!
!  FIND BRACKETING INTERVAL.
!
      DP=DBLE(P)
      DALPHA=DBLE(ALPHA)
      DC=DBLE(C)
!
      XL=0.0D0
      IF(DC.LE.0.0D0)THEN
        XINC=5.0
        XR=XL+XINC
      ELSE
        DMEAN=DEXP(DLNGAM(DALPHA+1.0D0/DC) - DLNGAM(DALPHA))
        XR=DMEAN
        DTERM1=DEXP(DLNGAM(DALPHA+2.0D0/DC) - DLNGAM(DALPHA))
        DTERM2=2.0D0*(DLNGAM(DALPHA+1.0D0/DC) - DLNGAM(DALPHA))
        DSD=DTERM1 - DEXP(DTERM2)
        DSD=DSQRT(DSD)
        XINC=DSD
      ENDIF
      ICOUNT=0
      MAXCNT=10000
!
   91 CONTINUE
      IF(XL.LE.0.0D0)XL=0.0D0
      IF(XR.LE.0.0D0)XR=XL+DMEAN
      CALL GG2CDF(XL,DALPHA,DC,CDFL)
      CALL GG2CDF(XR,DALPHA,DC,CDFR)
      IF(CDFL.LT.DP .AND. CDFR.LT.DP)THEN
        XL=XR
        XR=XL+XINC
      ELSEIF(CDFL.GT.DP .AND. CDFR.GT.DP)THEN
        XL=XL-XINC
        IF(XL.LT.0.0D0)XL=0.0D0
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** FATAL ERROR--GGDPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL. *****')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -DP
      FXR = 1.0D0 - DP
  105 CONTINUE
      X = (XL+XR)*0.5D0
      CALL GG2CDF(X,DALPHA,DC,DCDF)
      P1=DCDF
      PPF=REAL(X)
      FCS = P1 - DP
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** FATAL ERROR--GGDPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GGDPPF
      SUBROUTINE GGDRAN(N,ALPHA,C,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED GAMMA DISTRIBUTION
!              WITH SHAPE PARAMETERS GAMMA AND C.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = C*X**(ALPHA*C-1)*EXP((-X)**C)/GAMMA(ALPHA)
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                                ALPHA SHOULD BE POSITIVE.
!                     --C      = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GAMMA DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA SHOULD BE POSITIVE.
!                 --C NOT EQUAL TO 0.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JAMES E. GENTLE (2003). 'RANDOM NUMBER GENERATION
!                 AND MONTE CARLO METHODS', SPRINGER-VERLANG.
!                 USE HIS SUGGESTED METHOD OF OBTANING A GAMMA
!                 RANDOM VARIABLE AND EXPONENTIATING.
!               --"NON-UNIFORM RANDOM VARIATE GENERATION",
!                 LUC DEVROYE, SPRINGER-VERLAG, 1986, P. 423.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/9
!     ORIGINAL VERSION--SEPTEMBER 2003.
!     FIXED           --APRIL     2004. EXPONENTIATE BY (1/C), NOT C.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!CCCC DIMENSION XN(2)
!CCCC DIMENSION U(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!CCCC DATA ATHIRD/0.3333333/
!CCCC DATA SQRT3 /1.73205081/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
               'GAMMA RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(ALPHA.LE.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE ALPHA SHAPE PARAMETER FOR THE ',   &
               'GENERALIZED GAMMA RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.EQ.0)THEN
        WRITE(ICOUT,16)
   16   FORMAT('***** ERROR--THE C SHAPE PARAMETER FOR THE ',   &
               'GENERALIZED GAMMA RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     GENERATE N GAMMA DISTRIBUTION RANDOM NUMBERS
!     USING AHRENS-DIETER METHOD AND THEN EXPONENTIATE BY (1/C).
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        ATEMP=SGAMMA(ISEED,ALPHA)
        X(I)=ATEMP**(1.0/C)
!CCCC   ATEMP=X(I)
!CCCC   CALL GGDPPF(ATEMP,ALPHA,C,APPF)
!CCCC   X(I)=APPF
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE GGDRAN
      FUNCTION GFUNCT(X,NOBS,BETA,XGM)
!
! COMPUTE G FUNCTION USED IN ESTIMATING THE SHAPE PARAMETER (BETA)
!   XGM IS THE GEOMETRIC MEAN OF THE X'S USED IN ESTIMATING ALPHA
!
      DIMENSION X(*)
!
      RN=FLOAT(NOBS)
!
      ALPHA=FNALPH(X,NOBS,BETA,XGM)
      SUMYZ=0.0
      DO 10 I=1,NOBS
           SUMYZ=SUMYZ+LOG(X(I))*((X(I)/ALPHA)**BETA-1.)
   10 CONTINUE
!
      GFUNCT=(SUMYZ/RN)-1.0/BETA
!
      RETURN
      END FUNCTION GFUNCT
      SUBROUTINE GHCDF(X,G,H,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE G-H DISTRIBUTION
!              WITH SHAPE PARAMETERS G AND H.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND THE
!              CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE PPF FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --G      = THE SKEWNESS SHAPE PARAMETER
!                     --H      = THE KURTOSIS SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOAGLIN, 'SUMMARIZING SHAPES NUMERICALLY: THE
!                 G-AND-H DISTRIBUTION", IN "EXPLORING DATA TABLES,
!                 TRENDS AND SHAPES", HOAGLIN, MOSTELLER, TUKEY,
!                 WILEY, 1985.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL CDF
      REAL G
      REAL H
      REAL PLOW
      REAL PUP
      REAL XLOW
      REAL XUP
!
      REAL GHFU2
      EXTERNAL GHFU2
!
      REAL X2
      COMMON/GH2COM/X2
!
      REAL G2
      REAL H2
      COMMON/GHCOM/G2,H2
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      CDF=0.0
      XUP=0.0
      XLOW=0.0
      IF(H.LT.0.0)THEN
        WRITE(ICOUT, 7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)H
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    7 FORMAT('***** ERROR--THE THIRD (H) INPUT ARGUMENT TO THE ',   &
      'GHCDF SUBROUTINE IS NEGATIVE *****')
   48 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',F15.7,' *****')
!
!  IF G AND H BOTH ZERO, USE NORCDF.
!
      IF(G.EQ.0.0 .AND. H.EQ.0.0)THEN
        CALL NORCDF(X,CDF)
        GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.
!
!
      DP=-1.0D0
      CALL GHPPF(0.01,G,H,XCDF01,DP,DPPF)
      IF(X.LT.XCDF01)THEN
        PLOW=0.0000001
        DP=-1.0D0
        CALL GHPPF(PLOW,G,H,XLOW,DP,DPPF)
        IF(X.LT.XLOW)THEN
          CDF=0.0
          GO TO 9000
        ENDIF
        PUP=0.015
        GO TO 1000
      ENDIF
      DP=-1.0D0
      CALL GHPPF(0.1,G,H,XCDF1,DP,DPPF)
      IF(X.GE.XCDF01 .AND. X.LE.XCDF1)THEN
        PLOW=0.005
        PUP=0.15
        GO TO 1000
      ENDIF
      DP=-1.0D0
      CALL GHPPF(0.9,G,H,XCDF9,DP,DPPF)
      IF(X.GE.XCDF1 .AND. X.LE.XCDF9)THEN
        PLOW=0.05
        PUP=0.95
        GO TO 1000
      ENDIF
      DP=-1.0D0
      CALL GHPPF(0.95,G,H,XCDF95,DP,DPPF)
      IF(X.GE.XCDF95)THEN
        PUP=0.9999999
        DP=-1.0D0
        CALL GHPPF(PUP,G,H,XUP,DP,DPPF)
        IF(X.GT.XUP)THEN
          CDF=1.0
          GO TO 9000
        ENDIF
        PLOW=0.945
        GO TO 1000
      ELSE
        PLOW=0.89
        PUP=0.96
      ENDIF
!
 1000 CONTINUE
      AE=1.E-6
      RE=1.E-6
      G2=G
      H2=H
      X2=X
      IFLAG=0
      CALL FZERO(GHFU2,PLOW,PUP,PUP,RE,AE,IFLAG)
!
      CDF=PLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM GHCDF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      CDF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GHCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      CDF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GHCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM GHCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GHCDF
      SUBROUTINE GFUNC2(X,N,IR,ALPHA,GAMMA,WEIVAL)
!
!   COMPUTE FUNCTION USED IN ESTIMATING THE SHAPE
!   PARAMETERS FOR A CENSORED WEIBULL DISTRIBUTION.
!
      DOUBLE PRECISION DN, DG, DIR, DX, DALPHA
      DOUBLE PRECISION DSUM1, DSUM2, DSUM3
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4
      DIMENSION X(*)
!
!  CALCULATE SOME INTERMEDIATE VALUES
!
      DN=DBLE(N)
      DIR=DBLE(IR)
      DG=DBLE(GAMMA)
      DALPHA=DBLE(ALPHA)
!
      DSUM1=0.0
      DSUM2=0.0
      DSUM3=0.0
!
      DO 100 I=1,IR
        DX=DBLE(X(I))
        DSUM1=DSUM1 + DX**DG
        DSUM2=DSUM2 + (DX**DG)*DLOG(DX)
        DSUM3=DSUM3 + DLOG(DX)
  100 CONTINUE
!
      DX=DBLE(X(IR))
      DTERM1=DSUM2 + DBLE(N-IR)*(DX**DG)*DLOG(DX)
      DTERM2=1.0D0/(DSUM1 + DBLE(N-IR)*DX**DG)
      DTERM3=DSUM3/DIR
      DTERM4=1.0D0/(DTERM1 + DTERM2 - DTERM3)
!
      WEIVAL=GAMMA - REAL(DTERM4)
      ALPHA=FNALP2(X,N,IR,GAMMA)
!
      RETURN
      END SUBROUTINE GFUNC2
      REAL FUNCTION GHFU2(P)
!
!     PURPOSE--GHCDF CALLS FZERO TO FIND A ROOT FOR THE G-H
!              CUMULATIVE DISTRIBUTION FUNCTION.  GHFU2 IS THE
!              FUNCTION FOR WHICH THE ZERO IS FOUND.  IT IS:
!                 X - GHPPF(P,G,H)
!              WHERE X IS THE DESIRED CUMULATIVE DISTRIBUTION POINT.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION FUNCTION VALUE GHFU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GHPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOAGLIN, 'SUMMARIZING SHAPES NUMERICALLY: THE
!                 G-AND-H DISTRIBUTION", IN "EXPLORING DATA TABLES,
!                 TRENDS AND SHAPES", HOAGLIN, MOSTELLER, TUKEY,
!                 WILEY, 1985.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL P
!
      REAL X
      COMMON/GH2COM/X
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
!
      REAL G
      REAL H
      COMMON/GHCOM/G,H
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DP=-1.0D0
      CALL GHPPF(P,G,H,PPF,DP,DPPF)
      GHFU2=X - PPF
!
      RETURN
      END FUNCTION GHFU2
      REAL FUNCTION GHFU3(X)
!
!     PURPOSE--GHPDF CALLS DIFF TO FIND A NUMERICAL DERIVATIVE
!              FOR THE G-H CUMULATIVE DISTRIBUTION FUNCTION.  GHFU3
!              IS A FUNCTION THAT CALL GHCDF.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE DERIVATIVE
!                                IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION FUNCTION VALUE GHFU3.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GHCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOAGLIN, 'SUMMARIZING SHAPES NUMERICALLY: THE
!                 G-AND-H DISTRIBUTION", IN "EXPLORING DATA TABLES,
!                 TRENDS AND SHAPES", HOAGLIN, MOSTELLER, TUKEY,
!                 WILEY, 1985.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL G
      REAL H
      COMMON/GHCOM/G,H
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL GHCDF(X,G,H,CDF)
      GHFU3=CDF
!
      RETURN
      END FUNCTION GHFU3
      SUBROUTINE GHPDF(X,G,H,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE G-H DISTRIBUTION
!              WITH SHAPE PARAMETERS G AND H.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND THE
!              PROBABILITY DENSITY FUNCTION IS COMPUTED BY COMPUTING
!              THE NUMERICAL DERIVATIVE OF THE CUMULATIVE DISTRIBUTION
!              FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --G      = THE SKEWNESS SHAPE PARAMETER
!                     --H      = THE KURTOSIS SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOAGLIN, 'SUMMARIZING SHAPES NUMERICALLY: THE
!                 G-AND-H DISTRIBUTION", IN "EXPLORING DATA TABLES,
!                 TRENDS AND SHAPES", HOAGLIN, MOSTELLER, TUKEY,
!                 WILEY, 1985.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL PDF
      REAL G
      REAL H
!
      REAL GHFU3
      EXTERNAL GHFU3
!
      REAL G2
      REAL H2
      COMMON/GHCOM/G2,H2
!
      CHARACTER*4 IERROR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IERROR='OFF'
      PDF=0.0
      IF(H.LT.0.0)THEN
        WRITE(ICOUT, 7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)H
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    7 FORMAT('***** ERROR--THE THIRD (H) INPUT ARGUMENT TO THE ',   &
      'GHPDF SUBROUTINE IS NEGATIVE *****')
   48 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',F15.7,' *****')
!
!  IF G AND H BOTH ZERO, USE NORPDF.
!
      IF(G.EQ.0.0 .AND. H.EQ.0.0)THEN
        CALL NORPDF(X,PDF)
        GO TO 9000
      ENDIF
!
!  FIND NUMERIC DERIVATIVE OF CDF ROUTINE
!
      IORD=1
      EPS=0.0001
      ACCUR=0.0
      IFAIL=0
      X0 = X
      XMIN=CPUMIN
      XMAX=CPUMAX
      G2=G
      H2=H
!
      CALL DIFF(IORD,X0,XMIN,XMAX,GHFU3,EPS,ACCUR,PDF,ERROR,IFAIL)
!
        IF(IFAIL.EQ.1)THEN
  999     FORMAT(1X)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,301)
  301     FORMAT('***** WARNING IN NUMERICAL DERIVATIVE FOR GHPDF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,303)
  303     FORMAT('      THE ESTIMATED ERROR IN THE RESULT EXCEEDS THE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,305)
  305     FORMAT('      REQUESTED ERROR, BUT THE MOST ACCURATE RESULT')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,307)
  307     FORMAT('      POSSIBLE HAS BEEN RETURNED.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(IFAIL.EQ.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,311)
  311     FORMAT('***** ERROR IN NUMERICAL DERIVATIVE FOR GHPDF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,313)
  313     FORMAT('      ERROR IN THE INPUT TO THE DIFF ROUTINE.')
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          ERROR=0.0
          IERROR='YES'
          GO TO 9000
        ELSEIF(IFAIL.EQ.3)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,321)
  321     FORMAT('***** ERROR IN NUMERICAL DERIVATIVE FOR GHPDF--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,323)
  323     FORMAT('      THE INTERVAL FOR DIFFERENTIATION, (',G15.7,   &
                 ',',G15.7,')')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,325)
  325     FORMAT('      IS TOO SMALL.')
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          ERROR=0.0
          IERROR='YES'
          GO TO 9000
        ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GHPDF
      SUBROUTINE GHPPF(P,G,H,PPF,DP,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION FROM THE THE G AND H DISTIBUTION WITH
!              LOCATION = 0 AND SCALE = 1.  THE PERCENT POINT
!              FUNCTION IS DEFINED AS:
!              G(P,G,H) = [(EXP(G*Zp)-1)/G]*EXP(H*Zp**2/2)
!              WHERE Zp IS THE PERCENT POINT FUNCTION OF THE STANDARD
!              NORMAL DISTRIBUTION AND
!              G AND H ARE SHAPE PARAMETERS (G CONTROLS SKEWNESS
!              (0 = SYMMETRIC) AND H CONTROLS HOW HEAVY THE TAILS
!              ARE.  G=H=0 IMPLIES A STANDARD NORMAL DISTRIBUTION.
!              WHEN G=0, THE PERCENT POINT FUNCTION IS DEFINED AS:
!              F(X) = Z*EXP(H*Z**2/2)
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --G      = FIRST SHAPE PARAMETER (DETERMINES
!                                SKEWNESS WITH G=0 BEING SYMMETRIC)
!                     --H      = SECOND SHAPE PARAMETER (DETERMINES
!                                "HEAVY TAILEDNESS"
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     NOTE--SAVE DOUBLE PRECISION VALUES FOR P AND PPF (DP, DPPF)
!           FOR USE BY THE GHCDF FUNCTION
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION VALUE PPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOAGLIN, 'SUMMARIZING SHAPES NUMERICALLY: THE
!                 G-AND-H DISTRIBUTION", IN "EXPLORING DATA TABLES,
!                 TRENDS AND SHAPES", HOAGLIN, MOSTELLER, TUKEY,
!                 WILEY, 1985.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.1
!     ORIGINAL VERSION--JANUARY   2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL H
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DP
      DOUBLE PRECISION DG
      DOUBLE PRECISION DH
      DOUBLE PRECISION DPPF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
!CCCC ELSEIF(G.LT.0.0)THEN
!CCCC   WRITE(ICOUT, 6)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,48)G
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
      ELSEIF(H.LT.0.0)THEN
        WRITE(ICOUT, 7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)H
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST (P) ARGUMENT TO GHPPF ',   &
             'IS OUTSIDE THE (0,1) INTERVAL')
!CCC6 FORMAT('***** FATAL ERROR--THE SECOND (G) INPUT ARGUMENT TO THE ',
!CCC 1'GHPPF SUBROUTINE IS NEGATIVE *****')
    7 FORMAT('***** ERROR--THE THIRD (H) ARGUMENT TO GHPPF ',   &
             'IS NEGATIVE')
   48 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     TRANSFORM THE NORMAL PPF
!
      IF(DP.LT.0.0D0)THEN
        DP=DBLE(P)
      ENDIF
      DG=DBLE(G)
      DH=DBLE(H)
!
      CALL NODPPF(DP,DTERM3)
      IF(G.EQ.0.0 .AND. H.EQ.0.0)THEN
        PPF=REAL(DTERM3)
      ELSEIF(G.EQ.0.0)THEN
        DPPF=DTERM3*DEXP(DH*DTERM3*DTERM3/2.0D0)
        PPF=REAL(DPPF)
      ELSEIF(H.EQ.0.0)THEN
        DPPF=(DEXP(DG*DTERM3)-1.0D0)/DG
        PPF=REAL(DPPF)
      ELSE
        DTERM1=(DEXP(DG*DTERM3)-1.0D0)/DG
        DTERM2=DEXP(DH*DTERM3*DTERM3/2.0D0)
        DPPF=DTERM1*DTERM2
        PPF=REAL(DPPF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GHPPF
      SUBROUTINE GHRAN(N,G,H,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE THE G AND H DISTIBUTION WITH LOCATION = 0
!              AND SCALE = 1.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              X AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = [(EXP(G*Z)-1)/g]*EXP(H*Z**2/2)
!              WHERE Z IS A STANDARD NORMAL DISTRIBUTION AND
!              G AND H ARE SHAPE PARAMETERS (G CONTROLS SKEWNESS
!              (0 = SYMMETRIC) AND H CONTROLS HOW HEAVY THE TAILS
!              ARE.  G=H=0 IMPLIES A STANDARD NORMAL DISTRIBUTION.
!              WHEN G = 0, THE FUNCTION IS:
!              F(X) = Z*EXP(H*Z**2/2)
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!                     --G      = A SINGLE PRECISON SCALAR THAT DEFINES
!                                THE SKEWNESS SHAPE PARAMETER.
!                     --H      = A SINGLE PRECISON SCALAR THAT DEFINES
!                                THE "HEAVY-TAILEDNESS" SHAPE
!                                PARAMETER.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE G-AND-H DISTRIBUTION
!             WITH LOCATION = 0 AND SCALE = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     METHOD--TRANSFORM NORMAL RANDOM NUMBERS
!     REFERENCES--HOAGLIN, 'SUMMARIZING SHAPES NUMERICALLY: THE
!                 G-AND-H DISTRIBUTION", IN "EXPLORING DATA TABLES,
!                 TRENDS AND SHAPES", HOAGLIN, MOSTELLER, TUKEY,
!                 WILEY, 1985.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2003.1
!     ORIGINAL VERSION--JANUARY   2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      REAL G
      REAL H
      DOUBLE PRECISION DQ
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST (N) ARGUMENT TO ',   &
               'GHRAN IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
!CCCC ELSEIF(G.LT.0.0)THEN
!CCCC   WRITE(ICOUT, 6)
!CCC6   FORMAT('***** ERROR--THE SECOND (G) ARGUMENT TO GHRAN ',
!CCCC1         'IS NEGATIVE.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,48)G
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
      ELSEIF(H.LT.0.0)THEN
        WRITE(ICOUT, 7)
    7   FORMAT('***** ERROR--THE THIRD (H) ARGUMENT TO GHRAN ',   &
               'IS NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)H
   48   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',F10.5,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     GENERATE N UNIFORM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N G-AND-H RANDON NUMBERS USING THE PERCENT POINT
!     FUNCTION TRANSFORMATION.
!
      DO 100 I=1,N
        Q=X(I)
        DQ=DBLE(-1.0D0)
        CALL GHPPF(Q,G,H,PPF,DQ,DPPF)
        X(I)=PPF
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GHRAN
      SUBROUTINE GIGCDF(X,LAMBDA,CHI,PSI,CDF)
!
!CCCC NOTE 7/2008: MODIFY PARAMERIZATION,
!
!CCCC SUBROUTINE GIGCDF(DX,CHI,LAMBDA,THETA,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED INVERSE GAUSSIAN
!              DISTRIBUTION.
!
!
!              THE PROBABILITY DENSITY FUNCTION IS:
!
!              f(X;LAMBDA,CHI,PSI) = SQRT(PSI/CHI)*X**(LAMBDA-1)*
!                                    EXP[-0.5*(LAMBDA/X + PSI*X)]/
!                                    {2*K1(SQRT(XHI*PSI))}
!                                    X > 0;
!                                    CHI > 0; PSI > 0
!
!              FOLLOWING IS PREVIOUS PARAMETERIZATION (BASED ON
!              PARAMETERIZATION GIVEN IN JOHNSON, KOTZ, AND
!              BALAKRISHNAN.  NOTE THAT THESE DEFINITIONS ARE
!              ACTUALLY EQUIVALENT.  I MADE THE SWITCH BECAUSE
!              THE NEW PARAMETERIZATION SEEMS TO BE THE MORE
!              COMMONLY USED.
!
!              SPECIFICALLY, THE RELATIONSHIP BETWEEN THE
!              PARAMETERIZATIONS IS:
!
!              NEW          OLD
!              ================
!              LAMBDA       THETA
!              PSI          LAMBDA
!              CHI          CHI
!
!              IT HAS SHAPE PARAMETERS CHI, LAMBDA,
!              AND THETA.  THIS DISTRIBUTION IS DEFINED FOR POSITIVE
!              X AND HAS THE PROBABILITY DENSITY FUNCTION
!                 f(X,CHI,LAMBDA,THETA) = C*X**(THETA-1)*
!                                         EXP(-(1/2)*(LAMBDA*X+CHI/X))
!                                         X > 0; CHI, LAMBDA > 0;
!                                         -INF < THETA < INF
!
!              WITH
!
!                 C = (LAMBDA/X)**(THETA/2)/[2*K(0)(SQRT(CHI*LAMBDA))]
!                     CHI, LAMBDA > 0
!
!                   = LAMBDA**THETA/[2**THETA*GAMMA(THETA)]
!                     CHI = 0; LAMBDA, THETA > 0
!
!                   = 2**THETA/[X**THETA*GAMMA(-THETA)]
!                     CHI > 0; LAMBDA=0; THETA < 0
!
!              WHERE K(LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              BY NUMERICALLY INTEGRATING THE PROBABILITY DENSITY
!              FUNCTION.
!
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE CUMULATIVE DISTRIBUTION
!                                 FUNCTION IS TO BE EVALUATED.
!                                 X SHOULD BE POSITIVE.
!                     --LAMBDA  = THE FIRST SHAPE PARAMETER
!                     --CHI     = THE SECOND SHAPE PARAMETER
!                     --THETA   = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF     = THE DOUBLE PRECISION CUMULATIVE
!                                 DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GENERALIZED INVERSE
!             GAUSSIAN DISTRIBUTION WITH SHAPE PARAMETERS LAMBDA,
!             CHI, AND PSI.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. pp. 284-285.
!               --PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!     UPDATED         --JULY      2008. MODIFY PARAMETERIZATION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION CHI
      DOUBLE PRECISION LAMBDA
      DOUBLE PRECISION PSI
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION CDF
      DOUBLE PRECISION X
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION GIGFUN
      EXTERNAL GIGFUN
!
      DOUBLE PRECISION DCHI
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DPSI
      COMMON/GIGCOM/DCHI,DLMBDA,DPSI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IFLAG=0
      CDF=0.0D0
      CDF2=0.0D0
!
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)X
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    4 FORMAT('***** ERROR: THE VALUE OF THE FIRST ARGUMENT (X) TO ',   &
             'GIGCDF IS NON-POSITIVE.')
!
      ELSEIF(CHI.LT.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)CHI
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    5   FORMAT('***** ERROR: THE VALUE OF THE SECOND SHAPE PARAMETER ',   &
               '(CHI) TO GIGCDF IS NEGATIVE.')
!
      ELSEIF(PSI.LT.0.0D0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)PSI
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    6   FORMAT('***** ERROR: THE VALUE OF THE THIRD SHAPE PARAMETER ',   &
               '(PSI) TO GIGCDF IS NEGATIVE.')
!
      ELSEIF(CHI.EQ.0.0D0)THEN
        IF(LAMBDA.LE.0.0D0 .OR. PSI.LE.0.0D0)THEN
          WRITE(ICOUT,7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,8)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,49)LAMBDA
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,50)PSI
          CALL DPWRST('XXX','WRIT')
          GO TO 9000
        ELSE
          IFLAG=1
        ENDIF
    7   FORMAT('***** ERROR: IF VALUE OF SECOND SHAPE PARAMETER ',   &
             '(CHI) TO GIGCDF IS EQUAL ZERO,')
    8 FORMAT('      THEN FIRST (LAMBDA) AND THIRD (PSI) SHAPE ',   &
             'PARAMETERS MUST BE POSITIVE.')
   49 FORMAT('      VALUE OF FIRST SHAPE PARAMETER IS: ',G15.7)
   50 FORMAT('      VALUE OF THIRD SHAPE PARAMETER IS: ',G15.7)
!
      ELSEIF(PSI.EQ.0.0D0)THEN
        IF(LAMBDA.GE.0.0D0 .OR. CHI.LE.0.0D0)THEN
          WRITE(ICOUT,9)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,10)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,11)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,51)CHI
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,52)PSI
          CALL DPWRST('XXX','WRIT')
          GO TO 9000
        ELSE
          IFLAG=2
        ENDIF
    9   FORMAT('***** ERROR: IF VALUE OF THIRD SHAPE PARAMETER ',   &
             '(PSI) TO GIGCDF ROUTINE IS EQUAL ZERO,')
   10   FORMAT('      THEN FIRST SHAPE PARAMETER (LAMBDA) PARAMETER ',   &
             'MUST BE NEGATIVE AND')
   11   FORMAT('      THE SECOND SHAPE PARAMETER (CHI) MUST BE ',   &
             'POSITIVEE.')
   51   FORMAT('      VALUE OF FIRST SHAPE PARAMETER IS: ',G15.7)
   52   FORMAT('      VALUE OF SECOND SHAPE PARAMETER IS: ',G15.7)
      ENDIF
!
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE CDF     FUNCTION  **
!               ************************************
!
!
!     BOUNDARY CASE I: GAMMA DISTRIBUTION WITH SHAPE PARAMETER
!                      LAMBDA AND SCALE PARAMETER PSI/2.
!
      IF(IFLAG.EQ.1)THEN
!
        SCALE=REAL(PSI/2.0D0)
        X2=REAL(X)/SCALE
        CALL GAMCDF(X2,REAL(LAMBDA),CDF2)
        CDF=DBLE(CDF2)
        GO TO 9000
!
!     BOUNDARY CASE II: INVERTED GAMMA DISTRIBUTION WITH SHAPE PARAMETER
!                       -LAMBDA AND SCALE PARAMETER CHI/2.
!
      ELSEIF(IFLAG.EQ.2)THEN
!
        SCALE=REAL(CHI/2.0D0)
        X2=REAL(X)/SCALE
        CALL IGACDF(X2,REAL(-LAMBDA),PDF2)
        CDF=DBLE(CDF2)
        GO TO 9000
      ENDIF
!
      EPSABS=0.0D0
      EPSREL=1.0D-7
      IER=0
      DCHI=CHI
      DLMBDA=LAMBDA
      DPSI=PSI
      CDF=0.0D0
!
      INF=1
!
      CALL DQAGI(GIGFUN,X,INF,EPSABS,EPSREL,CDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
      CDF=1.0D0 - CDF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM GIGCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GIGCDF
