      SUBROUTINE GIGPDF(X,LAMBDA,CHI,PSI,PDF)
!
!CCCC NOTE 7/2008: MODIFY PARAMETERIZATION.
!
!CCCC SUBROUTINE GIGPDF(X,CHI,LAMBDA,THETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED INVERSE GAUSSIAN
!              DISTRIBUTION.
!
!              f(X;LAMBDA,CHI,PSI) = SQRT(PSI/CHI)*X**(LAMBDA-1)*
!                                    EXP[-0.5*(LAMBDA/X + PSI*X)]/
!                                    {2*K1(SQRT(XHI*PSI))}
!                                    X > 0;
!                                    CHI > 0; PSI > 0
!
!              FOLLOWING IS PREVIOUS PARAMETERIZATION (BASED ON
!              PARAMETERIZATION GIVEN IN JOHNSON, KOTZ, AND
!              BALAKRISHNAN.  NOTE THAT THESE DEFINITIONS ARE
!              ACTUALLY EQUIVALENT.  I MADE THE SWITCH BECAUSE
!              THE NEW PARAMETERIZATION SEEMS TO BE THE MORE
!              COMMONLY USED.
!
!              SPECIFICALLY, THE RELATIONSHIP BETWEEN THE
!              PARAMETERIZATIONS IS:
!
!              NEW          OLD
!              ================
!              LAMBDA       THETA
!              PSI          LAMBDA
!              CHI          CHI
!
!              IT HAS SHAPE PARAMETERS CHI, LAMBDA,
!              AND THETA.  THIS DISTRIBUTION IS DEFINED FOR POSITIVE
!              X AND HAS THE PROBABILITY DENSITY FUNCTION
!                 f(X,CHI,LAMBDA,THETA) = C*X**(THETA-1)*
!                                         EXP(-(1/2)*(LAMBDA*X+CHI/X))
!                                         X > 0; CHI, LAMBDA > 0;
!                                         -INF < THETA < INF
!
!              WITH
!
!                 C = (LAMBDA/X)**(THETA/2)/[2*K(0)(SQRT(CHI*LAMBDA))]
!                     CHI, LAMBDA > 0
!
!                   = LAMBDA**THETA/[2**THETA*GAMMA(THETA)]
!                     CHI = 0; LAMBDA, THETA > 0
!
!                   = 2**THETA/[X**THETA*GAMMA(-THETA)]
!                     CHI > 0; LAMBDA=0; THETA < 0
!
!              WHERE K(LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!                                 X SHOULD BE POSITIVE.
!                     --LAMBDA  = THE FIRST SHAPE PARAMETER
!                     --CHI     = THE SECOND SHAPE PARAMETER
!                     --THETA   = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF     = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE GENERALIZED INVERSE GAUSSIAN
!             DISTRIBUTION WITH SHAPE PARAMETERS = LAMBDA, CHI, PSI.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DBESK.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 284-285.
!               --PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!               --xx
!                 "HANDBOOK OF COMPUTATIONAL STATISTICS",
!                 SPRINGER-VERLAG, PP.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!     UPDATED         --JULY      2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION CHI
      DOUBLE PRECISION LAMBDA
      DOUBLE PRECISION PSI
      DOUBLE PRECISION PDF
      DOUBLE PRECISION ETA
      DOUBLE PRECISION OMEGA
      DOUBLE PRECISION P1
      DOUBLE PRECISION P2
      DOUBLE PRECISION C
!
      DOUBLE PRECISION DTEMP1(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      IFLAG=0
!
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)X
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
    4 FORMAT('***** ERROR: THE VALUE OF THE FIRST ARGUMENT (X) TO ',   &
             'GIGPDF IS NON-POSITIVE.')
!
      ELSEIF(CHI.LT.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)CHI
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
    5   FORMAT('***** ERROR: THE VALUE OF THE SECOND SHAPE PARAMETER ',   &
               '(CHI) TO GIGPDF IS NEGATIVE.')
!
      ELSEIF(PSI.LT.0.0D0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)PSI
        CALL DPWRST('XXX','WRIT')
        PDF=0.0
        GO TO 9000
    6   FORMAT('***** ERROR: THE VALUE OF THE THIRD SHAPE PARAMETER ',   &
               '(PSI) TO GIGPDF IS NEGATIVE.')
!
      ELSEIF(CHI.EQ.0.0D0)THEN
        IF(LAMBDA.LE.0.0D0 .OR. PSI.LE.0.0D0)THEN
          WRITE(ICOUT,7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,8)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,49)LAMBDA
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,50)PSI
          CALL DPWRST('XXX','WRIT')
          PDF=0.0
          GO TO 9000
        ELSE
          IFLAG=1
        ENDIF
    7   FORMAT('***** ERROR: IF VALUE OF SECOND SHAPE PARAMETER ',   &
             '(CHI) TO GIGPDF IS EQUAL ZERO,')
    8 FORMAT('      THEN FIRST (LAMBDA) AND THIRD (PSI) SHAPE ',   &
             'PARAMETERS MUST BE POSITIVE.')
   49 FORMAT('      VALUE OF FIRST SHAPE PARAMETER IS: ',G15.7)
   50 FORMAT('      VALUE OF THIRD SHAPE PARAMETER IS: ',G15.7)
!
      ELSEIF(PSI.EQ.0.0D0)THEN
        IF(LAMBDA.GE.0.0D0 .OR. CHI.LE.0.0D0)THEN
          WRITE(ICOUT,9)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,10)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,11)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,51)CHI
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,52)PSI
          CALL DPWRST('XXX','WRIT')
          PDF=0.0
          GO TO 9000
        ELSE
          IFLAG=2
        ENDIF
    9   FORMAT('***** ERROR: IF VALUE OF THIRD SHAPE PARAMETER ',   &
             '(PSI) TO GIGPDF ROUTINE IS EQUAL ZERO,')
   10   FORMAT('      THEN FIRST SHAPE PARAMETER (LAMBDA) PARAMETER ',   &
             'MUST BE NEGATIVE AND')
   11   FORMAT('      THE SECOND SHAPE PARAMETER (CHI) MUST BE ',   &
             'POSITIVEE.')
   51   FORMAT('      VALUE OF FIRST SHAPE PARAMETER IS: ',G15.7)
   52   FORMAT('      VALUE OF SECOND SHAPE PARAMETER IS: ',G15.7)
      ENDIF
!
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE DENSITY FUNCTION.  FOR **
!               **  BETTER NUMERICAL STABILITY,        **
!               **  COMPUTE LOGARIGHMS.                **
!               *****************************************
!
!
!
!CCCC USE ALGORITHM GIVEN ON PAGE 307 OF PAOLELLA.
!
      IF(IFLAG.EQ.0)THEN
        ETA=DSQRT(CHI/PSI)
        OMEGA=DSQRT(CHI*PSI)
        IARG1=1
        ISCALE=1
        CALL DBESK(OMEGA,DABS(LAMBDA),ISCALE,IARG1,DTEMP1,NZERO)
        C=1.0D0/(2*ETA**LAMBDA*DTEMP1(IARG1))
        P1=C*X**(LAMBDA-1.0D0)
        P2=-0.5D0*((CHI/X) + PSI*X)
        PDF=P1*EXP(P2)
!
!     BOUNDARY CASE I: GAMMA DISTRIBUTION WITH SHAPE PARAMETER
!                      LAMBDA AND SCALE PARAMETER PSI/2.
!
      ELSEIF(IFLAG.EQ.1)THEN
!
        SCALE=REAL(PSI/2.0D0)
        X2=REAL(X)/SCALE
        CALL GAMPDF(X2,REAL(LAMBDA),PDF2)
        PDF=DBLE(PDF2)/SCALE
!
!     BOUNDARY CASE II: INVERTED GAMMA DISTRIBUTION WITH SHAPE PARAMETER
!                       -LAMBDA AND SCALE PARAMETER CHI/2.
!
      ELSEIF(IFLAG.EQ.2)THEN
!
        SCALE=REAL(CHI/2.0D0)
        X2=REAL(X)/SCALE
        CALL IGAPDF(X2,REAL(-LAMBDA),PDF2)
        PDF=DBLE(PDF2)/SCALE
!
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GIGPDF
      SUBROUTINE GIGPPF(P,CHI,LAMBDA,PSI,PPF)
!
!     NOTE 7/2008: MODIFY PARAMETERIZATION.
!
!CCCC SUBROUTINE GIGPPF(P,CHI,LAMBDA,THETA,PPF)
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED INVERSE GAUSSIAN
!              DISTRIBUTION.
!
!              f(X;LAMBDA,CHI,PSI) = SQRT(PSI/CHI)*X**(LAMBDA-1)*
!                                    EXP[-0.5*(LAMBDA/X + PSI*X)]/
!                                    {2*K1(SQRT(XHI*PSI))}
!                                    X > 0;
!                                    CHI > 0; PSI > 0
!
!              FOLLOWING IS PREVIOUS PARAMETERIZATION (BASED ON
!              PARAMETERIZATION GIVEN IN JOHNSON, KOTZ, AND
!              BALAKRISHNAN.  NOTE THAT THESE DEFINITIONS ARE
!              ACTUALLY EQUIVALENT.  I MADE THE SWITCH BECAUSE
!              THE NEW PARAMETERIZATION SEEMS TO BE THE MORE
!              COMMONLY USED.
!
!              SPECIFICALLY, THE RELATIONSHIP BETWEEN THE
!              PARAMETERIZATIONS IS:
!
!              NEW          OLD
!              ================
!              LAMBDA       THETA
!              PSI          LAMBDA
!              CHI          CHI
!
!              IT HAS SHAPE PARAMETERS CHI, LAMBDA,
!              AND THETA.  THIS DISTRIBUTION IS DEFINED FOR POSITIVE
!              X AND HAS THE PROBABILITY DENSITY FUNCTION
!                 f(X,CHI,LAMBDA,THETA) = C*X**(THETA-1)*
!                                         EXP(-(1/2)*(LAMBDA*X+CHI/X))
!                                         X > 0; CHI, LAMBDA > 0;
!                                         -INF < THETA < INF
!
!              WITH
!
!                 C = (LAMBDA/X)**(THETA/2)/[2*K(0)(SQRT(CHI*LAMBDA))]
!                     CHI, LAMBDA > 0
!
!                   = LAMBDA**THETA/[2**THETA*GAMMA(THETA)]
!                     CHI = 0; LAMBDA, THETA > 0
!
!                   = 2**THETA/[X**THETA*GAMMA(-THETA)]
!                     CHI > 0; LAMBDA=0; THETA < 0
!
!              WHERE K(LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF WITH A BISECTION
!              METHOD (THE CDF IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE CDF FUNCTION).
!
!     INPUT  ARGUMENTS--P       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PERCENT POINT
!                                 FUNCTION IS TO BE EVALUATED.
!                                 0 < P < 1
!                     --LAMBDA  = THE FIRST SHAPE PARAMETER
!                     --CHI     = THE SECOND SHAPE PARAMETER
!                     --PSI     = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF     = THE DOUBLE PRECISION PERCENT POINT
!                                 FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE GENERALIZED INVERSE GAUSSIAN
!             DISTRIBUTION WITH SHAPE PARAMETERS = CHI, LAMBDA, PSI.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 284-285.
!               --PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--AUGUST    2004.
!     UPDATED         --JULY      2008. MODIFY PARAMETERIZATION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION PTEMP
      DOUBLE PRECISION CHI
      DOUBLE PRECISION LAMBDA
      DOUBLE PRECISION PSI
      DOUBLE PRECISION PPF
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      DOUBLE PRECISION DTEMP1(10)
!
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION RE
      DOUBLE PRECISION AE
!
      DOUBLE PRECISION GIGFU2
      EXTERNAL GIGFU2
!
      DOUBLE PRECISION DP
      COMMON/GIGCO2/DP
!
      DOUBLE PRECISION DCHI
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DPSI
      COMMON/GIGCOM/DCHI,DLMBDA,DPSI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      PPF=0.0D0
      IFLAG=0
!
      IF(P.LE.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)P
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    4   FORMAT('***** ERROR: VALUE OF THE FIRST ARGUMENT (P) TO ',   &
             'GIGPPF IS OUTSIDE THE (0,1) INTERVAL.')
!
      ELSEIF(CHI.LT.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)CHI
        CALL DPWRST('XXX','WRIT')
        PPF=0.0D0
        GO TO 9000
    5   FORMAT('***** ERROR: THE VALUE OF THE SECOND SHAPE PARAMETER ',   &
               '(CHI) TO GIGPPF IS NEGATIVE.')
!
      ELSEIF(PSI.LT.0.0D0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)PSI
        CALL DPWRST('XXX','WRIT')
        PPF=0.0
        GO TO 9000
    6   FORMAT('***** ERROR: THE VALUE OF THE THIRD SHAPE PARAMETER ',   &
               '(PSI) TO GIGPPF IS NEGATIVE.')
!
      ELSEIF(CHI.EQ.0.0D0)THEN
        IF(LAMBDA.LE.0.0D0 .OR. PSI.LE.0.0D0)THEN
          WRITE(ICOUT,7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,8)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,49)LAMBDA
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,50)PSI
          CALL DPWRST('XXX','WRIT')
          PPF=0.0
          GO TO 9000
        ELSE
          IFLAG=1
        ENDIF
    7   FORMAT('***** ERROR: IF VALUE OF SECOND SHAPE PARAMETER ',   &
             '(CHI) TO GIGPPF IS EQUAL ZERO,')
    8 FORMAT('      THEN FIRST (LAMBDA) AND THIRD (PSI) SHAPE ',   &
             'PARAMETERS MUST BE POSITIVE.')
   49 FORMAT('      VALUE OF FIRST SHAPE PARAMETER IS: ',G15.7)
   50 FORMAT('      VALUE OF THIRD SHAPE PARAMETER IS: ',G15.7)
!
      ELSEIF(PSI.EQ.0.0D0)THEN
        IF(LAMBDA.GE.0.0D0 .OR. CHI.LE.0.0D0)THEN
          WRITE(ICOUT,9)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,10)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,11)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,51)CHI
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,52)PSI
          CALL DPWRST('XXX','WRIT')
          PPF=0.0
          GO TO 9000
        ELSE
          IFLAG=2
        ENDIF
    9   FORMAT('***** ERROR: IF VALUE OF THIRD SHAPE PARAMETER ',   &
             '(PSI) TO GIGPPF ROUTINE IS EQUAL ZERO,')
   10   FORMAT('      THEN FIRST SHAPE PARAMETER (LAMBDA) PARAMETER ',   &
             'MUST BE NEGATIVE AND')
   11   FORMAT('      THE SECOND SHAPE PARAMETER (CHI) MUST BE ',   &
             'POSITIVEE.')
   51   FORMAT('      VALUE OF FIRST SHAPE PARAMETER IS: ',G15.7)
   52   FORMAT('      VALUE OF SECOND SHAPE PARAMETER IS: ',G15.7)
      ENDIF
!
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE PERCENT POINT FUNCTION.**
!               *****************************************
!
!     BOUNDARY CASE I: GAMMA DISTRIBUTION WITH SHAPE PARAMETER
!                      LAMBDA AND SCALE PARAMETER PSI/2.
!
      IF(IFLAG.EQ.1)THEN
!
        SCALE=REAL(PSI/2.0D0)
        P2=REAL(P)
        CALL GAMPPF(P2,REAL(LAMBDA),PPF2)
        PPF=SCALE*PPF2
        GO TO 9000
!
!     BOUNDARY CASE II: INVERTED GAMMA DISTRIBUTION WITH SHAPE PARAMETER
!                       -LAMBDA AND SCALE PARAMETER CHI/2.
!
      ELSEIF(IFLAG.EQ.2)THEN
!
        SCALE=REAL(CHI/2.0D0)
        P2=REAL(P)
        CALL IGAPPF(P2,REAL(-LAMBDA),PPF2)
        PPF=SCALE*PPF2
        GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  LOWER BOUND IS ZERO.  START
!          WITH UPPER BOUND = MEAN:
!             MEAN=K(LAMBDA+1)(SQRT(PSI*CHI))*SQRT(CHI/PSI)/
!                      K(LAMBDA)(SQRT(PSI*CHI))
!          INCREMENT IN INTERVALS OF 1 STANDARD DEVIATION:
!             VARIANCE=K(LAMBDA+2)(SQRT(PSI*CHI))*(CHI/PSI)/
!                      K(LAMBDA)(SQRT(PSI*CHI))
!
      XLOW=0.000000001D0
      CALL GIGCDF(XLOW,CHI,LAMBDA,PSI,PTEMP)
      IF(P.LE.PTEMP)THEN
        PPF=XLOW
        GO TO 9000
      ENDIF
!
      IARG1=1
      ISCALE=1
      DR=DABS(LAMBDA)
      CALL DBESK(DSQRT(PSI*CHI),DR,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM1=DTEMP1(1)
      DR=DABS(LAMBDA+1.0D0)
      CALL DBESK(DSQRT(PSI*CHI),DR,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM2=DTEMP1(1)
      DR=DABS(LAMBDA+2.0D0)
      CALL DBESK(DSQRT(PSI*CHI),DR,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM3=DTEMP1(1)
      DMEAN=(DTERM2/DTERM1)*DSQRT(CHI/PSI)
      DSD=DSQRT((DTERM3/DTERM1)*(CHI/PSI))
!
      MAXIT=1000
      NIT=0
!
      XUP2=DMEAN
  200 CONTINUE
        IF(NIT.GT.MAXIT)THEN
          PPF=0.0D0
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,131)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,133)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
        CALL GIGCDF(XUP2,CHI,LAMBDA,PSI,PTEMP)
        IF(PTEMP.GT.P)THEN
          XUP=XUP2
        ELSE
          XLOW=XUP2
          XUP2=XUP2 + DSD
          NIT=NIT+1
          GO TO 200
        ENDIF
!
      AE=1.D-7
      RE=1.D-7
      DCHI=CHI
      DLMBDA=LAMBDA
      DPSI=PSI
      DP=P
      CALL DFZERO(GIGFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM GIGPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GIGPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GIGPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM GIGPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GIGPPF
      SUBROUTINE GIGRAN(N,CHI,LAMBDA,PSI,ISEED,X)
!
!CCCC NOTE 7/2008: MODIFY PARAMETERIZATION.
!
!CCCC SUBROUTINE GIGRAN(N,CHI,LAMBDA,THETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE THE GENERALIZED INVERSE GAUSSIAN DISTIBUTION.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!                     --LAMBDA = A SINGLE PRECISON SCALAR THAT DEFINES
!                                THE FIRST SHAPE PARAMETER.
!                     --CHI     = A SINGLE PRECISON SCALAR THAT DEFINES
!                                THE SECOND SHAPE PARAMETER.
!                     --PSI    = A SINGLE PRECISON SCALAR THAT DEFINES
!                                THE THIRD SHAPE PARAMETER.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE COMPERTZ-MAKEHAM
!             DISTRIBUTION WITH LOCATION = 0 AND SCALE = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GIGPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     METHOD--TRANSFORM NORMAL RANDOM NUMBERS
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 284-285.
!               --PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.8
!     ORIGINAL VERSION--OCTOBER   2004.
!     UPDATED         --JULY      2008. MODIFY PARAMERIZATION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      REAL CHI
      REAL PSI
      REAL LAMBDA
!
      DOUBLE PRECISION DCHI
      DOUBLE PRECISION DPSI
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DXTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IFLAG=0
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 3)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT, 4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    3 FORMAT('***** ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
      'INVERSE GAUSIAN')
    4 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
!
      ELSEIF(CHI.LT.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)CHI
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
    5   FORMAT('***** ERROR: THE VALUE OF THE SECOND SHAPE PARAMETER ',   &
               '(CHI) IS NEGATIVE.')
!
      ELSEIF(PSI.LT.0.0D0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)PSI
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    6   FORMAT('***** ERROR: THE VALUE OF THE THIRD SHAPE PARAMETER ',   &
               '(PSI) IS NEGATIVE.')
!
      ELSEIF(CHI.EQ.0.0D0)THEN
        IF(LAMBDA.LE.0.0D0 .OR. PSI.LE.0.0D0)THEN
          WRITE(ICOUT,7)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,8)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,49)LAMBDA
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,50)PSI
          CALL DPWRST('XXX','WRIT')
          GO TO 9000
        ELSE
          IFLAG=1
        ENDIF
    7   FORMAT('***** ERROR: IF VALUE OF SECOND SHAPE PARAMETER ',   &
             '(CHI) IS EQUAL ZERO,')
    8 FORMAT('      THEN FIRST (LAMBDA) AND THIRD (PSI) SHAPE ',   &
             'PARAMETERS MUST BE POSITIVE.')
   49 FORMAT('      VALUE OF FIRST SHAPE PARAMETER IS: ',G15.7)
   50 FORMAT('      VALUE OF THIRD SHAPE PARAMETER IS: ',G15.7)
!
      ELSEIF(PSI.EQ.0.0D0)THEN
        IF(LAMBDA.GE.0.0D0 .OR. CHI.LE.0.0D0)THEN
          WRITE(ICOUT,9)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,10)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,11)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,51)CHI
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,52)PSI
          CALL DPWRST('XXX','WRIT')
          GO TO 9000
        ELSE
          IFLAG=2
        ENDIF
    9   FORMAT('***** ERROR: IF VALUE OF THIRD SHAPE PARAMETER ',   &
             '(PSI) IS EQUAL ZERO,')
   10   FORMAT('      THEN FIRST SHAPE PARAMETER (LAMBDA) PARAMETER ',   &
             'MUST BE NEGATIVE AND')
   11   FORMAT('      THE SECOND SHAPE PARAMETER (CHI) MUST BE ',   &
             'POSITIVEE.')
   51   FORMAT('      VALUE OF FIRST SHAPE PARAMETER IS: ',G15.7)
   52   FORMAT('      VALUE OF SECOND SHAPE PARAMETER IS: ',G15.7)
      ENDIF
!
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     GENERATE N GENERALIZED INVERSE GAUSSIAN RANDON NUMBERS USING
!     THE PERCENT POINT FUNCTION TRANSFORMATION.
!
      IF(IFLAG.EQ.0)THEN
!
!       GENERATE N UNIFORM NUMBERS;
!
        CALL UNIRAN(N,ISEED,X)
        DCHI=DBLE(CHI)
        DLMBDA=DBLE(LAMBDA)
        DPSI=DBLE(PSI)
        DO 100 I=1,N
          DXTEMP=DBLE(X(I))
          CALL GIGPPF(DXTEMP,DLMBDA,DCHI,DPSI,DPPF)
          X(I)=REAL(DPPF)
  100   CONTINUE
!
!     BOUNDARY CASE I: GAMMA DISTRIBUTION WITH SHAPE PARAMETER
!                      LAMBDA AND SCALE PARAMETER PSI/2.
!
      ELSEIF(IFLAG.EQ.1)THEN
        CALL GAMRAN(N,LAMBDA,ISEED,X)
        SCALE=PSI/2.0
        DO 210 I=1,N
          X(I)=SCALE*X(I)
  210   CONTINUE
!
!     BOUNDARY CASE II: INVERTED GAMMA DISTRIBUTION WITH SHAPE PARAMETER
!                       -LAMBDA AND SCALE PARAMETER PSI/2.
!
      ELSEIF(IFLAG.EQ.2)THEN
        SHAPE=-LAMBDA
        CALL IGARAN(N,SHAPE,ISEED,X)
        SCALE=CHI/2.0
        DO 310 I=1,N
          X(I)=SCALE*X(I)
  310   CONTINUE
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GIGRAN
      SUBROUTINE GI2CDF(X,LAMBDA,OMEGA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED INVERSE GAUSSIAN
!              DISTRIBUTION PARAMETERIZED TO HAVE 2 SHAPE PARAMETERS
!              (AS OPPOSSED TO 3 SHAPE PARAMETERS IN THE ORIGINAL
!              PARAMETERIZATION).
!
!              f(X;LAMBDA,OMEGA) = X**(LAMBDA-1)*EXP[-0.5*OMEGA((1/X) + X)]/
!                                    {2*K(OMEGA,LAMBDA)}
!                                    X > 0; OMEGA > 0;
!
!              WHERE K(X,LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              BY NUMERICALLY INTEGRATING THE PROBABILITY DENSITY
!              FUNCTION.
!
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE CUMULATIVE DISTRIBUTION
!                                 FUNCTION IS TO BE EVALUATED.
!                                 X SHOULD BE POSITIVE.
!                     --LAMBDA  = THE FIRST SHAPE PARAMETER
!                     --OMEGA   = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF     = THE DOUBLE PRECISION CUMULATIVE
!                                 DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GENERALIZED INVERSE
!             GAUSSIAN DISTRIBUTION WITH SHAPE PARAMETERS LAMBDA AND OMEGA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. pp. 284-285.
!               --PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.7
!     ORIGINAL VERSION--JULY      2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION LAMBDA
      DOUBLE PRECISION OMEGA
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION CDF
      DOUBLE PRECISION X
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION GI2FUN
      EXTERNAL GI2FUN
!
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DOMEGA
      COMMON/GI2COM/DLMBDA,DOMEGA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IFLAG=0
      CDF=0.0D0
!
      IF(X.LE.0.0D0)THEN
        GO TO 9000
!
      ELSEIF(OMEGA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)OMEGA
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    5   FORMAT('***** ERROR: THE VALUE OF THE SECOND SHAPE PARAMETER ',   &
               '(OMEGA) TO GIGCDF IS NEGATIVE.')
!
      ENDIF
!
   48 FORMAT('      THE VALUE OF THE ARGUMENT IS: ',G15.7)
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE CDF     FUNCTION  **
!               ************************************
!
      EPSABS=0.0D0
      EPSREL=1.0D-7
      IER=0
      DOMEGA=OMEGA
      DLMBDA=LAMBDA
      INF=1
!
      CALL DQAGI(GI2FUN,X,INF,EPSABS,EPSREL,CDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
      CDF=1.0D0 - CDF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM GI2CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GI2CDF
      DOUBLE PRECISION FUNCTION GI2FUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED INVERSE GAUSIAN
!              DISTRIBUTION WITH SHAPE PARAMETERS LAMBDA AND
!              OMEGA.  THIS DISTRIBUTION IS DEFINED FOR POSITIVE X.
!              FOR ALL X AND HAS THE PROBABILITY DENSITY FUNCTION
!              THE GI2PDF ROUTINE IS CALLED TO COMPUTE THE
!              PROBABILITY DENSITY (CHECK FOR THE FORMULA IN THAT
!              ROUTINE).  DEFINE AS FUNCTION TO BE USED FOR INTEGRATION
!              CODE CALLED BY GI2CDF.  THIS ROUTINE USES
!              DOUBLE PRECISION ARITHMETIC.
!     INPUT  ARGUMENTS--DX      = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--GI2FUN  = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED INVERSE
!             GAUSSIAN DISTRIBUTION WITH SHAPE PARAMETERS LAMBDA
!             AND OMEGA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GI2PDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!               --GENTLE, HARDLE, MORI (EDS.) (2004),
!                 "HANDBOOK OF COMPUTATIONAL STATISTICS: CONCEPTS AND
!                 METHODS", SPRINGER-VERLAG, PP. 933.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
