      SUBROUTINE GI2PDF(X,LAMBDA,OMEGA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED INVERSE GAUSSIAN
!              DISTRIBUTION PARAMETERIZED TO HAVE 2 SHAPE PARAMETERS
!              (AS OPPOSSED TO 3 SHAPE PARAMETERS IN THE ORIGINAL
!              PARAMETERIZATION).
!
!              f(X;LAMBDA,OMEGA) = X**(LAMBDA-1)*EXP[-0.5*OMEGA((1/X) + X)]/
!                                    {2*K(OMEGA,LAMBDA)}
!                                    X > 0; OMEGA > 0;
!
!              WHERE K(X,LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!                                 X SHOULD BE POSITIVE.
!                     --LAMBDA  = THE FIRST SHAPE PARAMETER
!                     --OMEGA   = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF     = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE GENERALIZED INVERSE GAUSSIAN
!             DISTRIBUTION WITH SHAPE PARAMETERS = LAMBDA AND OMEGA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DBESK.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!               --GENTLE, HARDLE, MORI (EDS.) (2004),
!                 "HANDBOOK OF COMPUTATIONAL STATISTICS: CONCEPTS AND
!                 METHODS", SPRINGER-VERLAG, PP. 933.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.7
!     ORIGINAL VERSION--JULY      2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION OMEGA
      DOUBLE PRECISION LAMBDA
      DOUBLE PRECISION PDF
      DOUBLE PRECISION P1
      DOUBLE PRECISION P2
      DOUBLE PRECISION C
!
      DOUBLE PRECISION DTEMP1(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      IFLAG=0
      PDF=0.0D0
!
      IF(X.LE.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)X
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    4 FORMAT('***** ERROR: THE VALUE OF THE FIRST ARGUMENT (X) TO ',   &
             'GIGPDF IS NON-POSITIVE.')
!
      ELSEIF(OMEGA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)OMEGA
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    5   FORMAT('***** ERROR: THE VALUE OF THE SECOND SHAPE PARAMETER ',   &
               '(OMEGA) TO GIGPDF IS NEGATIVE.')
!
      ENDIF
!
   48 FORMAT('      THE VALUE OF THE ARGUMENT IS: ',G15.7)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE DENSITY FUNCTION.  FOR **
!               **  BETTER NUMERICAL STABILITY,        **
!               **  COMPUTE LOGARIGHMS.                **
!               *****************************************
!
!
!
      IARG1=1
      ISCALE=1
      CALL DBESK(OMEGA,DABS(LAMBDA),ISCALE,IARG1,DTEMP1,NZERO)
      C=1.0D0/(2*DTEMP1(IARG1))
      P1=C*X**(LAMBDA-1.0D0)
      P2=-0.5D0*OMEGA*((1.0D0/X) + X)
      PDF=P1*EXP(P2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GI2PDF
      SUBROUTINE GI2PPF(P,LAMBDA,OMEGA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED INVERSE GAUSSIAN
!              DISTRIBUTION PARAMETERIZED TO HAVE 2 SHAPE PARAMETERS
!              (AS OPPOSSED TO 3 SHAPE PARAMETERS IN THE ORIGINAL
!              PARAMETERIZATION).
!
!              f(X;LAMBDA,OMEGA) = X**(LAMBDA-1)*EXP[-0.5*OMEGA((1/X) + X)]/
!                                    {2*K(OMEGA,LAMBDA)}
!                                    X > 0; OMEGA > 0;
!
!              WHERE K(X,LAMBDA) IS THE MODIFIED BESSEL FUNCTION
!              OF THE THIRD KIND.
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY
!              INVERTING THE CDF FUNCTION WITH A BISECTION
!              METHOD (THE CDF IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE CDF FUNCTION).
!
!     INPUT  ARGUMENTS--P       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PERCENT POINT
!                                 FUNCTION IS TO BE EVALUATED.
!                                 0 < P < 1
!                     --LAMBDA  = THE FIRST SHAPE PARAMETER
!                     --OMEGA   = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF     = THE DOUBLE PRECISION PERCENT POINT
!                                 FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE GENERALIZED INVERSE GAUSSIAN
!             DISTRIBUTION WITH SHAPE PARAMETERS LAMBDA AND OMEGA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!               --GENTLE, HARDLE, MORI (EDS.) (2004),
!                 "HANDBOOK OF COMPUTATIONAL STATISTICS: CONCEPTS AND
!                 METHODS", SPRINGER-VERLAG, PP. 933.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.7
!     ORIGINAL VERSION--JULY      2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION PTEMP
      DOUBLE PRECISION LAMBDA
      DOUBLE PRECISION OMEGA
      DOUBLE PRECISION PPF
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      DOUBLE PRECISION DTEMP1(10)
!
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION RE
      DOUBLE PRECISION AE
!
      DOUBLE PRECISION GI2FU2
      EXTERNAL GI2FU2
!
      DOUBLE PRECISION DP
      COMMON/GI2CO2/DP
!
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DOMEGA
      COMMON/GI2COM/DLMBDA,DOMEGA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      PPF=0.0D0
!
      IF(P.LE.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)P
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    4   FORMAT('***** ERROR: VALUE OF THE FIRST ARGUMENT (P) TO ',   &
             'GIGPPF IS OUTSIDE THE (0,1) INTERVAL.')
      ELSEIF(OMEGA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)OMEGA
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    5   FORMAT('***** ERROR: THE VALUE OF THE SECOND SHAPE PARAMETER ',   &
               '(OMEGA) TO GIGPDF IS NON-POSITIVE.')
!
      ENDIF
!
   48 FORMAT('      THE VALUE OF THE ARGUMENT IS: ',G15.7)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE PERCENT POINT FUNCTION.**
!               *****************************************
!
!  STEP 1: FIND BRACKETING INTERVAL.  LOWER BOUND IS ZERO.  START
!          WITH UPPER BOUND = MEAN:
!
!          MEAN=K(LAMBDA+1)(OMEGA)/K(LAMBDA)(OMEGA)
!
!          INCREMENT IN INTERVALS OF 1 STANDARD DEVIATION:
!
!          VARIANCE=
!          {K(LAMBDA+2)(OMEGA)*K(LAMBDA)(OMEGA) - K(LAMBDA+1)(OMEGA)**2}/
!          K(LAMBDA)(OMEGA)**2
!
      XLOW=0.000000001D0
      CALL GI2CDF(XLOW,LAMBDA,OMEGA,PTEMP)
      IF(P.LE.PTEMP)THEN
        PPF=XLOW
        GO TO 9000
      ENDIF
!
      IARG1=1
      ISCALE=1
      DR=DABS(LAMBDA)
      CALL DBESK(OMEGA,DR,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM1=DTEMP1(1)
      DR=DABS(LAMBDA+1.0D0)
      CALL DBESK(OMEGA,DR,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM2=DTEMP1(1)
      DR=DABS(LAMBDA+2.0D0)
      CALL DBESK(OMEGA,DR,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM3=DTEMP1(1)
      DMEAN=DTERM2/DTERM1
      DSD=DSQRT((DTERM1*DTERM3 - DTERM2**2)/DTERM1**2)
!
      MAXIT=1000
      NIT=0
!
      XUP2=DMEAN
  200 CONTINUE
        IF(NIT.GT.MAXIT)THEN
          PPF=0.0D0
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,131)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,133)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
        CALL GI2CDF(XUP2,LAMBDA,OMEGA,PTEMP)
        IF(PTEMP.GT.P)THEN
          XUP=XUP2
        ELSE
          XLOW=XUP2
          XUP2=XUP2 + DSD
          NIT=NIT+1
          GO TO 200
        ENDIF
!
      AE=1.D-7
      RE=1.D-7
      DLMBDA=LAMBDA
      DOMEGA=OMEGA
      DP=P
      CALL DFZERO(GI2FU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM GIGPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GI2PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GI2PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM GI2PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GI2PPF
      SUBROUTINE GI2RAN(N,LAMBDA,OMEGA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE THE GENERALIZED INVERSE GAUSSIAN DISTIBUTION
!              PARAMETERIZED WITH TWO SHAPE PARAMETERS.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!                     --LAMBDA = A SINGLE PRECISON SCALAR THAT DEFINES
!                                THE FIRST SHAPE PARAMETER.
!                     --OMEGA  = A SINGLE PRECISON SCALAR THAT DEFINES
!                                THE SECOND SHAPE PARAMETER.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE COMPERTZ-MAKEHAM
!             DISTRIBUTION WITH LOCATION = 0 AND SCALE = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GI2PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     METHOD--TRANSFORM NORMAL RANDOM NUMBERS
!     REFERENCES--PAOLELLA (2007), "INTERMEDIATE PROBABILITY: A
!                 COMPUTATIONAL APPROACH", WILEY, CHAPER 9.
!               --GENTLE, HARDLE, MORI (EDS.) (2004),
!                 "HANDBOOK OF COMPUTATIONAL STATISTICS: CONCEPTS AND
!                 METHODS", SPRINGER-VERLAG, PP. 933.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.7
!     ORIGINAL VERSION--JULY      2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      REAL OMEGA
      REAL LAMBDA
!
      DOUBLE PRECISION DOMEGA
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DXTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IFLAG=0
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 3)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT, 4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
    3 FORMAT('***** ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
      'INVERSE GAUSIAN')
    4 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
!
      ELSEIF(OMEGA.LE.0.0D0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)OMEGA
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
    6   FORMAT('***** ERROR: THE VALUE OF THE SECOND SHAPE PARAMETER ',   &
               '(OMEGA) IS NON-POSITIVE.')
!
      ENDIF
!
   47 FORMAT('      THE VALUE OF THE ARGUMENT IS: ',I8)
   48 FORMAT('      THE VALUE OF THE ARGUMENT IS: ',G15.7)
!
!     GENERATE N UNIFORM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED INVERSE GAUSSIAN RANDON NUMBERS USING
!     THE PERCENT POINT FUNCTION TRANSFORMATION.
!
!     NOTE: CHECK INTO DAGPUNAR'S GENERATOR.  UNTIL I TRACK THAT
!           DOWN, USE THE PERCENT POINT TRANSFORMATION.
!
      DLMBDA=DBLE(LAMBDA)
      DOMEGA=DBLE(OMEGA)
      DO 100 I=1,N
        DXTEMP=DBLE(X(I))
        CALL GI2PPF(DXTEMP,DLMBDA,DOMEGA,DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GI2RAN
      SUBROUTINE GINIMD(X,N,IWRITE,XTEMP,GMD,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE GINI MEAN DIFFERENCE
!              MEASURE OF DISPERSION.  THE FORMULA IS:
!
!                 GMD = (2/(N*(N-1))*
!                       SUM[j=1 to N][SUM[i < j][ABS(X(i) - X(j)]]
!                     = (2/(N*(N-1))*SUM[i=1 to N-1][i*(N-i)*
!                       (X(i+1) - X(i))]
!
!               WHERE X IS THE SORTED RESPONSES.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--GMD    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE GINI MEAN DIFFERENCE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE GINI
!             MEAN DIFFERENCE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TENA (2009), "TEST PROCEDURES FOR EQUALITY OF
!                 TWO VARIANCES IN DELTA DISTRIBUTIONS,"
!                 DISSERTATIONS, 695,
!                 https://scholarworks.wmich.edu/dissertations/695
!               --GINI (1921), "MEASUREMENT OF INEQUALITY IN
!                 INCOMES," THE ECONOMIC JOURNAL, 31, pp. 124-126.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/07
!     ORIGINAL VERSION--JULY      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DI
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DFACT
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DTERM
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GINI'
      ISUBN2='MD  '
      IERROR='NO'
!
      GMD=0.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NIMD')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF GINIMD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN GINI MEAN DIFFERENCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        GMD=0.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)
  136 FORMAT('***** WARNING IN GINI MEAN DIFFERENCE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,137)HOLD
  137 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
      CALL DPWRST('XXX','BUG ')
      GMD=0.0
      GO TO 9000
  139 CONTINUE
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  COMPUTE THE GINI MEAN DIFFERENCE         **
!               ***********************************************
!
      CALL SORT(X,N,XTEMP)
!
      DN=DBLE(N)
      DSUM=0.0D0
      DO 300 I=1,N-1
        DI=DBLE(I)
        DX1=XTEMP(I+1)
        DX2=XTEMP(I)
        DTERM=DI*(DN-DI)*(DX1-DX2)
        DSUM=DSUM+DTERM
  300 CONTINUE
      DFACT=2.0D0/(DN*(DN-1.0D0))
      DSUM=DFACT*DSUM
      GMD=REAL(DSUM)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,813)N,GMD
  813   FORMAT('THE GINI MEAN DIFFERENCE OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NIMD')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF GINIMD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,DSUM,DFACT,GMD
 9012   FORMAT('DSUM,DFACT,GMD = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE GINIMD
      SUBROUTINE GJACC(X,Y,N,ICASPL,IWRITE,STATVA,DIST,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE GENERALIZED JACCARD
!              COEFFICIENT BETWEEN THE TWO SETS OF DATA IN THE INPUT
!              VECTORS X AND Y.  THE SAMPLE GENERALIZED JACCARD
!              COEFFICIENT WILL BE A SINGLE PRECISION VALUE CALCULATED
!              USING THE FORMULA
!
!                 J(X,Y) = SUM[i=1 to n][MIN(X(i),Y(i)]/
!                          SUM[i=1 to n][MAX(X(i),Y(i)]
!
!              THE JACCARD DISTANCE IS THEN DEFINED AS 1 - J(X,Y).
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF UNSORTED
!                                OBSERVATIONS WHICH CONSTITUTE THE FIRST
!                                SET OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF UNSORTED
!                                OBSERVATIONS WHICH CONSTITUTE THE SECOND
!                                SET OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS IN
!                                THE IN THE VECTORS X AND Y.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED GENERALIZED JACCARD COEFFICIENT
!                                BETWEEN THE 2 SETS OF DATA IN THE INPUT
!                                VECTORS X AND Y.  THIS SINGLE PRECISION
!                                VALUE WILL BE BETWEEN -1.0 AND 1.0.
!                     --DIST   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED GENERALIZED JACCARD DISTANCE
!                                BETWEEN THE 2 SETS OF DATA IN THE INPUT
!                                VECTORS X AND Y.  THIS SINGLE PRECISION
!                                VALUE WILL BE BETWEEN -1.0 AND 1.0.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE JACCARD
!             COEFFICIENT BETWEEN THE 2 SETS OF DATA IN THE INPUT VECTORS
!             X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--MIN, MAX.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JACCARD (1912), "THE DISTRIBUTION OF FLORA IN THE
!                 ALPINE ZONE", NEW PHYTOLOGIST, VOL. 11, PP. 37-50.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/08
!     ORIGINAL VERSION--AUGUST    2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX1
      DOUBLE PRECISION DY1
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GJAC'
      ISUBN2='C   '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'JACC')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF GJACC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASPL,N
   52   FORMAT('IBUGA3,ISUBRO,ICASPL,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
         WRITE(ICOUT,56)I,X(I),Y(I)
   56    FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
         CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN GENERALIZED JACCARD COEFFICIENT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2--                                    **
!               **  COMPUTE THE GENERALIZED JACCARD COEFFICIENT **
!               **************************************************
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 200 I=1,N
        DX1=DBLE(X(I))
        DY1=DBLE(Y(I))
        IF(X(I).LE.Y(I))THEN
          DSUM1=DSUM1+DX1
          DSUM2=DSUM2+DY1
        ELSE
          DSUM1=DSUM1+DY1
          DSUM2=DSUM2+DX1
        ENDIF
  200 CONTINUE
!
      DSTAT=DSUM1/DSUM2
      STATVA=REAL(DSTAT)
      DSTAT=1.0D0 - DSTAT
      DIST=REAL(DSTAT)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(ICASPL.EQ.'GJCO')THEN
          WRITE(ICOUT,811)N,STATVA
  811     FORMAT('THE GENERALIZED JACCARD COEFFICIENT OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,813)N,DIST
  813     FORMAT('THE GENERALIZED JACCARD DISTANCE OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'JACC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF GJACC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,STATVA,DIST,DSUM1,DSUM2
 9012   FORMAT('IERROR,STATVA,DIST,DSUM1,DSUM2 = ',A4,2X,4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE GJACC
      SUBROUTINE GLDCDF(DX,DL3,DL4,DCDF,IGLDDF,IWRITE)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED LAMBDA DISTRIBUTION
!              WITH SHAPE PARAMETER VALUES = ALAMB3 AND ALAMB4.
!
!              NOTE THAT THERE ARE TWO COMMON PARAMETERIZATIONS
!              OF THIS PPF.
!
!              THE ORIGINAL RAMBERG AND SCHMEISER PARAMETERIZATION:
!
!                G(P) = P**LAMBDA3 - (1-P)**LAMBDA4
!
!              THE FREIMER, MUDHOLKAR, KOLLIA, AND LIN (FMKL)
!              PARAMETERIZATION:
!
!                G(P) = (P**LAMBDA3 - 1)/LAMBDA3  -
!                       ((1-P)**LAMBDA4 -1)/LAMBDA4
!
!              THE IDEF VARIABLE IDENTIFIES THE APPROPRIATE
!              DEFINITION TO USE.  THE FMKL DEFINITION IS
!              BECOMING THE PREFERRED PARAMETERIZATION) SINCE IT
!              DEFINES A VALID PROBABILITY DISTRIBUTION FOR ALL
!              VALUES OF LAMBDA3 AND LAMBDA4 (THE RAMBERG
!              PARAMETERIZATION HAS REGIONS OF LAMBDA3 AND LAMBDA4
!              WHERE A VALID PROBABILITY DISTRIBUTION IS NOT
!              DEFINED).
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DL3    = THE DOUBLE PRECISION VALUE OF LAMBDA3
!                                (THE FIRST SHAPE PARAMETER).
!                     --DL4    = THE DOUBLE PRECISION VALUE OF LAMBDA4
!                                (THE SECOND SHAPE PARAMETER).
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE DCDF FOR THE GENERALIZED TUKEY LAMBDA
!             DISTRIBUTION WITH SHAPE PARAMETERS = ALAMB3 AND ALAMB4.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--CALL GLDCHK TO CHECK FOR VALID VALUES OF THE
!                   SHAPE PARAMETERS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KARIAN AND DUDEWICZ, 'FITTING STATISTICAL
!                 DISTRIBUTIONS: THE GENERALIZED LAMBDA DISTRIBUTION
!                 AND GENERALIZED BOOTSTRAP METHODS', CRC, 2000.
!               --STEVE SU, "A DISCRETIZED APPROACH TO FLEXIBLY FIT
!                 GENRALIZED LAMBDA DISTRIBUTIONS TO DATA",
!                 JOURNAL OF MODERN APPLIED STATISTICAL METHODS,
!                 NOVEMBER, 2005,, VOL. 4, NO. 2, 408-424.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--AUGUST    2001.
!     UPDATED         --MARCH     2006. FLMK PARAMETERIZATION
!                                       MAKE DOUBLE PRECISION
!                                       BOUNDS ON CDF FOR CASE
!                                       WHERE EITHER LAMBDA3 OR
!                                       LAMBDA4 <= 0
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DL3
      DOUBLE PRECISION DL4
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DZERO
      DOUBLE PRECISION DONE
      DOUBLE PRECISION DLOWER
      DOUBLE PRECISION DUPPER
!CCCC DOUBLE PRECISION DEPS
      DOUBLE PRECISION PDEL
      DOUBLE PRECISION PMIN
      DOUBLE PRECISION PMAX
      DOUBLE PRECISION PMAXIN
      DOUBLE PRECISION PMID
      DOUBLE PRECISION PMIDZ
      DOUBLE PRECISION XCALC
      DOUBLE PRECISION XTEMP1
      DOUBLE PRECISION XTEMP2
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IGLDDF
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DZERO /0.0D0/
      DATA DONE  /1.0D0/
!CCCC DATA DEPS  /1.0D-8/
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DZERO=0.0D0
      DONE=1.0D0
!
!     RAMBERG PARAMETERIZATION NOT CURRENTLY SUPPORTED.  MAY
!     ADD LATER.
!
!CCCC IF(IGLDDF.EQ.'RAMB')THEN
!CCCC   CALL GLDCHK(REAL(DL3),REAL(DL4),ALOWER,AUPPER,IFLAG,
!CCCC1              ISIGN,IWRITE)
!CCCC   DLOWER=DBLE(ALOWER)
!CCCC   DUPPER=DBLE(AUPPER)
!CCCC   IF(IFLAG.EQ.1)GO TO 9000
!
!CCCC   IF(DX.LE.DLOWER)THEN
!CCCC     DCDF=0.0D0
!CCCC     GO TO 9000
!CCCC   ENDIF
!CCCC   IF(DX.GE.DUPPER)THEN
!CCCC     DCDF=1.0D0
!CCCC     GO TO 9000
!CCCC   ENDIF
!CCCC ELSE
!
!     FOR THE FMKL PARAMETERIZATION:
!
!     1) IF LAMBDA3 <= 0, THE LOWER TAIL IS UNBOUNDED.
!        IF LAMDA3   > 0, THE LOWER TAIL IS BOUNDED AT -1/LAMBDA3
!
!     2) IF LAMBDA4 <= 0, THE UPPER TAIL IS UNBOUNDED.
!        IF LAMDA4   > 0, THE UPPER TAIL IS BOUNDED AT 1/LAMBDA4
!
        IF(DL3.LE.0.0D0 .AND. DL4.LE.0.0D0)THEN
          DLOWER=DBLE(CPUMIN)
          DUPPER=DBLE(CPUMAX)
          PMIN=0.00001D0
          PMAX=0.99999D0
        ELSEIF(DL3.LE.0.0D0)THEN
          DLOWER=DBLE(CPUMIN)
          CALL GLDPPF(DONE,DL3,DL4,DUPPER,IGLDDF,IWRITE)
          PMIN=0.00001D0
          PMAX=1.0D0
        ELSEIF(DL4.LE.0.0D0)THEN
          CALL GLDPPF(DZERO,DL3,DL4,DLOWER,IGLDDF,IWRITE)
          DUPPER=DBLE(CPUMAX)
          PMIN=0.0D0
          PMAX=0.99999D0
        ELSE
          CALL GLDPPF(DZERO,DL3,DL4,DLOWER,IGLDDF,IWRITE)
          CALL GLDPPF(DONE,DL3,DL4,DUPPER,IGLDDF,IWRITE)
          PMIN=0.0D0
          PMAX=1.0D0
        ENDIF
!CCCC ENDIF
!
      DCDF=0.0D0
!
!  STEP 1: DETERMINE IF X IS OUTSIDE BOUNDS
!
      IF(DX.LE.DLOWER)THEN
        DCDF=0.0D0
        GO TO 9000
      ELSEIF(DX.GE.DUPPER)THEN
        DCDF=1.0D0
        GO TO 9000
      ENDIF
!
!  STEP 2: DETERMINE AN APPROPRIATE BRACKETING INTERVAL.
!          NOTE THAT THIS IS ONLY AN ISSUE IF ONE OR BOTH OF
!          THE SHAPE PARAMETERS IS ZERO.
!
      ITER=0
      PMAXIN=0.000009
  100 CONTINUE
        CALL GLDPPF(PMIN,DL3,DL4,XTEMP1,IGLDDF,IWRITE)
        CALL GLDPPF(PMAX,DL3,DL4,XTEMP2,IGLDDF,IWRITE)
        IF((DX.GE.XTEMP1) .AND. DX.LE.XTEMP2)THEN
          GO TO 200
          PMAX=XUP2
        ELSEIF(DX.LT.XTEMP1)THEN
          PMIN=PMIN/10.0D0
        ELSEIF(DX.GT.XTEMP2)THEN
          PMAXIN=PMAXIN/10.0D0
          PMAX=PMAX + PMAXIN
        ENDIF
!
        ITER=ITER+1
        IF(ITER.GT.20)THEN
          WRITE(ICOUT,201)
  201     FORMAT('***** ERROR FROM GLDCDF--UNABLE TO FIND A ',   &
                 'BRACKETING INTERVAL')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
!
      GO TO 100
!
!  ITERATION LOOP (BISECTION SEARCH OF PPF FUNCTION)
!
  200 CONTINUE
      PLOWER=PMIN
      PUPPER=PMAX
      PMID=0.5D0
      ICOUNT=0
!
      IWRITE='OFF'
  210 CONTINUE
      PMIDZ=PMID
      CALL GLDPPF(PMIDZ,DL3,DL4,XCALC,IGLDDF,IWRITE)
      IF(XCALC.EQ.DX)THEN
        DCDF=PMID
        GO TO 9000
      ELSEIF(XCALC.GT.DX)THEN
        PMAX=PMID
        PMID=(PMID+PMIN)/2.0D0
        PDEL=DABS(PMID-PMIN)
        ICOUNT=ICOUNT+1
        IF(PDEL.LT.0.00000001D0.OR.ICOUNT.GT.1000)THEN
          DCDF=PMID
          GO TO 9000
        ENDIF
        GO TO 210
      ELSE
        PMIN=PMID
        PMID=(PMID+PMAX)/2.0D0
        PDEL=DABS(PMID-PMIN)
        ICOUNT=ICOUNT+1
        IF(PDEL.LT.0.00000001D0.OR.ICOUNT.GT.1000)THEN
          DCDF=PMID
          GO TO 9000
        ENDIF
        GO TO 210
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GLDCDF
      SUBROUTINE GLDCHK(ALAMB3,ALAMB4,ALOWER,AUPPER,IFLAG,ISIGN,   &
      IWRITE)
!
!     PURPOSE--THIS SUBROUTINE DETERMINES IF THE SPECIFIED PARAMETERS
!              FOR THE GENERALIZD LAMBDA DISTRIBUTION RESULT IN
!              A VALID PROBABILITY DISTRIBUTION.  IF SO, IT ALSO
!              RETURNS THE LOWER AND UPPER RANGES OF THE PDF FOR
!              THE SPECIFIED VALUES.  IN PARTICULAR:
!              1) ALAMB3 >= 0, ALAMB4 >= 0:
!                 VALID,   (-1,1)
!              2) ALAMB3 <= 0, ALAMB4 <= 0:
!                 VALID,   (-1,1)
!              3) ALAMB3 <= -1, ALAMB4 >= 1:
!                 VALID,   (-1,1)
!              4) ALAMB3 >= 1, ALAMB4 <= -1:
!                 VALID
!              5) 0 < ALAMB3 < 1, ALAMB4 < 0:
!                 NOT VALID
!              6) ALAMB3 < 0, 0 < ALAMB4 < 1:
!                 NOT VALID
!              7) -1 < ALAMB3 < 0, ALAMB4 > 0:
!                 VALID IF
!                 [(1-ALAMB3)**(1-ALAMB3)]/
!                 [(ALAMB4-ALAMB3)**(ALAMB4-ALAMB3)]*
!                 (ALAMB4-1)**(ALAMB4-1) < -ALAMB3/ALAMB4
!              8)  ALAMB3 > 1, -1 < ALAMB4 < 0:
!                 VALID IF
!                 [(1-ALAMB4)**(1-ALAMB4)]/
!                 [(ALAMB3-ALAMB4)**(ALAMB3-ALAMB4)]*
!                 (ALAMB3-1)**(ALAMB3-1) < -ALAMB4/ALAMB3
!
!            --THE SUPPORT REGIONS ARE
!              1) ALAMB3 > 0, ALAMB4 > 0:     [-1,1]
!              2) ALAMB3 > 0, ALAMB4 = 0:     [0,1]
!              3) ALAMB3 = 0, ALAMB4 > 0:     [-1,0]
!              4) ALAMB3 < 0, ALAMB4 < 0:     (CPUMIN,CPUMAX)
!              5) ALAMB3 < 0, ALAMB4 = 0:     (CPUMIN,1]
!              6) ALAMB3 = 0, ALAMB4 < 0:     [-1,CPUMAX)
!
!           --NOTE: SIGN OF SHAPE PARAMETER MUST BE THE SAME AS
!                   SIGN RETURNED BY GLDPPF FUNCTION.  RETURN
!                   ISIGN AS +1 IF SHAPE MUST BE POSITIVE AND
!                   -1 IF SHAPE PARAMETER MUST BE NEGATIVE.
!
!           --THE ABOVE REGIONS FOR VALID PDFS AND SUPPORT REGIONS
!             ARE FROM KARIAN AND DUDEWIZC
!             (SEE REFERENCE BELOW)
!     INPUT  ARGUMENTS--ALAMB3 = THE SINGLE PRECISION VALUE OF LAMBDA3
!                                (THE FIRST SHAPE PARAMETER).
!                     --ALAMB4 = THE SINGLE PRECISION VALUE OF LAMBDA3
!                                (THE SECOND SHAPE PARAMETER).
!     OUTPUT ARGUMENTS--ALOWER = THE SINGLE PRECISION VALUE THAT IS
!                                THE MINIMUM OF THE ACCEPTABLE RANGE.
!                     --AUPPER = THE SINGLE PRECISION VALUE THAT IS
!                                THE MAXIMUM OF THE ACCEPTABLE RANGE.
!                     --IFLAG  = THE INTEGER FLAG THAT IS SET TO 0
!                                FOR A VALID DISTRIBUTION AND TO 1
!                                FOR AN INVALID DISTRIBUTION.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE TUKEY LAMBDA DISTRIBUTION
!             WITH TAIL LENGTH PARAMETERS = ALAMB3 AND ALAMB4.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--TO BE ADDED.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISIONS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KARIAN AND DUDEWICZ, 'FITTING STATISTICAL
!                 DISTRIBUTIONS: THE GENERALIZED LAMBDA DISTRIBUTION
!                 AND GENERALIZED BOOTSTRAP METHODS', CRC, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.8
!     ORIGINAL VERSION--AUGUST    2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DLAM3
      DOUBLE PRECISION DLAM4
      DOUBLE PRECISION DP
!
      CHARACTER*4 IWRITE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK FOR VALID PDF FIRST.  ASSUME VALID, THEN CHECK FOR
!     INVALID REGIONS AND THEN FOR AMBIGUOUS REGION.  NO NEED
!     TO EXPLICITLY CHECK THE FOUR VALID REGIONS.
!
      IFLAG=0
      IF(ALAMB3.GT.0.0 .AND. ALAMB4.GT.0.0)THEN
        ISIGN=+1
      ELSEIF(ALAMB3.LT.0.0 .AND. ALAMB4.LT.0.0)THEN
        ISIGN=-1
      ELSE
        DLAM3=ALAMB3
        DLAM4=ALAMB4
        DP=0.5D0
        DTERM1=DLAM3*DP**(DLAM3-1.0D0) +   &
               DLAM4*(1.0D0-DP)**(DLAM4-1.0D0)
        ISIGN=+1
        IF(DTERM1.LT.0.0D0)ISIGN=-1
      ENDIF
      ALOWER=CPUMIN
      AUPPER=CPUMAX
!
      IF(ALAMB3.LT.0.0 .AND. (0.0.LT.ALAMB4 .AND. ALAMB4.LT.1.0))THEN
        IFLAG=1
        GO TO 9000
      ENDIF
      IF(ALAMB4.LT.0.0 .AND. (0.0.LT.ALAMB3 .AND. ALAMB3.LT.1.0))THEN
        IFLAG=1
        GO TO 9000
      ENDIF
!
      IF(ALAMB4.GT.1.0 .AND. (-1.0.LT.ALAMB3 .AND. ALAMB3.LT.0.0))THEN
        DLAM3=DBLE(ALAMB3)
        DLAM4=DBLE(ALAMB4)
        DTERM1=(1.0D0-DLAM3)**(1.0D0-DLAM3)
        DTERM2=(DLAM4-DLAM3)**(DLAM4-DLAM3)
        DTERM3=(DLAM4-1.0D0)**(DLAM4-1.0D0)
        DTERM4=(DTERM1/DTERM2)*DTERM3
        DTERM5=-DLAM3/DLAM4
        IF(DTERM4.GE.DTERM5)THEN
          IFLAG=1
          GO TO 9000
        ENDIF
      ENDIF
      IF(ALAMB3.GT.1.0 .AND. (-1.0.LT.ALAMB4 .AND. ALAMB4.LT.0.0))THEN
        DLAM3=DBLE(ALAMB3)
        DLAM4=DBLE(ALAMB4)
        DTERM1=(1.0D0-DLAM4)**(1.0D0-DLAM4)
        DTERM2=(DLAM3-DLAM4)**(DLAM3-DLAM4)
        DTERM3=(DLAM3-1.0D0)**(DLAM3-1.0D0)
        DTERM4=(DTERM1/DTERM2)*DTERM3
        DTERM5=-DLAM4/DLAM3
        IF(DTERM4.GE.DTERM5)THEN
          IFLAG=1
          GO TO 9000
        ENDIF
      ENDIF
!
!     DETERMINE THE VALID SUPPORT REGION
!
      ALOWER=-1.0
      AUPPER=1.0
      IF(ALAMB3.GT.0.0 .AND. ALAMB4.EQ.0.0)THEN
        ALOWER=0.0
        AUPPER=1.0
      ELSEIF(ALAMB3.EQ.0.0 .AND. ALAMB4.GT.0.0)THEN
        ALOWER=-1.0
        AUPPER=0.0
      ELSEIF(ALAMB3.LT.0.0 .AND. ALAMB4.LT.0.0)THEN
        ALOWER=CPUMIN
        AUPPER=CPUMAX
      ELSEIF(ALAMB3.LT.0.0 .AND. ALAMB4.EQ.0.0)THEN
        ALOWER=CPUMIN
        AUPPER=1.0
      ELSEIF(ALAMB3.EQ.0.0 .AND. ALAMB4.LT.0.0)THEN
        ALOWER=-1.0
        AUPPER=CPUMAX
      ENDIF
!
 9000 CONTINUE
      IF(IFLAG.EQ.0 .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,9001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9003)ALAMB3
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9005)ALAMB4
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.1 .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,9011)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9003)ALAMB3
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9005)ALAMB4
        CALL DPWRST('XXX','BUG ')
      ENDIF
 9001 FORMAT('***** GIVEN SHAPE PARAMETERS RESULT IN A VALID ',   &
             'GENERALIZED LAMBDA DISTRIBUTION.')
 9003 FORMAT('      FIRST SHAPE PARAMETER (LAMBDA3)  = ',G15.7)
 9005 FORMAT('      SECOND SHAPE PARAMETER (LAMBDA4) = ',G15.7)
 9011 FORMAT('***** GIVEN SHAPE PARAMETERS DO NOT RESULT IN A VALID ',   &
             'GENERALIZED LAMBDA DISTRIBUTION.')
      RETURN
      END SUBROUTINE GLDCHK
      SUBROUTINE GLDPDF(DX,DL3,DL4,DPDF,IGLDDF,IWRITE)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED LAMBDA DISTRIBUTION
!              WITH SHAPE PARAMETER VALUES = DL3 (LAMBDA3) AND
!              DL4 (LAMBDA4).
!
!              NOTE THAT THERE ARE TWO COMMON PARAMETERIZATIONS
!              OF THIS PPF.
!
!              THE ORIGINAL RAMBERG AND SCHMEISER PARAMETERIZATION:
!
!                G(P) = P**LAMBDA3 - (1-P)**LAMBDA4
!
!              THE FREIMER, MUDHOLKAR, KOLLIA, AND LIN (FMKL)
!              PARAMETERIZATION:
!
!                G(P) = (P**LAMBDA3 - 1)/LAMBDA3  -
!                       ((1-P)**LAMBDA4 -1)/LAMBDA4
!
!              THE IDEF VARIABLE IDENTIFIES THE APPROPRIATE
!              DEFINITION TO USE.  THE FMKL DEFINITION IS
!              BECOMING THE PREFERRED PARAMETERIZATION) SINCE IT
!              DEFINES A VALID PROBABILITY DISTRIBUTION FOR ALL
!              VALUES OF LAMBDA3 AND LAMBDA4 (THE RAMBERG
!              PARAMETERIZATION HAS REGIONS OF LAMBDA3 AND LAMBDA4
!              WHERE A VALID PROBABILITY DISTRIBUTION IS NOT
!              DEFINED).
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DL3    = THE DOUBLE PRECISION VALUE OF LAMBDA3
!                                (THE FIRST SHAPE PARAMETER).
!                     --DL4    = THE DOUBLE PRECISION VALUE OF LAMBDA4
!                                (THE SECOND SHAPE PARAMETER).
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE GENERALIZED TUKEY LAMBDA DISTRIBUTION
!             WITH SHAPE PARAMETERS = DL3 AND DL4.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--CALL GLDCHK TO CHECK FOR VALID VALUES OF THE
!                   SHAPE PARAMETERS.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--KARIAN AND DUDEWICZ, 'FITTING STATISTICAL
!                 DISTRIBUTIONS: THE GENERALIZED LAMBDA DISTRIBUTION
!                 AND GENERALIZED BOOTSTRAP METHODS', CRC, 2000.
!               --STEVE SU, "A DISCRETIZED APPROACH TO FLEXIBLY FIT
!                 GENRALIZED LAMBDA DISTRIBUTIONS TO DATA",
!                 JOURNAL OF MODERN APPLIED STATISTICAL METHODS,
!                 NOVEMBER, 2005,, VOL. 4, NO. 2, 408-424.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSF
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DL3
      DOUBLE PRECISION DL4
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLOWER
      DOUBLE PRECISION DUPPER
      DOUBLE PRECISION DZERO
      DOUBLE PRECISION DONE
!
      CHARACTER*4 IGLDDF
      CHARACTER*4 IWRITE
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPDF=0.0D0
      DZERO=0.0D0
      DONE=1.0D0
!
!CCCC IF(IGLDDF.EQ.'RAMB')THEN
!CCCC   CALL GLDCHK(REAL(DL3),REAL(DL4),ALOWER,AUPPER,IFLAG,
!CCCC1              ISIGN,IWRITE)
!CCCC   IF(IFLAG.EQ.1)GO TO 9000
!CCCC   DLOWER=DBLE(ALOWER)
!CCCC   DUPPER=DBLE(AUPPER)
!CCCC ELSE
!
!     FOR THE FMKL PARAMETERIZATION:
!
!     1) IF LAMBDA3 <= 0, THE LOWER TAIL IS UNBOUNDED.
!        IF LAMDA3   > 0, THE LOWER TAIL IS BOUNDED AT -1/LAMBDA3
!
!     2) IF LAMBDA4 <= 0, THE UPPER TAIL IS UNBOUNDED.
!        IF LAMDA4   > 0, THE UPPER TAIL IS BOUNDED AT 1/LAMBDA4
!
        IF(DL3.LE.0.0D0 .AND. DL4.LE.0.0D0)THEN
          DLOWER=DBLE(CPUMIN)
          DUPPER=DBLE(CPUMAX)
        ELSEIF(DL3.LE.0.0D0)THEN
          DLOWER=DBLE(CPUMIN)
          CALL GLDPPF(DONE,DL3,DL4,DUPPER,IGLDDF,IWRITE)
        ELSEIF(DL4.LE.0.0D0)THEN
          CALL GLDPPF(DZERO,DL3,DL4,DLOWER,IGLDDF,IWRITE)
          DUPPER=DBLE(CPUMAX)
        ELSE
          CALL GLDPPF(DZERO,DL3,DL4,DLOWER,IGLDDF,IWRITE)
          CALL GLDPPF(DONE,DL3,DL4,DUPPER,IGLDDF,IWRITE)
        ENDIF
!CCCC ENDIF
!
      IF(DX.LT.DLOWER .OR. DX.GT.DUPPER)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3)DLOWER,DUPPER
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO GLDPDF',   &
             'IS OUTSIDE')
    3 FORMAT('      THE ALLOWABLE INTERVAL (',G15.7,',',G15.7,')')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
!
      IWRITE='OFF'
!
!CCCC IF(IGLDDF.EQ.'RAMB')THEN
!CCCC   CALL GLDCDF(DX,DL3,DL4,DCDF,IGLDDF,IWRITE)
!
!CCCC   DTERM1=0.0D0
!CCCC   DTERM2=0.0D0
!CCCC   DSF=0.0D0
!CCCC   IF(DCDF.GT.0.0D0)THEN
!CCCC     DTERM1=DL3*DCDF**DL3-1.0D0
!CCCC   ENDIF
!CCCC   IF((1.0D0-DCDF).GT.0.0D0)THEN
!CCCC     DTERM2=DL4*(1.0D0-DCDF)**(DL4-1.0D0)
!CCCC   ENDIF
!CCCC   DSF=DTERM1 + DTERM2
!CCCC   IF(DSF.NE.0.0D0)THEN
!CCCC     DPDF=1.0D0/DSF
!CCCC   ENDIF
!CCCC ELSE
        CALL GLDCDF(DX,DL3,DL4,DCDF,IGLDDF,IWRITE)
        DSF=DCDF**(DL3-1.0D0) + (1.0D0 - DCDF)**(DL4-1.0D0)
        IF(DSF.NE.0.0D0)THEN
          DPDF=1.0D0/DSF
        ELSE
          DPDF=0.0D0
        ENDIF
!CCCC ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GLDPDF
      SUBROUTINE GLDPPF(DP,DL3,DL4,DPPF,IGLDDF,IWRITE)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZD LAMBDA DISTRIBUTION
!              WITH SHAPE PARAMETERS ALAMB3 AND ALAMB4.
!              THIS DISTRIBUTION IS DEFINED IN TERMS OF ITS
!              PERCENT POINT FUNCTION.
!
!              NOTE THAT THERE ARE TWO COMMON PARAMETERIZATIONS
!              OF THIS PPF.
!
!              THE ORIGINAL RAMBERG AND SCHMEISER PARAMETERIZATION:
!
!                G(P) = P**LAMBDA3 - (1-P)**LAMBDA4
!
!              THE FREIMER, MUDHOLKAR, KOLLIA, AND LIN (FMKL)
!              PARAMETERIZATION:
!
!                G(P) = (P**LAMBDA3 - 1)/LAMBDA3  -
!                       ((1-P)**LAMBDA4 -1)/LAMBDA4
!
!              THE CASES WHERE LAMBDA3 AND LAMBDA4 EQUAL ZERO
!              HAVE TO BE HANDLED SEPARATELY.  SPECIFICALLY,
!              IF LAMBDA3 = 0, THEN
!
!                   (P**LAMBDA3 - 1)/LAMBDA3 = LOG(P)
!
!              IF LAMBDA4 = 0, THEN
!
!                   ((1-P)**LAMBDA4 - 1)/LAMBDA4 = LOG(1-P)
!
!              THE IDEF VARIABLE IDENTIFIES THE APPROPRIATE
!              DEFINITION TO USE.  THE FMKL DEFINITION IS
!              BECOMING THE PREFERRED PARAMETERIZATION) SINCE IT
!              DEFINES A VALID PROBABILITY DISTRIBUTION FOR ALL
!              VALUES OF LAMBDA3 AND LAMBDA4 (THE RAMBERG
!              PARAMETERIZATION HAS REGIONS OF LAMBDA3 AND LAMBDA4
!              WHERE A VALID PROBABILITY DISTRIBUTION IS NOT
!              DEFINED).
!
!              CURRENTLY, ONLY THE FMKL PARAMETERIZATION IS
!              SUPPORTED.
!
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DL3    = THE DOUBLE PRECISION VALUE OF LAMBDA3
!                                (THE FIRST SHAPE PARAMETER).
!                     --DL4    = THE DOUBLE PRECISION VALUE OF LAMBDA3
!                                (THE SECOND SHAPE PARAMETER).
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE TUKEY LAMBDA DISTRIBUTION
!             WITH TAIL LENGTH PARAMETERS = DL3 AND DL4.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--TO BE ADDED.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISIONS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KARIAN AND DUDEWICZ, "FITTING STATISTICAL
!                 DISTRIBUTIONS: THE GENERALIZED LAMBDA DISTRIBUTION
!                 AND GENERALIZED BOOTSTRAP METHODS", CRC, 2000.
!               --STEVE SU, "A DISCRETIZED APPROACH TO FLEXIBLY FIT
!                 GENRALIZED LAMBDA DISTRIBUTIONS TO DATA",
!                 JOURNAL OF MODERN APPLIED STATISTICAL METHODS,
!                 NOVEMBER, 2005,, VOL. 4, NO. 2, 408-424.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.8
!     ORIGINAL VERSION--AUGUST    2001.
!     UPDATED         --FEBRUARY  2006. SUPPORT FOR FMKL DEFINITION
!                                       AND MAKE ROUTINE DOUBLE
!                                       PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
!CCCC DOUBLE PRECISION DEPS
      DOUBLE PRECISION DL3
      DOUBLE PRECISION DL4
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      CHARACTER*4 IGLDDF
      CHARACTER*4 IWRITE
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ISUBG4.EQ.'DPPF')THEN
        WRITE(ICOUT,52)IWRITE,IGLDDF,DP,DL3,DL4
   52   FORMAT('IWRITE,IGLDDF,DP,DL3,DL4 = ',2(A4,2X),3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!CCCC IF(IGLDDF.EQ.'RAMB')THEN
!CCCC   IWRITE='ERRO'
!CCCC   CALL GLDCHK(ALAMB3,ALAMB4,ALOWER,AUPPER,IFLAG,ISIGN,IWRITE)
!CCCC   DPPF=0.0
!CCCC   DEPS=1.0D-12
!CCCC   IF(IFLAG.EQ.1)GO TO 9000
!CCCC   GO TO 9000
!CCCC ELSE
!CCCC   ALOWER=0.0
!CCCC   AUPPER=0.0
!CCCC ENDIF
!
!     FOR THE FMKL PARAMETERIZATION:
!
!     1) IF LAMBDA3 <= 0, THE LOWER TAIL IS UNBOUNDED.
!        IF LAMDA3   > 0, THE LOWER TAIL IS BOUNDED AT -1/LAMBDA3
!
!     2) IF LAMBDA4 <= 0, THE UPPER TAIL IS UNBOUNDED.
!        IF LAMDA4   > 0, THE UPPER TAIL IS BOUNDED AT 1/LAMBDA4
!
      IF(DL3.LE.0.0D0 .AND. DL4.LE.0.0D0)THEN
        IF(DP.LE.0.0D0 .OR. DP.GE.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSEIF(DL3.LE.0.0D0)THEN
        IF(DP.LE.0.0D0 .OR. DP.GT.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSEIF(DL4.LE.0.0D0)THEN
        IF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(DP.LT.0.0D0 .OR. DP.GT.1.0D0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO GLDPPF ',   &
      'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     CALCULATE THE PPF FUNCTION
!
!CCCC IF(IGLDDF.EQ.'RAMB')THEN
!CCCC   IF(DP.LE.DEPS)THEN
!CCCC     DPPF=DBLE(ALOWER)
!CCCC   ELSEIF(DP.GE.1.0D0-DEPS)THEN
!CCCC     DPPF=DBLE(AUPPER)
!CCCC   ELSEIF(DL3.EQ.0.0D0 .AND. DL4.EQ.0.0D0)THEN
!CCCC     DPPF=DLOG(DP) - DLOG(1.0D0 - DP)
!CCCC   ELSEIF(DL3.EQ.0.0D0)THEN
!CCCC     DPPF=DLOG(DP) - (1.0D0-DP)**DL4
!CCCC   ELSEIF(DL4.EQ.0.0D0)THEN
!CCCC     DPPF=DP**DL3 - DLOG(1.0D0 - DP)
!CCCC   ELSE
!CCCC     DPPF= DP**DL3 - (1.0D0-DP)**DL4
!CCCC   ENDIF
!CCCC ELSE
        IF(DL3.EQ.0.0D0 .AND. DL4.EQ.0.0D0)THEN
          DPPF=DLOG(DP) - DLOG(1.0D0 - DP)
        ELSEIF(DL3.EQ.0.0D0)THEN
          DPPF=DLOG(DP) - ((1.0D0-DP)**DL4 - 1.0D0)/DL4
        ELSEIF(DL4.EQ.0.0D0)THEN
          DPPF=(DP**DL3-1.0D0)/DL3 - DLOG(1.0D0 - DP)
        ELSE
          DTERM1=(DP**DL3-1.0D0)/DL3
          DTERM2=((1.0D0-DP)**DL4 - 1.0D0)/DL4
          DPPF=DTERM1 - DTERM2
        ENDIF
!CCCC ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GLDPPF
      SUBROUTINE GLDRAN(N,ALAMB3,ALAMB4,ISEED,IGLDDF,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FOR THE GENERALIZD LAMBDA DISTRIBUTION
!              WITH SHAPE PARAMETERS ALAMB3 AND ALAMB4.
!              THE PERCENT POINT FUNCTION FOR THIS DISTRIBUTION IS
!              G(P) = P**LAMBDA3 - (1-Y)**LAMBDA4
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALAMB3 = THE SINGLE PRECISION VALUE OF LAMBDA
!                                (THE FIRST SHAPE PARAMETER).
!                     --ALAMB4 = THE SINGLE PRECISION VALUE OF LAMBDA
!                                (THE FIRST SHAPE PARAMETER).
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED LAMBDA DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ALAMB3 AND ALAMB4.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 53-58.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --KARIAN AND DUDEWICZ, 'FITTING STATISTICAL
!                 DISTRIBUTIONS: THE GENERALIZED LAMBDA DISTRIBUTION
!                 AND GENERALIZED BOOTSTRAP METHODS', CRC, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.8
!     ORIGINAL VERSION--AUGUST    2001.
!     UPDATED         --FEBRUARY  2006. SUPPORT FOR FMKL
!                                       PARAMETERIZATION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DPPF
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IGLDDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IGLDDF.EQ.'RAMB')THEN
        IWRITE='ERRO'
        CALL GLDCHK(ALAMB3,ALAMB4,ALOWER,AUPPER,IFLAG,ISIGN,IWRITE)
        ZSCALE=1.0
        IF(ISIGN.LT.0)ZSCALE=-1.0
        IF(IFLAG.EQ.1)THEN
          DO 10 I=1,N
            X(I)=0.0
   10     CONTINUE
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--A NON-POSITIVE NUMBER OF RANDOM NUMBERS ',   &
             'WAS REQUESTED FOR ')
    6 FORMAT('      THE GENERALIZED TUKEY-LAMBDA DISTRIBUTION.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED TUKEY-LAMBDA DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      IWRITE='OFF'
      DO 100 I=1,N
        Q=X(I)
        CALL GLDPPF(DBLE(Q),DBLE(ALAMB3),DBLE(ALAMB4),DPPF,   &
                    IGLDDF,IWRITE)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GLDRAN
      SUBROUTINE GLGCDF(X,P,J,A,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE GENERALIZED LOST GAMES DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS P, A, AND
!              J.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= J.
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED FROM THE
!              RECURRENCE RELATION:
!
!              p(X;P,J,A) =(2*X+A-2*J-1)*(2*X+A-2*J-2)*P*(1-P)*p(X;P,J,A)/
!                          {(X-J)*(X+A-J)}
!
!              P(0;P,J,A)=P**A
!
!              THIS DISTRIBUTION IS USED TO MODEL THE "GAMBLER'S
!              RUIN" PROBLEM.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE AN INTEGR >= J.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER (PROBABILITY OF
!                                LOSING AN INDIVIDUAL GAME).
!                     --J      = THE INTEGER VALUE OF THE SECOND SHAPE
!                                PARAMETER.
!                     --A      = THE SINGLE PRECISION VALUE OF THE THIRD SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GENERALIZED LOST GAMES DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE AN INTEGER >= J
!                 --0.5 < P < 1,  AND J >= 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KEMP, AND KOTZ (2005).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION,
!                 WILEY, PP. 503-505.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/11
!     ORIGINAL VERSION--NOVEMBER  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DJ
      DOUBLE PRECISION DA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DC3
      DOUBLE PRECISION DC4
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.5 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GLGCDF ',   &
      ' IS OUTSIDE THE ALLOWABLE (0.5,1) INTERVAL')
!
      IF(J.LT.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)J
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO GLGCDF IS ',   &
      ' NEGATIVE')
!
      IF(A.LE.0.0)THEN
        WRITE(ICOUT,13)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)A
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
   13 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO GLGCDF IS ',   &
      ' NEGATIVE')
!
      INTX=INT(X+0.5)
      IF(INTX.LT.J)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)INTX
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GLGCDF IS LESS ',   &
      'THAN THE THIRD ARUGMENT')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
   48 FORMAT('***** THE VALUE OF THE THIRD ARGUMENT IS ',I8)
!
      DP=DBLE(P)
      DJ=DBLE(J)
      DA=DBLE(A)
      DCDF=0.0D0
!
!     USE THE RECURRENCE RELATION DESCRIBED ABOVE.
!
      DPDF=DA*DLOG(DP)
      DPDFSV=DPDF
      DCDF=DEXP(DPDF)
!
      IF(INTX.GT.J)THEN
        DO 200 I=J+1,INTX
          DX=DBLE(I)
          DC1=DLOG(2.0D0*DX+DA-2.0D0*DJ-1.0D0)
          DC2=DLOG(2.0D0*DX+DA-2.0D0*DJ-2.0D0)
          DC3=DLOG(DP) + DLOG(1.0D0-DP)
          DC4=DLOG(DX-DJ) + DLOG(DX+DA-DJ)
          DPDF=DC1 + DC2 + DC3 + DPDFSV - DC4
          DCDF=DCDF + DEXP(DPDF)
          DPDFSV=DPDF
  200   CONTINUE
      ENDIF
!
      CDF=REAL(DCDF)
!
 9999 CONTINUE
                                                                                                                                  
      RETURN
      END SUBROUTINE GLGCDF
      SUBROUTINE GLGFUN(N,X,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GENERALIZED LOST GAMES MAXIMUM LIKELIHOOD EQUATIONS.
!
!                 N*SUM[x>=0][f(x)*{(a+x)/p - x/(1-p)} = 0
!
!                 N*SUM[x >= 0][f(x)*{LOG(p) + 1/a + PSI(a+2*x) -
!                 PS(a+x-1)}] = 0
!
!              WITH P AND A DENOTING THE SHAPE PARAMETERS.
!
!              THIS ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--GENERALIZED LOST GAMES MAXIMUM LIKELIHOOD Y
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (2006).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION,
!                 WILEY, PP. 503-505.
!               --KEMP AND KEMP (1992), "A GROUP-DYNAMIC MODEL AND
!                 THE LOST-GAMES DISTRIBUTION", COMMUNICATIONS IN
!                 STATISTICS--THEORY AND METHODS, 21(3),
!                 PP. 791-798.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/12
!     ORIGINAL VERSION--DECEMBER  2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
!CCCC EXTERNAL DPSI
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DP
      DOUBLE PRECISION DA
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DFREQ
!CCCC DOUBLE PRECISION DPSI
!
      DOUBLE PRECISION XBAR,S2,F0
      COMMON/GLGCOM/XBAR,S2,F0,MAXNXT,IINDX,NTOT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DP=X(1)
      DA=X(2)
      DN=DBLE(NTOT)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 200 I=1,K
!
        DX=DBLE(Y(IINDX+I))
        DFREQ=DBLE(Y(I))
        IF(DFREQ.LE.0.0D0)GO TO 200
!
        DTERM1=((DA+DX)/DP) - (DX/(1.0D0-DP))
        DSUM1=DSUM1 + (DFREQ/DN)*DTERM1
!CCCC   DTERM1=DLOG(DP) + 1.0D0/DA + DPSI(DA+2.0D0*DX) -
!CCCC1         DPSI(DA+DX-1.0D0)
!CCCC   DSUM2=DSUM2 + (DFREQ/DN)*DTERM1
!
  200 CONTINUE
      FVEC(1)=DN*DSUM1
!CCCC FVEC(2)=DN*DSUM2
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 300 I=1,K
        DSUM2=0.0D0
        DX=DBLE(Y(IINDX+I))
        IF(DX.LT.1.99D0)GO TO 300
        DFREQ=Y(I)
        IK=INT(DX-1.0D0 + 0.5D0)
        DO 400 J=1,IK
          DX2=DBLE(Y(IINDX+J))
          DSUM2=DSUM2 + 1.0D0/(DA+DX+DBLE(J))
  400   CONTINUE
        DSUM1=DSUM1 + (DFREQ/DN)*DSUM2
  300 CONTINUE
!
      FVEC(2)=DN*DLOG(DP) + DN*(1.0D0 - F0)/DA + DN*DSUM1
!
      RETURN
      END SUBROUTINE GLGFUN
      SUBROUTINE GLGPDF(X,P,J,A,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE GENERALIZED LOST GAMES DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS P, A, AND
!              J.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= J AND HAS THE PROBABILITY
!              MASS FUNCTION:
!
!              p(X;P,J,A) = (2*X+A-2*J-1)!A*P**(A+X-J)*
!                           (1-P)**(X-J)/{(X+A-J)!*(X-J)!}
!                           X = J, J+1, ...
!                           A > 0; 0 < P < 1
!
!              THE PROBABILITIES CAN BE COMPUTED FROM THE FOLLOWING
!              RECURRENCE RELATION:
!
!              p(X;P,J,A) =(2*X+A-2*J-1)*(2*X+A-2*J-2)*P*(1-P)*p(X;P,J,A)/
!                          {(X-J)*(X+A-J)}
!
!              P(0;P,J,A)=P**A
!
!              THIS DISTRIBUTION IS USED TO MODEL THE "GAMBLER'S
!              RUIN" PROBLEM.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE AN INTEGR >= J.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER (PROBABILITY OF
!                                LOSING AN INDIVIDUAL GAME).
!                     --J      = THE INTEGER VALUE OF THE SECOND SHAPE
!                                PARAMETER.
!                     --A      = THE SINGLE PRECISION VALUE OF THE THIRD SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED LOST GAMES
!             DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE AN INTEGER >= J
!                 --0.5 < P < 1,  AND J >= 0, A > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KEMP, AND KOTZ (2005).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION,
!                 WILEY, PP. 503-505.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/11
!     ORIGINAL VERSION--NOVEMBER  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DJ
      DOUBLE PRECISION DA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DC3
      DOUBLE PRECISION DC4
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      SAVE DPDFSV
      SAVE PSV
      SAVE ASV
      SAVE XSV
      SAVE JSV
!
      DATA DPDFSV /-99.0/
      DATA PSV    /-99.0/
      DATA ASV    /-99.0/
      DATA JSV    /-99/
      DATA XSV    /-99.0/
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      DPDF=0.0D0
      INTX=INT(X+0.5)
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.5 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GLGPDF ',   &
               'IS OUTSIDE THE ALLOWABLE (0.5,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(J.LT.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GLGPDF IS ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)J
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,13)
   13   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO GLGPDF IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(INTX.LT.J)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GLGPDF IS LESS ',   &
               'THAN THE THIRD ARUGMENT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     NOTE: FOR EFFICIENCY, CHECK IF THE CURRENT VALUES OF THE
!           PARAMETERS ARE THE SAME AS THE SAVED VALUES AND IF
!           THE CURRENT X IS GREATER THAN OR EQUAL THE SAVED X.
!
      DP=DBLE(P)
      DJ=DBLE(J)
      DA=DBLE(A)
!
      IF(P.EQ.PSV .AND. A.EQ.ASV .AND. J.EQ.JSV .AND.   &
         X.GE.XSV)THEN
!
!       USE PARAMETERS FROM PREVIOUS CALL
!
        IF(X.EQ.XSV)THEN
          DPDF=DEXP(DPDFSV)
          PDF=REAL(DPDF)
          GO TO 10000
        ELSE
          ISTRT=INT(XSV+0.5)
          DO 100 I=ISTRT+1,INTX
            DX=DBLE(I)
            DC1=DLOG(2.0D0*DX+DA-2.0D0*DJ-1.0D0)
            DC2=DLOG(2.0D0*DX+DA-2.0D0*DJ-2.0D0)
            DC3=DLOG(DP) + DLOG(1.0D0-DP)
            DC4=DLOG(DX-DJ) + DLOG(DX+DA-DJ)
            DPDF=DC1 + DC2 + DC3 + DPDFSV - DC4
            DPDFSV=DPDF
  100     CONTINUE
          DPDF=DEXP(DPDF)
          PDF=REAL(DPDF)
        ENDIF
      ELSE
!
!       NEW PARAMETERS
!
        DPDF=DA*DLOG(DP)
        DPDFSV=DPDF
!
        IF(INTX.GT.J)THEN
          DO 200 I=J+1,INTX
            DX=DBLE(I)
            DC1=DLOG(2.0D0*DX+DA-2.0D0*DJ-1.0D0)
            DC2=DLOG(2.0D0*DX+DA-2.0D0*DJ-2.0D0)
            DC3=DLOG(DP) + DLOG(1.0D0-DP)
            DC4=DLOG(DX-DJ) + DLOG(DX+DA-DJ)
            DPDF=DC1 + DC2 + DC3 + DPDFSV - DC4
            DPDFSV=DPDF
  200     CONTINUE
        ENDIF
        DPDF=DEXP(DPDF)
        PDF=REAL(DPDF)
      ENDIF
      GO TO 9000
!
 9000 CONTINUE
      PSV=P
      ASV=A
      JSV=J
      XSV=X
      GO TO 10000
!
 9999 CONTINUE
      PSV=-99.0
      ASV=-99.0
      JSV=-99
      XSV=-99.0
!
10000 CONTINUE
      RETURN
      END SUBROUTINE GLGPDF
      SUBROUTINE GLGPPF(P,PPAR,J,A,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE P
!              FOR THE GENERALIZED LOST GAMES DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS P, A, AND
!              J.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= J.
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED FROM
!              THE RECURRENCE RELATION:
!
!              p(X;P,J,A) =(2*X+A-2*J-1)*(2*X+A-2*J-2)*P*(1-P)*p(X;P,J,A)/
!                          {(X-J)*(X+A-J)}
!
!              P(0;P,J,A)=P**A
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY GENERATING
!              THE CDF FUNCTION UNTIL THE APPROPRIATE PROBABILITY
!              IS REACHED.
!
!              THIS DISTRIBUTION IS USED TO MODEL THE "GAMBLER'S
!              RUIN" PROBLEM.  IT ADDS THE ADDITIONAL PARAMETER, A,
!              TO THE LOST GAMES DISTRIBUTION.
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                0 <= P < 1.
!                     --PPAR   = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER (PROBABILITY OF
!                                LOSING AN INDIVIDUAL GAME).
!                     --J      = THE INTEGER VALUE OF THE SECOND SHAPE
!                                PARAMETER.
!                     --A      = THE SINGLE PRECISION VALUE OF THE THIRD SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION VALUE
!             PPF FOR THE GENERALIZED LOST GAMES DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P < 1.
!                 --0.5 < P < 1,  AND J >= 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KEMP, AND KOTZ (2005).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION,
!                 WILEY, PP. 503-505.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/11
!     ORIGINAL VERSION--NOVEMBER  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPAR
      DOUBLE PRECISION DJ
      DOUBLE PRECISION DA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DC3
      DOUBLE PRECISION DC4
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PPF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GLGPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(PPAR.LE.0.5 .OR. PPAR.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GLGPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0.5,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)PPAR
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(J.LT.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GLGPPF IS ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)J
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,13)
   13   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO GLGPPF IS ',   &
               'NEGATIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      DEPS=1.0D-7
      DP=DBLE(P)
      DPPAR=DBLE(PPAR)
      DJ=DBLE(J)
      DA=DBLE(A)
      DCDF=0.0D0
!
!     USE THE RECURRENCE RELATION DESCRIBED ABOVE.
!
      I=J
      DPDF=DA*DLOG(DPPAR)
      DPDFSV=DPDF
      DCDF=DEXP(DPDF)
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=REAL(J)
        GO TO 9999
      ENDIF
!
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=REAL(I)
          GO TO 9999
        ENDIF
        DX=DBLE(I)
        DC1=DLOG(2.0D0*DX+DA-2.0D0*DJ-1.0D0)
        DC2=DLOG(2.0D0*DX+DA-2.0D0*DJ-2.0D0)
        DC3=DLOG(DPPAR) + DLOG(1.0D0-DPPAR)
        DC4=DLOG(DX-DJ) + DLOG(DX+DA-DJ)
        DPDF=DC1 + DC2 + DC3 + DPDFSV - DC4
        DCDF=DCDF + DEXP(DPDF)
        DPDFSV=DPDF
        IF(DCDF.GE.DP-DEPS)THEN
          PPF=REAL(I)
          GO TO 9999
        ENDIF
      GO TO 100
!
 9999 CONTINUE
                                                                                                                                  
      RETURN
      END SUBROUTINE GLGPPF
      SUBROUTINE GLGRAN(N,P,J,A,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF
!              SIZE N FROM THE GENERALIZED LOST GAMES DISTRIBUTION
!              WITH SHAPE PARAMETERS P AND IR.
!              IR.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= J.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;P,J,A) = ...
!                           X = J, J+ 1, ...
!                           A > 0, 0.5 < P < 1
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --J      = THE INTEGER VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE GENERALIZED
!             LOST GAMES DISTRIBUTION WITH SHAPE PARAMETERS
!             P, J, AND A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0.5 < P < 1, J A NON-NEGATIVE INTEGER, A > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, LOSPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KEMP, AND KOTZ (2005).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION,
!                 WILEY, PP. 503-505.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/11
!     ORIGINAL VERSION--NOVEMBER  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER N
      INTEGER J
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
      'GENERALIZED LOST GAMES RANDOM NUMBERS IS NON-POSITIVE')
!
      IF(P.LE.0.5 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE P PARAMETER FOR THE GENERALIZED ',   &
             'LOST GAMES')
   12 FORMAT('      RANDOM NUMBERS IS OUTSIDE THE ALLOWABLE (0.5,1) ',   &
             'INTERVAL')
!
      IF(J.LT.0)THEN
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)J
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   21 FORMAT('***** ERROR--THE J PARAMETER FOR THE GENERALIZED ',   &
             'LOST GAMES RANDOM NUMBERS IS NON-POSITIVE')
!
      IF(A.LE.0.0)THEN
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   31 FORMAT('***** ERROR--THE A PARAMETER FOR THE GENERALIZED ',   &
             'LOST GAMES')
   32 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        XTEMP=X(I)
        CALL GLGPPF(XTEMP,P,J,A,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE GLGRAN
      SUBROUTINE GLOCDF(X,ALPHA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE TYPE 1 GENERALIZED LOGISTIC
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!              F(X) = 1/(1+EXP(-X))**ALPHA
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE CDF FOR THE HALF-LOGISTIC
!             DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--DECEMBER  1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DA, DCDF
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
             'TO THE GLOCDF SUBROUTINE')
    5 FORMAT('      IS NON-POSITIVE. *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DA=DBLE(ALPHA)
      DTERM1=-DA*DLOG(1.D0+DEXP(-DX))
      IF(DTERM1.LE.-500.D0)THEN
        CDF=0.0
      ELSEIF(DTERM1.GE.500.D0)THEN
        CDF=1.0
      ELSE
        DCDF=DEXP(DTERM1)
        CDF=SNGL(DCDF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GLOCDF
      SUBROUTINE GLOPDF(X,ALPHA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE TYPE 1 GENERALIZED LOGISTIC
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = ALPHA*EXP(-X)/(1+EXP(-X))**(ALPHA+1)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED LOGISTIC
!             DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--DECEMBER  1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DA, DPDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT ',   &
             'TO THE GLOPDF SUBROUTINE')
    5 FORMAT('      IS NON-POSITIVE. *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DA=DBLE(ALPHA)
      DTERM1=DLOG(DA)
      DTERM2=DX + (DA+1.0D0)*DLOG(1.0+DEXP(-DX))
      DTERM3=DTERM1-DTERM2
      IF(DTERM3.LE.-500.D0)THEN
        PDF=0.0
      ELSE
        DPDF=DEXP(DTERM3)
        PDF=SNGL(DPDF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GLOPDF
      SUBROUTINE GLOPPF(P,ALPHA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE TYPE 1 GENERALIZED LOGISTIC
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = ALPHA/(EXP(X)*(1+EXP(-X))**(ALPHA+1))
!                                                     0<=X<=1/K
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE HALF-LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0 (EXCLUSIVELY)
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/12
!     ORIGINAL VERSION--DECEMBER  1995.
!
!-----STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP, DA, DPPF
      DOUBLE PRECISION DTERM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'GLOPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      DP=DBLE(P)
      DA=DBLE(ALPHA)
      DTERM1=DP**(-1.0D0/DA) - 1.0D0
      DPPF=-DLOG(DTERM1)
      PPF=SNGL(DPPF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GLOPPF
      SUBROUTINE GLORAN(N,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED LOGISTIC DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
             'LOGISTIC RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED LOGISTIC RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD
!
      DO 100 I=1,N
      CALL GLOPPF(X(I),ALPHA,XTEMP)
      X(I)=XTEMP
  100 CONTINUE
!
      RETURN
      END SUBROUTINE GLORAN
      SUBROUTINE GL2CDF(DX,DALPHA,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE TYPE 2 GENERALIZED LOGISTIC
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!              F(X) = 1 - EXP(-ALPHA*X)/(1+EXP(-X))**ALPHA
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE DOUBLE PRECISION SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE FOR THE TYPE 2 GENERALIZED LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA SHOULD BE POSITIVE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DALPHA
        CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE SHAPE PARAMETER FOR THE GL2CDF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=-DALPHA*DX - DALPHA*DLOG(1.0D0 + DEXP(-DX))
      DCDF=1.0D0 - DEXP(DTERM1)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GL2CDF
      DOUBLE PRECISION FUNCTION GL2FU2(DX)
!
!     PURPOSE--GL2PPF CALLS DFZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  GL2FU2 IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - GL2CDF(X,ALPHA)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE GL2FU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GL2CDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      COMMON/GL2COM/DP,DALPHA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL GL2CDF(DX,DALPHA,DCDF)
      GL2FU2=DP - DCDF
!
      RETURN
      END FUNCTION GL2FU2
      SUBROUTINE GL2PDF(DX,DALPHA,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE TYPE 2 GENERALIZED LOGISTIC
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X,ALPHA) = ALPHA*EXP(X)/(1+EXP(X))**(ALPHA+1)
!                           ALPHA > 0
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE DOUBLE PRECISION SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE FOR THE TYPE 2 GENERALIZED LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA SHOULD BE POSITIVE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DALPHA
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE SHAPE PARAMETER FOR THE GL2PDF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE FIRST COMPONENT
!
      DX=-DX
      DTERM1=DLOG(DALPHA)
      DTERM2=DX + (DALPHA+1.0D0)*DLOG(1.0+DEXP(-DX))
      DTERM3=DTERM1-DTERM2
      DPDF=DEXP(DTERM3)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GL2PDF
      SUBROUTINE GL2PPF(DP,DALPHA,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 2
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR REAL X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE FIRST SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE DPPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DPPF
!
      DOUBLE PRECISION GL2FU2
      EXTERNAL GL2FU2
!
      DOUBLE PRECISION DP2
      DOUBLE PRECISION DALPH2
      COMMON/GL2COM/DP2,DALPH2
!
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XLOW2
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION PTEMPL
      DOUBLE PRECISION PTEMPU
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
      NIT=0
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER, ALPHA, TO ',   &
               'GL2PPF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DALPHA
  104   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DP.LE.0.0D0.OR.DP.GE.1.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST ARGUMENT TO GL2PPF ',   &
                'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,104)DP
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH (-5,5) AND
!          INCREMENT UNITL A BRACKETING INTERVAL IS FOUND.
!
      NIT=0
      MAXIT=2000
      XLOW2=-10.0D0
      XUP2=10.0D0
  200 CONTINUE
        CALL GL2CDF(XLOW2,DALPHA,PTEMPL)
        CALL GL2CDF(XUP2,DALPHA,PTEMPU)
        IF(PTEMPL.LT.DP .AND. PTEMPU.GT.DP)THEN
          XUP=XUP2
          XLOW=XLOW2
          GO TO 300
        ELSEIF(PTEMPL.LT.DP .AND. PTEMPU.LT.DP)THEN
          NIT=NIT+1
          XUP2=10.0D0*XUP2
          IF(NIT.LE.MAXIT)GO TO 200
        ELSEIF(PTEMPL.GT.DP .AND. PTEMPU.GT.DP)THEN
          NIT=NIT+1
          XLOW2=10.0D0*XLOW2
          IF(NIT.LE.MAXIT)GO TO 200
        ENDIF
!
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR FROM GL2PPF--UNABLE TO FIND A ',   &
               'BRACKETING INTERVAL')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
!
  300 CONTINUE
      AE=1.0D-8
      RE=1.0D-8
      DP2=DP
      DALPH2=DALPHA
      CALL DFZERO(GL2FU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      DPPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,121)
!C111   FORMAT('***** WARNING FROM GL2PPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GL2PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GL2PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GL2PPF
      SUBROUTINE GL2RAN(N,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED LOGISTIC TYPE 2 DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SHAPE PARAMETER
!                     --SEED   = THE SEED FOR THE RANDOM NUMBER
!                                GENERATOR
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED LOGISTIC TYPE 2 DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GL2PPF.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
             'LOGISTIC TYPE 2')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED LOGISTIC TYPE 2 RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD
!
      DO 100 I=1,N
        DX=DBLE(X(I))
        CALL GL2PPF(DX,DBLE(ALPHA),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
      RETURN
      END SUBROUTINE GL2RAN
      SUBROUTINE GL3CDF(DX,DALPHA,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 3
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE DOUBLE PRECISION SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 3
!             DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME II", SECOND EDITION,
!                 JOHN WILEY, PP. 140-142, 1994.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION ALPHAMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=200)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DA
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION GL3FUN
      EXTERNAL GL3FUN
!
      DOUBLE PRECISION DALPH2
      COMMON/GL3COM/DALPH2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  101 FORMAT('***** ERROR--THE SHAPE PARAMETER, ALPHA, TO THE')
  102 FORMAT('      GL3CDF ROUTINE IS NON-POSITIVE.')
  104 FORMAT('***** VALUE OF THE ARGUMENT = ',G15.7)
!
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      EPSABS=1.0D-8
      EPSREL=1.0D-8
      IER=0
      IKEY=3
      DCDF=0.0D0
!
      DA=1.0D-7
      DALPH2=DALPHA
!
      IF(DX.LE.0.0D0)THEN
        INF=-1
        CALL DQAGI(GL3FUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
      ELSE
!
        INF=+1
        CALL DQAGI(GL3FUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
        DCDF=1.0D0 - DCDF
      ENDIF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM GL3CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM GL3CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GL3CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM GL3CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM GL3CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM GL3CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GL3CDF
      DOUBLE PRECISION FUNCTION GL3FUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 3
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR X > 0 AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              f(X;ALPHA) = (1/BETA(ALPHA,ALPHA)*EXP(-ALPHA*X)/
!                           (1+EXP(-X))**(2*ALPHA)    ALPHA > 0
!              THIS FUNCTION IS USED FOR INTEGRATION BY THE
!              GL3CDF ROUTINE.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--GL3FUN = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED LOGISTIC
!             TYPE 3 DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GL3PDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
