!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
!
      DOUBLE PRECISION DALPHA
      COMMON/GL3COM/DALPHA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL GL3PDF(DX,DALPHA,DPDF)
      GL3FUN=DPDF
!
      RETURN
      END FUNCTION GL3FUN
      DOUBLE PRECISION FUNCTION GL3FU2(DX)
!
!     PURPOSE--GL3PPF CALLS DFZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  GL3FU2 IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - GL3CDF(X,P,Q)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE GL3FU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GL3CDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-143
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      COMMON/GL3CO2/DP,DALPHA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL GL3CDF(DX,DALPHA,DCDF)
      GL3FU2=DP - DCDF
!
      RETURN
      END FUNCTION GL3FU2
      SUBROUTINE GL3RAN(N,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED LOGISTIC TYPE 3 DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SHAPE PARAMETER
!                     --SEED   = THE SEED FOR THE RANDOM NUMBER
!                                GENERATOR
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED LOGISTIC TYPE 3 DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GL3PPF.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
             'LOGISTIC TYPE 3')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED LOGISTIC TYPE 3 RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD
!
      DO 100 I=1,N
        DX=DBLE(X(I))
        CALL GL3PPF(DX,DBLE(ALPHA),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
      RETURN
      END SUBROUTINE GL3RAN
      SUBROUTINE GL3PDF(DX,DALPHA,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE TYPE 3 GENERALIZED LOGISTIC
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              f(X;ALPHA) = (1/BETA(ALPHA,ALPHA)*EXP(-ALPHA*X)/
!                           (1+EXP(-X))**(2*ALPHA)
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE DOUBLE PRECISION SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE FOR THE TYPE 3 GENERALIZED LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA SHOULD BE POSITIVE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP,DLBETA.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DLBETA
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DALPHA
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE SHAPE PARAMETER FOR THE GL3PDF ',   &
             'SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DLBETA(DALPHA,DALPHA)
      DTERM2=-DALPHA*DX - 2.0D0*DALPHA*DLOG(1.0D0 + DEXP(-DX))
      DPDF=DEXP(DTERM2 - DTERM1)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GL3PDF
      SUBROUTINE GL3PPF(DP,DALPHA,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 3
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR REAL X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE DPPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-143
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DPPF
!
      DOUBLE PRECISION GL3FU2
      EXTERNAL GL3FU2
!
      DOUBLE PRECISION DP2
      DOUBLE PRECISION DALPH2
      COMMON/GL3CO2/DP2,DALPH2
!
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XLOW2
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION PTEMPL
      DOUBLE PRECISION PTEMPU
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  101 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER, ALPHA, TO THE')
  102 FORMAT('      GL3PPF ROUTINE IS NON-POSITIVE.')
  104 FORMAT('      THE VALUE OF THE ARGUMENT IS ',E15.7,' ******')
!
      IF(DP.LE.0.0D0.OR.DP.GE.1.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT ',   &
                'TO THE GL3PPF SUBROUTINE ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)DP
   63    FORMAT('      THE VALUE OF ARGUMENT = ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH (-5,5) AND
!          INCREMENT UNITL A BRACKETING INTERVAL IS FOUND.
!
!          TAKE ADVANTAGE OF FACT THAT GL3 IS SYMMETRIC
!          (P = 0.5 IMPLIES PPF = 0).
!
!          ALSO, MEAN = 0 AND SD = SQRT(2*PSI'(ALPHA))
!
      MAXIT=1000
      NIT=1
      IF(DP.EQ.0.5D0)THEN
        DPPF=0.0D0
        GO TO 9000
      ELSEIF(DP.LT.0.5D0)THEN
        XLOW2=-10.0D0
        XUP2=0.0D0
      ELSE
        XLOW2=0.0D0
        XUP2=10.0D0
      ENDIF
!
  200 CONTINUE
        CALL GL3CDF(XLOW2,DALPHA,PTEMPL)
        CALL GL3CDF(XUP2,DALPHA,PTEMPU)
        IF(PTEMPL.LT.DP .AND. PTEMPU.GT.DP)THEN
          XUP=XUP2
          XLOW=XLOW2
          GO TO 300
        ELSEIF(PTEMPL.LT.DP .AND. PTEMPU.LT.DP)THEN
          NIT=NIT+1
          XUP2=10.0D0*XUP2
          IF(NIT.LE.MAXIT)GO TO 200
        ELSEIF(PTEMPL.GT.DP .AND. PTEMPU.GT.DP)THEN
          NIT=NIT+1
          XLOW2=10.0D0*XLOW2
          IF(NIT.LE.MAXIT)GO TO 200
        ENDIF
!
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR FROM GL3PPF--UNABLE TO FIND A ',   &
               'BRACKETING INTERVAL')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
!
  300 CONTINUE
      AE=1.0D-6
      RE=1.0D-6
      DP2=DP
      DALPH2=DALPHA
      CALL DFZERO(GL3FU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      DPPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,121)
!C111   FORMAT('***** WARNING FROM GL3PPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GL3PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GL3PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GL3PPF
      SUBROUTINE GL4CDF(DX,DP,DQ,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 4
!              DISTRIBUTION WITH SHAPE PARAMETER P AND Q.
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DALPHA = THE DOUBLE PRECISION SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 4
!             DISTRIBUTION WITH SHAPE PARAMETER P AND Q.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME II", SECOND EDITION,
!                 JOHN WILEY, PP. 140-142, 1994.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION ALPHAMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=200)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DQ
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION GL4FUN
      EXTERNAL GL4FUN
!
      DOUBLE PRECISION DP2,DQ2
      COMMON/GL4COM/DP2,DQ2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DCDF=0.0D0
      IF(DP.LE.0.0D0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(DQ.LE.0.0D0)THEN
        WRITE(ICOUT,105)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,106)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DQ
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  101 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER, P, TO THE')
  102 FORMAT('      GL4CDF ROUTINE IS NON-POSITIVE.')
  105 FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER, Q, TO THE')
  106 FORMAT('      GL4CDF ROUTINE IS NON-POSITIVE.')
  104 FORMAT('***** VALUE OF THE ARGUMENT = ',G15.7)
!
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      EPSABS=1.0D-10
      EPSREL=1.0D-10
      IER=0
      IKEY=3
      DCDF=0.0D0
!
      DP2=DP
      DQ2=DQ
!
      IF(DX.LE.0.0D0)THEN
        INF=-1
        CALL DQAGI(GL4FUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
      ELSE
!
        INF=+1
        CALL DQAGI(GL4FUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
        DCDF=1.0D0 - DCDF
      ENDIF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM GL4CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM GL4CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GL4CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM GL4CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM GL4CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM GL4CDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GL4CDF
      DOUBLE PRECISION FUNCTION GL4FUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 4
!              DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR X > 0 AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              f(X;P,Q) = (1/BETA(P,Q)*EXP(-Q*X)/
!                         (1+EXP(-X))**(P+Q)
!                         P, Q > 0
!              THIS FUNCTION IS USED FOR INTEGRATION BY THE
!              GL4CDF ROUTINE.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--GL4FUN = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED LOGISTIC
!             TYPE 4 DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GL4PDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-142
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DQ
      COMMON/GL4COM/DP,DQ
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL GL4PDF(DX,DP,DQ,DPDF)
      GL4FUN=DPDF
!
      RETURN
      END FUNCTION GL4FUN
      DOUBLE PRECISION FUNCTION GL4FU2(DX)
!
!     PURPOSE--GL4PPF CALLS DFZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  GL4FU2 IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - GL4CDF(X,P,Q)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE GL4FU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GL4CDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-143
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPAR
      DOUBLE PRECISION DQPAR
      COMMON/GL4CO2/DP,DPPAR,DQPAR
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL GL4CDF(DX,DPPAR,DQPAR,DCDF)
      GL4FU2=DP - DCDF
!
      RETURN
      END FUNCTION GL4FU2
      SUBROUTINE GL4PDF(DX,DP,DQ,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE TYPE 4 GENERALIZED LOGISTIC
!              DISTRIBUTION WITH SHAPE PARAMETERS P AND Q.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              f(X;P,Q) = (1/BETA(P,Q)*EXP(-Q*X)/
!                         (1+EXP(-X))**(P+Q)
!                         P, Q > 0
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DP     = THE DOUBLE PRECISION FIRST SHAPE
!                                PARAMETER.
!                     --DQ     = THE DOUBLE PRECISION SECOND SHAPE
!                                PARAMETER.
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE FOR THE TYPE 3 GENERALIZED LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA SHOULD BE POSITIVE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP,DLBETA.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-143
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DQ
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DLBETA
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPDF=0.0D0
      IF(DP.LE.0.0D0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER FOR ',   &
             'GL4PDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DQ.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER FOR GL4PDF ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DQ
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      DTERM1=DLBETA(DP,DQ)
      DTERM2=-DQ*DX - (DP+DQ)*DLOG(1.0D0 + DEXP(-DX))
      DPDF=DEXP(DTERM2 - DTERM1)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GL4PDF
      SUBROUTINE GL4PPF(DP,DPPAR,DQPAR,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED LOGISTIC TYPE 4
!              DISTRIBUTION WITH SHAPE PARAMETERS P AND Q.
!              THIS DISTRIBUTION IS DEFINED FOR REAL X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DPPAR  = THE FIRST SHAPE PARAMETER
!                     --DQPAR  = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE DPPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 140-143
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPAR
      DOUBLE PRECISION DQPAR
      DOUBLE PRECISION DPPF
!
      DOUBLE PRECISION GL4FU2
      EXTERNAL GL4FU2
!
      DOUBLE PRECISION DP2
      DOUBLE PRECISION DPPAR2
      DOUBLE PRECISION DQPAR2
      COMMON/GL4CO2/DP2,DPPAR2,DQPAR2
!
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XLOW2
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION PTEMPL
      DOUBLE PRECISION PTEMPU
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      DPPF=0.0D0
      IF(DPPAR.LE.0.0D0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DPPAR
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(DQPAR.LE.0.0D0)THEN
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)DQPAR
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  101 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER, P, TO THE')
  102 FORMAT('      GL4PPF ROUTINE IS NON-POSITIVE.')
  103 FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER, Q, TO THE')
  104 FORMAT('      THE VALUE OF THE ARGUMENT IS ',E15.7,' ******')
!
      IF(DP.LE.0.0D0.OR.DP.GE.1.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST  INPUT ARGUMENT ',   &
                'TO THE GL4PPF SUBROUTINE ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)DP
   63    FORMAT('      THE VALUE OF ARGUMENT = ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH (-5,5) AND
!          INCREMENT UNITL A BRACKETING INTERVAL IS FOUND.
!
      MAXIT=1000
      XLOW2=-5.0D0
      XUP2=5.0D0
!
  200 CONTINUE
        CALL GL4CDF(XLOW2,DPPAR,DQPAR,PTEMPL)
        CALL GL4CDF(XUP2,DPPAR,DQPAR,PTEMPU)
        IF(PTEMPL.LT.DP .AND. PTEMPU.GT.DP)THEN
          XUP=XUP2
          XLOW=XLOW2
          GO TO 300
        ELSEIF(PTEMPL.LT.DP .AND. PTEMPU.LT.DP)THEN
          MAXIT=MAXIT+1
          XUP2=5.0D0*XUP2
          IF(MAXIT.LE.MAXIT)GO TO 200
        ELSEIF(PTEMPL.GT.DP .AND. PTEMPU.GT.DP)THEN
          MAXIT=MAXIT+1
          XLOW2=5.0D0*XLOW2
          IF(MAXIT.LE.MAXIT)GO TO 200
        ENDIF
!
        WRITE(ICOUT,201)
  201   FORMAT('***** ERROR FROM GL4PPF--UNABLE TO FIND A ',   &
               'BRACKETING INTERVAL')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
!
  300 CONTINUE
      AE=1.0D-8
      RE=1.0D-8
      DP2=DP
      DPPAR2=DPPAR
      DQPAR2=DQPAR
      CALL DFZERO(GL4FU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      DPPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,121)
!C111   FORMAT('***** WARNING FROM GL4PPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GL4PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GL4PPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GL4PPF
      SUBROUTINE GL4RAN(N,P,Q,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED LOGISTIC TYPE 4 DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P      = THE FIRST SHAPE PARAMETER
!                     --Q      = THE SECOND SHAPE PARAMETER
!                     --SEED   = THE SEED FOR THE RANDOM NUMBER
!                                GENERATOR
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED LOGISTIC TYPE 4 DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GL4PPF.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/3
!     ORIGINAL VERSION--MARCH     2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
             'LOGISTIC TYPE 4')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED LOGISTIC TYPE 4 RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD
!
      DO 100 I=1,N
        DX=DBLE(X(I))
        CALL GL4PPF(DX,DBLE(P),DBLE(Q),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
      RETURN
      END SUBROUTINE GL4RAN
      SUBROUTINE GL5ML1(Y,N,   &
                        DTEMP1,XMOM,NMOM,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALOCML,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE L-MOMENTS ESTIMATES FOR THE
!              GENERALIZED LOGISTIC TYPE 5 DISTRIBUTION FOR THE RAW DATA
!              CASE (I.E., NO CENSORING AND NO GROUPING).  THIS ROUTINE
!              RETURNS ONLY THE POINT ESTIMATES.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLP3 WILL GENERATE THE OUTPUT
!              FOR THE GENERALIZED LOGISTIC TYPE 5 MLE COMMAND).
!
!     REFERENCE--FORTRAN CODE WRITTEN FOR INCLUSION IN IBM
!                RESEARCH REPORT RC20525, 'FORTRAN ROUTINES FOR
!                USE WITH THE METHOD OF L-MOMENTS, VERSION 3',
!                J. R. M. HOSKING, IBM RESEARCH DIVISION,
!                T. J. WATSON RESEARCH CENTER, YORKTOWN HEIGHTS
!                NEW YORK 10598, U.S.A., VERSION 3     AUGUST 1996
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLP3)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION XMOM(*)
      DOUBLE PRECISION XPAR(3)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GL5M'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'5ML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF GL5ML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  CARRY OUT CALCULATIONS                        **
!               **  FOR GENERALIZED LOGISTIC TYPE 5 MLE ESTIMATE  **
!               ****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'5ML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='GENERALIZED LOGISTIC TYPE 5'
      ALOCML=CPUMIN
      SCALML=CPUMIN
      SHAPML=CPUMIN
!
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      CALL SORT(Y,N,Y)
      NMOM=3
      DO 2110 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 2110 CONTINUE
      CALL SAMLMU(DTEMP1,N,XMOM,NMOM)
      CALL PELGLO(XMOM,XPAR)
      ALOCML=REAL(XPAR(1))
      SCALML=REAL(XPAR(2))
      SHAPML=REAL(XPAR(3))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'5ML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF GL5ML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)XMOM(1),XMOM(2),XMOM(3)
 9015   FORMAT('XMOM(1),XMOM(2),XMOM(3) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9016)XPAR(1),XPAR(2),XPAR(3)
 9016   FORMAT('XPAR(1),XPAR(2),XPAR(3) = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPML,SCALML,ALOCML
 9017   FORMAT('SHAPML,SCALML,ALOCML =  ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE GL5ML1
      SUBROUTINE GL5PDF(X,GAMMA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE TYPE 5 GENERALIZED LOGISTIC
!              DISTRIBUTION WITH SHAPE PARAMETER GAMMA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X
!              THIS DEFINITION IS DUE TO HOSKINGS AND HAS THE
!              FOLLOWING DEFINITION:
!
!              F(X,GAMMA) = (1-GAMMA*X)**((1/GAMMA)-1)/
!                           {1+(1-GAMMA*X)**(1/GAMMA}**2
!                           X <= 1/GAMMA    FOR GAMMA > 0
!                           X >= 1/GAMMA    FOR GAMMA < 0
!              FOR GAMMA = 0, JUST COMPUTE THE STANDARD
!              LOGISTIC DISTRIBUTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED LOGISTIC TYPE 5
!             DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGE 145
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--FEBRUARY  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION GAMMA
      DOUBLE PRECISION PDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.EQ.0.0D0)THEN
        CALL LOGPDF(REAL(X),PDF2)
        PDF=DBLE(PDF2)
        GO TO 9999
      ELSEIF(GAMMA.GT.0.0D0)THEN
        IF(X.GT.1.0D0/GAMMA)THEN
          WRITE(ICOUT,4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,5)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,47)GAMMA
          CALL DPWRST('XXX','BUG ')
          PDF=0.0D0
          GO TO 9999
        ENDIF
    4   FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
             'GL5PDF SUBROUTINE')
    5   FORMAT('      IS GREATER THAN 1/GAMMA')
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.8)
   47   FORMAT('***** THE VALUE OF GAMMA IS        ',G15.8)
!
        IF(X.EQ.1.0/GAMMA)THEN
          PDF=0.0D0
        ELSE
          DTERM1=(1.0D0/GAMMA)
          DTERM2=(DTERM1 - 1.0D0)*DLOG(1.0D0 - X*GAMMA)
          DTERM3=2.0D0*DLOG(1.0D0 + (1.0D0 - GAMMA*X)**DTERM1)
          PDF=DEXP(DTERM2 - DTERM3)
        ENDIF
!
      ELSEIF(GAMMA.LT.0.0)THEN
        IF(X.LT.1.0/GAMMA)THEN
          WRITE(ICOUT,4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,47)GAMMA
          CALL DPWRST('XXX','BUG ')
          PDF=0.0
          GO TO 9999
        ENDIF
   15   FORMAT('      IS LESS THAN 1/GAMMA')
!
        IF(X.EQ.1.0/GAMMA)THEN
          PDF=0.0D0
        ELSE
          DTERM1=(1.0D0/GAMMA)
          DTERM2=(DTERM1 - 1.0D0)*DLOG(1.0D0 - X*GAMMA)
          DTERM3=2.0D0*DLOG(1.0D0 + (1.0D0 - GAMMA*X)**DTERM1)
          PDF=DEXP(DTERM2 - DTERM3)
        ENDIF
!
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE GL5PDF
      SUBROUTINE GL5RAN(N,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED LOGISTIC TYPE 5 (HOSKING)
!              DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SHAPE PARAMETER
!                     --SEED   = THE SEED FOR THE RANDOM NUMBER
!                                GENERATOR
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED LOGISTIC TYPE 5 DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, QUAGLO.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/2
!     ORIGINAL VERSION--FEBRUARY  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION XPAR(3)
      DOUBLE PRECISION QUAGLO
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF GENERALIZED ',   &
             'LOGISTIC TYPE 5 (HOSKING)')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N GENERALIZED LOGISTIC TYPE 5 RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD
!
      XPAR(1)=0.0D0
      XPAR(2)=1.0D0
      XPAR(3)=DBLE(ALPHA)
!
      DO 100 I=1,N
        DX=DBLE(X(I))
        DPPF=QUAGLO(DX,XPAR)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
      RETURN
      END SUBROUTINE GL5RAN
      SUBROUTINE GLSCDF(X,THETA,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED LOGARITHMIC SERIES
!              DISTRIBUTION WITH SHAPE PARAMETERS THETA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL INTEGER X >= 1.
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA)=
!                  Gamma(BETA*X+1)*THETA**X*(1-THETA)**(BETA*X-X)/
!                  X!*(BETA*X)*Gamma(BETA*X-X+1)*[-LOG(1-THETA)]
!                  X = 1, 2, 3, ,...
!                  0 < THETA < 1; 1 <= BETA < 1/THETA
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              BY SUMMING THE PROBABILITY MASS FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --THETA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE GENERALIZED LOGARITHMIC SERIES
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A POSITIVE INTEGER
!                 --0 < THETA < 1; 1 < BETA < 1/THETA
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FAMOYE (1997), "SAMPLING FROM A GENERALIZED
!                 LOGARITHMIC SERIES DISTRIBUTION", COMPUTING,
!                 58(4), PP. 365-376.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 11.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5)
      IF(IX.LT.1)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GLSCDF IS LESS ',   &
      'THAN 1')
!
      IF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GLSCDF IS NOT IN ',   &
      'THE INTERVAL (0,1)')
!
      IF(BETA.LT.1.0 .OR. BETA.GE.1.0/THETA)THEN
        WRITE(ICOUT,25)1.0/THETA
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO GLSCDF IS NOT IN ',   &
      'THE INTERVAL (1,',G15.7,')')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DTHETA=DBLE(THETA)
      DBETA=DBLE(BETA)
!
!     USE THE RECURRENCE RELATION (PAGE 228 OF CONSUL AND FAMOYE):
!
!     P(X+1;THETA,BETA) = (BETA - X/(X+1))*THETA*(1-THETA)**(BETA-1)*
!                         PROD[j=1 to X-1][1 + BETA/(BETA*X-j)]*
!                         P(X;THETA,BETA)
!
!     COMPUTE BY TAKING LOG OF THIS FORMULA WHEN X >= 3.
!
      DCDF=DTHETA*(1.0D0 - DTHETA)**(DBETA - 1.0D0)/   &
           (-DLOG(1.0D0 - DTHETA))
      IF(IX.EQ.1)GO TO 1000
!
      DPDF=(DBETA-0.5D0)*DTHETA*(1.0D0-DTHETA)**(DBETA-1.0D0)*DCDF
      DCDF=DCDF + DPDF
      IF(IX.EQ.2)GO TO 1000
      DPDFSV=DPDF
      DTERM2=DLOG(DTHETA) + (DBETA - 1.0D0)*DLOG(1.0D0 - DTHETA)
!
      DO 100 I=3,IX
        DX=DBLE(I)
        DTERM1=DLOG(DBETA - (DX-1.0D0)/DX)
        IF(DPDFSV.LE.0.0D0)THEN
          GO TO 1000
        ELSE
          DTERM3=DLOG(DPDFSV)
        ENDIF
        DSUM=0.0D0
        DO 200 J=1,I-2
          DSUM=DSUM + DLOG(1.0D0 + DBETA/(DBETA*(DX-1.0D0)-DBLE(J)))
  200   CONTINUE
        DPDF=DEXP(DTERM1 + DTERM2 + DTERM3 + DSUM)
        DCDF=DCDF + DPDF
        DPDFSV=DPDF
  100 CONTINUE
!
 1000 CONTINUE
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GLSCDF
      DOUBLE PRECISION FUNCTION GLSFUN(DTHETA)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GENERALIZED LOGARITHMIC SERIES METHOD OF MOMENT
!              EQUATIONS.
!
!                 (1-THETA)*XBAR**3/ALPHA**2 -
!                 THETA**2*(s**2+XBAR**2) 0
!
!              WITH THETA DENOTING THE SHAPE PARAMETER AND
!              ALPHA = 1/-LOG(1-THETA).  THIS
!              ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--GENERALIZED LOGARITHMIC SERIES MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 11.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DALPHA
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION F1FREQ
      COMMON/GLSCOM/XBAR,S2,F1FREQ,MAXROW,N
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DALPHA=-1.0D0/DLOG(1.0D0 - DTHETA)
      GLSFUN=(1.0D0-DTHETA)*XBAR**3/(DALPHA**2) -   &
             DTHETA**2*(S2+XBAR**2)
!
      RETURN
      END FUNCTION GLSFUN
      SUBROUTINE GLSFU2(N,XPAR,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GENERALIZED LOGARITHMIC SERIES MAXIMUM LIKELIHOOD
!              EQUATIONS.
!
!              THE MAXIMUM LIKELIHOOD ESTIMATES ARE THE SOLUTIONS
!              TO THE EQUATIONS:
!
!                 (N*XBAR/THETA) - (BETA-1)*N*XBAR/(1-THETA) +
!                 N/((1-THETA)*LOG(1-THETA)) = 0
!
!                 N*XBAR*LOG(1-THETA) +
!                 SUM[X=2 to K][SUM[i=1 to x-1][X*N(X)/(BETA*X-i)]]
!                 = 0
!
!              WITH THETA DENOTING THE SHAPE PARAMETER AND
!              ALPHA = 1/-LOG(1-THETA).  THIS
!              ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--GENERALIZED LOGARITHMIC SERIES MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 11.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DFREQ
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DN
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION F1FREQ
      COMMON/GLSCOM/XBAR,S2,F1FREQ,MAXROW,NTOT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DTHETA=XPAR(1)
      DBETA=XPAR(2)
      DALPHA=-1.0D0/DLOG(1.0D0 - DTHETA)
      DN=DBLE(NTOT)
!
      IINDX=MAXROW/2
!
      DTERM1=DN*XBAR/DTHETA
      DTERM2=(DBETA-1.0D0)*DN*XBAR/(1.0D0-DTHETA)
      DTERM3=DN/((1.0D0-DTHETA)*DLOG(1.0D0-DTHETA))
      FVEC(1)=DTERM1 - DTERM2 + DTERM3
!
      DSUM1=0.0D0
      DTERM1=DN*XBAR*DLOG(1.0D0-DTHETA)
!
      DO 100 I=2,K
        DX=DBLE(Y(IINDX+I))
        DFREQ=Y(I)
        DO 200 J=1,I-1
          DSUM1=DSUM1 + DX*DFREQ/(DBETA*DX - DBLE(J))
  200   CONTINUE
  100 CONTINUE
!
      FVEC(2)=DTERM1 + DSUM1
!
      RETURN
      END SUBROUTINE GLSFU2
      DOUBLE PRECISION FUNCTION GLSFU3(DTHETA)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GENERALIZED LOGARITHMIC SERIES METHOD OF ONES
!              FREQUENCY AND SAMPLE MEAN EQUATIONS.
!
!                 LOG(THETA) + ((1/THETA) -
!                 (1/XBAR)*(-1/LOG(1-THETA) - 1)*LOG(1-THETA) -
!                 LOG(-LOG(1-THETA)) - LOG(F1/N) = 0
!
!              WITH THETA DENOTING THE SHAPE PARAMETER.
!
!              CALLED BY DFZERO ROUTINE.
!     EXAMPLE--GENERALIZED LOGARITHMIC SERIES MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 11.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION F1
      COMMON/GLSCOM/XBAR,S2,F1,MAXROW,N
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DN=DBLE(N)
      DTERM1=DLOG(DTHETA)
      DALPHA=-1.0D0/DLOG(1.0D0 - DTHETA)
      DTERM2=((1.0D0/DTHETA) - DALPHA/XBAR - 1.0D0)*   &
             DLOG(1.0D0 - DTHETA)
      DTERM3=DLOG(-DLOG(1.0D0-DTHETA))
      DTERM4=DLOG(F1)
      GLSFU3=DTERM1 + DTERM2 - DTERM3 - DTERM4
!
      RETURN
      END FUNCTION GLSFU3
      SUBROUTINE GLSPDF(X,THETA,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE FOR THE GENERALIZED LOGARITHMIC SERIES
!              DISTRIBUTION WITH SHAPE PARAMETERS THETA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL INTEGER X >= 1.
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA)=
!                  Gamma(BETA*X+1)*THETA**X*(1-THETA)**(BETA*X-X)/
!                  X!*(BETA*X)*Gamma(BETA*X-X+1)*[-LOG(1-THETA)]
!                  X = 1, 2, 3, ,...
!                  0 < THETA < 1; 1 <= BETA < 1/THETA
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --THETA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY MASS
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY MASS FUNCTION VALUE
!             PDF FOR THE GENERALIZED LOGARITHMIC SERIES
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A POSITIVE INTEGER
!                 --0 < THETA < 1; 1 < BETA < 1/THETA
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FAMOYE (1997), "SAMPLING FROM A GENERALIZED
!                 LOGARITHMIC SERIES DISTRIBUTION", COMPUTING,
!                 58(4), PP. 365-376.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 11.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5)
      IF(IX.LT.1)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GLSPDF IS LESS ',   &
      'THAN 1')
!
      IF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GLSPDF IS NOT IN ',   &
      'THE INTERVAL (0,1)')
!
      IF(BETA.LT.1.0 .OR. BETA.GE.1.0/THETA)THEN
        WRITE(ICOUT,25)1.0/THETA
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO GLSPDF IS NOT IN ',   &
      'THE INTERVAL (1,',G15.7,')')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DX=DBLE(IX)
      DTHETA=DBLE(THETA)
      DBETA=DBLE(BETA)
!
      DTERM1=DLNGAM(DBETA*DX+1.0D0) + DX*DLOG(DTHETA) +   &
             (DBETA*DX-DX)*DLOG(1.0D0 - DTHETA)
      DTERM2=DLNGAM(DX+1.0D0) + DLOG(DBETA) + DLOG(DX)
      DTERM3=DLNGAM(DBETA*DX-DX+1.0D0) + DLOG(-DLOG(1.0D0-DTHETA))
      DTERM4=DTERM1 - DTERM2 - DTERM3
      DPDF=DEXP(DTERM4)
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GLSPDF
      SUBROUTINE GLSPPF(P,THETA,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED LOGARITHMIC SERIES
!              DISTRIBUTION WITH SHAPE PARAMETERS THETA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL INTEGER X >= 1.
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA)=
!                  Gamma(BETA*X+1)*THETA**X*(1-THETA)**(BETA*X-X)/
!                  X!*(BETA*X)*Gamma(BETA*X-X+1)*[-LOG(1-THETA)]
!                  X = 1, 2, 3, ,...
!                  0 < THETA < 1; 1 <= BETA < 1/THETA
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              BY SUMMING THE PROBABILITY MASS FUNCTION.  THE
!              PERCENT POINT FUNCTION IS COMPUTED BY COMPUTING THE
!              CUMULATIVE DISTRIBUTION UNTIL THE APPROPRIATE
!              PROBABILITY IS REACHED.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                0 <= P < 1.
!                     --THETA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE GENERALIZED LOGARITHMIC SERIES
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P < 1
!                 --0 < THETA < 1; 1 < BETA < 1/THETA
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FAMOYE (1997), "SAMPLING FROM A GENERALIZED
!                 LOGARITHMIC SERIES DISTRIBUTION", COMPUTING,
!                 58(4), PP. 365-376.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 11.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GLSPPF IS OUTSIDE ',   &
      'THE (0,1] INTERVAL')
!
      IF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GLSPPF IS NOT IN ',   &
      'THE INTERVAL (0,1)')
!
      IF(BETA.LT.1.0 .OR. BETA.GE.1.0/THETA)THEN
        WRITE(ICOUT,25)1.0/THETA
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO GLSPPF IS NOT IN ',   &
      'THE INTERVAL (1,',G15.7,')')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DTHETA=DBLE(THETA)
      DBETA=DBLE(BETA)
      DP=DBLE(P)
      DEPS=1.0D-7
      DCDF=DTHETA*(1.0D0 - DTHETA)**(DBETA - 1.0D0)/   &
           (-DLOG(1.0D0 - DTHETA))
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=1.0
        GO TO 9000
      ENDIF
!
      DPDF=(DBETA-0.5D0)*DTHETA*(1.0D0-DTHETA)**(DBETA-1.0D0)*DCDF
      DCDF=DCDF + DPDF
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=2.0
        GO TO 9000
      ENDIF
      DPDFSV=DPDF
      DTERM2=DLOG(DTHETA) + (DBETA - 1.0D0)*DLOG(1.0D0 - DTHETA)
!
      I=2
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9000
        ENDIF
        DX=DBLE(I)
        DTERM1=DLOG(DBETA - (DX-1.0D0)/DX)
        IF(DPDFSV.LE.0.0D0)THEN
          DPDF=0.0D0
          GO TO 1000
        ELSE
          DTERM3=DLOG(DPDFSV)
        ENDIF
        DSUM=0.0D0
        DO 200 J=1,I-2
          DSUM=DSUM + DLOG(1.0D0 + DBETA/(DBETA*(DX-1.0D0)-DBLE(J)))
  200   CONTINUE
        DPDF=DEXP(DTERM1 + DTERM2 + DTERM3 + DSUM)
 1000   CONTINUE
        DCDF=DCDF + DPDF
        DPDFSV=DPDF
        IF(DCDF.GE.DP-DEPS)THEN
          PPF=REAL(I)
          GO TO 9000
        ENDIF
      GO TO 100
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GLSPPF
      SUBROUTINE GLSRAN(N,THETA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED LOGARITHMIC SERIES DISTRIBUTION
!              WITH SHAPE PARAMETERS THETA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= 1.
!              p(X;THETA,BETA)=
!                  Gamma(BETA*X+1)*THETA**X*(1-THETA)**(BETA*X-X)/
!                  X!*(BETA*X)*Gamma(BETA*X-X+1)*[-LOG(1-THETA)]
!                  X = 1, 2, 3, ,...
!                  0 < THETA < 1; 1 < BETA < 1/THETA
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --THETA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X    = A SINGLE PRECISION VECTOR
!                              (OF DIMENSION AT LEAST N)
!                              INTO WHICH THE GENERATED
!                              RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED LOGARITHMIC SERIES DISTRIBUTION
!             WITH SHAPE PARAMETERS THETA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 < THETA < 1, 1 < BETA < 1/THETA
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GLSPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FAMOYE (1997), "SAMPLING FROM A GENERALIZED
!                 LOGARITHMIC SERIES DISTRIBUTION", COMPUTING,
!                 58(4), PP. 365-376.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 11.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL THETA
      REAL BETA
      DIMENSION X(*)
!CCCC DIMENSION XTEMP(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!CCCC DATA PI / 3.1415926535 8979323846 E0 /
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'GENERALIZED LOGARITHMIC SERIES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
    6   FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE THETA PARAMETER FOR THE ',   &
               'GENERALIZED LOGARITHMIC SERIES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
   12   FORMAT('      RANDOM NUMBERS IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.LE.1.0 .OR. BETA.GE.1.0/THETA)THEN
        WRITE(ICOUT,21)
   21   FORMAT('***** ERROR--THE BETA PARAMETER FOR THE ',   &
               'GENERALIZED LOGARITHMIC SERIES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22)
   22   FORMAT('      RANDOM NUMBERS IS OUTSIDE THE (0,',G15.7,   &
               ') INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     GENERATE N GENERALIZED LOGARITHMIC SERIES DISTRIBUTION
!     RANDOM NUMBERS.  FOLLOWING RECOMMENDATION OF CONSUL AND
!     FAYMOE, USE INVERSION METHOD FOR THETA*BETA <= 0.45 AND
!     BRANCHING METHOD OTHERWISE.
!
!     BRANCHING ALGORITHM DOESN'T SEEM TO RETURN REASONABLE
!     RESULTS (MAYBE USING A SLIGHTLY DIFFERENT DEFINITION
!     FOR NEGATIVE BINOMIAL?), SO USE REJECTION ALGORITHM
!     INSTEAD.
!
!CCCC IF(THETA*BETA.LE.0.45)THEN
        CALL UNIRAN(N,ISEED,X)
        DO 100 I=1,N
          ZTEMP=X(I)
          CALL GLSPPF(ZTEMP,THETA,BETA,PPF)
          X(I)=PPF
  100   CONTINUE
!CCCC ELSE
!
!       BRANCHING ALGORITHM
!
!CCCC   NTEMP=1
!CCCC   DO200I=1,N
!CCCC     CALL DLGRAN(NTEMP,THETA,ISEED,XTEMP)
!CCCC     Y=XTEMP(1)
!CCCC     XX=Y
!C210     CONTINUE
!CCCC     AK=(BETA-1.0)*Y
!CCCC     CALL NBRAN(NTEMP,1.0-THETA,AK,ISEED,XTEMP)
!CCCC     Z=XTEMP(1)
!CCCC     XX=XX+Z
!CCCC     Y=Z
!CCCC     IF(Y.GT.0)GO TO 210
!CCCC     X(I)=XX
!C200   CONTINUE
!
!       REJECTION ALGORITHM
!
!CCCC   NTEMP=2
!CCCC   C=(1.0+SQRT(2.0))/((-LOG(1.0-THETA))*SQRT(PI*BETA*(BETA-1.0)))
!CCCC   DO300I=1,N
!C310     CONTINUE
!CCCC     CALL UNIRAN(NTEMP,ISEED,XTEMP)
!CCCC     U=XTEMP(1)
!CCCC     V=XTEMP(2)
!CCCC     IXX=INT(1.0/V**2)
!CCCC     XX=IXX
!CCCC     CALL GLSPDF(XX,THETA,BETA,PDF)
!CCCC     TERM1=U*C*(1.0/SQRT(XX) - 1.0/SQRT(XX+1.0))
!CCCC     IF(TERM1.LE.PDF)THEN
!CCCC       X(I)=XX
!CCCC     ELSE
!CCCC       GO TO 310
!CCCC     ENDIF
!C300   CONTINUE
!CCCC ENDIF
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE GLSRAN
      SUBROUTINE GMCCDF(X,ALPHA,A,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED MCLEISH
!              DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND A.
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE CUMULATIVE DISTRIBUTION
!                                 FUNCTION IS TO BE EVALUATED.
!                     --ALPHA   = THE FIRST SHAPE PARAMETER
!                     --A       = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF     = THE DOUBLE PRECISION CUMULATIVE
!                                 DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE FOR THE GENERALIZED MCLEISH
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION A
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION CDF
      DOUBLE PRECISION X
      DOUBLE PRECISION DX
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION GMCFUN
      EXTERNAL GMCFUN
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DA
      COMMON/GMCCOM/DALPHA,DA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      CDF=0.0D0
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR: VALUE OF SHAPE PARAMETER (ALPHA)',   &
               ' IN GMCCDF ROUTINE IS NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
   48   FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ELSEIF(ABS(A).GE.1.0D0)THEN
        WRITE(ICOUT,8)
    8   FORMAT('***** ERROR: ABSOLUTE VALUE OF SECOND SHAPE ',   &
               'PARAMETER (A) IN GMCCDF ROUTINE IS >= 1.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)A
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      INF=-1
      EPSABS=0.0D0
      EPSREL=1.0D-7
      IER=0
      DCDF=0.0D0
      IFLAG=0
!
      DX=X
      IF(DX.LT.0.0D0)THEN
        IFLAG=1
        INF=1
      ENDIF
      DA=A
      DALPHA=ALPHA
!
      CALL DQAGI(GMCFUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
!
      IF(IFLAG.EQ.1)THEN
        CDF=1.0D0 - DCDF
      ELSE
        CDF=DCDF
      ENDIF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM GMCCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM GMCCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GMCCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM GMCCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM GMCCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM GMCCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GMCCDF
      DOUBLE PRECISION FUNCTION GMCFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED MCLEISH
!              DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND A.
!              THIS DISTRIBUTION IS DEFINED FOR ALL REAL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 f(X;ALPHA,A) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                (ABS(X)/2)**(ALPHA-1/2)*K(X,ALPHA-1/2)
!                                *(1-A**2)**ALPHA*EXP(A*X)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!              THE GMCPDF ROUTINE IS CALLED TO COMPUTE THE
!              PROBABILITY DENSITY.  DEFINE AS FUNCTION TO BE USED FOR
!              INTEGRATION CODE CALLED BY GMCCDF.  THIS ROUTINE USES
!              DOUBLE PRECISION ARITHMETIC.
!     INPUT  ARGUMENTS--DX      = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--GMCFUN  = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE GENERALIZED MCLEISH
!             DISTRIBUTION WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GMCPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DA
      COMMON/GMCCOM/DALPHA,DA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL GMCPDF(DX,DALPHA,DA,DTERM)
      GMCFUN=DTERM
!
      RETURN
      END FUNCTION GMCFUN
      DOUBLE PRECISION FUNCTION GMCFU2(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED MCLEISH
!              DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND A.
!              THIS DISTRIBUTION IS DEFINED FOR ALL REAL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 f(X;ALPHA,A) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                (ABS(X)/2)**(ALPHA-1/2)*K(X,ALPHA-1/2)
!                                *(1-A**2)**ALPHA*EXP(A*X)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!              THE GMCCDF ROUTINE IS CALLED TO COMPUTE THE
!              PROBABILITY DENSITY.  DEFINE AS FUNCTION TO BE USED FOR
!              INTEGRATION CODE CALLED BY GMCCDF.  THIS ROUTINE USES
!              DOUBLE PRECISION ARITHMETIC.
!     INPUT  ARGUMENTS--DX      = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--GMCFU2  = THE DOUBLE PRECISION CUMULATIVE
!                                 DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE GENERALIZED MCLEISH
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GMCCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
!
      DOUBLE PRECISION DP
      COMMON/GM2COM/DP
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DA
      COMMON/GMCCOM/DALPHA,DA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL GMCCDF(DX,DALPHA,DA,DCDF)
      GMCFU2=DP - DCDF
!
      RETURN
      END FUNCTION GMCFU2
      SUBROUTINE GMCPDF(X,ALPHA,A,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE GENERALIZED MCLEISH BESSEL
!              K-FUNCTION DISTRIBUTION.  IT HAS SHAPE PARAMETERS
!              ALPHA.  THIS DISTRIBUTION IS ASYMMETRIC AND IS DEFINED
!              FOR ALL REAL X AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 f(X;ALPHA,A) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                (ABS(X)/2)**(ALPHA-1/2)*K(X,ALPHA-1/2)
!                                *(1-A**2)**ALPHA*EXP(A*X)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!     NOTE--ARGUMENTS TO THIS ROUTINE ARE IN DOUBLE PRECISION.
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!                                 X SHOULD BE POSITIVE
!                     --ALPHA   = THE FIRST SHAPE PARAMETER
!                     --A       = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF     = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE GENERALIZED MCLEISH DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA AND NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DBESI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG, DLNGAM.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 WILEY, 1994, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION DX
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION A
      DOUBLE PRECISION PDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTERM6
      DOUBLE PRECISION DORD
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
!
      DOUBLE PRECISION DTEMP1(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DPI / 3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (ALPHA)',   &
             ' IN GMCPDF ROUTINE IS NON-POSITIVE.')
      IF(ABS(A).GE.1.0D0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)A
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
      ENDIF
    8 FORMAT('***** ERROR: ABSOLUTE VALUE OF SECOND SHAPE PARAMETER ',   &
             '(A) IN GMCPDF ROUTINE IS >= 1.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE DENSITY FUNCTION.  FOR **
!               **  BETTER NUMERICAL STABILITY,        **
!               **  COMPUTE LOGARIGHMS.                **
!               *****************************************
!
!
!  COMPUTE BESSEL FUNCTION FIRST.  IF THIS IS 0, SET PDF TO
!  0 AND RETURN.
!
      DEPS=1.0D-12
      IF(ALPHA.GT.25.0)DEPS=1.0D-10
      DX=X
      DX=DABS(DX)
      IF(DX.EQ.0.0D0)DX=DEPS
      DORD=DABS(ALPHA-0.5D0)
      IARG1=1
      ISCALE=1
      CALL DBESK(DX,DORD,ISCALE,IARG1,DTEMP1,NZERO)
      DTERM3=DTEMP1(IARG1)
      IF(DTERM3.LE.0.0D0)THEN
        PDF=0.0D0
        GO TO 9000
      ENDIF
      DTERM3=DLOG(DTERM3)
!
      DTERM1=0.5D0*DLOG(DPI) + DLNGAM(ALPHA)
      DTERM2=(ALPHA-0.5D0)*DLOG(DX/2.0D0)
      DTERM4=ALPHA*DLOG(1.0D0 - A**2)
      DTERM5=A*X
      DTERM6 = -DTERM1+DTERM2+DTERM3+DTERM4+DTERM5
      PDF=DEXP(DTERM6)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GMCPDF
      SUBROUTINE GMCPPF(P,ALPHA,A,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION
!              VALUE FOR THE GENERALIZED MCLEISH DISTRIBUTION.  IT HAS
!              SHAPE PARAMETERS ALPHA AND A.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL REAL X AND HAS THE PROBABILITY DENSITY
!              FUNCTION
!
!                 f(X;ALPHA,A) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                (ABS(X)/2)**(ALPHA-1/2)*K(X,ALPHA-1/2)
!                                *(1-A**2)**ALPHA*EXP(A*X)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY NUMERICALLY
!              INVERTING THE GENERALIZED MCLEISH CUMULATIVE
!              DISTRIBUTION FUNCTION (WHICH IN TURN IS COMPUTED BY
!              NUMERICAL INTEGRATION OF THE PROBABILITYT DENSITY).
!
!     INPUT  ARGUMENTS--P       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PERCENT POINT
!                                 FUNCTION IS TO BE EVALUATED.
!                                 0 < P < 1
!                     --ALPHA   = THE FIRST SHAPE PARAMETER
!                     --A       = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF     = THE DOUBLE PRECISION PERCENT POINT
!                                 FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE GENERALIZED MCLEISH
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DFZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, (1994), "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME 1", SECOND EDITION,
!                 WILEY, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION P
      DOUBLE PRECISION PTEMPL
      DOUBLE PRECISION PTEMPU
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION A
      DOUBLE PRECISION PPF
      DOUBLE PRECISION DINC
!
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XUP2
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION RE
      DOUBLE PRECISION AE
!
      DOUBLE PRECISION GMCFU2
      EXTERNAL GMCFU2
!
      DOUBLE PRECISION DP
      COMMON/GM2COM/DP
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DA
      COMMON/GMCCOM/DALPHA,DA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************************
!               **  STEP 1--                           **
!               **  CHECK FOR VALID PARAMETERS         **
!               *****************************************
!
      IF(P.LE.0.0D0 .OR. P.GE.1.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)P
        CALL DPWRST('XXX','WRIT')
        PPF=0.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR: VALUE OF INPUT ARGUMENT (P) IN ',   &
             'GMCPPF ROUTINE')
   14 FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        PPF=0.0D0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (ALPHA)',   &
             ' IN GMCPPF ROUTINE IS NON-POSITIVE.')
      IF(ABS(A).GE.1.0D0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)A
        CALL DPWRST('XXX','WRIT')
        PPF=0.0D0
        GO TO 9000
      ENDIF
    8 FORMAT('***** ERROR: ABSOLUTE VALUE OF SECOND SHAPE PARAMETER ',   &
             '(A) IN GMCPPF ROUTINE IS >= 1.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE PERCENT POINT FUNCTION.**
!               *****************************************
!
!  STEP 1: FIND BRACKETING INTERVAL.  START WITH -10 AND +10,
!          INCREMENT BY 10.
!
      XLOW=-10.0D0
      XUP2=10.0D0
      CALL GMCCDF(XLOW,ALPHA,A,PTEMPL)
      CALL GMCCDF(XUP2,ALPHA,A,PTEMPU)
      DINC=10.0D0
      IF(ALPHA.GT.20.0D0)THEN
        DINC=ALPHA
      ENDIF
!
      MAXIT=1000
      NIT=0
!
  200 CONTINUE
      IF(NIT.GT.MAXIT)THEN
        PPF=0.0D0
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      CALL GMCCDF(XLOW,ALPHA,A,PTEMPL)
      CALL GMCCDF(XUP2,ALPHA,A,PTEMPU)
      IF(PTEMPL.LE.P .AND. P.LE.PTEMPU)THEN
        XUP=XUP2
        GO TO 300
      ELSEIF(P.GT.PTEMPU)THEN
        XLOW=XUP2
        XUP2=XUP2 + DINC
        NIT=NIT+1
        GO TO 200
      ELSEIF(P.LT.PTEMPL)THEN
        XUP2=XLOW
        XLOW=XLOW - DINC
        NIT=NIT+1
        GO TO 200
      ENDIF
!
  300 CONTINUE
      AE=1.D-7
      RE=1.D-7
      DALPHA=ALPHA
      DP=P
      CALL DFZERO(GMCFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM GMCPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM GMCPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM GMCPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM GMCPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GMCPPF
      SUBROUTINE GMCRAN(N,ALPHA,A,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED MCLEISH DISTRIBUTION WITH SHAPE
!              PARAMETERS ALPHA AND A.  THIS DISTRIBUTION IS DEFINED
!              FOR ALL X AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 f(X;ALPHA,A) = [1/(SQRT(PI)*GAMMA(ALPHA))]*
!                                (ABS(X)/2)**(ALPHA-1/2)*K(X,ALPHA-1/2)
!                                *(1-A**2)**ALPHA*EXP(A*X)
!              WHERE
!                 K(X,N) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND
!                 GAMMA IS THE GAMMA FUNCTION
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE FIRST SHAPE PARAMETER FOR THE
!                                GENERALIZED MCLEISH DISTRIBUTION
!                     --A      = THE SECOND SHAPE PARAMETER FOR THE
!                                GENERALIZED MCLEISH DISTRIBUTION
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE GENERALIZED MCLEISH
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND A.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 WILEY, 1994, PP. 50-53.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DPPF
      DIMENSION X(*)
!CCCC DIMENSION Y(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
    5 FORMAT('***** ERROR--FOR THE GENERALIZED MCLEISH DISTRIBUTION, ',   &
             'THE REQUESTED')
    6 FORMAT('      NUMBER OF RANDOM NUMBERS WAS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,17)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
    7 FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (ALPHA)',   &
             ' FOR GENERALIZED MCLEISH')
   17 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
      IF(ABS(A).GE.1.0D0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,18)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)A
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
    8 FORMAT('***** ERROR: VALUE OF SECOND SHAPE PARAMETER (A)',   &
             ' FOR GENERALIZED MCLEISH')
   18 FORMAT('      RANDOM NUMBERS HAS ABSOLUTE VALUE >= 1')
   48 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!     MCLEISH IS DISTRIBUTION OF SQRT(G)*Z WHERE G IS A GAMMA
!     DISTRIBUTION WITH SHAPE PARAMETER ALPHA AND SCALE PARAMETER 2.
!     Z IS A STANDARD NORMAL DISTRIBUTION.
!
!     FOR THE GENERALIZED MCLEISH, ...
!
      CALL UNIRAN(N,ISEED,X)
      NTEMP=1
      DO 100 I=1,N
!CCCC   CALL GAMRAN(NTEMP,ALPHA,ISEED,Y)
!CCCC   G1=SQRT(2.0*Y(1))
!CCCC   CALL NORRAN(NTEMP,ISEED,Y)
!CCCC   G2=Y(1)
!CCCC   APPF=G1*G2
!CCCC   X(I)=APPF
        ATEMP=X(I)
        CALL GMCPPF(DBLE(ATEMP),DBLE(ALPHA),DBLE(A),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GMCRAN
      SUBROUTINE GMDRAT(X1,N1,X2,N2,IWRITE,XTEMP,GRATIO,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE LOG OF THE RATIO OF TWO
!              SAMPLE GINI MEAN DIFFERENCE STATISTICS.  THE GINI MEAN
!              DIFFERENCE IS A MEASURE OF DISPERSION WITH THE FORMULA:
!
!                 GMD = (2/(N*(N-1))*
!                       SUM[j=1 to N][SUM[i < j][ABS(X(i) - X(j)]]
!                     = (2/(N*(N-1))*SUM[i=1 to N-1][i*(N-i)*
!                       (X(i+1) - X(i))]
!
!               WHERE X ARE THE SORTED RESPONSES.
!
!               THIS SUBROUTINE COMPUTES
!
!                    G = LOG(GMD1/GMD2)
!
!               WHERE GMD1 AND GMD2 ARE THE GINI MEAN DIFFERENCES
!               OF SAMPLE 1 AND SAMPLE 2, RESPECTIVELY.
!
!     INPUT  ARGUMENTS--X1     = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                FOR SAMPLE ONE.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X1.
!                     --X2     = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                FOR SAMPLE TWO.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X2.
!     OUTPUT ARGUMENTS--GRATIO = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE GINI MEAN DIFFERENCE
!                                LOG RATIO.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE GINI
!             MEAN DIFFERENCE LOG RATIO.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GINIMD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TENA (2009), "TEST PROCEDURES FOR EQUALITY OF
!                 TWO VARIANCES IN DELTA DISTRIBUTIONS,"
!                 DISSERTATIONS, 695,
!                 https://scholarworks.wmich.edu/dissertations/695
!               --GINI (1921), "MEASUREMENT OF INEQUALITY IN
!                 INCOMES," THE ECONOMIC JOURNAL, 31, pp. 124-126.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/07
!     ORIGINAL VERSION--JULY      2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION XTEMP(*)
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GINI'
      ISUBN2='MD  '
      IERROR='NO'
!
      GRATIO=0.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'DRAT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF GMDRAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,N2
   52   FORMAT('IBUGA3,ISUBRO,N1,N2 = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,X1(I)
   56     FORMAT('I,X1(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,X2(I)
   66     FORMAT('I,X2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N1.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN GINI MEAN DIFFERENCE LOG DIFFERENCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLE IS LESS THAN OR EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N1
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N2.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N2
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  COMPUTE THE GINI MEAN DIFFERENCE         **
!               **  LOG RATIO                                **
!               ***********************************************
!
      CALL GINIMD(X1,N1,IWRITE,XTEMP,GMD1,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(GMD1.LE.0.0)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,201)
  201   FORMAT('      THE GINI MEAN DIFFERENCE FOR THE FIRST ',   &
               'RESPONSE VARIABLE IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      CALL GINIMD(X2,N2,IWRITE,XTEMP,GMD2,IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(GMD2.LE.0.0)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,211)
  211   FORMAT('      THE GINI MEAN DIFFERENCE FOR THE SECOND ',   &
               'RESPONSE VARIABLE IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      GRATIO=LOG(GMD1/GMD2)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,813)N,GRATIO
  813   FORMAT('THE GINI MEAN DIFFERENCE LOG RATIO OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'DRAT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF GMDRAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,GMD1,GMD2,GRATIO
 9012   FORMAT('IERROR,GMD1,GMD2,GRATIO = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE GMDRAT
      SUBROUTINE GNBCDF(X,THETA,BETA,M,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE GENERALIZED NEGATIVE BINOMIAL
!              DISTRIBUTION WITH SHAPE PARAMETERS THETA, BETA, AND
!              M.  THIS DISTRIBUTION IS DEFINED FOR ALL INTEGER
!              X >= 1.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA,M)=
!                  (M/(M+BETA*X)*
!                  (M+BETA*X  X)*THETA**X*(1-THETA)**(M+BETA*X-X)
!                  X = 0, 1, 2, 3, ,...
!                  0 < THETA < 1; BETA = 0 OR 1 <= BETA <= 1/THETA;
!                  M > 0 (M A POSITIVE INTEGER IF BETA = 0)
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              FROM THE FOLLOWING RECURRENCE RELATION:
!
!              P(X+1) = (M+(BETA-1)*X+BETA)/(X+1)*
!                       THETA*(1-THETA)**(BETA-1)*
!                       PROD[J=1 TO X-1][1 + BETA/(M+BETA*X-J)]*P(X)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --THETA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --M      = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE GENERALIZED NEGATIVE BINOMIAL
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 < THETA < 1; 1 <= BETA <= 1/THETA
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL M
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5)
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GNBCDF IS LESS ',   &
      'THAN 0')
!
      IF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GNBCDF IS NOT IN ',   &
      'THE INTERVAL (0,1)')
!
      IF(BETA.LE.1.0 .OR. BETA.GE.1.0/THETA .AND. BETA.NE.0.0)THEN
        WRITE(ICOUT,25)1.0/THETA
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO GNBCDF IS NOT IN ',   &
      'THE INTERVAL (1,',G15.7,')')
!
      IF(M.LE.0.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)M
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   35 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO GNBCDF IS ',   &
      'NON-POSITIVE')
      IF(BETA.EQ.0.0)THEN
        IM=INT(M+0.5)
        IF(IM.EQ.0)IM=1
        M=REAL(IM)
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DTHETA=DBLE(THETA)
      DBETA=DBLE(BETA)
      DM=DBLE(M)
!
!     USE THE RECURRENCE RELATION (PAGE 199 OF CONSUL AND FAMOYE):
!
      DCDF=(1.0D0 - DTHETA)**DM
      IF(IX.EQ.0)GO TO 1000
!
      DPDF=DM*DTHETA*(1.0D0 - DTHETA)**(DM+DBETA-1.0D0)
      DCDF=DCDF + DPDF
      IF(IX.EQ.1)GO TO 1000
!
      DPDFSV=DPDF
      DTERM2=DLOG(DTHETA) + (DBETA - 1.0D0)*DLOG(1.0D0 - DTHETA)
!
      DO 100 I=2,IX
        DX=DBLE(I)
        DTERM1=DLOG(DM + (DBETA-1.0D0)*(DX-1.0D0) + DBETA) -   &
               DLOG(DX)
        IF(DPDFSV.LE.0.0D0)THEN
          GO TO 1000
        ELSE
          DTERM3=DLOG(DPDFSV)
        ENDIF
        IF(I-2.GE.1)THEN
          DSUM=0.0D0
          DO 200 J=1,I-2
            DSUM=DSUM + DLOG(1.0D0 + DBETA/   &
                 (DM + DBETA*(DX-1.0D0)-DBLE(J)))
  200     CONTINUE
        ELSE
          DSUM=0.0D0
        ENDIF
        DPDF=DEXP(DTERM1 + DTERM2 + DTERM3 + DSUM)
        DCDF=DCDF + DPDF
        DPDFSV=DPDF
  100 CONTINUE
!
 1000 CONTINUE
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GNBCDF
      DOUBLE PRECISION FUNCTION GNBFUN(DTHETA)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTION FOR FINDING
!              THE ESTIMATE OF THETA FOR THE
!              GENERALIZED NEGATIVE BINOMIAL METHOD OF MOMENT
!              EQUATIONS.
!
!                 THETAHAT = 1 - 0.5*A + (A**2/4 - 1)**(0.5)
!                 A = -2 + (XBAR*S3 - 3*S2**2)**2/(XBAR*S2**3)
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF
!              A NONLINEAR EQUATIONS.
!     EXAMPLE--GENERALIZED NEGATIVE BINOMIAL MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DA
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION S3
      DOUBLE PRECISION F0FREQ
      DOUBLE PRECISION F1FREQ
      DOUBLE PRECISION F10FRE
      DOUBLE PRECISION DC1
      COMMON/GNBCOM/XBAR,S2,S3,F0FREQ,F1FREQ,F10FRE,DC1,   &
                    MAXROW,NTOT2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DA=-2.0D0 + (XBAR*S3 - 3.0D0*S2**2)**2/(XBAR*S2**3)
      GNBFUN=1.0D0 - 0.5D0*DA + DSQRT(DA**2/4.0D0 - 1.0D0)
!
      IF(ISUBG4.EQ.'BFUN')THEN
        WRITE(ICOUT,52)DTHETA,DA,GNBFUN
   52   FORMAT('DTHETA,DA,GNBFUN = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END FUNCTION GNBFUN
      SUBROUTINE GNBFU2(N,XPAR,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              GENERALIZED NEGATIVE BINOMIAL MAXIMUM LIKELIHOOD
!              EQUATIONS.
!
!              THE MAXIMUM LIKELIHOOD ESTIMATES ARE THE SOLUTIONS
!              TO THE EQUATIONS:
!
!                 M*(XBAR - THETA*(M + BETA*XBAR))/
!                 (THETA*(1 - THETA))
!
!                 N*XBAR*LOG(1-THETA) +
!                 SUM[X=2 to k][SUM[i=1 to x-1]
!                 [X*N(x)/(M+BETA*X-i]] = 0
!
!                 (N-N0)*XBAR/M + N*LOG(1 - THETA) +
!                 SUM[X=2 to k][SUM[i=1 to x-1]
!                 [(X-XBAR)*N(x)/(M+BETA*X-i]] = 0
!
!              ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--GENERALIZED NEGATIVE BINOMIAL MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DM
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DN
      DOUBLE PRECISION DJ
      DOUBLE PRECISION DN0
      DOUBLE PRECISION DFREQ
      DOUBLE PRECISION DNUM1
      DOUBLE PRECISION DNUM2
      DOUBLE PRECISION DENOM
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION S3
      DOUBLE PRECISION F0FREQ
      DOUBLE PRECISION F1FREQ
      DOUBLE PRECISION F10FRE
      DOUBLE PRECISION DC1
      COMMON/GNBCOM/XBAR,S2,S3,F0FREQ,F1FREQ,F10FRE,DC1,   &
                    MAXROW,NTOT2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DBETA=XPAR(1)
      DM=XPAR(2)
      DTHETA=XPAR(3)
      DN=DBLE(NTOT2)
!
      IINDX=MAXROW/2
!
      DN0=DN*F0FREQ
      DTERM1=DN*XBAR*DLOG(1.0D0 - DTHETA)
      DTERM2=(DN - DN0)/DM + DN*DLOG(1.0D0 - DTHETA)
!
      DSUM1=0.0D0
      DSUM2=0.0D0
!
!     NOTE: CONSUL AND FAMOYE DEFINE CLASSES FOR I = 0 TO K,
!           SO ADJUST FOR FACT THAT FORTRAN ARRAYS START AT 1.
!
      DO 100 I=1,K
        DX=DBLE(Y(IINDX+I))
        IX=INT(DX + 0.5D0)
        IF(IX.LT.2)GO TO 100
        DFREQ=DBLE(Y(I))
        IF(DFREQ.LE.0.0D0)GO TO 100
        DNUM1=DX*DFREQ
        DNUM2=DFREQ
        DO 200 J=1,K
          DJ=DBLE(Y(IINDX+J))
          IJ=INT(DJ + 0.5D0)
          IF(IJ.LT.1 .OR. IJ.GT.IX-1)GO TO 200
          DENOM=DM + DBETA*DX - DJ
          DSUM1=DSUM1 + DNUM1/DENOM
          DSUM2=DSUM2 + DNUM2/DENOM
  200   CONTINUE
  100 CONTINUE
!
      FVEC(1)=DM*(XBAR - DTHETA*(DM + DBETA*XBAR))/   &
              (DTHETA*(1.0D0 - DTHETA))
      FVEC(2)=DTERM1 + DSUM1
      FVEC(3)=DTERM2 + DSUM2
!
      RETURN
      END SUBROUTINE GNBFU2
      DOUBLE PRECISION FUNCTION GNBFU3(DTHETA)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTION FOR FINDING
!              THE ESTIMATE OF THETA FOR THE
!              GENERALIZED NEGATIVE BINOMIAL METHOD OF MOMENTS
!              AND ZERO-CLASS FREQUENCY EQUATION.
!
!                 S2*(LOG(F0)**2/XBAR**3 -
!                 (1-THETA)*(LOG(1-THETA))**2/THETA**2 = 0
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF
!              A NONLINEAR EQUATIONS.
!     EXAMPLE--GENERALIZED NEGATIVE BINOMIAL MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTHETA
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION S3
      DOUBLE PRECISION F0FREQ
      DOUBLE PRECISION F1FREQ
      DOUBLE PRECISION F10FRE
      DOUBLE PRECISION DC1
      COMMON/GNBCOM/XBAR,S2,S3,F0FREQ,F1FREQ,F10FRE,DC1,   &
                    MAXROW,NTOT2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      GNBFU3=DC1 - (1.0D0 - DTHETA)*DLOG(1.0D0 - DTHETA)**2/DTHETA**2
!
      RETURN
      END FUNCTION GNBFU3
      DOUBLE PRECISION FUNCTION GNBFU4(DTHETA)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTION FOR FINDING
!              THE ESTIMATE OF THETA FOR THE
!              GENERALIZED NEGATIVE BINOMIAL METHOD OF MOMENTS
!              AND RATIO OF FREQUENCIES EQUATION
!
!                 {(2/THETA) - (2/THETA)*SQRT(XBAR*(1-THETA)/S2)-1}*
!                 LOG(1-THETA) - LOG(S2*F10**2/XBAR**3) = 0
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF
!              A NONLINEAR EQUATIONS.
!     EXAMPLE--GENERALIZED NEGATIVE BINOMIAL MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTHETA
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION S3
      DOUBLE PRECISION F0FREQ
      DOUBLE PRECISION F1FREQ
      DOUBLE PRECISION F10FRE
      DOUBLE PRECISION DC1
      COMMON/GNBCOM/XBAR,S2,S3,F0FREQ,F1FREQ,F10FRE,DC1,   &
                    MAXROW,NTOT2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      GNBFU4=((2.0D0/DTHETA) -   &
             (2.0D0/DTHETA)*DSQRT(XBAR*(1.0D0-DTHETA)/S2)-1.0D0)*   &
             DLOG(1.0D0-DTHETA) - DLOG(S2*F10FRE**2/XBAR**3)
!
      RETURN
      END FUNCTION GNBFU4
      DOUBLE PRECISION FUNCTION GNBFU5(DM)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTION FOR FINDING
!              THE ESTIMATE OF M FOR THE TRUNCATED GENERALIZED
!              NEGATIVE BINOMIAL RATIO OF FREQUENCIES METHOD.
!              SOLVE THE FOLLOWING EQUATONS:
!
!              H(M) = -XBAR/M + (1-XBAR)*F1/(M*F0) +
!                     SUM[X=2 to t][((X-XBAR)/X!)*(F1/(M*F0))*
!                     PROD[i=1 to x-1][M + (X*M*F0*F2/F(i)**2) -
!                     X*(M-1)/2 - i]]
!
!              WITH XBAR, F0, F1, F2 DENOTING THE SAMPLE MEAN
!              AND THE FREQUENCIES FOR THE FIRST THREE CLASSES.
!              F(i) IS THE FREQUENCY OF CLASS i.
!
!              CALLED BY DFZERO ROUTINE FOR FINDING THE ROOT OF
!              A NONLINEAR EQUATIONS.
!     EXAMPLE--GENERALIZED NEGATIVE BINOMIAL MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!               --FAMOYE AND CONSUL (1993), "THE TRUNCATED
!                 GENERALZIED NEGATIVE BINOMIAL DISTRIBUTION",
!                 JOURNAL OF APPLIED STATISTICAL SCIENCES,
!                 VOL. 1, NO. 2, PP. 141-157.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/1
!     ORIGINAL VERSION--JANUARY   2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DM
!
      DOUBLE PRECISION XBAR
      DOUBLE PRECISION S2
      DOUBLE PRECISION S3
      DOUBLE PRECISION F0FREQ
      DOUBLE PRECISION F1FREQ
      DOUBLE PRECISION F10FRE
      DOUBLE PRECISION DC1
      COMMON/GNBCOM/XBAR,S2,S3,F0FREQ,F1FREQ,F10FRE,DC1,   &
                    MAXROW,NTOT2
!
!CCCC DOUBLE PRECISION DN
!CCCC DOUBLE PRECISION DTERM1
!CCCC DOUBLE PRECISION DTERM2
!CCCC DOUBLE PRECISION DTERM3
!CCCC DOUBLE PRECISION DTERM4
!CCCC DOUBLE PRECISION DTERM5
!CCCC DOUBLE PRECISION DTERM6
!CCCC DOUBLE PRECISION DSUM
!CCCC DOUBLE PRECISION DPROD
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
!CCCC DN=DBLE(NTOT2)
!CCCC IINDX=MAXROW/2
!CCCC DF0=DBLE(Y(1))
!CCCC DF1=DBLE(Y(2))
!CCCC DF2=DBLE(Y(2))
!
!CCCC DTERM1=XBAR/DM
!CCCC DTERM2=(1.0D0 - XBAR)*DF2/(DM*DF1)
!
!     NOTE: CONSUL AND FAMOYE DEFINE CLASSES FOR I = 0 TO K,
!           SO ADJUST FOR FACT THAT FORTRAN ARRAYS START AT 1.
!
!CCCC DSUM=0.0D0
!CCCC DO100I=3,K
!
!CCCC   DX=DBLE(Y(IINDX+I))
!CCCC   IX=INT(DX+0.5D0)
!CCCC   DFREQ=DBLE(Y(I))
!CCCC   DTERM3=(DX-XBAR)/DGAMMA(DX+1)
!CCCC   DTERM4=(DF1/(DM*DF0))**DX
!
!CCCC   DPROD=1.0D0
!CCCC   DO200J=2,IX-1
!CCCC     DTERM5=DM + (DX*DM*DF0*DF2/DFREQ**2)
!CCCC     DTERM6=-DX*(DM-1.0D0)/2.0D0  - DBLE(J-1)
!CCCC     DPROD=DPROD*(DTERM5 + DTERM6)
!C200   CONTINUE
!CCCC   DSUM=DSUM + DTERM3*DTERM4*DPROD
!C100 CONTINUE
!
!CCCC GNBFU5=DTERM1 + DTERM2 + DSUM
      GNBFU5=0.0D0
!
      IF(ISUBG4.EQ.'BFU5')THEN
        WRITE(ICOUT,52)DM,GNBFU5
   52   FORMAT('DM,GNBFU5 = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END FUNCTION GNBFU5
      SUBROUTINE GNBPDF(X,THETA,BETA,M,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE FOR THE GENERALIZED NEGATIVE BINOMIAL
!              DISTRIBUTION WITH SHAPE PARAMETERS THETA, BETA, AND
!              M.  THIS DISTRIBUTION IS DEFINED FOR ALL INTEGER
!              X >= 1.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA,M)=
!                  (M/(M+BETA*X)*
!                  (M+BETA*X  X)*THETA**X*(1-THETA)**(M+BETA*X-X)
!                  X = 0, 1, 2, 3, ,...
!                  0 < THETA < 1; BETA = 0 OR 1 <= BETA <= 1/THETA;
!                  M > 0 (M A POSITIVE INTEGER IF BETA = 0)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --THETA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --M      = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY MASS FUNCTION
!             VALUE PDF FOR THE GENERALIZED NEGATIVE BINOMIAL
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA, BETA AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 < THETA < 1; 1 <= BETA <= 1/THETA
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL M
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLNGAM
      EXTERNAL DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5)
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GNBPDF IS LESS ',   &
      'THAN 0')
!
      IF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GNBPDF IS NOT IN ',   &
      'THE INTERVAL (0,1)')
!
      IF(BETA.LE.1.0 .OR. BETA.GE.1.0/THETA .AND. BETA.NE.0.0)THEN
        WRITE(ICOUT,25)1.0/THETA
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO GNBPDF IS NOT IN ',   &
      'THE INTERVAL (1,',G15.7,')')
!
      IF(M.LE.0.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)M
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
   35 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO GNBPDF IS ',   &
      'NON-POSITIVE')
      IF(BETA.EQ.0.0)THEN
        IM=INT(M+0.5)
        IF(IM.EQ.0)IM=1
        M=REAL(IM)
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DTHETA=DBLE(THETA)
      DBETA=DBLE(BETA)
      DM=DBLE(M)
      DX=DBLE(IX)
!
      IF(IX.EQ.0)THEN
        DPDF=(1.0D0 - DTHETA)**DM
      ELSEIF(IX.EQ.1)THEN
        DPDF=DM*DTHETA*(1.0D0 - DTHETA)**(DM+DBETA-1.0D0)
      ELSE
        DTERM1=DLOG(DM) - DLOG(DM + DBETA*DX)
        DTERM2=DX*DLOG(DTHETA)
        DTERM3=(DM+DBETA*DX-DX)*DLOG(1.0D0 - DTHETA)
        DTERM4=DLNGAM(DM+DBETA*DX+1.0D0) - DLNGAM(DX+1.0D0) -   &
               DLNGAM(DM+DBETA*DX-DX+1.0D0)
        DPDF=DEXP(DTERM1+DTERM2+DTERM3+DTERM4)
      ENDIF
!
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GNBPDF
      SUBROUTINE GNBPPF(P,THETA,BETA,M,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE GENERALIZED NEGATIVE BINOMIAL
!              DISTRIBUTION WITH SHAPE PARAMETERS THETA, BETA, AND
!              M.  THIS DISTRIBUTION IS DEFINED FOR ALL INTEGER
!              X >= 1.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA,M)=
!                  (M/(M+BETA*X)*
!                  (M+BETA*X  X)*THETA**X*(1-THETA)**(M+BETA*X-X)
!                  X = 0, 1, 2, 3, ,...
!                  0 < THETA < 1; BETA = 0 OR 1 <= BETA <= 1/THETA;
!                  M > 0 (M A POSITIVE INTEGER IF BETA = 0)
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              FROM THE FOLLOWING RECURRENCE RELATION:
!
!              P(X+1) = (M+(BETA-1)*X+BETA)/(X+1)*
!                       THETA*(1-THETA)**(BETA-1)*
!                       PROD[J=1 TO X-1][1 + BETA/(M+BETA*X-J)]*P(X)
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY COMPUTING
!              THE CUMULATIVE DISTRIBUTION FUNCTION UNTIL THE
!              THE SPECIFIED PROBABILITY IS REACHED.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                0 <= P < 1
!                     --THETA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --M      = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE GENERALIZED NEGATIVE BINOMIAL
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA, BETA AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P < 1
!                 --0 < THETA < 1; 1 <= BETA <= 1/THETA; M > 0
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL M
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DP
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      DPPF=0.0D0
!
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO GNBPPF IS OUTSIDE ',   &
               'THE (0,1] INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO GNBPPF IS NOT IN ',   &
               'THE INTERVAL (0,1).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LE.1.0 .OR. BETA.GE.1.0/THETA .AND. BETA.NE.0.0)THEN
        WRITE(ICOUT,25)1.0/THETA
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO GNBPPF IS NOT IN ',   &
               'THE INTERVAL (1,',G15.7,').')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(M.LE.0.0)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO GNBPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)M
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(BETA.EQ.0.0)THEN
        IM=INT(M+0.5)
        IF(IM.EQ.0)IM=1
        M=REAL(IM)
      ENDIF
!
      DTHETA=DBLE(THETA)
      DBETA=DBLE(BETA)
      DM=DBLE(M)
      DP=DBLE(P)
      DEPS=1.0D-7
!
!     USE THE RECURRENCE RELATION (PAGE 199 OF CONSUL AND FAMOYE):
!
      DCDF=(1.0D0 - DTHETA)**DM
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=0.0
        GO TO 9000
      ENDIF
!
      DPDF=DM*DTHETA*(1.0D0 - DTHETA)**(DM+DBETA-1.0D0)
      DCDF=DCDF + DPDF
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=1.0
        GO TO 9000
      ENDIF
!
      DPDFSV=DPDF
      DTERM2=DLOG(DTHETA) + (DBETA - 1.0D0)*DLOG(1.0D0 - DTHETA)
      I=1
!
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9000
        ENDIF
        DX=DBLE(I)
!
        DTERM1=DLOG(DM + (DBETA-1.0D0)*(DX-1.0D0) + DBETA) -   &
               DLOG(DX)
        IF(DPDFSV.LE.0.0D0)THEN
          GO TO 1000
        ELSE
          DTERM3=DLOG(DPDFSV)
        ENDIF
        IF(I-2.GE.1)THEN
          DSUM=0.0D0
          DO 200 J=1,I-2
            DSUM=DSUM + DLOG(1.0D0 + DBETA/   &
                 (DM + DBETA*(DX-1.0D0)-DBLE(J)))
  200     CONTINUE
        ELSE
          DSUM=0.0D0
        ENDIF
        DPDF=DEXP(DTERM1 + DTERM2 + DTERM3 + DSUM)
        DCDF=DCDF + DPDF
        DPDFSV=DPDF
        IF(DCDF.GE.DP-DEPS)THEN
          PPF=REAL(I)
          GO TO 9000
        ENDIF
      GO TO 100
!
 1000 CONTINUE
      PPF=REAL(DPPF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GNBPPF
      SUBROUTINE GNBRAN(N,THETA,BETA,AM,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION
!              WITH SHAPE PARAMETERS THETA, BETA, AND M.
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;THETA,BETA,M)=
!                  (M/(M+BETA*X)*
!                  (M+BETA*X  X)*THETA**X*(1-THETA)**(M+BETA*X-X)
!                  X = 0, 1, 2, 3, ,...
!                  0 < THETA < 1; BETA = 0 OR 1 <= BETA <= 1/THETA;
!                  M > 0 (M A POSITIVE INTEGER IF BETA = 0)
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --AM     = THE SINGLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION
!             WITH SHAPE PARAMETERS THETA, BETA, AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 < THETA < 1, 1 < BETA < 1/THETA, M > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GNBPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FAMOYE (1997), "SAMPLING FROM A GENERALIZED
!                 NEGATIVE BINOMIAL DISTRIBUTION", COMPUTING,
!                 58(4), PP. 365-376.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTERS 11 AND 16.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL THETA
      REAL BETA
      DIMENSION X(*)
      DIMENSION XTEMP(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!CCCC DATA PI / 3.1415926535 8979323846 E0 /
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'GENERALIZED NEGATIVE BINOMIAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
    6   FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE THETA PARAMETER FOR THE ',   &
               'GENERALIZED NEGATIVE BINOMIAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
   12   FORMAT('      RANDOM NUMBERS IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.LE.1.0 .OR. BETA.GE.1.0/THETA)THEN
        WRITE(ICOUT,21)
   21   FORMAT('***** ERROR--THE BETA PARAMETER FOR THE ',   &
               'GENERALIZED NEGATIVE BINOMIAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22)
   22   FORMAT('      RANDOM NUMBERS IS OUTSIDE THE (0,',G15.7,   &
               ') INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(AM.LE.0.0)THEN
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR--THE M PARAMETER FOR THE ',   &
               'GENERALIZED NEGATIVE BINOMIAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)AM
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     GENERATE N GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION
!     RANDOM NUMBERS.  FOLLOWING RECOMMENDATION OF CONSUL AND
!     FAYMOE, USE INVERSION METHOD FOR THETA*BETA <= 0.60 AND
!     BRANCHING METHOD OTHERWISE.
!
!     BRANCHING ALGORITHM DOESN'T SEEM TO RETURN AS ACCURATE
!     A RESULT AS THE INVERSION METHOD, SO USE THE INVERSION
!     METHOD EVEN IF SOMEWHAT SLOWER.
!
      IFLAG=0
      IF(THETA*BETA.LE.0.6 .OR. IFLAG.EQ.0)THEN
        CALL UNIRAN(N,ISEED,X)
        DO 100 I=1,N
          ZTEMP=X(I)
          CALL GNBPPF(ZTEMP,THETA,BETA,AM,PPF)
          X(I)=PPF
  100   CONTINUE
      ELSE
!
!       BRANCHING ALGORITHM
!
        NTEMP=1
        DO 200 I=1,N
          CALL NBRAN(NTEMP,1.0-THETA,AM,ISEED,XTEMP)
          Y=XTEMP(1)
          IF(Y.LE.0.0)THEN
            X(I)=Y
            GO TO 200
          ENDIF
          XX=0.0
  220     CONTINUE
          AK=(BETA-1.0)*Y
          CALL NBRAN(NTEMP,1.0-THETA,AK,ISEED,XTEMP)
          Z=XTEMP(1)
          XX=XX+Y+Z
          Y=Z
          IF(Y.GT.0.0)GO TO 220
          X(I)=XX
  200   CONTINUE
      ENDIF
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE GNBRAN
      SUBROUTINE GNTCDF(X,THETA,BETA,M,NTRUNC,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE TRUNCATED GENERALIZED
!              NEGATIVE BINOMIAL DISTRIBUTION WITH SHAPE PARAMETERS
!              THETA, BETA, AND M.
!
!              THE PROBABILITY MASS FUNCTION FOR THE NON-TRUNCATED
!              GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION IS:
!
!              p(X;THETA,BETA,M)=
!                  (M/(M+BETA*X)*
!                  (M+BETA*X  X)*THETA**X*(1-THETA)**(M+BETA*X-X)
!                  X = 0, 1, 2, 3, ,...
!                  0 < THETA < 1; BETA = 0 OR 1 <= BETA <= 1/THETA;
!                  M > 0 (M A POSITIVE INTEGER IF BETA = 0)
!
!              THE TRUNCATED GENERALIZED NEGATIVE BINOMIAL
!              DISTRIBUTION CAN BE DEFINED AS:
!
!              p(X;THETA,BETA,M)/F(NTRUNC,THETA,BETA,M)
!
!              WITH p, F, AND NTRUNC DENOTING THE PROBABILITY
!              MASS AND CUMULATIVE DISTRIBUTION FUNCTION OF
!              THE GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION
!              AND THE TRUNCATION POINT, RESPECTIVELY.
!
!              THE TRUNCATED CUMULATIVE DISTRIBUTION FUNCTION
!              CAN THEREFORE BE COMPUTED AS:
!
!              F(X;THETA,BETA,M)/F(NTRUNC,THETA,BETA,M)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --THETA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --M      = THE THIRD SHAPE PARAMETER
!                     --NTRUNC = THE TRUNCATION POINT
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE GENERALIZED NEGATIVE BINOMIAL
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA, BETA AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= X <= NTRUNC; SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 < THETA < 1; 1 <= BETA <= 1/THETA
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     REFERENCES--CONSUL AND FAMOYE (1993), "THE TRUNCATED
!                 GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION",
!                 JOURNAL OF APPLIED STATISTICAL SCIENCE,
!                 VOL. 1, NO. 2, PP. 141-157.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/1
!     ORIGINAL VERSION--JANUARY   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL M
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(NTRUNC.LT.1)THEN
        WRITE(ICOUT,3)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NTRUNC
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    3 FORMAT('***** ERROR--THE FIFTH ARGUMENT TO GNTCDF, THE ',   &
            'TRUNCATION POINT, IS LESS THAN 1')
!
      IX=INT(X+0.5)
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO GNTCDF IS LESS ',   &
      'THAN 0')
!
      IF(THETA.LE.0.0 .OR. THETA.GE.1.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO GNTCDF IS NOT IN ',   &
      'THE INTERVAL (0,1)')
!
      IF(BETA.LE.1.0 .OR. BETA.GE.1.0/THETA .AND. BETA.NE.0.0)THEN
        WRITE(ICOUT,25)1.0/THETA
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   25 FORMAT('***** ERROR--THE THIRD ARGUMENT TO GNTCDF IS NOT IN ',   &
      'THE INTERVAL (1,',G15.7,')')
!
      IF(M.LE.0.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)M
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   35 FORMAT('***** ERROR--THE FOURTH ARGUMENT TO GNTCDF IS ',   &
      'NON-POSITIVE')
      IF(BETA.EQ.0.0)THEN
        IM=INT(M+0.5)
        IF(IM.EQ.0)IM=1
        M=REAL(IM)
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      IF(IX.EQ.NTRUNC)THEN
        CDF=1.0
      ELSE
        CALL GNBCDF(X,THETA,BETA,M,TERM1)
        CALL GNBCDF(REAL(NTRUNC),THETA,BETA,M,TERM2)
        CDF=TERM1/TERM2
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE GNTCDF
      SUBROUTINE GNTPDF(X,THETA,BETA,M,NTRUNC,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE FOR THE TRUNCATED GENERALIZED
!              NEGATIVE BINOMIAL DISTRIBUTION WITH SHAPE PARAMETERS
!              THETA, BETA, AND M.
!
!              THE PROBABILITY MASS FUNCTION FOR THE NON-TRUNCATED
!              GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION IS:
!
!              p(X;THETA,BETA,M)=
!                  (M/(M+BETA*X)*
!                  (M+BETA*X  X)*THETA**X*(1-THETA)**(M+BETA*X-X)
!                  X = 0, 1, 2, 3, ,...
!                  0 < THETA < 1; BETA = 0 OR 1 <= BETA <= 1/THETA;
!                  M > 0 (M A POSITIVE INTEGER IF BETA = 0)
!
!              THE TRUNCATED GENERALIZED NEGATIVE BINOMIAL
!              DISTRIBUTION CAN BE DEFINED AS:
!
!              p(X;THETA,BETA,M)/F(NTRUNC,THETA,BETA,M)
!
!              WITH p, F, AND NTRUNC DENOTING THE PROBABILITY
!              MASS AND CUMULATIVE DISTRIBUTION FUNCTION OF
!              THE GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION
!              AND THE TRUNCATION POINT, RESPECTIVELY.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --THETA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --M      = THE THIRD SHAPE PARAMETER
!                     --NTRUNC = THE TRUNCATION POINT
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY MASS FUNCTION
!             VALUE PDF FOR THE GENERALIZED NEGATIVE BINOMIAL
!             DISTRIBUTION WITH SHAPE PARAMETERS THETA, BETA AND M.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= X <= NTRUNC; SHOULD BE A NON-NEGATIVE INTEGER
!                 --0 < THETA < 1; 1 <= BETA <= 1/THETA
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 10.
!     REFERENCES--CONSUL AND FAMOYE (1993), "THE TRUNCATED
!                 GENERALIZED NEGATIVE BINOMIAL DISTRIBUTION",
!                 JOURNAL OF APPLIED STATISTICAL SCIENCE,
!                 VOL. 1, NO. 2, PP. 141-157.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
